        private void StampPacketOwnedUtilityRequestState()
        {
            _packetOwnedUtilityRequestTick = Environment.TickCount;
        }

        private string ApplyPacketQuestGuideLaunch(int questId, IReadOnlyDictionary<int, IReadOnlyList<int>> targetsByMobId)
        {
            StampPacketOwnedUtilityRequestState();
            ClearQuestDemandItemQueryState(refreshWorldMap: false);
            ClearPacketQuestGuideTargets(refreshWorldMap: false);

            if (targetsByMobId != null)
            {
                foreach ((int targetMobId, IReadOnlyList<int> mapIds) in targetsByMobId)
                {
                    if (targetMobId <= 0 || mapIds == null)
                    {
                        continue;
                    }

                    for (int i = 0; i < mapIds.Count; i++)
                    {
                        AddPacketQuestGuideTarget(targetMobId, mapIds[i]);
                    }
                }
            }

            if (_packetQuestGuideTargetsByMobId.Count == 0)
            {
                ClearPacketQuestGuideTargets();
                string notice = ResolvePacketQuestGuideUnavailableNotice();
                NotifyEventAlarmOwnerActivity("packet-owned quest guide");
                ShowUtilityFeedbackMessage(notice);
                return notice;
            }

            _packetQuestGuideQuestId = Math.Max(0, questId);
            RefreshWorldMapWindow(_mapBoard?.MapInfo?.id ?? 0);

            if (uiWindowManager?.GetWindow(MapSimulatorWindowNames.WorldMap) is not WorldMapUI worldMapWindow)
            {
                ClearPacketQuestGuideTargets(refreshWorldMap: false);
                const string unavailable = "World map window is not available in this UI build.";
                NotifyEventAlarmOwnerActivity("packet-owned quest guide");
                ShowUtilityFeedbackMessage(unavailable);
                return unavailable;
            }

            if (!TryResolveFirstQuestGuideTarget(out int mobId, out int mapId))
            {
                ClearPacketQuestGuideTargets();
                string notice = ResolvePacketQuestGuideUnavailableNotice();
                NotifyEventAlarmOwnerActivity("packet-owned quest guide");
                ShowUtilityFeedbackMessage(notice);
                return notice;
            }

            string mobName = ResolvePacketGuideMobName(mobId);
            if (!worldMapWindow.FocusSearchResult(WorldMapUI.SearchResultKind.Mob, mobName, mapId))
            {
                ClearPacketQuestGuideTargets();
                string notice = ResolvePacketQuestGuideUnavailableNotice();
                NotifyEventAlarmOwnerActivity("packet-owned quest guide");
                ShowUtilityFeedbackMessage(notice);
                return notice;
            }

            uiWindowManager.ShowWindow(MapSimulatorWindowNames.WorldMap);
            uiWindowManager.BringToFront(worldMapWindow);
            NotifyEventAlarmOwnerActivity("packet-owned quest guide");
            return $"Opened packet-authored quest guide for quest #{_packetQuestGuideQuestId} targeting {mobName}.";
        }

        private string ResetPacketQuestGuideLaunch()
        {
            ClearQuestDemandItemQueryState(refreshWorldMap: false);
            ClearPacketQuestGuideTargets();
            return "Cleared packet-authored quest guide demand state.";
        }

        private static string ResolvePacketQuestGuideUnavailableNotice()
        {
            return MapleStoryStringPool.GetOrFallback(
                PacketOwnedQuestGuideUnavailableNoticeStringPoolId,
                "Quest guide data did not contain any usable world-map mob targets.");
        }

        private void AppendPacketQuestGuideSearchResults(List<WorldMapUI.SearchResultEntry> results, HashSet<string> seen)
        {
            if (results == null || _packetQuestGuideTargetsByMobId.Count == 0)
            {
                return;
            }

            foreach ((int mobId, HashSet<int> mapIds) in _packetQuestGuideTargetsByMobId.OrderBy(entry => entry.Key))
            {
                string mobName = ResolvePacketGuideMobName(mobId);
                foreach (int mapId in mapIds.OrderBy(value => value))
                {
                    string dedupeKey = $"packetmob:{mobId}:{mapId}";
                    if (!seen.Add(dedupeKey))
                    {
                        continue;
                    }

                    results.Add(new WorldMapUI.SearchResultEntry
                    {
                        Kind = WorldMapUI.SearchResultKind.Mob,
                        MapId = mapId,
                        Label = mobName,
                        Description = $"Packet-authored quest guide target in {ResolveMapTransferDisplayName(mapId, null)}"
                    });
                }
            }
        }

        private string ApplyDeliveryQuestLaunch(
            int questId,
            int itemId,
            IReadOnlyList<int> disallowedQuestIds,
            QuestDetailDeliveryType packetOwnedDeliveryType = QuestDetailDeliveryType.None)
        {
            StampPacketOwnedUtilityRequestState();
            _lastDeliveryQuestId = Math.Max(0, questId);
            _lastDeliveryItemId = Math.Max(0, itemId);
            _lastPacketOwnedDeliveryType = packetOwnedDeliveryType;
            _lastDeliveryDisallowedQuestIds.Clear();
            SetPacketOwnedQuestDeliveryTypeHint(_lastDeliveryQuestId, _lastPacketOwnedDeliveryType);
            RegisterPendingQuestDeliveryResultPhaseHint(_lastDeliveryQuestId, _lastPacketOwnedDeliveryType);

            if (disallowedQuestIds != null)
            {
                for (int i = 0; i < disallowedQuestIds.Count; i++)
                {
                    int blockedQuestId = disallowedQuestIds[i];
                    if (blockedQuestId > 0 && !_lastDeliveryDisallowedQuestIds.Contains(blockedQuestId))
                    {
                        _lastDeliveryDisallowedQuestIds.Add(blockedQuestId);
                    }
                }
            }

            if (!TryResolvePacketOwnedDeliveryItemInfo(_lastDeliveryItemId, out string itemName))
            {
                string unavailable = _lastDeliveryItemId > 0
                    ? $"Packet-authored delivery item {_lastDeliveryItemId} could not be resolved through the client item-info seam, so the delivery owner stayed closed."
                    : "Packet-authored delivery item info was missing, so the delivery owner stayed closed.";
                CancelPacketOwnedQuestDeliveryLaunchPhaseHint(_lastDeliveryQuestId, _lastPacketOwnedDeliveryType);
                NotifyEventAlarmOwnerActivity("packet-owned delivery quest");
                ShowUtilityFeedbackMessage(unavailable);
                return unavailable;
            }

            string blockingOwner = GetVisibleUniqueModelessOwner(MapSimulatorWindowNames.QuestDelivery);
            if (!string.IsNullOrWhiteSpace(blockingOwner))
            {
                string statusBarNotice = MapleStoryStringPool.GetOrFallback(
                    PacketOwnedDeliveryUniqueModelessNoticeStringPoolId,
                    "Another utility dialog is already active, so quest delivery stayed on the status-bar chat path.");
                string message = $"{statusBarNotice} Active owner: {blockingOwner}.";
                CancelPacketOwnedQuestDeliveryLaunchPhaseHint(_lastDeliveryQuestId, _lastPacketOwnedDeliveryType);
                NotifyEventAlarmOwnerActivity("packet-owned delivery quest");
                ShowUtilityFeedbackMessage(message);
                return message;
            }

            if (uiWindowManager?.GetWindow(MapSimulatorWindowNames.QuestDelivery) is not QuestDeliveryWindow questDeliveryWindow)
            {
                const string unavailable = "Quest delivery window is not available in this UI build.";
                CancelPacketOwnedQuestDeliveryLaunchPhaseHint(_lastDeliveryQuestId, _lastPacketOwnedDeliveryType);
                NotifyEventAlarmOwnerActivity("packet-owned delivery quest");
                ShowUtilityFeedbackMessage(unavailable);
                return unavailable;
            }

            IReadOnlyList<QuestDeliveryWindow.DeliveryEntry> entries = BuildQuestDeliveryEntries(
                _lastDeliveryQuestId,
                _lastDeliveryItemId,
                _lastDeliveryDisallowedQuestIds,
                _lastPacketOwnedDeliveryType);
            if (entries.Count == 0)
            {
                string emptyMessage = _lastDeliveryQuestId > 0
                    ? $"Quest delivery suppressed quest #{_lastDeliveryQuestId} because no packet-worthy target with a usable NPC and live delivery-item slot survived the packet-owned filter."
                    : $"{itemName} delivery could not surface a packet-worthy quest target with a usable NPC and live delivery-item slot.";
                CancelPacketOwnedQuestDeliveryLaunchPhaseHint(_lastDeliveryQuestId, _lastPacketOwnedDeliveryType);
                NotifyEventAlarmOwnerActivity("packet-owned delivery quest");
                ShowUtilityFeedbackMessage(emptyMessage);
                return emptyMessage;
            }

            questDeliveryWindow.Configure(_lastDeliveryQuestId, _lastDeliveryItemId, entries, _packetOwnedUtilityRequestTick);
            if (!TryShowFieldRestrictedWindow(MapSimulatorWindowNames.QuestDelivery))
            {
                CancelPacketOwnedQuestDeliveryLaunchPhaseHint(_lastDeliveryQuestId, _lastPacketOwnedDeliveryType);
                return GetFieldWindowRestrictionMessage(MapSimulatorWindowNames.QuestDelivery)
                    ?? "Quest delivery cannot be opened in this map.";
            }

            ShowWindow(MapSimulatorWindowNames.QuestDelivery, questDeliveryWindow, trackDirectionModeOwner: true);
            NotifyEventAlarmOwnerActivity("packet-owned delivery quest");
            return $"Opened packet-authored quest delivery for {itemName}.";
        }

        private string ApplyQuestDemandItemQueryLaunch(QuestDemandItemQueryState queryState, int preferredVisibleItemId = 0)
        {
            StampPacketOwnedUtilityRequestState();
            ClearPacketQuestGuideTargets(refreshWorldMap: false);
            _lastQuestDemandItemQueryQuestId = Math.Max(0, queryState?.QuestId ?? 0);
            _lastQuestDemandQueryVisibleItemIds.Clear();
            _lastQuestDemandQueryVisibleItemMapIds.Clear();
            _lastQuestDemandQueryVisibleItemMapSources.Clear();
            _lastQuestDemandQueryPreferredItemId = Math.Max(0, queryState?.PreferredItemId ?? 0);
            _lastQuestDemandQueryHiddenItemCount = Math.Max(0, queryState?.HiddenItemCount ?? 0);
            _lastQuestDemandQueryHasPacketOwnedMapResults = queryState?.HasPacketOwnedMapResults == true;

            if (queryState?.VisibleItemIds != null)
            {
                for (int i = 0; i < queryState.VisibleItemIds.Count; i++)
                {
                    int itemId = queryState.VisibleItemIds[i];
                    if (itemId > 0 && !_lastQuestDemandQueryVisibleItemIds.Contains(itemId))
                    {
                        _lastQuestDemandQueryVisibleItemIds.Add(itemId);
                    }
                }
            }

            if (preferredVisibleItemId > 0 && _lastQuestDemandQueryVisibleItemIds.Contains(preferredVisibleItemId))
            {
                _lastQuestDemandQueryPreferredItemId = preferredVisibleItemId;
            }

            if (queryState?.VisibleItemMapIds != null)
            {
                foreach ((int itemId, IReadOnlyList<int> mapIds) in queryState.VisibleItemMapIds)
                {
                    if (itemId <= 0 || mapIds == null)
                    {
                        continue;
                    }

                    List<int> normalizedMapIds = mapIds
                        .Where(mapId => mapId > 0)
                        .Distinct()
                        .OrderBy(mapId => mapId)
                        .ToList();
                    if (normalizedMapIds.Count > 0)
                    {
                        _lastQuestDemandQueryVisibleItemMapIds[itemId] = normalizedMapIds;
                    }
                }
            }

            if (queryState?.VisibleItemMapResults != null)
            {
                foreach ((int itemId, QuestDemandItemMapResultSet resultSet) in queryState.VisibleItemMapResults)
                {
                    if (itemId <= 0 || resultSet == null)
                    {
                        continue;
                    }

                    _lastQuestDemandQueryVisibleItemMapSources[itemId] = resultSet.Source;
                }
            }

            if (_lastQuestDemandQueryVisibleItemIds.Count == 0)
            {
                string fallbackNpc = queryState?.FallbackNpcName;
                if (!string.IsNullOrWhiteSpace(fallbackNpc) &&
                    uiWindowManager?.GetWindow(MapSimulatorWindowNames.WorldMap) is WorldMapUI worldMapWindow)
                {
                    RefreshWorldMapWindow(_mapBoard?.MapInfo?.id ?? 0);
                    int currentMapId = _mapBoard?.MapInfo?.id ?? 0;
                    bool focused = worldMapWindow.FocusSearchResult(WorldMapUI.SearchResultKind.Npc, fallbackNpc, currentMapId);
                    uiWindowManager.ShowWindow(MapSimulatorWindowNames.WorldMap);
                    uiWindowManager.BringToFront(worldMapWindow);
                    return focused
                        ? $"Quest demand query only exposed hidden items, so the world map fell back to {fallbackNpc}."
                        : $"Quest demand query only exposed hidden items, and {fallbackNpc} could not be resolved in the current world-map search results.";
                }

                return "Quest demand query only exposed hidden items, so no local item search target could be surfaced.";
            }

            RefreshWorldMapWindow(_mapBoard?.MapInfo?.id ?? 0);
            if (uiWindowManager?.GetWindow(MapSimulatorWindowNames.WorldMap) is not WorldMapUI demandWorldMapWindow)
            {
                ClearQuestDemandItemQueryState(refreshWorldMap: false);
                const string unavailable = "World map window is not available in this UI build.";
                ShowUtilityFeedbackMessage(unavailable);
                return unavailable;
            }

            int currentFieldId = _mapBoard?.MapInfo?.id ?? 0;
            int focusItemId = ResolveQuestDemandQueryFocusItemId(currentFieldId);
            IReadOnlyList<int> focusMapIds = ResolveQuestDemandQueryMapIds(focusItemId, currentFieldId);
            int focusMapId = focusMapIds.Count > 0 ? focusMapIds[0] : currentFieldId;
            string focusItemName = InventoryItemMetadataResolver.TryResolveItemName(focusItemId, out string resolvedItemName)
                ? resolvedItemName
                : $"Item {focusItemId}";
            bool focusedItem = demandWorldMapWindow.FocusSearchResult(WorldMapUI.SearchResultKind.Item, focusItemName, focusMapId);
            uiWindowManager.ShowWindow(MapSimulatorWindowNames.WorldMap);
            uiWindowManager.BringToFront(demandWorldMapWindow);

            string hiddenSuffix = _lastQuestDemandQueryHiddenItemCount > 0
                ? $" {_lastQuestDemandQueryHiddenItemCount} hidden demand item(s) remain packet-only."
                : string.Empty;
            QuestDemandItemMapResultSource focusSource = ResolveQuestDemandQueryMapSource(focusItemId);
            string mapSuffix = focusMapIds.Count > 0
                ? focusMapIds.Count == 1
                    ? $" Routed to {ResolveMapTransferDisplayName(focusMapId, null)} via {FormatQuestDemandQueryMapSource(focusSource)}."
                    : $" Routed across {focusMapIds.Count} {FormatQuestDemandQueryMapSource(focusSource)} map result(s)."
                : string.Empty;
            return focusedItem
                ? $"Opened a packet-shaped quest demand item query for {focusItemName}.{hiddenSuffix}{mapSuffix}".TrimEnd()
                : $"Opened the world map, but the demand-item query for {focusItemName} could not be resolved.{hiddenSuffix}{mapSuffix}".TrimEnd();
        }

        private string LaunchQuestDemandItemQuery(QuestDemandItemQueryState queryState, int preferredVisibleItemId = 0)
        {
            if (!TryDispatchQuestDemandItemQueryRequest(queryState, out string dispatchMessage, out bool blockedByCooldown))
            {
                return blockedByCooldown
                    ? dispatchMessage
                    : ApplyQuestDemandItemQueryLaunch(queryState, preferredVisibleItemId);
            }

            string launchMessage = ApplyQuestDemandItemQueryLaunch(queryState, preferredVisibleItemId);
            return string.IsNullOrWhiteSpace(dispatchMessage)
                ? launchMessage
                : $"{dispatchMessage} {launchMessage}".Trim();
        }

        private bool TryDispatchQuestDemandItemQueryRequest(
            QuestDemandItemQueryState queryState,
            out string message,
            out bool blockedByCooldown)
        {
            blockedByCooldown = false;
            int questId = Math.Max(0, queryState?.QuestId ?? 0);
            IReadOnlyList<int> requestItemIds = queryState?.RequestItemIds ?? Array.Empty<int>();
            if (questId <= 0 || requestItemIds.Count <= 0)
            {
                message = "Quest demand-item query stayed local because the loaded quest data did not expose a client-shaped item-query payload.";
                return false;
            }

            int currentTick = Environment.TickCount;
            if (_packetOwnedUtilityRequestTick != int.MinValue &&
                unchecked(currentTick - _packetOwnedUtilityRequestTick) < QuestDemandItemQueryExclusiveRequestCooldownMs)
            {
                blockedByCooldown = true;
                message = "Quest demand-item query stayed blocked by the client 500 ms exclusive-request cooldown.";
                return false;
            }

            byte[] payload = BuildQuestDemandItemQueryRequestPayload(questId, requestItemIds);
            StampPacketOwnedUtilityRequestState();
            message = DispatchQuestDemandItemQueryRequestPayload(questId, requestItemIds.Count, payload);
            return true;
        }

        internal static byte[] BuildQuestDemandItemQueryRequestPayload(int questId, IReadOnlyList<int> requestItemIds)
        {
            int itemCount = Math.Max(0, requestItemIds?.Count ?? 0);
            byte[] payload = new byte[sizeof(byte) + sizeof(ushort) + sizeof(int) + (itemCount * sizeof(int))];
            using var stream = new MemoryStream(payload, writable: true);
            using var writer = new BinaryWriter(stream, Encoding.Default, leaveOpen: false);
            writer.Write((byte)0);
            writer.Write((ushort)Math.Clamp(questId, 0, ushort.MaxValue));
            writer.Write(itemCount);
            for (int i = 0; i < itemCount; i++)
            {
                writer.Write(Math.Max(0, requestItemIds[i]));
            }

            return payload;
        }

        private string DispatchQuestDemandItemQueryRequestPayload(int questId, int itemCount, byte[] payload)
        {
            payload ??= Array.Empty<byte>();
            string summary = $"Mirrored CUIQuestInfoDetail demand-item query opcode {QuestDemandItemQueryRequestOpcode} for quest #{questId} with {itemCount} client item row(s).";
            if (_localUtilityOfficialSessionBridge.TrySendOutboundPacket(
                    QuestDemandItemQueryRequestOpcode,
                    payload,
                    out string dispatchStatus))
            {
                return $"{summary} Dispatched it through the live official-session bridge. {dispatchStatus}";
            }

            if (_localUtilityPacketOutbox.TrySendOutboundPacket(
                    QuestDemandItemQueryRequestOpcode,
                    payload,
                    out string outboxStatus))
            {
                return $"{summary} Dispatched it through the generic packet outbox after the live bridge path was unavailable. Bridge: {dispatchStatus} Outbox: {outboxStatus}";
            }

            string deferredBridgeStatus = "Official-session bridge deferred delivery is disabled.";
            if (_localUtilityOfficialSessionBridgeEnabled
                && _localUtilityOfficialSessionBridge.TryQueueOutboundPacket(
                    QuestDemandItemQueryRequestOpcode,
                    payload,
                    out deferredBridgeStatus))
            {
                return $"{summary} Queued it for deferred official-session injection after the immediate bridge and outbox paths were unavailable. Bridge: {dispatchStatus} Outbox: {outboxStatus} Deferred official bridge: {deferredBridgeStatus}";
            }

            if (_localUtilityPacketOutbox.TryQueueOutboundPacket(
                    QuestDemandItemQueryRequestOpcode,
                    payload,
                    out string queuedStatus))
            {
                return $"{summary} Queued it for deferred generic packet outbox delivery after the immediate bridge path was unavailable. Bridge: {dispatchStatus} Outbox: {outboxStatus} Deferred official bridge: {deferredBridgeStatus} Deferred outbox: {queuedStatus}";
            }

            return $"{summary} It remained simulator-owned because neither the live bridge nor the packet outbox accepted opcode {QuestDemandItemQueryRequestOpcode}. Bridge: {dispatchStatus} Outbox: {outboxStatus} Deferred official bridge: {deferredBridgeStatus}";
        }

        private int ResolveQuestDemandQueryFocusItemId(int currentMapId)
        {
            if (_lastQuestDemandQueryVisibleItemIds.Count == 0)
            {
                return 0;
            }

            if (_lastQuestDemandQueryPreferredItemId > 0 &&
                _lastQuestDemandQueryVisibleItemIds.Contains(_lastQuestDemandQueryPreferredItemId))
            {
                return _lastQuestDemandQueryPreferredItemId;
            }

            for (int i = 0; i < _lastQuestDemandQueryVisibleItemIds.Count; i++)
            {
                int itemId = _lastQuestDemandQueryVisibleItemIds[i];
                IReadOnlyList<int> mapIds = ResolveQuestDemandQueryMapIds(itemId, fallbackMapId: 0);
                if (mapIds.Count == 0)
                {
                    continue;
                }

                if (currentMapId > 0 && mapIds.Contains(currentMapId))
                {
                    return itemId;
                }

                return itemId;
            }

            return _lastQuestDemandQueryVisibleItemIds[0];
        }

        private void AppendQuestDemandItemSearchResults(List<WorldMapUI.SearchResultEntry> results, HashSet<string> seen)
        {
            if (results == null || _lastQuestDemandQueryVisibleItemIds.Count == 0)
            {
                return;
            }

            int currentMapId = _mapBoard?.MapInfo?.id ?? 0;
            for (int i = 0; i < _lastQuestDemandQueryVisibleItemIds.Count; i++)
            {
                int itemId = _lastQuestDemandQueryVisibleItemIds[i];
                if (itemId <= 0)
                {
                    continue;
                }

                string itemName = InventoryItemMetadataResolver.TryResolveItemName(itemId, out string resolvedItemName)
                    ? resolvedItemName
                    : $"Item {itemId}";
                IReadOnlyList<int> mapIds = ResolveQuestDemandQueryMapIds(itemId, currentMapId);
                if (mapIds.Count == 0)
                {
                    continue;
                }

                for (int mapIndex = 0; mapIndex < mapIds.Count; mapIndex++)
                {
                    int mapId = mapIds[mapIndex];
                    string dedupeKey = $"questitem:{_lastQuestDemandItemQueryQuestId}:{mapId}:{itemId}";
                    if (!seen.Add(dedupeKey))
                    {
                        continue;
                    }

                    string mapName = ResolveMapTransferDisplayName(mapId, null);
                    string sourceText = FormatQuestDemandQuerySearchResultSource(ResolveQuestDemandQueryMapSource(itemId));
                    results.Add(new WorldMapUI.SearchResultEntry
                    {
                        Kind = WorldMapUI.SearchResultKind.Item,
                        MapId = mapId,
                        Label = itemName,
                        Description = $"{sourceText} for quest #{_lastQuestDemandItemQueryQuestId} in {mapName}"
                    });
                }
            }
        }

        private void AppendQuestDetailInlineReferenceSearchResult(List<WorldMapUI.SearchResultEntry> results, HashSet<string> seen)
        {
            if (results == null || seen == null ||
                _lastQuestDetailInlineWorldMapReference is not QuestDetailInlineReference reference ||
                _lastQuestDetailInlineWorldMapIds == null ||
                _lastQuestDetailInlineWorldMapIds.Count == 0)
            {
                return;
            }

            WorldMapUI.SearchResultKind kind;
            string label;
            switch (reference.Kind)
            {
                case QuestDetailInlineReferenceKind.Npc:
                    kind = WorldMapUI.SearchResultKind.Npc;
                    label = ResolveQuestDetailInlineNpcName(reference);
                    break;
                case QuestDetailInlineReferenceKind.Mob:
                    kind = WorldMapUI.SearchResultKind.Mob;
                    label = ResolveQuestDetailInlineMobName(reference);
                    break;
                case QuestDetailInlineReferenceKind.Map:
                    kind = WorldMapUI.SearchResultKind.Field;
                    label = ResolveQuestDetailInlineMapName(reference);
                    break;
                case QuestDetailInlineReferenceKind.Item:
                    kind = WorldMapUI.SearchResultKind.Item;
                    label = ResolveQuestDetailInlineItemName(reference);
                    break;
                default:
                    return;
            }

            for (int i = 0; i < _lastQuestDetailInlineWorldMapIds.Count; i++)
            {
                int mapId = _lastQuestDetailInlineWorldMapIds[i];
                if (mapId <= 0)
                {
                    continue;
                }

                string dedupeKey = $"questdetailref:{reference.Kind}:{reference.TargetId}:{mapId}";
                if (!seen.Add(dedupeKey))
                {
                    continue;
                }

                string mapName = ResolveMapTransferDisplayName(mapId, null);
                results.Add(new WorldMapUI.SearchResultEntry
                {
                    Kind = kind,
                    MapId = mapId,
                    Label = label,
                    Description = $"Quest-detail inline reference for quest #{_activeQuestDetailQuestId} in {mapName}"
                });
            }
        }

        private string ResolveQuestDetailInlineNpcName(QuestDetailInlineReference reference)
        {
            if (!string.IsNullOrWhiteSpace(reference.Label))
            {
                return reference.Label.Trim();
            }

            string key = reference.TargetId.ToString(CultureInfo.InvariantCulture);
            return Program.InfoManager?.NpcNameCache != null &&
                   Program.InfoManager.NpcNameCache.TryGetValue(key, out var info) &&
                   !string.IsNullOrWhiteSpace(info?.Item1)
                ? info.Item1
                : $"NPC #{reference.TargetId}";
        }

        private string ResolveQuestDetailInlineMobName(QuestDetailInlineReference reference)
        {
            if (!string.IsNullOrWhiteSpace(reference.Label))
            {
                return reference.Label.Trim();
            }

            string key = reference.TargetId.ToString(CultureInfo.InvariantCulture);
            return Program.InfoManager?.MobNameCache != null &&
                   Program.InfoManager.MobNameCache.TryGetValue(key, out string mobName) &&
                   !string.IsNullOrWhiteSpace(mobName)
                ? mobName
                : $"Mob #{reference.TargetId}";
        }

        private string ResolveQuestDetailInlineMapName(QuestDetailInlineReference reference)
        {
            if (!string.IsNullOrWhiteSpace(reference.Label))
            {
                return reference.Label.Trim();
            }

            return ResolveMapTransferDisplayName(reference.TargetId, null);
        }

        private static string ResolveQuestDetailInlineItemName(QuestDetailInlineReference reference)
        {
            if (!string.IsNullOrWhiteSpace(reference.Label))
            {
                return reference.Label.Trim();
            }

            return InventoryItemMetadataResolver.TryResolveItemName(reference.TargetId, out string itemName)
                ? itemName
                : $"Item {reference.TargetId}";
        }

        private void ClearQuestDemandItemQueryState(bool refreshWorldMap = true)
        {
            _lastQuestDemandItemQueryQuestId = 0;
            _lastQuestDemandQueryVisibleItemIds.Clear();
            _lastQuestDemandQueryVisibleItemMapIds.Clear();
            _lastQuestDemandQueryVisibleItemMapSources.Clear();
            _lastQuestDemandQueryPreferredItemId = 0;
            _lastQuestDemandQueryHiddenItemCount = 0;
            _lastQuestDemandQueryHasPacketOwnedMapResults = false;
            _lastQuestDetailInlineWorldMapReference = null;
            _lastQuestDetailInlineWorldMapIds = Array.Empty<int>();

            if (refreshWorldMap)
            {
                RefreshWorldMapWindow(_mapBoard?.MapInfo?.id ?? 0);
            }
        }

        private IReadOnlyList<int> ResolveQuestDemandQueryMapIds(int itemId, int fallbackMapId)
        {
            if (itemId > 0 &&
                _lastQuestDemandQueryVisibleItemMapIds.TryGetValue(itemId, out List<int> storedMapIds) &&
                storedMapIds != null &&
                storedMapIds.Count > 0)
            {
                return storedMapIds;
            }

            return fallbackMapId > 0
                ? new[] { fallbackMapId }
                : Array.Empty<int>();
        }

        private QuestDemandItemMapResultSource ResolveQuestDemandQueryMapSource(int itemId)
        {
            return itemId > 0 &&
                   _lastQuestDemandQueryVisibleItemMapSources.TryGetValue(itemId, out QuestDemandItemMapResultSource source)
                ? source
                : QuestDemandItemMapResultSource.None;
        }

        private static string FormatQuestDemandQueryMapSource(QuestDemandItemMapResultSource source)
        {
            return source switch
            {
                QuestDemandItemMapResultSource.PacketOwnedMob => "packet-authored mob",
                QuestDemandItemMapResultSource.WzMobDemand => "WZ mob-demand",
                QuestDemandItemMapResultSource.WzNpcFallback => "WZ NPC fallback",
                QuestDemandItemMapResultSource.CurrentFieldFallback => "current-field fallback",
                _ => "quest-demand"
            };
        }

        private static IReadOnlyList<int> ResolveRuntimeFallbackDemandItemMapIds(QuestDemandItemQueryState runtimeFallbackQuery, int itemId)
        {
            QuestDemandItemMapResultSet resultSet = ResolveRuntimeFallbackDemandItemMapResult(runtimeFallbackQuery, itemId);
            return resultSet?.MapIds ?? Array.Empty<int>();
        }

        private static QuestDemandItemMapResultSet ResolveRuntimeFallbackDemandItemMapResult(QuestDemandItemQueryState runtimeFallbackQuery, int itemId)
        {
            if (itemId <= 0 || runtimeFallbackQuery == null)
            {
                return null;
            }

            if (runtimeFallbackQuery.VisibleItemMapResults != null &&
                runtimeFallbackQuery.VisibleItemMapResults.TryGetValue(itemId, out QuestDemandItemMapResultSet resultSet) &&
                resultSet?.MapIds != null &&
                resultSet.MapIds.Count > 0)
            {
                return resultSet;
            }

            if (runtimeFallbackQuery.VisibleItemMapIds != null &&
                runtimeFallbackQuery.VisibleItemMapIds.TryGetValue(itemId, out IReadOnlyList<int> mapIds) &&
                mapIds != null &&
                mapIds.Count > 0)
            {
                return new QuestDemandItemMapResultSet
                {
                    MapIds = mapIds,
                    Source = QuestDemandItemMapResultSource.WzNpcFallback
                };
            }

            return null;
        }

        private string ApplyClassCompetitionPageLaunch()
        {
            StampPacketOwnedUtilityRequestState();
            _lastClassCompetitionOpenTick = Environment.TickCount;
            bool hadNavigatedPage = _lastClassCompetitionLoggedIn && !string.IsNullOrWhiteSpace(_lastClassCompetitionUrl);
            RefreshClassCompetitionRuntimeState(forceAuthRequest: false);

            if (uiWindowManager?.GetWindow(MapSimulatorWindowNames.ClassCompetition) is not UIWindowBase window)
            {
                const string unavailable = "Class Competition page owner is not available in this UI build.";
                NotifyEventAlarmOwnerActivity("packet-owned class competition");
                ShowUtilityFeedbackMessage(unavailable);
                return unavailable;
            }

            ShowWindow(MapSimulatorWindowNames.ClassCompetition, window, trackDirectionModeOwner: true);
            NotifyEventAlarmOwnerActivity("packet-owned class competition");
            if (_lastClassCompetitionAuthPending)
            {
                return hadNavigatedPage && _lastClassCompetitionLoggedIn
                    ? "Opened packet-authored Class Competition page, kept the cached NavigateUrl page live, and queued opcode 291 auth refresh in the background."
                    : "Opened packet-authored Class Competition page and seeded the initial opcode 291 auth request.";
            }

            return hadNavigatedPage && _lastClassCompetitionLoggedIn
                ? "Opened packet-authored Class Competition page using the cached NavigateUrl page."
                : "Opened packet-authored Class Competition page.";
        }

        private void ClearPacketQuestGuideTargets(bool refreshWorldMap = true)
        {
            _packetQuestGuideTargetsByMobId.Clear();
            _packetQuestGuideQuestId = 0;

            if (refreshWorldMap)
            {
                RefreshWorldMapWindow(_mapBoard?.MapInfo?.id ?? 0);
            }
        }

        private void AddPacketQuestGuideTarget(int mobId, int mapId)
        {
            if (mobId <= 0 || mapId <= 0)
            {
                return;
            }

            if (!_packetQuestGuideTargetsByMobId.TryGetValue(mobId, out HashSet<int> mapIds))
            {
                mapIds = new HashSet<int>();
                _packetQuestGuideTargetsByMobId[mobId] = mapIds;
            }

            mapIds.Add(mapId);
        }

        private bool TryResolveFirstQuestGuideTarget(out int mobId, out int mapId)
        {
            foreach ((int currentMobId, HashSet<int> mapIds) in _packetQuestGuideTargetsByMobId.OrderBy(entry => entry.Key))
            {
                if (mapIds.Count == 0)
                {
                    continue;
                }

                mobId = currentMobId;
                mapId = mapIds.OrderBy(value => value).First();
                return true;
            }

            mobId = 0;
            mapId = 0;
            return false;
        }

        private string GetVisibleUniqueModelessOwner(string ignoredWindowName)
        {
            if (uiWindowManager == null)
            {
                return null;
            }

            for (int i = 0; i < UniqueModelessUtilityWindowNames.Length; i++)
            {
                string windowName = UniqueModelessUtilityWindowNames[i];
                if (string.Equals(windowName, ignoredWindowName, StringComparison.Ordinal))
                {
                    continue;
                }

                if (uiWindowManager.GetWindow(windowName) is UIWindowBase window && window.IsVisible)
                {
                    return ResolveWindowDisplayName(windowName);
                }
            }

            return null;
        }

        private static bool IsUniqueModelessUtilityWindowName(string windowName)
        {
            if (string.IsNullOrWhiteSpace(windowName))
            {
                return false;
            }

            for (int i = 0; i < UniqueModelessUtilityWindowNames.Length; i++)
            {
                if (string.Equals(UniqueModelessUtilityWindowNames[i], windowName, StringComparison.Ordinal))
                {
                    return true;
                }
            }

            return false;
        }

        private void PreparePacketOwnedAdminShopForUniqueModelessOwnerShow(string ownerWindowName)
        {
            if (uiWindowManager == null
                || string.IsNullOrWhiteSpace(ownerWindowName)
                || string.Equals(ownerWindowName, MapSimulatorWindowNames.CashShop, StringComparison.Ordinal)
                || !IsUniqueModelessUtilityWindowName(ownerWindowName))
            {
                return;
            }

            if (uiWindowManager.GetWindow(MapSimulatorWindowNames.CashShop) is not AdminShopDialogUI cashShopWindow
                || !cashShopWindow.IsVisible
                || !cashShopWindow.HasPacketOwnedAdminShopSession)
            {
                return;
            }

            string replacingOwner = ResolveWindowDisplayName(ownerWindowName);
            cashShopWindow.RecordPacketOwnedAdminShopOwnerSurfaceHidden(
                $"CAdminShopDlg owner surface was hidden because {replacingOwner} took the unique-modeless slot.",
                AdminShopPacketOwnedOwnerVisibilityState.HiddenByUniqueModelessOwner);
            uiWindowManager.HideWindow(MapSimulatorWindowNames.CashShop);
        }

