        private IReadOnlyList<QuestDeliveryWindow.DeliveryEntry> BuildQuestDeliveryEntries(
            int requestedQuestId,
            int itemId,
            IReadOnlyList<int> disallowedQuestIds,
            QuestDetailDeliveryType packetOwnedDeliveryType)
        {
            var entries = new List<QuestDeliveryWindow.DeliveryEntry>();
            var appendedQuestIds = new HashSet<int>();
            var candidateQuestIds = new HashSet<int>();
            var blockedQuestIds = new HashSet<int>(disallowedQuestIds?.Where(id => id > 0) ?? Array.Empty<int>());
            IReadOnlyList<QuestDeliveryEntrySnapshot> deliverySnapshot = _questRuntime.BuildQuestDeliverySnapshot(
                requestedQuestId,
                itemId,
                disallowedQuestIds,
                _playerManager?.Player?.Build,
                packetOwnedDeliveryType);

            for (int i = 0; i < deliverySnapshot.Count; i++)
            {
                QuestDeliveryEntrySnapshot snapshot = deliverySnapshot[i];
                if (snapshot == null || !appendedQuestIds.Add(snapshot.QuestId))
                {
                    continue;
                }

                int deliveryCashItemId = snapshot.DeliveryCashItemId ?? 0;
                bool resolvedDeliverySlot = TryResolveQuestDeliveryCashItemSlot(
                    deliveryCashItemId,
                    out InventoryType deliveryInventoryType,
                    out int deliveryRuntimeSlotIndex,
                    out int deliveryClientSlotIndex);
                bool requiresDeliverySlot = deliveryCashItemId > 0;
                if (snapshot.IsBlocked || snapshot.TargetNpcId <= 0 || (requiresDeliverySlot && !resolvedDeliverySlot))
                {
                    appendedQuestIds.Remove(snapshot.QuestId);
                    continue;
                }

                entries.Add(new QuestDeliveryWindow.DeliveryEntry
                {
                    QuestId = snapshot.QuestId,
                    DisplayQuestId = snapshot.DisplayQuestId,
                    TargetNpcId = snapshot.TargetNpcId,
                    Title = snapshot.Title,
                    NpcName = snapshot.NpcName,
                    StatusText = snapshot.StatusText,
                    DetailText = snapshot.DetailText,
                    DeliveryCashItemName = snapshot.DeliveryCashItemName,
                    CompletionPhase = snapshot.CompletionPhase,
                    CanConfirm = snapshot.CanConfirm && (!requiresDeliverySlot || resolvedDeliverySlot),
                    IsBlocked = snapshot.IsBlocked,
                    IsSeriesRepresentative = snapshot.IsSeriesRepresentative,
                    DeliveryCashInventoryType = resolvedDeliverySlot ? deliveryInventoryType : InventoryType.NONE,
                    DeliveryCashItemRuntimeSlotIndex = resolvedDeliverySlot ? deliveryRuntimeSlotIndex : -1,
                    DeliveryCashItemClientSlotIndex = resolvedDeliverySlot ? deliveryClientSlotIndex : 0
                });
                SetPacketOwnedQuestDeliveryTypeHint(snapshot.QuestId, ResolveDeliveryTypeForQuestDeliveryEntry(snapshot.CompletionPhase));
            }

            if (requestedQuestId > 0)
            {
                candidateQuestIds.Add(requestedQuestId);
            }

            AppendQuestIds(candidateQuestIds, BuildQuestLogSnapshotWithPacketState(QuestLogTabType.Available, showAllLevels: true));
            AppendQuestIds(candidateQuestIds, BuildQuestLogSnapshotWithPacketState(QuestLogTabType.InProgress, showAllLevels: true));

            foreach (int questId in blockedQuestIds)
            {
                candidateQuestIds.Add(questId);
            }

            foreach (int questId in candidateQuestIds)
            {
                if (appendedQuestIds.Contains(questId))
                {
                    continue;
                }

                QuestWindowDetailState state = GetQuestWindowDetailStateWithPacketState(questId);
                bool blockedByPacket = blockedQuestIds.Contains(questId);
                bool matchingItem = state?.TargetItemId == itemId && itemId > 0;
                bool isDeliveryAction = state?.DeliveryType is QuestDetailDeliveryType.Accept or QuestDetailDeliveryType.Complete;
                if (!blockedByPacket && (!matchingItem || !isDeliveryAction))
                {
                    continue;
                }

                if (blockedByPacket || (state?.TargetNpcId ?? 0) <= 0)
                {
                    continue;
                }

                bool completionPhase = state?.DeliveryType == QuestDetailDeliveryType.Complete;
                bool canConfirm = state?.DeliveryActionEnabled == true && !blockedByPacket;
                string npcName = string.IsNullOrWhiteSpace(state?.TargetNpcName)
                    ? "NPC unavailable"
                    : state.TargetNpcName;
                int deliveryCashItemId = state?.DeliveryCashItemId ?? 0;
                bool resolvedDeliverySlot = TryResolveQuestDeliveryCashItemSlot(
                    deliveryCashItemId,
                    out InventoryType deliveryInventoryType,
                    out int deliveryRuntimeSlotIndex,
                    out int deliveryClientSlotIndex);
                if (deliveryCashItemId > 0 && !resolvedDeliverySlot)
                {
                    continue;
                }

                string statusText = blockedByPacket
                    ? "Blocked by disallowed-delivery packet state"
                    : canConfirm
                        ? completionPhase
                            ? $"Complete delivery at {npcName}"
                            : $"Accept delivery at {npcName}"
                        : completionPhase
                            ? $"Complete delivery is not ready at {npcName}"
                            : $"Accept delivery is not ready at {npcName}";
                string detailText = !string.IsNullOrWhiteSpace(state?.HintText)
                    ? state.HintText.Replace("\r", " ", StringComparison.Ordinal).Replace("\n", " ", StringComparison.Ordinal)
                    : !string.IsNullOrWhiteSpace(state?.RequirementText)
                        ? state.RequirementText
                        : "The packet-owned delivery owner mirrors the client's worthy-quest list over the simulator quest runtime.";

                entries.Add(new QuestDeliveryWindow.DeliveryEntry
                {
                    QuestId = questId,
                    DisplayQuestId = questId,
                    TargetNpcId = state?.TargetNpcId ?? 0,
                    Title = state?.Title ?? $"Quest #{questId}",
                    NpcName = npcName,
                    StatusText = statusText,
                    DetailText = detailText,
                    DeliveryCashItemName = state?.DeliveryCashItemName ?? string.Empty,
                    CompletionPhase = completionPhase,
                    CanConfirm = canConfirm,
                    IsBlocked = blockedByPacket,
                    IsSeriesRepresentative = false,
                    DeliveryCashInventoryType = resolvedDeliverySlot ? deliveryInventoryType : InventoryType.NONE,
                    DeliveryCashItemRuntimeSlotIndex = resolvedDeliverySlot ? deliveryRuntimeSlotIndex : -1,
                    DeliveryCashItemClientSlotIndex = resolvedDeliverySlot ? deliveryClientSlotIndex : 0
                });
                SetPacketOwnedQuestDeliveryTypeHint(questId, state.DeliveryType);
            }

            return entries
                .OrderByDescending(entry => entry.QuestId == requestedQuestId)
                .ThenByDescending(entry => entry.CanConfirm)
                .ThenBy(entry => entry.CompletionPhase)
                .ThenBy(entry => entry.DisplayQuestId > 0 ? entry.DisplayQuestId : entry.QuestId)
                .ThenBy(entry => entry.QuestId)
                .ToArray();
        }

        private static QuestDetailDeliveryType ResolveDeliveryTypeForQuestDeliveryEntry(bool completionPhase)
        {
            return completionPhase
                ? QuestDetailDeliveryType.Complete
                : QuestDetailDeliveryType.Accept;
        }

        private void SetPacketOwnedQuestDeliveryTypeHint(int questId, QuestDetailDeliveryType deliveryType)
        {
            if (questId <= 0)
            {
                return;
            }

            if (deliveryType == QuestDetailDeliveryType.None)
            {
                _packetOwnedDeliveryTypeHintsByQuestId.Remove(questId);
                return;
            }

            _packetOwnedDeliveryTypeHintsByQuestId[questId] = deliveryType;
        }

        private void CancelPacketOwnedQuestDeliveryLaunchPhaseHint(int questId, QuestDetailDeliveryType deliveryType)
        {
            RemoveLatestPendingQuestDeliveryResultPhaseHint(questId, deliveryType);
            RefreshPacketOwnedQuestDeliveryTypeHintAfterResult(questId);
        }

        private QuestDetailDeliveryType ResolvePacketOwnedQuestDeliveryTypeHint(int questId)
        {
            if (questId <= 0)
            {
                return QuestDetailDeliveryType.None;
            }

            if (_packetOwnedDeliveryTypeHintsByQuestId.TryGetValue(questId, out QuestDetailDeliveryType deliveryType))
            {
                return deliveryType;
            }

            return _lastDeliveryQuestId == questId
                ? _lastPacketOwnedDeliveryType
                : QuestDetailDeliveryType.None;
        }

        private bool IsPacketOwnedDeliveryQuestBlocked(int questId)
        {
            return questId > 0 && _lastDeliveryDisallowedQuestIds.Contains(questId);
        }

        private QuestWindowDetailState ApplyPacketOwnedDeliveryDisallowParity(QuestWindowDetailState state)
        {
            if (state == null ||
                state.DeliveryType == QuestDetailDeliveryType.None ||
                !IsPacketOwnedDeliveryQuestBlocked(state.QuestId))
            {
                return state;
            }

            const string blockedHint = "Packet-owned delivery state currently blocks this quest in the active delivery-owner snapshot.";
            string hintText = string.IsNullOrWhiteSpace(state.HintText)
                ? blockedHint
                : $"{blockedHint}\n{state.HintText}";

            return new QuestWindowDetailState
            {
                QuestId = state.QuestId,
                Title = state.Title,
                HeaderNoteText = state.HeaderNoteText,
                State = state.State,
                SummaryText = state.SummaryText,
                RequirementText = state.RequirementText,
                RewardText = state.RewardText,
                HintText = hintText,
                NpcText = state.NpcText,
                RequirementLines = state.RequirementLines,
                RewardLines = state.RewardLines,
                CurrentProgress = state.CurrentProgress,
                TotalProgress = state.TotalProgress,
                PrimaryAction = state.PrimaryAction,
                PrimaryActionEnabled = state.PrimaryActionEnabled,
                PrimaryActionSelected = state.PrimaryActionSelected,
                PrimaryActionLabel = state.PrimaryActionLabel,
                SecondaryAction = state.SecondaryAction,
                SecondaryActionEnabled = state.SecondaryActionEnabled,
                SecondaryActionLabel = state.SecondaryActionLabel,
                TertiaryAction = state.TertiaryAction,
                TertiaryActionEnabled = state.TertiaryActionEnabled,
                TertiaryActionLabel = state.TertiaryActionLabel,
                QuaternaryAction = state.QuaternaryAction,
                QuaternaryActionEnabled = state.QuaternaryActionEnabled,
                QuaternaryActionLabel = state.QuaternaryActionLabel,
                TargetNpcId = state.TargetNpcId,
                TargetNpcName = state.TargetNpcName,
                TargetMobId = state.TargetMobId,
                TargetMobName = state.TargetMobName,
                TargetItemId = state.TargetItemId,
                TargetItemName = state.TargetItemName,
                HasDetailInset = state.HasDetailInset,
                TimeLimitSeconds = state.TimeLimitSeconds,
                RemainingTimeSeconds = state.RemainingTimeSeconds,
                TimerUiKey = state.TimerUiKey,
                DeliveryType = state.DeliveryType,
                DeliveryActionEnabled = false,
                DeliveryCashItemId = state.DeliveryCashItemId,
                DeliveryCashItemName = state.DeliveryCashItemName,
                NpcButtonStyle = state.NpcButtonStyle
            };
        }

        private bool TryResolveQuestDeliveryCashItemSlot(
            int itemId,
            out InventoryType inventoryType,
            out int runtimeSlotIndex,
            out int clientSlotIndex)
        {
            inventoryType = InventoryItemMetadataResolver.ResolveInventoryType(itemId);
            runtimeSlotIndex = -1;
            clientSlotIndex = 0;
            if (itemId <= 0 || inventoryType == InventoryType.NONE || uiWindowManager?.InventoryWindow is not IInventoryRuntime inventoryWindow)
            {
                return false;
            }

            IReadOnlyList<InventorySlotData> slots = inventoryWindow.GetSlots(inventoryType);
            if (slots == null)
            {
                return false;
            }

            for (int i = 0; i < slots.Count; i++)
            {
                InventorySlotData slot = slots[i];
                if (slot == null
                    || slot.IsDisabled
                    || slot.ItemId != itemId
                    || Math.Max(0, slot.Quantity) <= 0)
                {
                    continue;
                }

                runtimeSlotIndex = i;
                clientSlotIndex = i + 1;
                return true;
            }

            return false;
        }

        private static bool TryResolvePacketOwnedDeliveryItemInfo(int itemId, out string itemName)
        {
            itemName = string.Empty;
            if (itemId <= 0
                || !InventoryItemMetadataResolver.TryResolveImageSource(itemId, out string category, out string imagePath))
            {
                return false;
            }

            WzImage itemImage = Program.FindImage(category, imagePath);
            if (itemImage == null)
            {
                return false;
            }

            try
            {
                itemImage.ParseImage();
                string itemNodeName = string.Equals(category, "Character", StringComparison.OrdinalIgnoreCase)
                    ? itemId.ToString("D8", CultureInfo.InvariantCulture)
                    : itemId.ToString("D7", CultureInfo.InvariantCulture);
                if (itemImage[itemNodeName] is not WzSubProperty)
                {
                    return false;
                }
            }
            catch
            {
                return false;
            }

            itemName = InventoryItemMetadataResolver.TryResolveItemName(itemId, out string resolvedItemName) && !string.IsNullOrWhiteSpace(resolvedItemName)
                ? resolvedItemName
                : $"Item {itemId}";
            return true;
        }

        private void HandleQuestDeliveryWindowRequest(QuestDeliveryWindow.DeliveryEntry entry)
        {
            if (entry == null)
            {
                return;
            }

            int targetNpcId = entry.TargetNpcId;
            if (targetNpcId <= 0)
            {
                string error = $"{entry.Title} does not have a delivery NPC in the loaded quest data.";
                _chat?.AddErrorMessage(error, currTickCount);
                return;
            }

            HandleQuestWindowActionResult(HandleQuestDeliveryLocalHandoff(
                entry.QuestId,
                entry.CompletionPhase,
                sourceContext: "packet-authored quest-delivery owner",
                localHandoff: () =>
                {
                    return OpenPacketQuestDeliveryNpcInteraction(entry);
                },
                resolvedInventoryType: entry.DeliveryCashInventoryType,
                resolvedRuntimeSlotIndex: entry.DeliveryCashItemRuntimeSlotIndex,
                resolvedClientSlotIndex: entry.DeliveryCashItemClientSlotIndex));
        }

        private string OpenPacketQuestDeliveryNpcInteraction(QuestDeliveryWindow.DeliveryEntry entry)
        {
            if (entry == null || _npcInteractionOverlay == null)
            {
                return "Packet-authored delivery could not open because the local NPC interaction owner is unavailable.";
            }

            NpcItem targetNpc = CreateNpcPreview(entry.TargetNpcId, includeTooltips: false) ?? FindNpcById(entry.TargetNpcId);
            if (targetNpc?.NpcInstance?.NpcInfo == null)
            {
                return $"Packet-authored delivery could not resolve NPC template #{entry.TargetNpcId}, so the created-NPC interaction stayed closed.";
            }

            string npcName = targetNpc?.NpcInstance?.NpcInfo?.StringName;
            if (string.IsNullOrWhiteSpace(npcName))
            {
                npcName = string.IsNullOrWhiteSpace(entry.NpcName)
                    ? ResolveNpcDisplayName(entry.TargetNpcId)
                    : entry.NpcName;
            }

            NpcInteractionState interactionState = ApplyPacketOwnedQuestDeliveryPresentation(
                _questRuntime.BuildQuestDeliveryInteractionState(
                    entry.QuestId,
                    _playerManager?.Player?.Build,
                    _lastDeliveryItemId),
                npcName)
                ?? ApplyPacketOwnedQuestDeliveryPresentation(
                    _questRuntime.BuildSingleQuestInteractionState(
                        entry.TargetNpcId,
                        npcName,
                        entry.QuestId,
                        _playerManager?.Player?.Build,
                        includeDeliveryFallback: false),
                    npcName);
            if (interactionState == null)
            {
                return $"Packet-authored delivery could not build a single-quest interaction for quest #{entry.QuestId}.";
            }

            string talkToNpcDispatchStatus = MirrorPacketOwnedQuestDeliveryTalkToNpcRequest(entry);
            _gameState.EnterDirectionMode();
            _scriptedDirectionModeOwnerActive = true;
            _activeNpcInteractionNpc = targetNpc;
            _activeNpcInteractionNpcId = entry.TargetNpcId;
            TryRegisterAnimationDisplayerQuestDeliveryLocalUserState(_lastDeliveryItemId, out _);
            PublishDynamicObjectTagStatesForNpc(entry.TargetNpcId, currTickCount, targetNpc);
            _npcInteractionOverlay.Open(interactionState);

            if (uiWindowManager?.GetWindow(MapSimulatorWindowNames.QuestDelivery) is QuestDeliveryWindow questDeliveryWindow)
            {
                questDeliveryWindow.Hide();
            }

            return $"Opened packet-authored quest delivery interaction for {entry.Title}. {talkToNpcDispatchStatus}";
        }

        private string MirrorPacketOwnedQuestDeliveryTalkToNpcRequest(QuestDeliveryWindow.DeliveryEntry entry)
        {
            if (entry == null || entry.TargetNpcId <= 0)
            {
                return "CUserLocal::TalkToNpc request was skipped because the selected delivery entry has no NPC template.";
            }

            Vector2 localPosition = _playerManager?.Player?.Position ?? Vector2.Zero;
            int localX = (int)Math.Round(localPosition.X);
            int localY = (int)Math.Round(localPosition.Y);
            byte[] payload = BuildPacketOwnedQuestDeliveryTalkToNpcPayload(entry.TargetNpcId, localX, localY);
            string payloadHex = Convert.ToHexString(payload);
            short encodedX = ClampPacketOwnedQuestDeliveryTalkCoordinate(localX);
            short encodedY = ClampPacketOwnedQuestDeliveryTalkCoordinate(localY);
            string dispatchPrefix =
                $"Mirrored CUIQuestDelivery OK -> CUserLocal::TalkToNpc opcode {PacketOwnedQuestDeliveryTalkToNpcOpcode} " +
                $"for NPC {entry.TargetNpcId}, quest {entry.QuestId}, pos=({encodedX},{encodedY}) [{payloadHex}]";

            if (_localUtilityOfficialSessionBridge.TrySendOutboundPacket(
                    PacketOwnedQuestDeliveryTalkToNpcOpcode,
                    payload,
                    out string dispatchStatus))
            {
                return $"{dispatchPrefix} through the live official-session bridge. {dispatchStatus}";
            }

            if (_localUtilityPacketOutbox.TrySendOutboundPacket(
                    PacketOwnedQuestDeliveryTalkToNpcOpcode,
                    payload,
                    out string outboxStatus))
            {
                return $"{dispatchPrefix} through the generic local-utility outbox after the live bridge path was unavailable. Bridge: {dispatchStatus} Outbox: {outboxStatus}";
            }

            string deferredBridgeStatus = "Official-session bridge deferred delivery is disabled.";
            if (_localUtilityOfficialSessionBridgeEnabled
                && _localUtilityOfficialSessionBridge.TryQueueOutboundPacket(
                    PacketOwnedQuestDeliveryTalkToNpcOpcode,
                    payload,
                    out deferredBridgeStatus))
            {
                return $"{dispatchPrefix} queued for deferred live official-session injection after immediate delivery was unavailable. Bridge: {dispatchStatus} Outbox: {outboxStatus} Deferred official bridge: {deferredBridgeStatus}";
            }

            if (_localUtilityPacketOutbox.TryQueueOutboundPacket(
                    PacketOwnedQuestDeliveryTalkToNpcOpcode,
                    payload,
                    out string queuedStatus))
            {
                return $"{dispatchPrefix} queued for deferred generic local-utility outbox delivery after immediate delivery was unavailable. Bridge: {dispatchStatus} Outbox: {outboxStatus} Deferred official bridge: {deferredBridgeStatus} Deferred outbox: {queuedStatus}";
            }

            return $"{dispatchPrefix} stayed simulator-owned because the live bridge, deferred bridge, outbox, and queued outbox paths were unavailable. Bridge: {dispatchStatus} Outbox: {outboxStatus} Deferred official bridge: {deferredBridgeStatus}";
        }

        internal static byte[] BuildPacketOwnedQuestDeliveryTalkToNpcPayloadForTests(int npcTemplateId, int localX, int localY)
        {
            return BuildPacketOwnedQuestDeliveryTalkToNpcPayload(npcTemplateId, localX, localY);
        }

        private static byte[] BuildPacketOwnedQuestDeliveryTalkToNpcPayload(int npcTemplateId, int localX, int localY)
        {
            using PacketWriter writer = new();
            writer.WriteInt(npcTemplateId);
            writer.Write(ClampPacketOwnedQuestDeliveryTalkCoordinate(localX));
            writer.Write(ClampPacketOwnedQuestDeliveryTalkCoordinate(localY));
            return writer.ToArray();
        }

        private static short ClampPacketOwnedQuestDeliveryTalkCoordinate(int coordinate)
        {
            return (short)Math.Clamp(coordinate, short.MinValue, short.MaxValue);
        }

        private static NpcInteractionState ApplyPacketOwnedQuestDeliveryPresentation(NpcInteractionState interactionState, string npcName)
        {
            if (interactionState == null)
            {
                return null;
            }

            return new NpcInteractionState
            {
                NpcName = string.IsNullOrWhiteSpace(npcName)
                    ? interactionState.NpcName
                    : npcName,
                Entries = interactionState.Entries,
                SelectedEntryId = interactionState.SelectedEntryId,
                PresentationStyle = interactionState.PresentationStyle
            };
        }

        private IReadOnlyList<string> BuildClassCompetitionPageLines()
        {
            RefreshClassCompetitionRuntimeState();
            var lines = new List<string>();
            var build = _playerManager?.Player?.Build;
            string urlTemplate = ResolveClassCompetitionUrlTemplate(out bool usedResolvedTemplate);
            lines.Add("Packet-authored web owner mirroring CUserLocal::OnOpenClassCompetitionPage and CClassCompetition.");
            lines.Add("Constructor shape: CWebWnd, 312x389 owner bounds, close/OK dismissal only, opcode 291 auth requests, and a loading layer while initial auth is pending.");

            string authState;
            if (_lastClassCompetitionAuthPending)
            {
                authState = _lastClassCompetitionNavigatePending || !_lastClassCompetitionLoggedIn
                    ? $"Auth request {PacketOwnedClassCompetitionAuthRequestOpcode} was issued at {_lastClassCompetitionAuthRequestTick}, and the owner is waiting for its first navigable auth cache."
                    : $"Background auth refresh {PacketOwnedClassCompetitionAuthRequestOpcode} was issued at {_lastClassCompetitionAuthRequestTick} while the cached NavigateUrl page remains navigated.";
            }
            else if (_lastClassCompetitionAuthIssuedTick == int.MinValue)
            {
                authState = "No class-competition auth response has populated the local cache yet.";
            }
            else if (_lastClassCompetitionLoggedIn)
            {
                authState = $"Auth cache landed at {_lastClassCompetitionAuthIssuedTick} and the seeded page last navigated at {_lastClassCompetitionNavigateTick}.";
            }
            else
            {
                authState = $"Auth cache landed at {_lastClassCompetitionAuthIssuedTick}, but navigation has not completed yet.";
            }

            lines.Add(authState);
            lines.Add($"Auth cache source: {_lastClassCompetitionAuthSource}");
            lines.Add($"Auth request dispatch: {_lastClassCompetitionAuthDispatchStatus}");
            lines.Add($"NavigateUrl template: {(usedResolvedTemplate ? MapleStoryStringPool.FormatFallbackLabel(PacketOwnedClassCompetitionUrlTemplateStringPoolId, 4) : "local fallback")} -> {urlTemplate}");
            lines.Add($"Recovered server host: {PacketOwnedClassCompetitionServerHost}");
            if (_lastClassCompetitionAuthIssuedTick != int.MinValue)
            {
                lines.Add($"Cached auth token: {SummarizeClassCompetitionAuthKey(_lastClassCompetitionAuthKey)}");
            }

            if (!string.IsNullOrWhiteSpace(_lastClassCompetitionUrl))
            {
                lines.Add($"NavigateUrl target: {_lastClassCompetitionUrl}");
            }

            bool hasRemoteSnapshot =
                _lastClassCompetitionRemotePageTick != int.MinValue
                && (!string.IsNullOrWhiteSpace(_lastClassCompetitionRemoteNavigateUrl)
                    || !string.IsNullOrWhiteSpace(_lastClassCompetitionRemotePageSource)
                    || _lastClassCompetitionRemotePageLines.Count > 0
                    || _lastClassCompetitionRemoteLadderLines.Count > 0);
            if (hasRemoteSnapshot)
            {
                if (!string.IsNullOrWhiteSpace(_lastClassCompetitionRemoteNavigateUrl))
                {
                    lines.Add($"Remote NavigateUrl snapshot: {_lastClassCompetitionRemoteNavigateUrl}");
                }

                if (!string.IsNullOrWhiteSpace(_lastClassCompetitionRemotePageSource))
                {
                    lines.Add($"Remote snapshot source: {_lastClassCompetitionRemotePageSource}");
                }

                lines.Add($"Remote snapshot tick: {_lastClassCompetitionRemotePageTick}");
                for (int i = 0; i < _lastClassCompetitionRemotePageLines.Count && i < PacketOwnedClassCompetitionMaxRemotePageLines; i++)
                {
                    lines.Add(_lastClassCompetitionRemotePageLines[i]);
                }
            }

            if (build != null)
            {
                lines.Add($"{build.Name}  Lv.{Math.Max(1, build.Level)}  {build.JobName}");
                lines.Add($"Map {(_mapBoard?.MapInfo?.id ?? 0)}  Fame {build.Fame}  HP {Math.Max(0, build.HP)}/{Math.Max(1, build.MaxHP)}");
                lines.Add($"Local ladder context: world {(build.WorldRank > 0 ? $"#{build.WorldRank}" : "local only")}  job {(build.JobRank > 0 ? $"#{build.JobRank}" : "local only")}");
                lines.Add($"Combat seed: PAD {build.TotalAttack}  MAD {build.TotalMagicAttack}  ACC {build.TotalAccuracy}  EVA {build.TotalAvoidability}");
                if (_lastClassCompetitionRemoteLadderLines.Count > 0)
                {
                    lines.Add("Remote ladder snapshot:");
                    for (int i = 0; i < _lastClassCompetitionRemoteLadderLines.Count && i < PacketOwnedClassCompetitionMaxRemoteLadderLines; i++)
                    {
                        lines.Add(_lastClassCompetitionRemoteLadderLines[i]);
                    }
                }
                else
                {
                    lines.AddRange(BuildClassCompetitionSeededStandingLines(build));
                }
            }
            else
            {
                lines.Add("No active player build is bound to the simulator.");
            }

            lines.Add(hasRemoteSnapshot
                ? "Remote class-competition snapshot rows are packet-authored into this owner, but live CWebWnd payloads and true server auth keys are still not simulated end to end."
                : "This owner still has no live server-fed auth or ladder payload, so the first NavigateUrl and later auth refresh cadence match the client more closely while standings remain seeded from the active local build instead of a remote page response.");

            if (_lastClassCompetitionOpenTick != int.MinValue)
            {
                lines.Add($"Last packet launch tick: {_lastClassCompetitionOpenTick.ToString(CultureInfo.InvariantCulture)}");
            }

            return lines;
        }

        private IReadOnlyList<string> BuildClassCompetitionSeededStandingLines(CharacterBuild build)
        {
            if (build == null)
            {
                return Array.Empty<string>();
            }

            return new[]
            {
                "Synthetic ladder preview:",
                BuildClassCompetitionStandingLine("World", Math.Max(1, ResolveSeededWorldCompetitionRank(build.WorldRank) - 1), "Aldebaran", Math.Max(1, build.Level + 2), ResolveNeighborJobName(build.JobName, -1), Math.Max(0, build.Fame + 6), Math.Max(1, build.TotalAttack + 9)),
                BuildClassCompetitionStandingLine("World", ResolveSeededWorldCompetitionRank(build.WorldRank), build.Name, Math.Max(1, build.Level), build.JobName, build.Fame, Math.Max(1, build.TotalAttack)),
                BuildClassCompetitionStandingLine("World", ResolveSeededWorldCompetitionRank(build.WorldRank) + 1, "Bellflower", Math.Max(1, build.Level - 1), ResolveNeighborJobName(build.JobName, 1), Math.Max(0, build.Fame - 3), Math.Max(1, build.TotalAttack - 5)),
                BuildClassCompetitionStandingLine("Job", Math.Max(1, ResolveSeededJobCompetitionRank(build.JobRank) - 1), "Juniper", Math.Max(1, build.Level + 1), build.JobName, Math.Max(0, build.Fame + 4), Math.Max(1, build.TotalAttack + 6)),
                BuildClassCompetitionStandingLine("Job", ResolveSeededJobCompetitionRank(build.JobRank), build.Name, Math.Max(1, build.Level), build.JobName, build.Fame, Math.Max(1, build.TotalAttack)),
                BuildClassCompetitionStandingLine("Job", ResolveSeededJobCompetitionRank(build.JobRank) + 1, "Rowan", Math.Max(1, build.Level - 2), build.JobName, Math.Max(0, build.Fame - 2), Math.Max(1, build.TotalAttack - 4))
            };
        }

        private static int ResolveSeededWorldCompetitionRank(int rank)
        {
            return rank > 0 ? rank : 57;
        }

        private static int ResolveSeededJobCompetitionRank(int rank)
        {
            return rank > 0 ? rank : 12;
        }

        private static string ResolveNeighborJobName(string jobName, int direction)
        {
            if (string.IsNullOrWhiteSpace(jobName))
            {
                return "Adventurer";
            }

            return direction < 0
                ? $"{jobName} Veteran"
                : $"{jobName} Scout";
        }

        private static string BuildClassCompetitionStandingLine(string ladderName, int rank, string name, int level, string jobName, int fame, int attack)
        {
            return $"{ladderName} {FormatClassCompetitionRank(rank)}  {name}  Lv.{Math.Max(1, level)} {jobName}  Fame {Math.Max(0, fame)}  PAD {Math.Max(1, attack)}";
        }

        private static string FormatClassCompetitionRank(int rank)
        {
            return rank > 0
                ? $"#{rank}"
                : "local only";
        }

        private static string SummarizeClassCompetitionAuthKey(string authKey)
        {
            if (string.IsNullOrWhiteSpace(authKey))
            {
                return "empty";
            }

            return authKey.Length <= 20
                ? authKey
                : $"{authKey[..12]}...{authKey[^6..]}";
        }

        private string BuildClassCompetitionFooter()
        {
            RefreshClassCompetitionRuntimeState();
            if (_packetOwnedUtilityRequestTick == int.MinValue && _lastClassCompetitionAuthRequestTick == int.MinValue)
            {
                return "Utility request timing idle.";
            }

            string requestStamp = _packetOwnedUtilityRequestTick == int.MinValue
                ? "Shared request stamp: idle"
                : $"Shared request stamp: {_packetOwnedUtilityRequestTick} ({Math.Max(0, unchecked(currTickCount - _packetOwnedUtilityRequestTick))}ms ago)";
            string authStamp = _lastClassCompetitionAuthRequestTick == int.MinValue
                ? "auth request idle"
                : $"auth request: {_lastClassCompetitionAuthRequestTick} ({Math.Max(0, unchecked(currTickCount - _lastClassCompetitionAuthRequestTick))}ms ago)";
            string cacheStamp = _lastClassCompetitionAuthIssuedTick == int.MinValue
                ? "auth cache: empty"
                : $"auth cache: {_lastClassCompetitionAuthIssuedTick} ({Math.Max(0, unchecked(currTickCount - _lastClassCompetitionAuthIssuedTick))}ms old)";
            return $"{requestStamp}, {authStamp}, {cacheStamp}, source: {_lastClassCompetitionAuthSource}";
        }

        private void UpdatePacketOwnedClassCompetitionRuntime(int currentTickCount)
        {
            if (_lastClassCompetitionOpenTick == int.MinValue)
            {
                return;
            }

            RefreshClassCompetitionRuntimeState();
        }

        private void RefreshClassCompetitionRuntimeState(bool forceAuthRequest = false)
        {
            int now = Environment.TickCount;
            bool shouldRequestAuth = ShouldRequestClassCompetitionAuth(
                _lastClassCompetitionOpenTick,
                _lastClassCompetitionAuthRequestTick,
                _lastClassCompetitionAuthIssuedTick,
                forceAuthRequest,
                now);

            if (shouldRequestAuth && !_lastClassCompetitionAuthPending)
            {
                bool requiresFreshNavigation = !_lastClassCompetitionLoggedIn
                    || string.IsNullOrWhiteSpace(_lastClassCompetitionUrl);
                _lastClassCompetitionAuthRequestTick = now;
                _lastClassCompetitionAuthPending = true;
                _lastClassCompetitionNavigatePending = requiresFreshNavigation;
                _lastClassCompetitionAuthDispatchStatus = DispatchClassCompetitionAuthRequest();
                if (requiresFreshNavigation)
                {
                    _lastClassCompetitionLoggedIn = false;
                    _lastClassCompetitionNavigateTick = int.MinValue;
                    _lastClassCompetitionAuthKey = string.Empty;
                    _lastClassCompetitionUrl = string.Empty;
                    _lastClassCompetitionAuthIssuedTick = int.MinValue;
                    _lastClassCompetitionAuthSource = "pending opcode 291 auth cache";
                }
            }

            // Keep auth strictly packet-owned: navigation remains pending until opcode 291
            // provides a real auth cache through CUserLocal::OnOpenClassCompetitionPage flow.
        }

        private static bool ShouldRequestClassCompetitionAuth(
            int lastOpenTick,
            int lastAuthRequestTick,
            int lastAuthIssuedTick,
            bool forceAuthRequest,
            int now)
        {
            if (lastOpenTick == int.MinValue && !forceAuthRequest)
            {
                return false;
            }

            bool authExpired = lastAuthIssuedTick == int.MinValue
                || Math.Max(0, unchecked(now - lastAuthIssuedTick)) >= PacketOwnedClassCompetitionAuthLifetimeMs;
            return forceAuthRequest
                || lastAuthRequestTick == int.MinValue
                || Math.Max(0, unchecked(now - lastAuthRequestTick)) >= PacketOwnedClassCompetitionAuthRefreshIntervalMs
                || authExpired;
        }

        internal static bool ShouldRequestClassCompetitionAuthForTests(
            int lastOpenTick,
            int lastAuthRequestTick,
            int lastAuthIssuedTick,
            bool forceAuthRequest,
            int now)
        {
            return ShouldRequestClassCompetitionAuth(
                lastOpenTick,
                lastAuthRequestTick,
                lastAuthIssuedTick,
                forceAuthRequest,
                now);
        }

        private string DispatchClassCompetitionAuthRequest()
        {
            ReadOnlySpan<byte> emptyPayload = Array.Empty<byte>();
            if (_localUtilityOfficialSessionBridge.TrySendOutboundPacket(
                PacketOwnedClassCompetitionAuthRequestOpcode,
                emptyPayload.ToArray(),
                out string dispatchStatus))
            {
                return $"Mirrored opcode {PacketOwnedClassCompetitionAuthRequestOpcode} through the live official-session bridge. {dispatchStatus}";
            }

            if (_localUtilityPacketOutbox.TrySendOutboundPacket(
                PacketOwnedClassCompetitionAuthRequestOpcode,
                emptyPayload.ToArray(),
                out string outboxStatus))
            {
                return $"Mirrored opcode {PacketOwnedClassCompetitionAuthRequestOpcode} through the generic local-utility outbox after the live bridge path was unavailable. Bridge: {dispatchStatus} Outbox: {outboxStatus}";
            }

            string deferredBridgeStatus = "Official-session bridge deferred delivery is disabled.";
            if (_localUtilityOfficialSessionBridgeEnabled
                && _localUtilityOfficialSessionBridge.TryQueueOutboundPacket(
                    PacketOwnedClassCompetitionAuthRequestOpcode,
                    emptyPayload.ToArray(),
                    out deferredBridgeStatus))
            {
                return $"Queued opcode {PacketOwnedClassCompetitionAuthRequestOpcode} for deferred live official-session injection after the immediate bridge and outbox paths were unavailable. Bridge: {dispatchStatus} Outbox: {outboxStatus} Deferred official bridge: {deferredBridgeStatus}";
            }

            if (_localUtilityPacketOutbox.TryQueueOutboundPacket(
                PacketOwnedClassCompetitionAuthRequestOpcode,
                emptyPayload.ToArray(),
                out string queuedStatus))
            {
                return $"Queued opcode {PacketOwnedClassCompetitionAuthRequestOpcode} for deferred generic outbox delivery after the immediate bridge path was unavailable. Bridge: {dispatchStatus} Outbox: {outboxStatus} Deferred official bridge: {deferredBridgeStatus} Deferred outbox: {queuedStatus}";
            }

            return $"Auth stayed simulator-owned because opcode {PacketOwnedClassCompetitionAuthRequestOpcode} could not be dispatched through the live bridge, deferred bridge, outbox, or queued outbox paths. Bridge: {dispatchStatus} Outbox: {outboxStatus} Deferred official bridge: {deferredBridgeStatus}";
        }

        private void ApplyClassCompetitionAuthCache(string authKey, string source)
        {
            int now = Environment.TickCount;
            string normalizedAuthKey = authKey?.Trim() ?? string.Empty;
            _lastClassCompetitionAuthIssuedTick = now;
            _lastClassCompetitionAuthPending = false;
            _lastClassCompetitionAuthKey = normalizedAuthKey;
            _lastClassCompetitionAuthSource = string.IsNullOrWhiteSpace(source)
                ? "class-competition auth cache"
                : source.Trim();

            if (_lastClassCompetitionNavigatePending
                || !_lastClassCompetitionLoggedIn
                || string.IsNullOrWhiteSpace(_lastClassCompetitionUrl))
            {
                _lastClassCompetitionUrl = BuildClassCompetitionUrl(normalizedAuthKey);
                _lastClassCompetitionLoggedIn = true;
                _lastClassCompetitionNavigateTick = now;
            }

            _lastClassCompetitionNavigatePending = false;
        }

        private bool TryApplyPacketOwnedClassCompetitionPagePayload(byte[] payload, out string message)
        {
            if (!TryDecodePacketOwnedClassCompetitionLaunchPayloadForTests(payload, out message))
            {
                return false;
            }

            message = ApplyClassCompetitionPageLaunch();
            return true;
        }

        internal static bool TryDecodePacketOwnedClassCompetitionLaunchPayloadForTests(byte[] payload, out string message)
        {
            if (payload != null && payload.Length > 0)
            {
                message = $"Class-competition launch packet should be empty, but received {payload.Length} trailing byte(s).";
                return false;
            }

            message = "Decoded packet-owned Class Competition launch payload.";
            return true;
        }

        private bool TryApplyPacketOwnedClassCompetitionAuthPayload(byte[] payload, out string message)
        {
            message = null;
            if (TryDecodePacketOwnedClassCompetitionAuthCacheRemotePagePayload(
                    payload,
                    out ClassCompetitionRemotePagePayload remotePayload,
                    out string remoteDecodeDetail))
            {
                StampPacketOwnedUtilityRequestState();
                ApplyClassCompetitionRemotePagePayload(remotePayload, out message);
                return true;
            }

            if (TryDecodeClassCompetitionAuthKeyPayload(payload, out string authKey, out string decodeDetail))
            {
                StampPacketOwnedUtilityRequestState();
                ApplyClassCompetitionAuthCache(authKey, "packet opcode 291 auth cache");
                message = $"Applied packet-authored class-competition auth cache from opcode {PacketOwnedClassCompetitionAuthRequestOpcode} and {(string.IsNullOrWhiteSpace(_lastClassCompetitionUrl) ? "kept the owner waiting for navigation." : "updated the cached auth token without resetting an already navigated page.")}";
                return true;
            }

            message = decodeDetail ?? remoteDecodeDetail ?? "Class-competition auth payload could not be decoded.";
            return false;
        }

        private bool TryApplyPacketOwnedClassCompetitionRemotePagePayload(byte[] payload, out string message)
        {
            message = null;
            if (!TryDecodePacketOwnedClassCompetitionRemotePagePayload(payload, out ClassCompetitionRemotePagePayload remotePayload, out string decodeError))
            {
                message = decodeError ?? "Class-competition remote-page payload could not be decoded.";
                return false;
            }

            StampPacketOwnedUtilityRequestState();
            ApplyClassCompetitionRemotePagePayload(remotePayload, out message);
            return true;
        }

        private void ApplyClassCompetitionRemotePagePayload(
            ClassCompetitionRemotePagePayload remotePayload,
            out string message)
        {
            int now = Environment.TickCount;
            if (string.Equals(remotePayload.Source, "clear", StringComparison.OrdinalIgnoreCase))
            {
                _lastClassCompetitionRemotePageLines.Clear();
                _lastClassCompetitionRemoteLadderLines.Clear();
                _lastClassCompetitionRemoteNavigateUrl = string.Empty;
                _lastClassCompetitionRemotePageSource = "cleared";
                _lastClassCompetitionRemotePageTick = now;
                message = "Cleared packet-authored class-competition remote-page snapshot state.";
                return;
            }

            if (!string.IsNullOrWhiteSpace(remotePayload.AuthKey)
                && TryNormalizeClassCompetitionAuthKey(remotePayload.AuthKey, out string normalizedAuthKey))
            {
                ApplyClassCompetitionAuthCache(normalizedAuthKey, "packet class-competition remote-page auth");
            }

            _lastClassCompetitionRemoteNavigateUrl = remotePayload.NavigateUrl ?? string.Empty;
            _lastClassCompetitionRemotePageSource = string.IsNullOrWhiteSpace(remotePayload.Source)
                ? "packet class-competition remote-page payload"
                : remotePayload.Source.Trim();
            _lastClassCompetitionRemotePageTick = now;
            ClassCompetitionRemotePageSnapshot mergedSnapshot = MergeClassCompetitionRemotePageSnapshot(
                _lastClassCompetitionRemoteNavigateUrl,
                _lastClassCompetitionRemotePageSource,
                _lastClassCompetitionRemotePageLines,
                _lastClassCompetitionRemoteLadderLines,
                remotePayload);
            _lastClassCompetitionRemoteNavigateUrl = mergedSnapshot.NavigateUrl;
            _lastClassCompetitionRemotePageSource = string.IsNullOrWhiteSpace(mergedSnapshot.Source)
                ? "packet class-competition remote-page payload"
                : mergedSnapshot.Source;
            _lastClassCompetitionRemotePageLines.Clear();
            _lastClassCompetitionRemotePageLines.AddRange(mergedSnapshot.PageLines);
            _lastClassCompetitionRemoteLadderLines.Clear();
            _lastClassCompetitionRemoteLadderLines.AddRange(mergedSnapshot.LadderLines);

            if (!string.IsNullOrWhiteSpace(_lastClassCompetitionRemoteNavigateUrl)
                && string.IsNullOrWhiteSpace(_lastClassCompetitionUrl))
            {
                _lastClassCompetitionUrl = _lastClassCompetitionRemoteNavigateUrl;
                _lastClassCompetitionLoggedIn = true;
                _lastClassCompetitionNavigateTick = now;
            }

            message = $"Applied packet-authored class-competition remote-page snapshot with {_lastClassCompetitionRemotePageLines.Count} page line(s) and {_lastClassCompetitionRemoteLadderLines.Count} ladder line(s).";
        }

        internal static ClassCompetitionRemotePageSnapshot MergeClassCompetitionRemotePageSnapshotForTests(
            string existingNavigateUrl,
            string existingSource,
            IReadOnlyList<string> existingPageLines,
            IReadOnlyList<string> existingLadderLines,
            ClassCompetitionRemotePagePayload remotePayload)
        {
            return MergeClassCompetitionRemotePageSnapshot(
                existingNavigateUrl,
                existingSource,
                existingPageLines,
                existingLadderLines,
                remotePayload);
        }

        private static ClassCompetitionRemotePageSnapshot MergeClassCompetitionRemotePageSnapshot(
            string existingNavigateUrl,
            string existingSource,
            IReadOnlyList<string> existingPageLines,
            IReadOnlyList<string> existingLadderLines,
            ClassCompetitionRemotePagePayload remotePayload)
        {
            IReadOnlyList<string> normalizedPageLines = NormalizeClassCompetitionRemoteLines(
                remotePayload?.PageLines,
                PacketOwnedClassCompetitionMaxRemotePageLines);
            IReadOnlyList<string> normalizedLadderLines = NormalizeClassCompetitionRemoteLines(
                remotePayload?.LadderLines,
                PacketOwnedClassCompetitionMaxRemoteLadderLines);

            return new ClassCompetitionRemotePageSnapshot
            {
                NavigateUrl = !string.IsNullOrWhiteSpace(remotePayload?.NavigateUrl)
                    ? remotePayload.NavigateUrl.Trim()
                    : existingNavigateUrl ?? string.Empty,
                Source = !string.IsNullOrWhiteSpace(remotePayload?.Source)
                    ? remotePayload.Source.Trim()
                    : existingSource ?? string.Empty,
                PageLines = normalizedPageLines.Count > 0
                    ? normalizedPageLines
                    : NormalizeClassCompetitionRemoteLines(existingPageLines, PacketOwnedClassCompetitionMaxRemotePageLines),
                LadderLines = normalizedLadderLines.Count > 0
                    ? normalizedLadderLines
                    : NormalizeClassCompetitionRemoteLines(existingLadderLines, PacketOwnedClassCompetitionMaxRemoteLadderLines)
            };
        }

        private static bool TryDecodeClassCompetitionAuthKeyPayload(byte[] payload, out string authKey, out string detail)
        {
            authKey = string.Empty;
            detail = null;
            if (payload == null || payload.Length == 0)
            {
                detail = "Class-competition auth payload is missing.";
                return false;
            }

            if (TryExtractMapleStringClassCompetitionAuthKey(payload, out authKey)
                || TryExtractLikelyClassCompetitionAuthKey(payload, Encoding.ASCII, out authKey)
                || TryExtractLikelyClassCompetitionAuthKey(payload, Encoding.UTF8, out authKey)
                || TryExtractLikelyClassCompetitionAuthKey(payload, Encoding.Unicode, out authKey)
                || TryExtractLengthPrefixedClassCompetitionAuthKey(payload, Encoding.ASCII, out authKey)
                || TryExtractLengthPrefixedClassCompetitionAuthKey(payload, Encoding.UTF8, out authKey)
                || TryExtractLengthPrefixedClassCompetitionAuthKey(payload, Encoding.Unicode, out authKey))
            {
                detail = $"Recovered auth token {SummarizeClassCompetitionAuthKey(authKey)}.";
                return true;
            }

            detail = $"Class-competition auth payload did not contain a recognizable auth token. Raw={Convert.ToHexString(payload)}";
            return false;
        }

        internal static bool TryDecodeClassCompetitionAuthKeyPayloadForTests(byte[] payload, out string authKey, out string detail)
        {
            return TryDecodeClassCompetitionAuthKeyPayload(payload, out authKey, out detail);
        }

        internal static bool TryDecodePacketOwnedDeliveryQuestPayloadForTests(
            byte[] payload,
            out int questId,
            out int itemId,
            out int[] disallowedQuestIds,
            out QuestDetailDeliveryType deliveryType,
            out string error)
        {
            return TryDecodePacketOwnedDeliveryQuestPayload(payload, out questId, out itemId, out disallowedQuestIds, out deliveryType, out error);
        }

        private static bool TryDecodePacketOwnedDeliveryQuestPayload(
            byte[] payload,
            out int questId,
            out int itemId,
            out int[] disallowedQuestIds,
            out QuestDetailDeliveryType deliveryType,
            out string error)
        {
            questId = 0;
            itemId = 0;
            disallowedQuestIds = Array.Empty<int>();
            deliveryType = QuestDetailDeliveryType.None;
            error = null;

            if (payload == null || payload.Length < 8)
            {
                error = "Delivery-quest payload must contain questId and itemId Int32 values.";
                return false;
            }

            try
            {
                using var stream = new MemoryStream(payload, writable: false);
                using var reader = new BinaryReader(stream, Encoding.Default, leaveOpen: false);
                questId = reader.ReadInt32();
                itemId = reader.ReadInt32();
                disallowedQuestIds = DecodePacketOwnedDeliveryQuestIdsWithOptionalCount(reader).ToArray();
                if (!TryDecodePacketOwnedDeliveryType(reader, out deliveryType, out error))
                {
                    return false;
                }

                if (reader.BaseStream.Position != reader.BaseStream.Length)
                {
                    error = $"Delivery-quest payload has {reader.BaseStream.Length - reader.BaseStream.Position} trailing byte(s) after the optional delivery-type discriminator.";
                    return false;
                }

                return true;
            }
            catch (Exception ex) when (ex is EndOfStreamException or IOException or InvalidDataException)
            {
                error = ex.Message;
                return false;
            }
        }

        private static bool TryExtractMapleStringClassCompetitionAuthKey(byte[] payload, out string authKey)
        {
            authKey = string.Empty;
            if (payload == null || payload.Length < sizeof(ushort))
            {
                return false;
            }

            try
            {
                using MemoryStream stream = new(payload, writable: false);
                using BinaryReader reader = new(stream, Encoding.Default, leaveOpen: false);
                string mapleString = ReadPacketOwnedMapleString(reader);
                if (reader.BaseStream.Position != reader.BaseStream.Length)
                {
                    return false;
                }

                return TryNormalizeClassCompetitionAuthKey(mapleString, out authKey);
            }
            catch (Exception ex) when (ex is EndOfStreamException or IOException)
            {
                return false;
            }
        }

        private static bool TryExtractLengthPrefixedClassCompetitionAuthKey(byte[] payload, Encoding encoding, out string authKey)
        {
            authKey = string.Empty;
            if (payload == null || payload.Length < sizeof(short))
            {
                return false;
            }

            int byteLength = BitConverter.ToInt16(payload, 0);
            if (byteLength <= 0 || byteLength > payload.Length - sizeof(short))
            {
                return false;
            }

            return TryNormalizeClassCompetitionAuthKey(
                encoding.GetString(payload, sizeof(short), byteLength),
                out authKey);
        }

        private static bool TryExtractLikelyClassCompetitionAuthKey(byte[] payload, Encoding encoding, out string authKey)
        {
            authKey = string.Empty;
            if (payload == null || payload.Length == 0)
            {
                return false;
            }

            return TryNormalizeClassCompetitionAuthKey(encoding.GetString(payload), out authKey);
        }

        private static bool TryNormalizeClassCompetitionAuthKey(string candidate, out string authKey)
        {
            authKey = string.Empty;
            if (string.IsNullOrWhiteSpace(candidate))
            {
                return false;
            }

            string normalized = candidate
                .Replace("\0", string.Empty, StringComparison.Ordinal)
                .Trim();
            if (normalized.Length < 8)
            {
                return false;
            }

            int separatorIndex = normalized.IndexOfAny(new[] { '\r', '\n', '\t', ' ' });
            if (separatorIndex >= 0)
            {
                normalized = normalized[..separatorIndex].Trim();
            }

            if (normalized.Length < 8)
            {
                return false;
            }

            bool hasOnlySupportedCharacters = normalized.All(ch =>
                char.IsLetterOrDigit(ch)
                || ch is '-' or '_' or '=' or '+' or '/' or '.');
            if (!hasOnlySupportedCharacters)
            {
                return false;
            }

            authKey = normalized;
            return true;
        }

        internal static bool TryDecodePacketOwnedClassCompetitionRemotePagePayloadForTests(
            byte[] payload,
            out ClassCompetitionRemotePagePayload remotePayload,
            out string error)
        {
            return TryDecodePacketOwnedClassCompetitionRemotePagePayload(payload, out remotePayload, out error);
        }

        internal static bool TryDecodePacketOwnedClassCompetitionAuthCachePayloadForTests(
            byte[] payload,
            out string authKey,
            out ClassCompetitionRemotePagePayload remotePayload,
            out string detail)
        {
            authKey = string.Empty;
            remotePayload = null;
            detail = null;

            if (TryDecodePacketOwnedClassCompetitionAuthCacheRemotePagePayload(payload, out remotePayload, out detail))
            {
                return true;
            }

            if (TryDecodeClassCompetitionAuthKeyPayload(payload, out authKey, out detail))
            {
                return true;
            }

            authKey = string.Empty;
            remotePayload = null;
            return false;
        }

        private static bool TryDecodePacketOwnedClassCompetitionAuthCacheRemotePagePayload(
            byte[] payload,
            out ClassCompetitionRemotePagePayload remotePayload,
            out string detail)
        {
            remotePayload = null;
            detail = "Class-competition auth payload did not contain a structured remote-page snapshot.";
            if (payload == null || payload.Length == 0)
            {
                return false;
            }

            if (!TryDecodeClassCompetitionStructuredTextPayload(payload, out string decodedText))
            {
                detail = "Class-competition auth payload did not decode as text.";
                return false;
            }

            string normalizedText = decodedText.Trim();
            if (string.IsNullOrWhiteSpace(normalizedText))
            {
                detail = "Class-competition auth payload text was empty.";
                return false;
            }

            if (string.Equals(normalizedText, "clear", StringComparison.OrdinalIgnoreCase)
                || string.Equals(normalizedText, "reset", StringComparison.OrdinalIgnoreCase))
            {
                remotePayload = new ClassCompetitionRemotePagePayload
                {
                    Source = "clear"
                };
                detail = "Decoded class-competition auth-cache remote-page clear command.";
                return true;
            }

            if (TryDecodePacketOwnedClassCompetitionRemotePageJsonPayload(normalizedText, out remotePayload))
            {
                detail = "Decoded class-competition auth-cache remote-page JSON payload.";
                return true;
            }

            if (TryDecodePacketOwnedClassCompetitionRemotePageQueryPayload(normalizedText, out remotePayload))
            {
                detail = "Decoded class-competition auth-cache remote-page query/form payload.";
                return true;
            }

            if (TryDecodePacketOwnedClassCompetitionRemotePageHtmlPayload(normalizedText, out remotePayload))
            {
                detail = "Decoded class-competition auth-cache remote-page HTML payload.";
                return true;
            }

            if (!LooksLikeStructuredClassCompetitionRemoteTextPayload(normalizedText))
            {
                detail = "Class-competition auth payload text did not contain structured remote-page fields.";
                return false;
            }

            remotePayload = DecodePacketOwnedClassCompetitionRemotePageTextPayload(normalizedText);
            if (remotePayload == null)
            {
                detail = "Class-competition auth payload text could not be parsed as a structured remote-page payload.";
                return false;
            }

            detail = "Decoded class-competition auth-cache structured text payload.";
            return true;
        }

        private static bool TryDecodePacketOwnedClassCompetitionRemotePagePayload(
            byte[] payload,
            out ClassCompetitionRemotePagePayload remotePayload,
            out string error)
        {
            remotePayload = null;
            error = "Class-competition remote-page payload is missing.";
            if (payload == null || payload.Length == 0)
            {
                return false;
            }

            if (TryDecodeClassCompetitionStructuredTextPayload(payload, out string decodedText))
            {
                string normalizedText = decodedText.Trim();
                if (string.Equals(normalizedText, "clear", StringComparison.OrdinalIgnoreCase)
                    || string.Equals(normalizedText, "reset", StringComparison.OrdinalIgnoreCase))
                {
                    remotePayload = new ClassCompetitionRemotePagePayload
                    {
                        Source = "clear"
                    };
                    error = null;
                    return true;
                }

                if (TryDecodePacketOwnedClassCompetitionRemotePageJsonPayload(normalizedText, out remotePayload))
                {
                    error = null;
                    return true;
                }

                if (TryDecodePacketOwnedClassCompetitionRemotePageQueryPayload(normalizedText, out remotePayload))
                {
                    error = null;
                    return true;
                }

                if (TryDecodePacketOwnedClassCompetitionRemotePageHtmlPayload(normalizedText, out remotePayload))
                {
                    error = null;
                    return true;
                }

                remotePayload = DecodePacketOwnedClassCompetitionRemotePageTextPayload(normalizedText);
                if (remotePayload != null)
                {
                    error = null;
                    return true;
                }
            }

            error = "Class-competition remote-page payload did not decode as a MapleString or supported text payload with usable content.";
            return false;
        }

        private static bool TryDecodeClassCompetitionStructuredTextPayload(byte[] payload, out string text)
        {
            text = null;
            if (payload == null || payload.Length == 0)
            {
                return false;
            }

            if (TryDecodePacketOwnedStringPayload(payload, out text) && !string.IsNullOrWhiteSpace(text))
            {
                return true;
            }

            if (TryDecodeLengthPrefixedClassCompetitionTextPayload(payload, sizeof(short), Encoding.Unicode, out text)
                || TryDecodeLengthPrefixedClassCompetitionTextPayload(payload, sizeof(short), Encoding.UTF8, out text)
                || TryDecodeLengthPrefixedClassCompetitionTextPayload(payload, sizeof(short), Encoding.ASCII, out text)
                || TryDecodeLengthPrefixedClassCompetitionTextPayload(payload, sizeof(int), Encoding.Unicode, out text)
                || TryDecodeLengthPrefixedClassCompetitionTextPayload(payload, sizeof(int), Encoding.UTF8, out text)
                || TryDecodeLengthPrefixedClassCompetitionTextPayload(payload, sizeof(int), Encoding.ASCII, out text))
            {
                return true;
            }

            if (TryAcceptClassCompetitionStructuredTextCandidate(Encoding.UTF8.GetString(payload), out text)
                || TryAcceptClassCompetitionStructuredTextCandidate(Encoding.ASCII.GetString(payload), out text)
                || TryAcceptClassCompetitionStructuredTextCandidate(Encoding.Unicode.GetString(payload), out text))
            {
                return true;
            }

            return false;
        }

        private static bool TryAcceptClassCompetitionStructuredTextCandidate(string candidate, out string text)
        {
            text = null;
            string normalized = candidate?.TrimEnd('\0', '\r', '\n', ' ');
            if (string.IsNullOrWhiteSpace(normalized))
            {
                return false;
            }

            string trimmed = normalized.Trim();
            if (string.Equals(trimmed, "clear", StringComparison.OrdinalIgnoreCase)
                || string.Equals(trimmed, "reset", StringComparison.OrdinalIgnoreCase)
                || LooksLikeStructuredClassCompetitionRemoteTextPayload(trimmed)
                || LooksLikeClassCompetitionRemoteHtmlPayload(trimmed)
                || (trimmed.StartsWith("{", StringComparison.Ordinal) && trimmed.EndsWith("}", StringComparison.Ordinal)))
            {
                text = trimmed;
                return true;
            }

            return false;
        }

        private static bool TryDecodeLengthPrefixedClassCompetitionTextPayload(
            byte[] payload,
            int prefixWidth,
            Encoding encoding,
            out string text)
        {
            text = null;
            if (payload == null || payload.Length < prefixWidth)
            {
                return false;
            }

            int byteLength = prefixWidth switch
            {
                sizeof(short) => BitConverter.ToInt16(payload, 0),
                sizeof(int) => BitConverter.ToInt32(payload, 0),
                _ => -1
            };
            if (byteLength <= 0 || byteLength > payload.Length - prefixWidth)
            {
                return false;
            }

            string decoded = encoding.GetString(payload, prefixWidth, byteLength).TrimEnd('\0', '\r', '\n', ' ');
            if (string.IsNullOrWhiteSpace(decoded))
            {
                return false;
            }

            text = decoded;
            return true;
        }

        private static bool LooksLikeStructuredClassCompetitionRemoteTextPayload(string text)
        {
            if (string.IsNullOrWhiteSpace(text))
            {
                return false;
            }

            foreach (string segment in EnumerateClassCompetitionStructuredSegments(text))
            {
                if (IsClassCompetitionStructuredPrefix(segment))
                {
                    return true;
                }
            }

            return false;
        }

        private static bool TryDecodePacketOwnedClassCompetitionRemotePageJsonPayload(
            string text,
            out ClassCompetitionRemotePagePayload remotePayload)
        {
            remotePayload = null;
            if (string.IsNullOrWhiteSpace(text))
            {
                return false;
            }

            try
            {
                using JsonDocument document = JsonDocument.Parse(text);
                if (document.RootElement.ValueKind != JsonValueKind.Object)
                {
                    return false;
                }

                JsonElement root = document.RootElement;
                if (TryDecodePacketOwnedClassCompetitionRemotePageJsonObject(root, out remotePayload))
                {
                    return true;
                }

                foreach (string nestedPropertyName in EnumerateClassCompetitionRemoteNestedJsonPropertyNames())
                {
                    if (TryGetClassCompetitionRemoteProperty(root, nestedPropertyName, out JsonElement nested)
                        && nested.ValueKind == JsonValueKind.Object
                        && TryDecodePacketOwnedClassCompetitionRemotePageJsonObject(nested, out remotePayload))
                    {
                        return true;
                    }
                }

                return false;
            }
            catch (JsonException)
            {
                return false;
            }
        }

        private static bool TryDecodePacketOwnedClassCompetitionRemotePageJsonObject(
            JsonElement root,
            out ClassCompetitionRemotePagePayload remotePayload)
        {
            remotePayload = null;
            if (root.ValueKind != JsonValueKind.Object)
            {
                return false;
            }

            string authKey = TryGetClassCompetitionRemoteStringProperty(root, "authKey")
                ?? TryGetClassCompetitionRemoteStringProperty(root, "auth_key")
                ?? TryGetClassCompetitionRemoteStringProperty(root, "auth")
                ?? TryGetClassCompetitionRemoteStringProperty(root, "key")
                ?? TryGetClassCompetitionRemoteStringProperty(root, "sessionKey")
                ?? TryGetClassCompetitionRemoteStringProperty(root, "session_key")
                ?? TryGetClassCompetitionRemoteStringProperty(root, "token");
            string navigateUrl = TryGetClassCompetitionRemoteStringProperty(root, "navigateUrl")
                ?? TryGetClassCompetitionRemoteStringProperty(root, "navigate_url")
                ?? TryGetClassCompetitionRemoteStringProperty(root, "navigate")
                ?? TryGetClassCompetitionRemoteStringProperty(root, "url")
                ?? TryGetClassCompetitionRemoteStringProperty(root, "href")
                ?? TryGetClassCompetitionRemoteStringProperty(root, "requestUrl")
                ?? TryGetClassCompetitionRemoteStringProperty(root, "request_url");
            string source = TryGetClassCompetitionRemoteStringProperty(root, "source")
                ?? TryGetClassCompetitionRemoteStringProperty(root, "origin")
                ?? TryGetClassCompetitionRemoteStringProperty(root, "provider");
            IReadOnlyList<string> pageLines = NormalizeClassCompetitionRemoteLines(
                TryGetClassCompetitionRemoteStringValues(root, "pageLines")
                    ?? TryGetClassCompetitionRemoteStringValues(root, "page_lines")
                    ?? TryGetClassCompetitionRemoteStringValues(root, "lines")
                    ?? TryGetClassCompetitionRemoteStringValues(root, "page")
                    ?? TryGetClassCompetitionRemoteStringValues(root, "line")
                    ?? TryGetClassCompetitionRemoteStringValues(root, "body")
                    ?? TryGetClassCompetitionRemoteStringValues(root, "html")
                    ?? TryGetClassCompetitionRemoteStringValues(root, "content"),
                PacketOwnedClassCompetitionMaxRemotePageLines);
            IReadOnlyList<string> ladderLines = NormalizeClassCompetitionRemoteLines(
                TryGetClassCompetitionRemoteStringValues(root, "ladderLines")
                    ?? TryGetClassCompetitionRemoteStringValues(root, "ladder_lines")
                    ?? TryGetClassCompetitionRemoteStringValues(root, "ladder")
                    ?? TryGetClassCompetitionRemoteStringValues(root, "standings")
                    ?? TryGetClassCompetitionRemoteStringValues(root, "rows")
                    ?? TryGetClassCompetitionRemoteStringValues(root, "rankings")
                    ?? TryGetClassCompetitionRemoteStringValues(root, "ranking")
                    ?? TryGetClassCompetitionRemoteStringValues(root, "rankList")
                    ?? TryGetClassCompetitionRemoteStringValues(root, "rank_list"),
                PacketOwnedClassCompetitionMaxRemoteLadderLines);

            if (string.IsNullOrWhiteSpace(authKey)
                && TryExtractClassCompetitionAuthKeyFromNavigateUrl(navigateUrl, out string extractedAuthKey))
            {
                authKey = extractedAuthKey;
            }

            navigateUrl = HydrateClassCompetitionNavigateUrlWithAuthKey(navigateUrl, authKey);
            if (string.IsNullOrWhiteSpace(authKey)
                && string.IsNullOrWhiteSpace(navigateUrl)
                && string.IsNullOrWhiteSpace(source)
                && pageLines.Count == 0
                && ladderLines.Count == 0)
            {
                return false;
            }

            remotePayload = new ClassCompetitionRemotePagePayload
            {
                AuthKey = authKey ?? string.Empty,
                NavigateUrl = navigateUrl ?? string.Empty,
                Source = source ?? string.Empty,
                PageLines = pageLines,
                LadderLines = ladderLines
            };
            return true;
        }

        private static IEnumerable<string> EnumerateClassCompetitionRemoteNestedJsonPropertyNames()
        {
            yield return "payload";
            yield return "data";
            yield return "web";
            yield return "page";
            yield return "result";
            yield return "response";
            yield return "snapshot";
            yield return "classCompetition";
            yield return "class_competition";
        }

        private static bool TryDecodePacketOwnedClassCompetitionRemotePageJsonPayload(
            string text,
            out ClassCompetitionRemotePagePayload remotePayload,
            bool legacyFlatDecoder)
        {
            remotePayload = null;
            if (!legacyFlatDecoder)
            {
                return TryDecodePacketOwnedClassCompetitionRemotePageJsonPayload(text, out remotePayload);
            }

            try
            {
                using JsonDocument document = JsonDocument.Parse(text);
                JsonElement root = document.RootElement;
                string authKey = TryGetClassCompetitionRemoteStringProperty(root, "authKey")
                    ?? TryGetClassCompetitionRemoteStringProperty(root, "auth_key")
                    ?? TryGetClassCompetitionRemoteStringProperty(root, "auth")
                    ?? TryGetClassCompetitionRemoteStringProperty(root, "key");
                string navigateUrl = TryGetClassCompetitionRemoteStringProperty(root, "navigateUrl")
                    ?? TryGetClassCompetitionRemoteStringProperty(root, "navigate_url")
                    ?? TryGetClassCompetitionRemoteStringProperty(root, "navigate")
                    ?? TryGetClassCompetitionRemoteStringProperty(root, "url");
                string source = TryGetClassCompetitionRemoteStringProperty(root, "source")
                    ?? TryGetClassCompetitionRemoteStringProperty(root, "origin");
                IReadOnlyList<string> pageLines = NormalizeClassCompetitionRemoteLines(
                    TryGetClassCompetitionRemoteStringValues(root, "pageLines")
                        ?? TryGetClassCompetitionRemoteStringValues(root, "page_lines")
                        ?? TryGetClassCompetitionRemoteStringValues(root, "lines")
                        ?? TryGetClassCompetitionRemoteStringValues(root, "page")
                        ?? TryGetClassCompetitionRemoteStringValues(root, "line")
                        ?? TryGetClassCompetitionRemoteStringValues(root, "body")
                        ?? TryGetClassCompetitionRemoteStringValues(root, "html"),
                    PacketOwnedClassCompetitionMaxRemotePageLines);
                IReadOnlyList<string> ladderLines = NormalizeClassCompetitionRemoteLines(
                    TryGetClassCompetitionRemoteStringValues(root, "ladderLines")
                        ?? TryGetClassCompetitionRemoteStringValues(root, "ladder_lines")
                        ?? TryGetClassCompetitionRemoteStringValues(root, "ladder")
                        ?? TryGetClassCompetitionRemoteStringValues(root, "standings")
                        ?? TryGetClassCompetitionRemoteStringValues(root, "rows"),
                    PacketOwnedClassCompetitionMaxRemoteLadderLines);
                if (string.IsNullOrWhiteSpace(authKey)
                    && TryExtractClassCompetitionAuthKeyFromNavigateUrl(navigateUrl, out string extractedAuthKey))
                {
                    authKey = extractedAuthKey;
                }

                navigateUrl = HydrateClassCompetitionNavigateUrlWithAuthKey(navigateUrl, authKey);
                if (string.IsNullOrWhiteSpace(authKey)
                    && string.IsNullOrWhiteSpace(navigateUrl)
                    && string.IsNullOrWhiteSpace(source)
                    && pageLines.Count == 0
                    && ladderLines.Count == 0)
                {
                    return false;
                }

                remotePayload = new ClassCompetitionRemotePagePayload
                {
                    AuthKey = authKey ?? string.Empty,
                    NavigateUrl = navigateUrl ?? string.Empty,
                    Source = source ?? string.Empty,
                    PageLines = pageLines,
                    LadderLines = ladderLines
                };
                return true;
            }
            catch (JsonException)
            {
                return false;
            }
        }

        private static bool TryDecodePacketOwnedClassCompetitionRemotePageQueryPayload(
            string text,
            out ClassCompetitionRemotePagePayload remotePayload)
        {
            remotePayload = null;
            if (string.IsNullOrWhiteSpace(text))
            {
                return false;
            }

            string normalized = text.Trim().TrimStart('?').Replace("&amp;", "&", StringComparison.OrdinalIgnoreCase);
            if (!normalized.Contains('=', StringComparison.Ordinal) || !normalized.Contains('&', StringComparison.Ordinal))
            {
                return false;
            }

            string authKey = string.Empty;
            string navigateUrl = string.Empty;
            string source = string.Empty;
            var pageLines = new List<string>();
            var ladderLines = new List<string>();
            string[] pairs = normalized.Split('&', StringSplitOptions.RemoveEmptyEntries | StringSplitOptions.TrimEntries);
            int recognizedCount = 0;
            for (int i = 0; i < pairs.Length; i++)
            {
                string pair = pairs[i];
                int separatorIndex = pair.IndexOf('=');
                if (separatorIndex <= 0 || separatorIndex >= pair.Length - 1)
                {
                    continue;
                }

                string key = Uri.UnescapeDataString(pair[..separatorIndex]).Trim();
                string rawValue = pair[(separatorIndex + 1)..].Trim();
                if (key.Equals("auth", StringComparison.OrdinalIgnoreCase)
                    || key.Equals("authkey", StringComparison.OrdinalIgnoreCase)
                    || key.Equals("key", StringComparison.OrdinalIgnoreCase))
                {
                    authKey = Uri.UnescapeDataString(rawValue).Trim();
                    recognizedCount++;
                    continue;
                }

                if (key.Equals("url", StringComparison.OrdinalIgnoreCase)
                    || key.Equals("navigate", StringComparison.OrdinalIgnoreCase)
                    || key.Equals("navigateurl", StringComparison.OrdinalIgnoreCase))
                {
                    navigateUrl = DecodeClassCompetitionFormTextValue(rawValue);
                    recognizedCount++;
                    continue;
                }

                if (key.Equals("source", StringComparison.OrdinalIgnoreCase))
                {
                    source = DecodeClassCompetitionFormTextValue(rawValue);
                    recognizedCount++;
                    continue;
                }

                if (key.Equals("line", StringComparison.OrdinalIgnoreCase)
                    || key.Equals("page", StringComparison.OrdinalIgnoreCase)
                    || key.Equals("lines", StringComparison.OrdinalIgnoreCase)
                    || key.Equals("pagelines", StringComparison.OrdinalIgnoreCase))
                {
                    AppendClassCompetitionFormTextLines(pageLines, rawValue);
                    recognizedCount++;
                    continue;
                }

                if (key.Equals("ladder", StringComparison.OrdinalIgnoreCase)
                    || key.Equals("ladderline", StringComparison.OrdinalIgnoreCase)
                    || key.Equals("ladderlines", StringComparison.OrdinalIgnoreCase))
                {
                    AppendClassCompetitionFormTextLines(ladderLines, rawValue);
                    recognizedCount++;
                }
            }

            if (recognizedCount == 0)
            {
                return false;
            }

            if (string.IsNullOrWhiteSpace(authKey)
                && TryExtractClassCompetitionAuthKeyFromNavigateUrl(navigateUrl, out string extractedAuthKey))
            {
                authKey = extractedAuthKey;
            }

            navigateUrl = HydrateClassCompetitionNavigateUrlWithAuthKey(navigateUrl, authKey);
            IReadOnlyList<string> normalizedPageLines = NormalizeClassCompetitionRemoteLines(pageLines, PacketOwnedClassCompetitionMaxRemotePageLines);
            IReadOnlyList<string> normalizedLadderLines = NormalizeClassCompetitionRemoteLines(ladderLines, PacketOwnedClassCompetitionMaxRemoteLadderLines);
            if (string.IsNullOrWhiteSpace(authKey)
                && string.IsNullOrWhiteSpace(navigateUrl)
                && string.IsNullOrWhiteSpace(source)
                && normalizedPageLines.Count == 0
                && normalizedLadderLines.Count == 0)
            {
                return false;
            }

            remotePayload = new ClassCompetitionRemotePagePayload
            {
                AuthKey = authKey,
                NavigateUrl = navigateUrl,
                Source = source,
                PageLines = normalizedPageLines,
                LadderLines = normalizedLadderLines
            };
            return true;
        }

        private static bool TryDecodePacketOwnedClassCompetitionRemotePageHtmlPayload(
            string text,
            out ClassCompetitionRemotePagePayload remotePayload)
        {
            remotePayload = null;
            if (!LooksLikeClassCompetitionRemoteHtmlPayload(text))
            {
                return false;
            }

            string authKey = TryExtractClassCompetitionAuthKeyFromHtml(text, out string extractedAuthKey)
                ? extractedAuthKey
                : string.Empty;
            string navigateUrl = TryExtractClassCompetitionNavigateUrlFromHtml(text, out string extractedNavigateUrl)
                ? extractedNavigateUrl
                : string.Empty;
            if (string.IsNullOrWhiteSpace(authKey)
                && TryExtractClassCompetitionAuthKeyFromNavigateUrl(navigateUrl, out string navigateAuthKey))
            {
                authKey = navigateAuthKey;
            }

            navigateUrl = HydrateClassCompetitionNavigateUrlWithAuthKey(navigateUrl, authKey);
            IReadOnlyList<string> ladderLines = NormalizeClassCompetitionRemoteLines(
                ExtractClassCompetitionHtmlTableRows(text),
                PacketOwnedClassCompetitionMaxRemoteLadderLines);
            IReadOnlyList<string> pageLines = NormalizeClassCompetitionRemoteLines(
                ExtractClassCompetitionHtmlPageLines(text, ladderLines),
                PacketOwnedClassCompetitionMaxRemotePageLines);

            if (string.IsNullOrWhiteSpace(authKey)
                && string.IsNullOrWhiteSpace(navigateUrl)
                && pageLines.Count == 0
                && ladderLines.Count == 0)
            {
                return false;
            }

            remotePayload = new ClassCompetitionRemotePagePayload
            {
                AuthKey = authKey,
                NavigateUrl = navigateUrl,
                Source = "packet class-competition html snapshot",
                PageLines = pageLines,
                LadderLines = ladderLines
            };
            return true;
        }

        private static bool LooksLikeClassCompetitionRemoteHtmlPayload(string text)
        {
            if (string.IsNullOrWhiteSpace(text))
            {
                return false;
            }

            return text.Contains('<', StringComparison.Ordinal)
                && (text.Contains("<html", StringComparison.OrdinalIgnoreCase)
                    || text.Contains("<body", StringComparison.OrdinalIgnoreCase)
                    || text.Contains("<table", StringComparison.OrdinalIgnoreCase)
                    || text.Contains("<tr", StringComparison.OrdinalIgnoreCase)
                    || text.Contains("Event/classbattle", StringComparison.OrdinalIgnoreCase)
                    || text.Contains("classbattle/gameview", StringComparison.OrdinalIgnoreCase)
                    || text.Contains(PacketOwnedClassCompetitionServerHost, StringComparison.OrdinalIgnoreCase));
        }

        private static bool TryExtractClassCompetitionAuthKeyFromHtml(string text, out string authKey)
        {
            authKey = string.Empty;
            if (string.IsNullOrWhiteSpace(text))
            {
                return false;
            }

            foreach (Match match in Regex.Matches(
                         text,
                         @"(?:[?&#;]|&amp;|\b)(?:key|auth)\s*=\s*[""']?(?<value>[^&""'<>\s]+)",
                         RegexOptions.IgnoreCase | RegexOptions.CultureInvariant))
            {
                string candidate = WebUtility.HtmlDecode(match.Groups["value"].Value);
                candidate = Uri.UnescapeDataString(candidate ?? string.Empty);
                if (TryNormalizeClassCompetitionAuthKey(candidate, out string normalizedAuthKey))
                {
                    authKey = normalizedAuthKey;
                    return true;
                }
            }

            return false;
        }

        private static bool TryExtractClassCompetitionNavigateUrlFromHtml(string text, out string navigateUrl)
        {
            navigateUrl = string.Empty;
            if (string.IsNullOrWhiteSpace(text))
            {
                return false;
            }

            foreach (Match match in Regex.Matches(
                         text,
                         @"(?:href|src|action)\s*=\s*[""'](?<url>[^""']+)[""']",
                         RegexOptions.IgnoreCase | RegexOptions.CultureInvariant))
            {
                string candidate = WebUtility.HtmlDecode(match.Groups["url"].Value).Trim();
                if (candidate.Contains("classbattle", StringComparison.OrdinalIgnoreCase)
                    || candidate.Contains(PacketOwnedClassCompetitionServerHost, StringComparison.OrdinalIgnoreCase))
                {
                    navigateUrl = candidate;
                    return true;
                }
            }

            Match urlMatch = Regex.Match(
                text,
                @"(?:URL|url|navigate)\s*=\s*(?<url>Event/classbattle/gameview[^""'<>\s]*)",
                RegexOptions.IgnoreCase | RegexOptions.CultureInvariant);
            if (urlMatch.Success)
            {
                navigateUrl = WebUtility.HtmlDecode(urlMatch.Groups["url"].Value).Trim();
                return true;
            }

            return false;
        }

        private static IReadOnlyList<string> ExtractClassCompetitionHtmlTableRows(string text)
        {
            if (string.IsNullOrWhiteSpace(text))
            {
                return Array.Empty<string>();
            }

            var rows = new List<string>();
            foreach (Match match in Regex.Matches(
                         text,
                         @"<tr\b[^>]*>(?<row>.*?)</tr>",
                         RegexOptions.IgnoreCase | RegexOptions.Singleline | RegexOptions.CultureInvariant))
            {
                string row = string.Join(" ", SplitClassCompetitionRemoteTextLines(match.Groups["row"].Value));
                if (!string.IsNullOrWhiteSpace(row))
                {
                    rows.Add(row);
                }
            }

            return rows;
        }

        private static IReadOnlyList<string> ExtractClassCompetitionHtmlPageLines(string text, IReadOnlyList<string> ladderLines)
        {
            string[] normalizedLines = SplitClassCompetitionRemoteTextLines(text);
            if (normalizedLines.Length == 0)
            {
                return Array.Empty<string>();
            }

            var ladderSet = new HashSet<string>(
                ladderLines ?? Array.Empty<string>(),
                StringComparer.OrdinalIgnoreCase);
            return normalizedLines
                .Where(line => !ladderSet.Contains(line))
                .ToArray();
        }

        private static ClassCompetitionRemotePagePayload DecodePacketOwnedClassCompetitionRemotePageTextPayload(string text)
        {
            if (string.IsNullOrWhiteSpace(text))
            {
                return null;
            }

            string authKey = string.Empty;
            string navigateUrl = string.Empty;
            string source = string.Empty;
            var pageLines = new List<string>();
            var ladderLines = new List<string>();
            foreach (string line in EnumerateClassCompetitionStructuredSegments(text))
            {
                if (TryParseClassCompetitionPrefixedValue(line, "auth", out string authValue)
                    || TryParseClassCompetitionPrefixedValue(line, "authkey", out authValue)
                    || TryParseClassCompetitionPrefixedValue(line, "key", out authValue))
                {
                    authKey = authValue;
                    continue;
                }

                if (TryParseClassCompetitionPrefixedValue(line, "url", out string navigateValue)
                    || TryParseClassCompetitionPrefixedValue(line, "navigate", out navigateValue))
                {
                    navigateUrl = navigateValue;
                    continue;
                }

                if (TryParseClassCompetitionPrefixedValue(line, "navigateurl", out string navigateUrlValue))
                {
                    navigateUrl = navigateUrlValue;
                    continue;
                }

                if (TryParseClassCompetitionPrefixedValue(line, "source", out string sourceValue))
                {
                    source = sourceValue;
                    continue;
                }

                if (TryParseClassCompetitionPrefixedValue(line, "line", out string pageLineValue)
                    || TryParseClassCompetitionPrefixedValue(line, "page", out pageLineValue))
                {
                    if (!string.IsNullOrWhiteSpace(pageLineValue))
                    {
                        pageLines.Add(pageLineValue);
                    }

                    continue;
                }

                if (TryParseClassCompetitionPrefixedValue(line, "ladder", out string ladderValue))
                {
                    if (!string.IsNullOrWhiteSpace(ladderValue))
                    {
                        ladderLines.Add(ladderValue);
                    }

                    continue;
                }

                pageLines.Add(line);
            }

            if (string.IsNullOrWhiteSpace(authKey)
                && TryExtractClassCompetitionAuthKeyFromNavigateUrl(navigateUrl, out string extractedAuthKey))
            {
                authKey = extractedAuthKey;
            }

            navigateUrl = HydrateClassCompetitionNavigateUrlWithAuthKey(navigateUrl, authKey);

            IReadOnlyList<string> normalizedPageLines = NormalizeClassCompetitionRemoteLines(pageLines, PacketOwnedClassCompetitionMaxRemotePageLines);
            IReadOnlyList<string> normalizedLadderLines = NormalizeClassCompetitionRemoteLines(ladderLines, PacketOwnedClassCompetitionMaxRemoteLadderLines);
            if (string.IsNullOrWhiteSpace(authKey)
                && string.IsNullOrWhiteSpace(navigateUrl)
                && string.IsNullOrWhiteSpace(source)
                && normalizedPageLines.Count == 0
                && normalizedLadderLines.Count == 0)
            {
                return null;
            }

            return new ClassCompetitionRemotePagePayload
            {
                AuthKey = authKey,
                NavigateUrl = navigateUrl,
                Source = source,
                PageLines = normalizedPageLines,
                LadderLines = normalizedLadderLines
            };
        }

        private static string TryGetClassCompetitionRemoteStringProperty(JsonElement root, string propertyName)
        {
            if (root.TryGetProperty(propertyName, out JsonElement value)
                && value.ValueKind == JsonValueKind.String)
            {
                return value.GetString()?.Trim();
            }

            foreach (JsonProperty property in root.EnumerateObject())
            {
                if (property.NameEquals(propertyName)
                    || property.Name.Equals(propertyName, StringComparison.OrdinalIgnoreCase))
                {
                    return property.Value.ValueKind == JsonValueKind.String
                        ? property.Value.GetString()?.Trim()
                        : null;
                }
            }

            return null;
        }

        private static IReadOnlyList<string> TryGetClassCompetitionRemoteStringValues(JsonElement root, string propertyName)
        {
            if (!TryGetClassCompetitionRemoteProperty(root, propertyName, out JsonElement element))
            {
                return null;
            }

            if (element.ValueKind == JsonValueKind.String)
            {
                string value = element.GetString();
                if (string.IsNullOrWhiteSpace(value))
                {
                    return null;
                }

                string[] parts = SplitClassCompetitionRemoteTextLines(value);
                return parts.Length == 0
                    ? null
                    : parts.ToArray();
            }

            if (element.ValueKind != JsonValueKind.Array)
            {
                if (element.ValueKind == JsonValueKind.Object
                    && TryFormatClassCompetitionRemoteObjectLine(element, out string objectLine))
                {
                    return new[] { objectLine };
                }

                return null;
            }

            var lines = new List<string>();
            foreach (JsonElement item in element.EnumerateArray())
            {
                if (item.ValueKind == JsonValueKind.String)
                {
                    string value = item.GetString();
                    if (!string.IsNullOrWhiteSpace(value))
                    {
                        lines.AddRange(SplitClassCompetitionRemoteTextLines(value));
                    }
                }
                else if (item.ValueKind == JsonValueKind.Object
                    && TryFormatClassCompetitionRemoteObjectLine(item, out string objectLine))
                {
                    lines.Add(objectLine);
                }
            }

            return lines;
        }

        private static bool TryFormatClassCompetitionRemoteObjectLine(JsonElement element, out string line)
        {
            line = string.Empty;
            string text = TryGetClassCompetitionRemoteObjectString(element, "line")
                ?? TryGetClassCompetitionRemoteObjectString(element, "text")
                ?? TryGetClassCompetitionRemoteObjectString(element, "title")
                ?? TryGetClassCompetitionRemoteObjectString(element, "html")
                ?? TryGetClassCompetitionRemoteObjectString(element, "body");
            if (!string.IsNullOrWhiteSpace(text))
            {
                line = string.Join(" ", SplitClassCompetitionRemoteTextLines(text));
                return !string.IsNullOrWhiteSpace(line);
            }

            string rank = TryGetClassCompetitionRemoteObjectScalar(element, "rank")
                ?? TryGetClassCompetitionRemoteObjectScalar(element, "ranking")
                ?? TryGetClassCompetitionRemoteObjectScalar(element, "place")
                ?? TryGetClassCompetitionRemoteObjectScalar(element, "no");
            string name = TryGetClassCompetitionRemoteObjectScalar(element, "name")
                ?? TryGetClassCompetitionRemoteObjectScalar(element, "character")
                ?? TryGetClassCompetitionRemoteObjectScalar(element, "characterName")
                ?? TryGetClassCompetitionRemoteObjectScalar(element, "char_name");
            string level = TryGetClassCompetitionRemoteObjectScalar(element, "level")
                ?? TryGetClassCompetitionRemoteObjectScalar(element, "lv");
            string job = TryGetClassCompetitionRemoteObjectScalar(element, "job")
                ?? TryGetClassCompetitionRemoteObjectScalar(element, "class");
            string score = TryGetClassCompetitionRemoteObjectScalar(element, "score")
                ?? TryGetClassCompetitionRemoteObjectScalar(element, "point")
                ?? TryGetClassCompetitionRemoteObjectScalar(element, "points");

            var parts = new List<string>();
            if (!string.IsNullOrWhiteSpace(rank))
            {
                parts.Add(rank.StartsWith("#", StringComparison.Ordinal) ? rank : $"#{rank}");
            }

            if (!string.IsNullOrWhiteSpace(name))
            {
                parts.Add(name);
            }

            if (!string.IsNullOrWhiteSpace(level))
            {
                parts.Add($"Lv.{level}");
            }

            if (!string.IsNullOrWhiteSpace(job))
            {
                parts.Add(job);
            }

            if (!string.IsNullOrWhiteSpace(score))
            {
                parts.Add($"{score} pts");
            }

            line = string.Join(" ", parts);
            return !string.IsNullOrWhiteSpace(line);
        }

        private static string TryGetClassCompetitionRemoteObjectString(JsonElement element, string propertyName)
        {
            if (!TryGetClassCompetitionRemoteProperty(element, propertyName, out JsonElement value)
                || value.ValueKind != JsonValueKind.String)
            {
                return null;
            }

            return value.GetString()?.Trim();
        }

        private static string TryGetClassCompetitionRemoteObjectScalar(JsonElement element, string propertyName)
        {
            if (!TryGetClassCompetitionRemoteProperty(element, propertyName, out JsonElement value))
            {
                return null;
            }

            return value.ValueKind switch
            {
                JsonValueKind.String => value.GetString()?.Trim(),
                JsonValueKind.Number => value.TryGetInt64(out long longValue)
                    ? longValue.ToString(CultureInfo.InvariantCulture)
                    : value.GetRawText().Trim(),
                _ => null
            };
        }

        private static bool TryGetClassCompetitionRemoteProperty(JsonElement root, string propertyName, out JsonElement element)
        {
            if (root.TryGetProperty(propertyName, out element))
            {
                return true;
            }

            foreach (JsonProperty property in root.EnumerateObject())
            {
                if (property.NameEquals(propertyName)
                    || property.Name.Equals(propertyName, StringComparison.OrdinalIgnoreCase))
                {
                    element = property.Value;
                    return true;
                }
            }

            element = default;
            return false;
        }

        private static void AppendClassCompetitionFormTextLines(List<string> lines, string rawValue)
        {
            if (lines == null || string.IsNullOrWhiteSpace(rawValue))
            {
                return;
            }

            string decodedValue = DecodeClassCompetitionFormTextValue(rawValue);
            if (string.IsNullOrWhiteSpace(decodedValue))
            {
                return;
            }

            string[] splitLines = decodedValue.Split(
                new[] { "\r\n", "\n", "\0", "|" },
                StringSplitOptions.RemoveEmptyEntries | StringSplitOptions.TrimEntries);
            if (splitLines.Length == 0)
            {
                lines.Add(decodedValue.Trim());
                return;
            }

            for (int i = 0; i < splitLines.Length; i++)
            {
                if (!string.IsNullOrWhiteSpace(splitLines[i]))
                {
                    lines.Add(splitLines[i].Trim());
                }
            }
        }

        private static string[] SplitClassCompetitionRemoteTextLines(string text)
        {
            if (string.IsNullOrWhiteSpace(text))
            {
                return Array.Empty<string>();
            }

            string normalized = NormalizeClassCompetitionRemoteText(text);
            if (string.IsNullOrWhiteSpace(normalized))
            {
                return Array.Empty<string>();
            }

            return normalized.Split(
                new[] { "\r\n", "\n", "\0", "|" },
                StringSplitOptions.RemoveEmptyEntries | StringSplitOptions.TrimEntries);
        }

        private static string NormalizeClassCompetitionRemoteText(string text)
        {
            if (string.IsNullOrWhiteSpace(text))
            {
                return string.Empty;
            }

            string normalized = WebUtility.HtmlDecode(text)
                .Replace("<br>", "\n", StringComparison.OrdinalIgnoreCase)
                .Replace("<br/>", "\n", StringComparison.OrdinalIgnoreCase)
                .Replace("<br />", "\n", StringComparison.OrdinalIgnoreCase)
                .Replace("</tr>", "\n", StringComparison.OrdinalIgnoreCase)
                .Replace("</li>", "\n", StringComparison.OrdinalIgnoreCase)
                .Replace("</p>", "\n", StringComparison.OrdinalIgnoreCase)
                .Replace("</div>", "\n", StringComparison.OrdinalIgnoreCase);
            normalized = Regex.Replace(normalized, "<[^>]+>", " ");
            normalized = Regex.Replace(normalized, "[ \t\f\v]+", " ");
            normalized = Regex.Replace(normalized, " *(\r\n|\n|\r) *", "\n");
            return normalized.Trim();
        }

        private static string DecodeClassCompetitionFormTextValue(string rawValue)
        {
            return Uri.UnescapeDataString((rawValue ?? string.Empty).Replace('+', ' ')).Trim();
        }

        private static bool TryParseClassCompetitionPrefixedValue(string line, string key, out string value)
        {
            value = string.Empty;
            if (string.IsNullOrWhiteSpace(line) || string.IsNullOrWhiteSpace(key))
            {
                return false;
            }

            ReadOnlySpan<char> span = line.AsSpan().Trim();
            if (span.Length <= key.Length)
            {
                return false;
            }

            ReadOnlySpan<char> keySpan = key.AsSpan();
            if (!span.StartsWith(keySpan, StringComparison.OrdinalIgnoreCase))
            {
                return false;
            }

            int separatorIndex = key.Length;
            while (separatorIndex < span.Length && char.IsWhiteSpace(span[separatorIndex]))
            {
                separatorIndex++;
            }

            if (separatorIndex >= span.Length || (span[separatorIndex] != '=' && span[separatorIndex] != ':'))
            {
                return false;
            }

            separatorIndex++;
            while (separatorIndex < span.Length && char.IsWhiteSpace(span[separatorIndex]))
            {
                separatorIndex++;
            }

            value = span[separatorIndex..].ToString().Trim();
            return true;
        }

        private static IEnumerable<string> EnumerateClassCompetitionStructuredSegments(string text)
        {
            if (string.IsNullOrWhiteSpace(text))
            {
                yield break;
            }

            string normalized = text
                .Replace('\0', '\n')
                .Replace('\u001E', '\n');
            string[] lines = normalized.Split(
                new[] { "\r\n", "\n" },
                StringSplitOptions.RemoveEmptyEntries | StringSplitOptions.TrimEntries);
            for (int i = 0; i < lines.Length; i++)
            {
                string line = lines[i].Trim();
                if (line.Length == 0)
                {
                    continue;
                }

                if (!TrySplitClassCompetitionStructuredLine(line, out List<string> splitSegments))
                {
                    yield return line;
                    continue;
                }

                for (int segmentIndex = 0; segmentIndex < splitSegments.Count; segmentIndex++)
                {
                    yield return splitSegments[segmentIndex];
                }
            }
        }

        private static bool TrySplitClassCompetitionStructuredLine(string line, out List<string> segments)
        {
            segments = null;
            if (string.IsNullOrWhiteSpace(line))
            {
                return false;
            }

            if (!line.Contains('&') && !line.Contains(';'))
            {
                return false;
            }

            string[] parts = line.Split(new[] { '&', ';' }, StringSplitOptions.RemoveEmptyEntries | StringSplitOptions.TrimEntries);
            if (parts.Length <= 1)
            {
                return false;
            }

            int structuredCount = 0;
            for (int i = 0; i < parts.Length; i++)
            {
                if (IsClassCompetitionStructuredPrefix(parts[i]))
                {
                    structuredCount++;
                }
            }

            if (structuredCount < 2)
            {
                return false;
            }

            segments = new List<string>(parts.Length);
            for (int i = 0; i < parts.Length; i++)
            {
                string part = parts[i].Trim();
                if (part.Length > 0)
                {
                    segments.Add(part);
                }
            }

            return segments.Count > 0;
        }

        private static bool IsClassCompetitionStructuredPrefix(string line)
        {
            if (string.IsNullOrWhiteSpace(line))
            {
                return false;
            }

            return TryParseClassCompetitionPrefixedValue(line, "auth", out _)
                || TryParseClassCompetitionPrefixedValue(line, "authkey", out _)
                || TryParseClassCompetitionPrefixedValue(line, "key", out _)
                || TryParseClassCompetitionPrefixedValue(line, "url", out _)
                || TryParseClassCompetitionPrefixedValue(line, "navigate", out _)
                || TryParseClassCompetitionPrefixedValue(line, "navigateurl", out _)
                || TryParseClassCompetitionPrefixedValue(line, "line", out _)
                || TryParseClassCompetitionPrefixedValue(line, "page", out _)
                || TryParseClassCompetitionPrefixedValue(line, "source", out _)
                || TryParseClassCompetitionPrefixedValue(line, "ladder", out _);
        }

        private static string HydrateClassCompetitionNavigateUrlWithAuthKey(string navigateUrl, string authKey)
        {
            string normalizedNavigateUrl = navigateUrl?.Trim() ?? string.Empty;
            if (string.IsNullOrWhiteSpace(normalizedNavigateUrl)
                || string.IsNullOrWhiteSpace(authKey)
                || !TryNormalizeClassCompetitionAuthKey(authKey, out string normalizedAuthKey))
            {
                return normalizedNavigateUrl;
            }

            if (TryExtractClassCompetitionAuthKeyFromNavigateUrl(normalizedNavigateUrl, out _))
            {
                return normalizedNavigateUrl;
            }

            char separator = normalizedNavigateUrl.Contains('?', StringComparison.Ordinal) ? '&' : '?';
            return $"{normalizedNavigateUrl}{separator}key={Uri.EscapeDataString(normalizedAuthKey)}";
        }

        private static bool TryExtractClassCompetitionAuthKeyFromNavigateUrl(
            string navigateUrl,
            out string authKey)
        {
            authKey = string.Empty;
            if (string.IsNullOrWhiteSpace(navigateUrl))
            {
                return false;
            }

            if (TryExtractClassCompetitionAuthKeyFromQueryText(navigateUrl, allowNestedNavigate: true, out authKey))
            {
                return true;
            }

            int queryIndex = navigateUrl.IndexOf('?', StringComparison.Ordinal);
            if (queryIndex >= 0 && queryIndex < navigateUrl.Length - 1)
            {
                string query = navigateUrl[(queryIndex + 1)..];
                if (TryExtractClassCompetitionAuthKeyFromQueryText(query, allowNestedNavigate: true, out authKey))
                {
                    return true;
                }
            }

            int fragmentIndex = navigateUrl.IndexOf('#', StringComparison.Ordinal);
            if (fragmentIndex >= 0 && fragmentIndex < navigateUrl.Length - 1)
            {
                string fragment = navigateUrl[(fragmentIndex + 1)..];
                if (TryExtractClassCompetitionAuthKeyFromQueryText(fragment, allowNestedNavigate: true, out authKey))
                {
                    return true;
                }
            }

            string unescaped = Uri.UnescapeDataString(navigateUrl);
            if (!string.Equals(unescaped, navigateUrl, StringComparison.Ordinal)
                && TryExtractClassCompetitionAuthKeyFromQueryText(unescaped, allowNestedNavigate: true, out authKey))
            {
                return true;
            }

            return false;
        }

        private static bool TryExtractClassCompetitionAuthKeyFromQueryText(
            string queryText,
            bool allowNestedNavigate,
            out string authKey)
        {
            authKey = string.Empty;
            if (string.IsNullOrWhiteSpace(queryText))
            {
                return false;
            }

            string normalizedQuery = queryText
                .Trim()
                .TrimStart('?', '#')
                .Replace("&amp;", "&", StringComparison.OrdinalIgnoreCase);
            if (string.IsNullOrWhiteSpace(normalizedQuery))
            {
                return false;
            }

            string[] pairs = normalizedQuery.Split('&', StringSplitOptions.RemoveEmptyEntries | StringSplitOptions.TrimEntries);
            for (int i = 0; i < pairs.Length; i++)
            {
                string pair = pairs[i];
                int separator = pair.IndexOf('=');
                if (separator <= 0 || separator >= pair.Length - 1)
                {
                    continue;
                }

                string key = Uri.UnescapeDataString(pair[..separator]);
                if (!key.Equals("key", StringComparison.OrdinalIgnoreCase)
                    && !key.Equals("auth", StringComparison.OrdinalIgnoreCase))
                {
                    if (!allowNestedNavigate
                        || (!key.Equals("url", StringComparison.OrdinalIgnoreCase)
                            && !key.Equals("navigate", StringComparison.OrdinalIgnoreCase)
                            && !key.Equals("navigateurl", StringComparison.OrdinalIgnoreCase)))
                    {
                        continue;
                    }

                    string nested = Uri.UnescapeDataString(pair[(separator + 1)..]).Trim();
                    if (nested.Length == 0
                        || string.Equals(nested, queryText, StringComparison.Ordinal))
                    {
                        continue;
                    }

                    if (TryExtractClassCompetitionAuthKeyFromNavigateUrl(nested, out authKey)
                        || TryExtractClassCompetitionAuthKeyFromQueryText(nested, allowNestedNavigate: false, out authKey))
                    {
                        return true;
                    }

                    continue;
                }

                string candidate = Uri.UnescapeDataString(pair[(separator + 1)..]);
                if (TryNormalizeClassCompetitionAuthKey(candidate, out string normalizedAuthKey))
                {
                    authKey = normalizedAuthKey;
                    return true;
                }
            }

            return false;
        }

        private static IReadOnlyList<string> NormalizeClassCompetitionRemoteLines(
            IEnumerable<string> lines,
            int maxCount)
        {
            if (lines == null || maxCount <= 0)
            {
                return Array.Empty<string>();
            }

            return lines
                .Where(line => !string.IsNullOrWhiteSpace(line))
                .Select(line => line.Trim())
                .Where(line => line.Length > 0)
                .Take(maxCount)
                .ToArray();
        }

        private string BuildClassCompetitionUrl(string authKey)
        {
            string urlTemplate = ResolveClassCompetitionUrlTemplate(out _);
            return string.Format(
                CultureInfo.InvariantCulture,
                urlTemplate,
                PacketOwnedClassCompetitionServerHost,
                authKey ?? string.Empty);
        }

        private static string ResolveClassCompetitionUrlTemplate(out bool usedResolvedTemplate)
        {
            return MapleStoryStringPool.GetCompositeFormatOrFallback(
                PacketOwnedClassCompetitionUrlTemplateStringPoolId,
                "http://{0}.nexon.com/maplestory/page/Gnxgame.aspx?URL=Event/classbattle/gameview&key={1}",
                2,
                out usedResolvedTemplate);
        }

        private void DispatchRepeatSkillModeEndEffectRequest(
            int skillId,
            int returnSkillId,
            int requestedAt,
            PacketOwnedSkillEffectRequest request)
        {
            if (request.Opcode <= 0 || request.Payload == null)
            {
                return;
            }

            MechanicAuthorityTransportPlanner.DispatchRequest(
                requestedAt,
                request.Opcode,
                request.Payload,
                _localUtilityOfficialSessionBridgeEnabled,
                _localUtilityOfficialSessionBridge.TrySendOutboundPacket,
                _localUtilityPacketOutbox.TrySendOutboundPacket,
                _localUtilityOfficialSessionBridge.TryQueueOutboundPacket,
                _localUtilityPacketOutbox.TryQueueOutboundPacket);
        }

        private void DispatchSg88FirstUseRequest(PacketOwnedSg88FirstUseRequest request)
        {
            if (request.Opcode <= 0 || request.Payload == null || request.Payload.Length == 0)
            {
                return;
            }

            MechanicAuthorityTransportPlanner.DispatchRequest(
                request.RequestTime,
                request.Opcode,
                request.Payload,
                _localUtilityOfficialSessionBridgeEnabled,
                _localUtilityOfficialSessionBridge.TrySendOutboundPacket,
                _localUtilityPacketOutbox.TrySendOutboundPacket,
                _localUtilityOfficialSessionBridge.TryQueueOutboundPacket,
                _localUtilityPacketOutbox.TryQueueOutboundPacket);
        }

