        private void DrainLocalUtilityPacketInbox()
        {
            while (_localUtilityPacketInbox.TryDequeue(out LocalUtilityPacketInboxMessage message))
            {
                if (message == null)
                {
                    continue;
                }

                bool applied = TryApplyPacketOwnedUtilityPacket(message.PacketType, message.Payload, out string detail, message.Source);
                _localUtilityPacketInbox.RecordDispatchResult(message, applied, detail);
                if (message.Source?.StartsWith("official-session:", StringComparison.OrdinalIgnoreCase) == true)
                {
                    _localUtilityOfficialSessionBridge.RecordDispatchResult(message.Source, applied, detail);
                }

                if (!string.IsNullOrWhiteSpace(detail))
                {
                    if (applied)
                    {
                        _chat?.AddSystemMessage(detail, currTickCount);
                    }
                    else
                    {
                        _chat?.AddErrorMessage(detail, currTickCount);
                    }
                }
            }
        }

        private void DrainAdminShopPacketInbox()
        {
            while (_adminShopPacketInbox.TryDequeue(out AdminShopPacketInboxMessage message))
            {
                if (message == null)
                {
                    continue;
                }

                bool applied = TryApplyPacketOwnedAdminShopPacket(message.PacketType, message.Payload, out string detail, message.Source);
                _adminShopPacketInbox.RecordDispatchResult(message, applied, detail);
                if (message.Source?.StartsWith("official-session:admin-shop:", StringComparison.OrdinalIgnoreCase) == true)
                {
                    _adminShopOfficialSessionBridge.RecordDispatchResult(message, applied, detail);
                }

                if (!string.IsNullOrWhiteSpace(detail))
                {
                    if (applied)
                    {
                        _chat?.AddSystemMessage(detail, currTickCount);
                    }
                    else
                    {
                        _chat?.AddErrorMessage(detail, currTickCount);
                    }
                }
            }
        }

        private void DrainAdminShopOfficialSessionBridge()
        {
            while (_adminShopOfficialSessionBridge.TryDequeue(out AdminShopPacketInboxMessage message))
            {
                if (message == null)
                {
                    continue;
                }

                _adminShopPacketInbox.EnqueueProxy(message.PacketType, message.Payload, message.Source);
            }
        }

        private static string FormatQuestDemandQuerySearchResultSource(QuestDemandItemMapResultSource source)
        {
            return source switch
            {
                QuestDemandItemMapResultSource.PacketOwnedMob => "Packet-authored quest demand item query",
                QuestDemandItemMapResultSource.WzMobDemand => "WZ mob-demand quest item query",
                QuestDemandItemMapResultSource.WzNpcFallback => "WZ NPC fallback quest item query",
                QuestDemandItemMapResultSource.CurrentFieldFallback => "Current-field fallback quest item query",
                _ => "Quest demand item query"
            };
        }

