        private bool TryApplyPacketOwnedChairSitResultPayload(byte[] payload, out string message)
        {
            message = null;
            PlayerCharacter player = _playerManager?.Player;
            if (player?.Build == null)
            {
                message = "Sit-result payload could not be applied because the local player is not initialized.";
                return false;
            }

            if (payload == null || payload.Length < 1)
            {
                message = "Sit-result payload must contain at least the success flag.";
                return false;
            }

            StampPacketOwnedUtilityRequestState();
            int currentTick = Environment.TickCount;
            _packetOwnedLocalUtilityContext.ObserveChairSitResult(currentTick);

            using var stream = new MemoryStream(payload, writable: false);
            using var reader = new BinaryReader(stream, Encoding.Default, leaveOpen: false);

            bool succeeded = reader.ReadByte() != 0;
            if (!succeeded)
            {
                player.ApplyPacketOwnedChairStandCorrection();
                message = "Packet-owned sit result rejected the chair request and forced a stand-up correction.";
                return true;
            }

            string chairRestrictionMessage = FieldInteractionRestrictionEvaluator.GetPortableChairRestrictionMessage(_mapBoard?.MapInfo);
            if (!string.IsNullOrWhiteSpace(chairRestrictionMessage))
            {
                player.ApplyPacketOwnedChairStandCorrection();
                ShowFieldRestrictionMessage(chairRestrictionMessage);
                message = $"Packet-owned sit result stayed in stand-up correction because current field metadata blocks chair owners.";
                return true;
            }

            if (stream.Length - stream.Position < sizeof(ushort))
            {
                player.ApplyPacketOwnedChairStandCorrection();
                message = "Sit-result payload is missing the seat index.";
                return false;
            }

            int seatIndex = reader.ReadUInt16();
            if (!TryResolvePacketOwnedChairSeatPosition(_mapBoard?.MapInfo?.id ?? 0, seatIndex, out Vector2 seatPosition))
            {
                player.ApplyPacketOwnedChairStandCorrection();
                message = BuildPacketOwnedChairCorrectionMessage(
                    player,
                    seatIndex,
                    "the current field does not expose that seat index",
                    currentTick);
                return true;
            }

            if (!IsPacketOwnedChairSeatValidForPlayer(player, seatPosition))
            {
                player.ApplyPacketOwnedChairStandCorrection();
                message = BuildPacketOwnedChairCorrectionMessage(
                    player,
                    seatIndex,
                    "the local player is outside the client chair rectangle for that seat",
                    currentTick);
                return true;
            }

            string detachedPassengerMessage = ClearPacketOwnedChairPassengerLink(player);
            player.SetPortableChairPairRequestActive(false);
            player.ClearPortableChairExternalOwnerPair();
            player.ApplyPacketOwnedSitPlacement(seatPosition.X, seatPosition.Y);
            message = string.IsNullOrWhiteSpace(detachedPassengerMessage)
                ? $"Applied packet-owned sit result for seat {seatIndex} at ({seatPosition.X:0},{seatPosition.Y:0})."
                : $"Applied packet-owned sit result for seat {seatIndex} at ({seatPosition.X:0},{seatPosition.Y:0}). {detachedPassengerMessage}";
            return true;
        }

        private bool TryApplyPacketOwnedMesoGiveSucceededPayload(byte[] payload, out string message)
        {
            message = null;
            if (!PacketOwnedRewardResultRuntime.TryDecodeMesoGiveSucceeded(payload, out int mesoAmount, out int trailingByteCount, out string decodeError))
            {
                message = decodeError ?? "Meso-give success payload could not be decoded.";
                return false;
            }

            StampPacketOwnedUtilityRequestState();
            string noticeText = PacketOwnedRewardResultRuntime.FormatMesoGiveSucceededText(mesoAmount);
            ShowPacketOwnedRewardResultNotice(noticeText, tightLine: true);
            message = trailingByteCount > 0
                ? $"Applied packet-owned meso-give success for {mesoAmount.ToString("N0", CultureInfo.InvariantCulture)} mesos through the dedicated reward-result notice owner and ignored {trailingByteCount} trailing byte(s), matching the native handler."
                : $"Applied packet-owned meso-give success for {mesoAmount.ToString("N0", CultureInfo.InvariantCulture)} mesos through the dedicated reward-result notice owner.";
            return true;
        }

        private bool TryApplyCharacterInfoRemoteProfilePayload(byte[] payload, out string message)
        {
            message = null;
            if (payload == null || payload.Length < sizeof(int) + sizeof(int))
            {
                message = "Character-info remote profile payload is missing the target character id or profile flags.";
                return false;
            }

            if (!RemoteUserPacketCodec.TryParseProfile(payload, out RemoteUserProfilePacket profilePacket, out string profileError))
            {
                message = profileError ?? "Character-info remote profile payload could not be decoded.";
                return false;
            }

            StampPacketOwnedUtilityRequestState();

            bool hasRemoteActor = _remoteUserPool.TryGetActor(profilePacket.CharacterId, out RemoteUserActor actor);
            if (hasRemoteActor && !_remoteUserPool.TryApplyProfileMetadata(profilePacket, out string profileMessage))
            {
                message = profileMessage;
                return false;
            }

            if (!hasRemoteActor)
            {
                _pendingRemoteUserProfilesByCharacterId[profilePacket.CharacterId] = profilePacket;
            }
            else
            {
                _pendingRemoteUserProfilesByCharacterId.Remove(profilePacket.CharacterId);
            }

            CharacterBuild inspectionBuild = hasRemoteActor
                ? actor.Build?.Clone()
                : TryCreateRemoteCharacterInfoInspectionBuildFromPendingProfile(
                    profilePacket.CharacterId,
                    null,
                    out CharacterBuild pendingProfileBuild)
                    ? pendingProfileBuild
                    : null;
            if (inspectionBuild != null)
            {
                TryResolveCharacterInfoPresence(
                    profilePacket.CharacterId,
                    inspectionBuild.Name,
                    hasRemoteActor ? actor : null,
                    "Packet-owned profile payload",
                    0,
                    out string locationSummary,
                    out int channel);
                ShowCharacterInfoWindow(
                    inspectionTarget: new UserInfoUI.UserInfoInspectionTarget
                    {
                        Build = inspectionBuild,
                        CharacterId = profilePacket.CharacterId,
                        Name = inspectionBuild.Name,
                        LocationSummary = locationSummary,
                        Channel = channel,
                        IsLiveRemoteTarget = actor?.IsVisibleInWorld == true
                    });
            }
            else
            {
                ShowPacketOwnedWindow(MapSimulatorWindowNames.CharacterInfo, "Character Info");
            }

            message = hasRemoteActor
                ? $"Applied packet-owned character-info remote profile payload for character {profilePacket.CharacterId.ToString(CultureInfo.InvariantCulture)} through the shared remote-user profile metadata seam and refreshed the inspected UserInfo owner."
                : $"Applied packet-owned character-info remote profile payload for character {profilePacket.CharacterId.ToString(CultureInfo.InvariantCulture)} to the active UserInfo inspection owner while queuing it for the future remote actor.";
            return true;
        }

        private bool TryApplyCharacterInfoCollectionClaimResultPayload(byte[] payload, out string message)
        {
            message = null;
            if (!UserInfoCollectionClaimResultCodec.TryDecode(payload, out UserInfoCollectionClaimResult result, out string decodeError))
            {
                message = decodeError ?? "CUIUserInfo BtArrayGet result payload could not be decoded.";
                return false;
            }

            StampPacketOwnedUtilityRequestState();

            string claimKey = $"id:{result.CharacterId.ToString(CultureInfo.InvariantCulture)}";
            string noticeText = string.IsNullOrWhiteSpace(result.NoticeText)
                ? ResolveCharacterInfoCollectionClaimResultNotice(result.ResultCode)
                : result.NoticeText.Trim();

            if (result.ResultCode == UserInfoCollectionClaimResultCode.Success)
            {
                _characterInfoCollectionClaimFingerprints[claimKey] = result.SnapshotFingerprint;
                message = $"Applied packet-owned CUIUserInfo BtArrayGet success for character {result.CharacterId.ToString(CultureInfo.InvariantCulture)} with collection fingerprint {result.SnapshotFingerprint.ToString(CultureInfo.InvariantCulture)}. {noticeText}";
                return true;
            }

            message = $"Applied packet-owned CUIUserInfo BtArrayGet {result.ResultCode.ToString()} result for character {result.CharacterId.ToString(CultureInfo.InvariantCulture)} without changing the local collection fingerprint. {noticeText}";
            return true;
        }

        private static string ResolveCharacterInfoCollectionClaimResultNotice(UserInfoCollectionClaimResultCode resultCode)
        {
            return resultCode switch
            {
                UserInfoCollectionClaimResultCode.Success => "Collection summary claim completed.",
                UserInfoCollectionClaimResultCode.NoPendingSummary => "No collection summary is waiting to be claimed.",
                UserInfoCollectionClaimResultCode.Unavailable => "Collection claim is unavailable for this profile.",
                UserInfoCollectionClaimResultCode.Rejected => "Collection claim was rejected by the profile owner.",
                _ => "Collection claim returned an unrecognized result."
            };
        }

