        private bool TryApplyPacketOwnedEmotionPayload(byte[] payload, out string message)
        {
            message = null;
            PlayerCharacter player = _playerManager?.Player;
            if (player == null)
            {
                message = "Packet-owned avatar emotion requires an initialized local player.";
                return false;
            }

            if (!TryDecodePacketOwnedEmotionPayload(
                    payload,
                    out int emotionId,
                    out int durationMs,
                    out bool byItemOption,
                    out message))
            {
                return false;
            }

            StampPacketOwnedUtilityRequestState();
            return player.TryApplyPacketOwnedEmotion(
                emotionId,
                durationMs,
                byItemOption,
                Environment.TickCount,
                out message);
        }

        private bool TryApplyPacketOwnedActiveEffectItemPayload(byte[] payload, out string message)
        {
            message = null;
            PlayerCharacter player = _playerManager?.Player;
            if (player == null)
            {
                message = "Packet-owned active-effect-item routing requires an initialized local player.";
                return false;
            }

            if (!TryDecodePacketOwnedActiveEffectItemPayload(payload, out int itemId, out message))
            {
                return false;
            }

            StampPacketOwnedUtilityRequestState();
            int currentTick = Environment.TickCount;
            _packetOwnedActiveEffectItemId = Math.Max(0, itemId);
            ClearPacketOwnedActiveEffectItemMotionBlurOwner();

            if (itemId <= 0)
            {
                player.TryApplyPacketOwnedEmotion(
                    emotionId: 0,
                    durationMs: 0,
                    byItemOption: false,
                    currentTick,
                    out _);
                message = "Cleared packet-owned active-effect-item owner state and motion-blur owner.";
                return true;
            }

            bool hasEmotionSelection = PacketOwnedAvatarEmotionResolver.TryResolveItemEmotion(
                itemId,
                currentTick,
                out PacketOwnedAvatarEmotionSelection selection,
                out bool byItemOption,
                out string emotionResolveError);
            bool emotionApplied = false;
            string emotionMessage = null;
            if (hasEmotionSelection)
            {
                emotionApplied = player.TryApplyPacketOwnedEmotion(
                    selection.EmotionId,
                    durationMs: 0,
                    byItemOption,
                    currentTick,
                    out emotionMessage);
            }

            bool hasMotionBlur = ActiveEffectItemMotionBlurResolver.TryResolve(
                itemId,
                out ActiveEffectItemMotionBlurDefinition motionBlurDefinition,
                out string motionBlurResolveError);
            string motionBlurMessage = null;
            bool motionBlurApplied = false;
            if (hasMotionBlur)
            {
                motionBlurApplied = TryRegisterPacketOwnedActiveEffectItemMotionBlur(
                    player,
                    motionBlurDefinition,
                    currentTick,
                    out motionBlurMessage);
            }

            if (!hasEmotionSelection && !hasMotionBlur)
            {
                message = $"Active-effect item {itemId} did not resolve packet-owned emotion or spectrum motion-blur metadata. Emotion: {emotionResolveError} MotionBlur: {motionBlurResolveError}";
                return true;
            }

            string emotionSummary = hasEmotionSelection
                ? (emotionApplied ? emotionMessage : $"Resolved emotion '{selection.EmotionName}' ({selection.EmotionId}) but could not apply it.")
                : $"No packet-owned emotion mapping ({emotionResolveError}).";
            string motionBlurSummary = hasMotionBlur
                ? (motionBlurApplied
                    ? $"Registered spectrum motion blur delay={motionBlurDefinition.DelayMs}, interval={motionBlurDefinition.IntervalMs}, alpha={motionBlurDefinition.Alpha}, follow={(motionBlurDefinition.Follow ? 1 : 0)}."
                    : $"Spectrum metadata resolved but could not register motion blur ({motionBlurMessage}).")
                : $"No spectrum motion-blur metadata ({motionBlurResolveError}).";
            message = $"Applied packet-owned active-effect item {itemId}. {emotionSummary} {motionBlurSummary}";
            return true;
        }

        private bool TryApplyPacketOwnedRandomEmotionPayload(byte[] payload, out string message)
        {
            message = null;
            int currentTick = Environment.TickCount;
            if (!TryResolvePacketOwnedRandomEmotionRequest(
                    payload,
                    _packetOwnedLocalUtilityContext,
                    currentTick,
                    out PacketOwnedAvatarEmotionSelection selection,
                    out PacketOwnedLocalUtilityOutboundRequest request,
                    out message))
            {
                return false;
            }

            StampPacketOwnedUtilityRequestState();
            if (request.Opcode < 0)
            {
                message = $"Resolved area-buff item {selection.AreaBuffItemId} to packet-owned emotion '{selection.EmotionName}' ({selection.EmotionId}) with roll {selection.RandomRoll}/{selection.TotalWeight}, but the simulated CWvsContext gate suppressed SendEmotionChange(56). {_packetOwnedLocalUtilityContext.DescribeEmotionContext(currentTick)}";
                return true;
            }

            string payloadHex = Convert.ToHexString(request.Payload?.ToArray() ?? Array.Empty<byte>());
            string dispatchSummary = DescribePacketOwnedEmotionOutboundDispatch(request, payloadHex, currentTick);
            message = $"Resolved area-buff item {selection.AreaBuffItemId} to packet-owned emotion '{selection.EmotionName}' ({selection.EmotionId}) with roll {selection.RandomRoll}/{selection.TotalWeight} and mirrored CWvsContext::SendEmotionChange(56); the local avatar now waits for the inbound OnEmotion(232) echo before changing expression. {dispatchSummary}";
            return true;
        }

        internal static bool TryResolvePacketOwnedRandomEmotionRequest(
            byte[] payload,
            PacketOwnedLocalUtilityContextState contextState,
            int currentTick,
            out PacketOwnedAvatarEmotionSelection selection,
            out PacketOwnedLocalUtilityOutboundRequest request,
            out string message)
        {
            selection = default;
            request = new PacketOwnedLocalUtilityOutboundRequest(-1, 0, Array.Empty<byte>());
            message = null;

            if (contextState == null)
            {
                message = "Random-emotion routing requires a local-utility context state.";
                return false;
            }

            if (!TryDecodePacketOwnedRandomEmotionPayload(payload, out int areaBuffItemId, out message))
            {
                return false;
            }

            if (!PacketOwnedAvatarEmotionResolver.TryResolveRandomEmotion(
                    areaBuffItemId,
                    currentTick,
                    out selection,
                    out string error))
            {
                message = error ?? $"Area-buff item {areaBuffItemId} did not resolve a packet-owned random emotion.";
                return false;
            }

            if (!contextState.TryEmitEmotionChangeRequest(
                    currentTick,
                    selection.EmotionId,
                    byItemOption: false,
                    durationMs: -1,
                    out request))
            {
                request = new PacketOwnedLocalUtilityOutboundRequest(-1, 0, Array.Empty<byte>());
            }

            return true;
        }

