        internal static bool TryDecodePacketOwnedEmotionPayload(
            byte[] payload,
            out int emotionId,
            out int durationMs,
            out bool byItemOption,
            out string message)
        {
            emotionId = 0;
            durationMs = 0;
            byItemOption = false;
            message = null;

            if (payload == null || payload.Length < sizeof(int) + sizeof(int) + sizeof(byte))
            {
                message = "Emotion payload must contain emotionId Int32, durationMs Int32, and byItemOption Byte values.";
                return false;
            }

            try
            {
                using MemoryStream stream = new(payload, writable: false);
                using BinaryReader reader = new(stream);
                emotionId = reader.ReadInt32();
                durationMs = reader.ReadInt32();
                byItemOption = reader.ReadByte() != 0;

                if (stream.Position != stream.Length)
                {
                    message = $"Emotion payload has {stream.Length - stream.Position} trailing byte(s).";
                    return false;
                }

                return true;
            }
            catch (Exception ex)
            {
                message = $"Emotion payload could not be decoded: {ex.Message}";
                return false;
            }
        }

        internal static bool TryDecodePacketOwnedActiveEffectItemPayload(
            byte[] payload,
            out int itemId,
            out string message)
        {
            itemId = 0;
            message = null;

            if (payload == null || payload.Length < sizeof(int))
            {
                message = "Active-effect-item payload must contain an item id Int32 value.";
                return false;
            }

            try
            {
                using MemoryStream stream = new(payload, writable: false);
                using BinaryReader reader = new(stream);
                itemId = reader.ReadInt32();

                if (stream.Position != stream.Length)
                {
                    message = $"Active-effect-item payload has {stream.Length - stream.Position} trailing byte(s).";
                    return false;
                }

                return true;
            }
            catch (Exception ex)
            {
                message = $"Active-effect-item payload could not be decoded: {ex.Message}";
                return false;
            }
        }

        internal static bool TryDecodePacketOwnedRandomEmotionPayload(
            byte[] payload,
            out int areaBuffItemId,
            out string message)
        {
            areaBuffItemId = 0;
            message = null;

            if (payload == null || payload.Length < sizeof(int))
            {
                message = "Random-emotion payload must contain an area-buff item id Int32 value.";
                return false;
            }

            try
            {
                using MemoryStream stream = new(payload, writable: false);
                using BinaryReader reader = new(stream);
                areaBuffItemId = reader.ReadInt32();

                if (stream.Position != stream.Length)
                {
                    message = $"Random-emotion payload has {stream.Length - stream.Position} trailing byte(s).";
                    return false;
                }

                return true;
            }
            catch (Exception ex)
            {
                message = $"Random-emotion payload could not be decoded: {ex.Message}";
                return false;
            }
        }

        private void ClearPacketOwnedActiveEffectItemMotionBlurOwner()
        {
            if (_packetOwnedActiveEffectMotionBlurState != null)
            {
                _packetOwnedActiveEffectMotionBlurState.MarkTerminated();
                _packetOwnedActiveEffectMotionBlurState = null;
            }

            if (_packetOwnedActiveEffectMotionBlurId < 0)
            {
                return;
            }

            _animationEffects?.RemoveMotionBlurAnimation(_packetOwnedActiveEffectMotionBlurId);
            _packetOwnedActiveEffectMotionBlurId = -1;
        }

        private bool TryRegisterPacketOwnedActiveEffectItemMotionBlur(
            PlayerCharacter player,
            ActiveEffectItemMotionBlurDefinition definition,
            int currentTime,
            out string message)
        {
            message = null;
            if (!definition.IsValid)
            {
                message = "Active-effect-item motion-blur definition is not valid.";
                return false;
            }

            if (_animationEffects == null)
            {
                message = "Animation effects runtime is unavailable.";
                return false;
            }

            int ownerCharacterId = player?.Build?.Id ?? 0;
            IReadOnlyDictionary<AvatarRenderLayer, int> simulatedLayerHandleIds =
                ResolvePacketOwnedActiveEffectMotionBlurLayerHandleIds(ownerCharacterId);
            if (!TryCreatePacketOwnedActiveEffectMotionBlurFrame(
                    player,
                    currentTime,
                    definition.DelayMs,
                    simulatedLayerHandleIds,
                    out List<IDXObject> frames,
                    out bool snapshotFacingRight,
                    out string captureError))
            {
                message = captureError ?? "Could not capture active-effect-item motion-blur frame.";
                return false;
            }

            Func<Vector2> getPosition = () => player.Position;
            Func<bool> getFlip = () => player.FacingRight;
            Vector2 fallbackPosition = getPosition();
            var ownerSampleByTime = new Dictionary<int, PacketOwnedActiveEffectMotionBlurOwnerSample>();
            PacketOwnedActiveEffectMotionBlurOwnerSample ResolveOwnerSample(int sampleTime)
            {
                if (ownerSampleByTime.TryGetValue(sampleTime, out PacketOwnedActiveEffectMotionBlurOwnerSample cachedSample))
                {
                    return cachedSample;
                }

                PacketOwnedActiveEffectMotionBlurOwnerSample resolvedSample =
                    ResolvePacketOwnedActiveEffectMotionBlurSnapshotOwnerState(player, sampleTime);
                ownerSampleByTime[sampleTime] = resolvedSample;
                return resolvedSample;
            }

            Func<int, Vector2?> snapshotPositionFactory = sampleTime => ResolveOwnerSample(sampleTime).Position;
            Func<int, bool?> snapshotFlipFactory = sampleTime => ResolveOwnerSample(sampleTime).FacingRight;
            var state = new Animation.AnimationEffects.SecondaryMotionBlurAnimationState
            {
                SimulatedAnimationStateId = NextPacketOwnedActiveEffectMotionBlurStateId(),
                SimulatedOverlayLayerHandleId = ResolvePacketOwnedActiveEffectMotionBlurOverlayLayerHandleId(),
                SimulatedLayerHandleIdsByLayerCode = simulatedLayerHandleIds
                    .ToDictionary(static entry => (int)entry.Key, static entry => entry.Value)
            };
            Func<int, List<IDXObject>> snapshotFrameFactory = sampleTime =>
            {
                return TryCreatePacketOwnedActiveEffectMotionBlurFramesAtSampleTime(
                    player,
                    sampleTime,
                    definition.DelayMs,
                    simulatedLayerHandleIds,
                    out List<IDXObject> sampledFrames)
                    ? sampledFrames
                    : null;
            };
            _packetOwnedActiveEffectMotionBlurId = _animationEffects.RegisterMotionBlurAnimation(
                frames,
                getPosition,
                getFlip,
                fallbackPosition,
                snapshotFacingRight,
                delayMs: 0,
                intervalMs: definition.IntervalMs,
                alpha: definition.Alpha,
                currentTime,
                durationMs: PacketOwnedActiveEffectMotionBlurOwnerDurationMs,
                follow: definition.Follow,
                snapshotRetentionMs: definition.DelayMs,
                ownsFrameTextures: true,
                snapshotFrameFactory: snapshotFrameFactory,
                snapshotPositionFactory: snapshotPositionFactory,
                snapshotFlipFactory: snapshotFlipFactory,
                animationState: state);
            if (_packetOwnedActiveEffectMotionBlurId < 0)
            {
                message = "Motion blur owner registration failed.";
                return false;
            }

            _packetOwnedActiveEffectMotionBlurState = state;
            return true;
        }

        private bool TryCreatePacketOwnedActiveEffectMotionBlurFrame(
            PlayerCharacter player,
            int currentTime,
            int frameDelayMs,
            IReadOnlyDictionary<AvatarRenderLayer, int> layerHandleIds,
            out List<IDXObject> frames,
            out bool facingRight,
            out string message)
        {
            frames = null;
            facingRight = true;
            message = null;

            if (player == null)
            {
                message = "Local player is not initialized.";
                return false;
            }

            if (GraphicsDevice == null)
            {
                message = "Graphics device is unavailable.";
                return false;
            }

            AssembledFrame frame = player.TryGetCurrentFrame(currentTime);
            if (frame == null || frame.Parts == null || frame.Parts.Count == 0)
            {
                message = "Current local avatar frame is unavailable.";
                return false;
            }

            if (frame.Bounds.Width <= 0 || frame.Bounds.Height <= 0)
            {
                message = "Current local avatar frame has empty bounds.";
                return false;
            }

            if (!TryCreatePacketOwnedActiveEffectMotionBlurLayerStack(
                    frame,
                    frameDelayMs,
                    layerHandleIds,
                    out frames,
                    out message))
            {
                return false;
            }

            facingRight = player.FacingRight;
            return true;
        }

        private bool TryCreatePacketOwnedActiveEffectMotionBlurFramesAtSampleTime(
            PlayerCharacter player,
            int sampleTime,
            int frameDelayMs,
            IReadOnlyDictionary<AvatarRenderLayer, int> layerHandleIds,
            out List<IDXObject> frames)
        {
            frames = null;
            return TryCreatePacketOwnedActiveEffectMotionBlurFrame(
                player,
                sampleTime,
                frameDelayMs,
                layerHandleIds,
                out frames,
                out _,
                out _);
        }

        private readonly struct PacketOwnedActiveEffectMotionBlurOwnerSample
        {
            public PacketOwnedActiveEffectMotionBlurOwnerSample(Vector2 position, bool facingRight)
            {
                Position = position;
                FacingRight = facingRight;
            }

            public Vector2 Position { get; }
            public bool FacingRight { get; }
        }

        private PacketOwnedActiveEffectMotionBlurOwnerSample ResolvePacketOwnedActiveEffectMotionBlurSnapshotOwnerState(
            PlayerCharacter player,
            int sampleTime)
        {
            Vector2 fallbackPosition = player?.Position ?? Vector2.Zero;
            bool fallbackFacingRight = player?.FacingRight ?? true;
            PlayerMovementSyncSnapshot movementSnapshot = ResolvePacketOwnedActiveEffectMotionBlurSnapshotSource(player, sampleTime);
            return ResolvePacketOwnedActiveEffectMotionBlurSnapshotOwnerState(
                movementSnapshot,
                fallbackPosition,
                fallbackFacingRight,
                sampleTime);
        }

        private PlayerMovementSyncSnapshot ResolvePacketOwnedActiveEffectMotionBlurSnapshotSource(
            PlayerCharacter player,
            int sampleTime)
        {
            PlayerMovementSyncSnapshot passiveMoveSnapshot = _lastPacketOwnedPassiveMoveSnapshot;
            PlayerMovementSyncSnapshot localMovementSnapshot =
                TryResolvePacketOwnedActiveEffectMotionBlurLocalMovementSnapshot(player, sampleTime);
            return ResolvePacketOwnedActiveEffectMotionBlurSnapshotSource(
                passiveMoveSnapshot,
                localMovementSnapshot,
                sampleTime);
        }

        private static PlayerMovementSyncSnapshot TryResolvePacketOwnedActiveEffectMotionBlurLocalMovementSnapshot(
            PlayerCharacter player,
            int sampleTime)
        {
            if (player == null)
            {
                return null;
            }

            try
            {
                int referenceTime = Environment.TickCount;
                if (referenceTime < sampleTime)
                {
                    referenceTime = sampleTime;
                }

                return player.GetMovementSyncSnapshotFromRecordedPath(
                    referenceTime,
                    appendLatestState: true);
            }
            catch
            {
                return null;
            }
        }

        private static PlayerMovementSyncSnapshot ResolvePacketOwnedActiveEffectMotionBlurSnapshotSource(
            PlayerMovementSyncSnapshot passiveMoveSnapshot,
            PlayerMovementSyncSnapshot localMovementSnapshot,
            int sampleTime)
        {
            if (ShouldUsePacketOwnedActiveEffectMotionBlurPassiveSnapshot(passiveMoveSnapshot, sampleTime))
            {
                return passiveMoveSnapshot;
            }

            return ShouldUsePacketOwnedActiveEffectMotionBlurSnapshot(localMovementSnapshot, sampleTime)
                ? localMovementSnapshot
                : null;
        }

        private static bool ShouldUsePacketOwnedActiveEffectMotionBlurPassiveSnapshot(
            PlayerMovementSyncSnapshot passiveMoveSnapshot,
            int sampleTime)
        {
            return ShouldUsePacketOwnedActiveEffectMotionBlurSnapshot(
                passiveMoveSnapshot,
                sampleTime);
        }

        private static bool ShouldUsePacketOwnedActiveEffectMotionBlurSnapshot(
            PlayerMovementSyncSnapshot movementSnapshot,
            int sampleTime)
        {
            if (!TryResolvePacketOwnedActiveEffectMotionBlurSnapshotSampleTimeBounds(
                    movementSnapshot,
                    out int startTime,
                    out int endTime))
            {
                return false;
            }

            return sampleTime >= startTime && sampleTime <= endTime;
        }

        private static bool TryResolvePacketOwnedActiveEffectMotionBlurSnapshotSampleTimeBounds(
            PlayerMovementSyncSnapshot movementSnapshot,
            out int startTime,
            out int endTime)
        {
            startTime = 0;
            endTime = 0;
            if (movementSnapshot == null)
            {
                return false;
            }

            startTime = movementSnapshot.PassivePosition.TimeStamp;
            endTime = movementSnapshot.PassivePosition.TimeStamp;
            List<MovePathElement> movePath = movementSnapshot.MovePath;
            if (movePath == null || movePath.Count == 0)
            {
                return true;
            }

            for (int i = 0; i < movePath.Count; i++)
            {
                int timeStamp = movePath[i].TimeStamp;
                int sampleEndTime = ResolvePacketOwnedActiveEffectMotionBlurMovePathElementSampleEndTime(movePath[i]);
                if (timeStamp < startTime)
                {
                    startTime = timeStamp;
                }

                if (sampleEndTime > endTime)
                {
                    endTime = sampleEndTime;
                }
            }

            return true;
        }

        private static int ResolvePacketOwnedActiveEffectMotionBlurMovePathElementSampleEndTime(MovePathElement element)
        {
            int duration = Math.Max(0, (int)element.Duration);
            long candidate = (long)element.TimeStamp + duration;
            if (candidate > int.MaxValue)
            {
                return int.MaxValue;
            }

            return (int)Math.Max(element.TimeStamp, candidate);
        }

        private static PacketOwnedActiveEffectMotionBlurOwnerSample ResolvePacketOwnedActiveEffectMotionBlurSnapshotOwnerState(
            PlayerMovementSyncSnapshot movementSnapshot,
            Vector2 fallbackPosition,
            bool fallbackFacingRight,
            int sampleTime)
        {
            if (ShouldUsePacketOwnedActiveEffectMotionBlurSnapshot(movementSnapshot, sampleTime))
            {
                PassivePositionSnapshot sample = movementSnapshot.SampleAtTime(sampleTime);
                return new PacketOwnedActiveEffectMotionBlurOwnerSample(
                    new Vector2(sample.X, sample.Y),
                    sample.FacingRight);
            }

            return new PacketOwnedActiveEffectMotionBlurOwnerSample(fallbackPosition, fallbackFacingRight);
        }

        private bool TryCreatePacketOwnedActiveEffectMotionBlurLayerStack(
            AssembledFrame frame,
            int frameDelayMs,
            IReadOnlyDictionary<AvatarRenderLayer, int> layerHandleIds,
            out List<IDXObject> frames,
            out string message)
        {
            frames = new List<IDXObject>(PacketOwnedActiveEffectMotionBlurLayerCaptureOrder.Length);
            message = null;
            if (GraphicsDevice == null)
            {
                message = "Graphics device is unavailable.";
                return false;
            }

            int delay = Math.Max(1, frameDelayMs);
            try
            {
                for (int i = 0; i < PacketOwnedActiveEffectMotionBlurLayerCaptureOrder.Length; i++)
                {
                    AvatarRenderLayer layer = PacketOwnedActiveEffectMotionBlurLayerCaptureOrder[i];
                    if (!TryCreatePacketOwnedActiveEffectMotionBlurLayerFrame(
                            frame,
                            layer,
                            delay,
                            out IDXObject layerFrame))
                    {
                        continue;
                    }

                    layerFrame.Tag = new HaCreator.MapSimulator.Animation.AnimationEffects.SecondaryMotionBlurLayerStackEntryTag(
                        drawOrder: ResolvePacketOwnedActiveEffectMotionBlurLayerDrawOrder(layer),
                        sourceLayerCode: (int)layer,
                        sourceLayerCaptureOrder: i,
                        simulatedLayerHandleId: ResolvePacketOwnedActiveEffectMotionBlurLayerHandleId(layer, layerHandleIds),
                        simulatedLayerHandleRefCount: ResolvePacketOwnedActiveEffectMotionBlurCopiedLayerHandleRefCount(layer, layerHandleIds),
                        simulatedSnapshotLayerHandleId: NextPacketOwnedActiveEffectMotionBlurLayerHandleId(),
                        simulatedRepeatAnimationStateId: NextPacketOwnedActiveEffectMotionBlurStateId());
                    frames.Add(layerFrame);
                }
            }
            catch (Exception ex)
            {
                DisposePacketOwnedActiveEffectMotionBlurFrames(frames);
                frames = null;
                message = $"Could not capture active-effect-item layer-stack motion blur frame: {ex.Message}";
                return false;
            }

            if (frames.Count == 0)
            {
                message = "Current local avatar frame did not produce any visible layer snapshots.";
                return false;
            }

            return true;
        }

        private bool TryCreatePacketOwnedActiveEffectMotionBlurLayerFrame(
            AssembledFrame frame,
            AvatarRenderLayer layer,
            int frameDelayMs,
            out IDXObject frameObject)
        {
            frameObject = null;
            IReadOnlyList<AssembledPart> layerParts = ResolvePacketOwnedActiveEffectMotionBlurLayerParts(frame, layer);
            if (layerParts == null || layerParts.Count == 0 || frame.Bounds.Width <= 0 || frame.Bounds.Height <= 0)
            {
                return false;
            }

            RenderTargetBinding[] previousTargets = GraphicsDevice.GetRenderTargets();
            Viewport previousViewport = GraphicsDevice.Viewport;
            var renderTarget = new RenderTarget2D(
                GraphicsDevice,
                frame.Bounds.Width,
                frame.Bounds.Height,
                false,
                SurfaceFormat.Color,
                DepthFormat.None);
            try
            {
                GraphicsDevice.SetRenderTarget(renderTarget);
                GraphicsDevice.Clear(Color.Transparent);
                using var spriteBatch = new SpriteBatch(GraphicsDevice);
                spriteBatch.Begin(SpriteSortMode.Deferred, BlendState.AlphaBlend, SamplerState.PointClamp, DepthStencilState.None, RasterizerState.CullNone);
                for (int partIndex = 0; partIndex < layerParts.Count; partIndex++)
                {
                    AssembledPart part = layerParts[partIndex];
                    if (part?.Texture == null || !part.IsVisible)
                    {
                        continue;
                    }

                    int drawX = part.OffsetX - frame.Bounds.Left;
                    int drawY = part.OffsetY - frame.Bounds.Top;
                    part.Texture.DrawBackground(spriteBatch, _skeletonMeshRenderer, null, drawX, drawY, Color.White, flip: false, null);
                }

                spriteBatch.End();
            }
            catch
            {
                renderTarget.Dispose();
                throw;
            }
            finally
            {
                if (previousTargets.Length > 0)
                {
                    GraphicsDevice.SetRenderTargets(previousTargets);
                }
                else
                {
                    GraphicsDevice.SetRenderTarget(null);
                }

                GraphicsDevice.Viewport = previousViewport;
            }

            Point offset = ResolvePacketOwnedActiveEffectMotionBlurLayerFrameOffset(frame);
            frameObject = new DXObject(offset.X, offset.Y, renderTarget, frameDelayMs);
            return true;
        }

        internal static Point ResolvePacketOwnedActiveEffectMotionBlurLayerFrameOffsetForTesting(
            AssembledFrame frame)
        {
            return ResolvePacketOwnedActiveEffectMotionBlurLayerFrameOffset(frame);
        }

        private static Point ResolvePacketOwnedActiveEffectMotionBlurLayerFrameOffset(AssembledFrame frame)
        {
            if (frame == null)
            {
                return Point.Zero;
            }

            return new Point(frame.Bounds.Left, frame.Bounds.Top - frame.FeetOffset);
        }

        private static IReadOnlyList<AssembledPart> ResolvePacketOwnedActiveEffectMotionBlurLayerParts(
            AssembledFrame frame,
            AvatarRenderLayer layer)
        {
            if (frame?.AvatarRenderLayers != null)
            {
                int layerIndex = (int)layer;
                if (layerIndex >= 0
                    && layerIndex < frame.AvatarRenderLayers.Length
                    && frame.AvatarRenderLayers[layerIndex] != null
                    && frame.AvatarRenderLayers[layerIndex].Count > 0)
                {
                    return frame.AvatarRenderLayers[layerIndex];
                }
            }

            return frame?.Parts?
                .Where(part => part != null && part.IsVisible && part.RenderLayer == layer)
                .ToArray();
        }

        private static int ResolvePacketOwnedActiveEffectMotionBlurLayerDrawOrder(AvatarRenderLayer layer)
        {
            return layer switch
            {
                AvatarRenderLayer.UnderCharacter => 0,
                AvatarRenderLayer.OverCharacter => 1,
                AvatarRenderLayer.UnderFace => 2,
                AvatarRenderLayer.Face => 3,
                AvatarRenderLayer.OverFace => 4,
                _ => 2
            };
        }

        private static int ResolvePacketOwnedActiveEffectMotionBlurLayerHandleId(
            AvatarRenderLayer layer,
            IReadOnlyDictionary<AvatarRenderLayer, int> layerHandleIds)
        {
            if (layerHandleIds != null
                && layerHandleIds.TryGetValue(layer, out int handleId)
                && handleId > 0)
            {
                return handleId;
            }

            return 0;
        }

        private static int ResolvePacketOwnedActiveEffectMotionBlurCopiedLayerHandleRefCount(
            AvatarRenderLayer layer,
            IReadOnlyDictionary<AvatarRenderLayer, int> layerHandleIds)
        {
            return ResolvePacketOwnedActiveEffectMotionBlurLayerHandleId(layer, layerHandleIds) > 0
                ? 2
                : 0;
        }

        private static IReadOnlyDictionary<AvatarRenderLayer, int> CreatePacketOwnedActiveEffectMotionBlurLayerHandleIds()
        {
            var handleIds = new Dictionary<AvatarRenderLayer, int>(PacketOwnedActiveEffectMotionBlurLayerCaptureOrder.Length);
            for (int i = 0; i < PacketOwnedActiveEffectMotionBlurLayerCaptureOrder.Length; i++)
            {
                AvatarRenderLayer layer = PacketOwnedActiveEffectMotionBlurLayerCaptureOrder[i];
                if (!handleIds.ContainsKey(layer))
                {
                    handleIds[layer] = NextPacketOwnedActiveEffectMotionBlurLayerHandleId();
                }
            }

            return handleIds;
        }

        private IReadOnlyDictionary<AvatarRenderLayer, int> ResolvePacketOwnedActiveEffectMotionBlurLayerHandleIds(int ownerCharacterId)
        {
            (IReadOnlyDictionary<AvatarRenderLayer, int> layerHandleIds, int resolvedOwnerCharacterId) =
                ResolvePacketOwnedActiveEffectMotionBlurLayerHandleIds(
                    _packetOwnedActiveEffectMotionBlurLayerHandleIds,
                    _packetOwnedActiveEffectMotionBlurOwnerCharacterId,
                    ownerCharacterId);
            _packetOwnedActiveEffectMotionBlurLayerHandleIds = layerHandleIds;
            _packetOwnedActiveEffectMotionBlurOwnerCharacterId = resolvedOwnerCharacterId;
            return _packetOwnedActiveEffectMotionBlurLayerHandleIds;
        }

        private static bool IsCompletePacketOwnedActiveEffectMotionBlurLayerHandleIdMap(
            IReadOnlyDictionary<AvatarRenderLayer, int> layerHandleIds)
        {
            if (layerHandleIds == null)
            {
                return false;
            }

            for (int i = 0; i < PacketOwnedActiveEffectMotionBlurLayerCaptureOrder.Length; i++)
            {
                AvatarRenderLayer layer = PacketOwnedActiveEffectMotionBlurLayerCaptureOrder[i];
                if (!layerHandleIds.TryGetValue(layer, out int handleId) || handleId <= 0)
                {
                    return false;
                }
            }

            return true;
        }

        private static int NextPacketOwnedActiveEffectMotionBlurStateId()
        {
            return HaCreator.MapSimulator.Animation.SimulatedMotionBlurIdentitySource.NextAnimationStateId();
        }

        private int ResolvePacketOwnedActiveEffectMotionBlurOverlayLayerHandleId()
        {
            if (_packetOwnedActiveEffectMotionBlurOverlayLayerHandleId > 0)
            {
                return _packetOwnedActiveEffectMotionBlurOverlayLayerHandleId;
            }

            _packetOwnedActiveEffectMotionBlurOverlayLayerHandleId = NextPacketOwnedActiveEffectMotionBlurLayerHandleId();
            return _packetOwnedActiveEffectMotionBlurOverlayLayerHandleId;
        }

        private static int NextPacketOwnedActiveEffectMotionBlurLayerHandleId()
        {
            return HaCreator.MapSimulator.Animation.SimulatedMotionBlurIdentitySource.NextLayerHandleId();
        }

        internal static IReadOnlyDictionary<AvatarRenderLayer, int> CreatePacketOwnedActiveEffectMotionBlurLayerHandleIdsForTesting()
        {
            return CreatePacketOwnedActiveEffectMotionBlurLayerHandleIds();
        }

        internal static bool IsCompletePacketOwnedActiveEffectMotionBlurLayerHandleIdMapForTesting(
            IReadOnlyDictionary<AvatarRenderLayer, int> layerHandleIds)
        {
            return IsCompletePacketOwnedActiveEffectMotionBlurLayerHandleIdMap(layerHandleIds);
        }

        private static (IReadOnlyDictionary<AvatarRenderLayer, int> LayerHandleIds, int OwnerCharacterId)
            ResolvePacketOwnedActiveEffectMotionBlurLayerHandleIds(
                IReadOnlyDictionary<AvatarRenderLayer, int> existingLayerHandleIds,
                int existingOwnerCharacterId,
                int currentOwnerCharacterId)
        {
            bool hasCompleteExistingMap = IsCompletePacketOwnedActiveEffectMotionBlurLayerHandleIdMap(existingLayerHandleIds);
            if (currentOwnerCharacterId <= 0)
            {
                return hasCompleteExistingMap
                    ? (existingLayerHandleIds, existingOwnerCharacterId)
                    : (CreatePacketOwnedActiveEffectMotionBlurLayerHandleIds(), existingOwnerCharacterId);
            }

            bool sameOwner = existingOwnerCharacterId > 0 && existingOwnerCharacterId == currentOwnerCharacterId;
            if (sameOwner && hasCompleteExistingMap)
            {
                return (existingLayerHandleIds, existingOwnerCharacterId);
            }

            return (CreatePacketOwnedActiveEffectMotionBlurLayerHandleIds(), currentOwnerCharacterId);
        }

        internal static IReadOnlyDictionary<AvatarRenderLayer, int> ResolvePacketOwnedActiveEffectMotionBlurLayerHandleIdsForTesting(
            IReadOnlyDictionary<AvatarRenderLayer, int> existingLayerHandleIds,
            int existingOwnerCharacterId,
            int currentOwnerCharacterId,
            out int resolvedOwnerCharacterId)
        {
            (IReadOnlyDictionary<AvatarRenderLayer, int> layerHandleIds, int ownerCharacterId) =
                ResolvePacketOwnedActiveEffectMotionBlurLayerHandleIds(
                    existingLayerHandleIds,
                    existingOwnerCharacterId,
                    currentOwnerCharacterId);
            resolvedOwnerCharacterId = ownerCharacterId;
            return layerHandleIds;
        }

        internal static int NextPacketOwnedActiveEffectMotionBlurStateIdForTesting()
        {
            return NextPacketOwnedActiveEffectMotionBlurStateId();
        }

        internal static int NextPacketOwnedActiveEffectMotionBlurLayerHandleIdForTesting()
        {
            return NextPacketOwnedActiveEffectMotionBlurLayerHandleId();
        }

        internal static (Vector2 Position, bool FacingRight) ResolvePacketOwnedActiveEffectMotionBlurSnapshotOwnerStateForTesting(
            PlayerMovementSyncSnapshot movementSnapshot,
            Vector2 fallbackPosition,
            bool fallbackFacingRight,
