        private static bool TryDecodeQuestAlarmRegistrationSyncPayload(
            byte[] payload,
            out bool? opened,
            out bool? minimized,
            out bool? autoRegisterEnabled,
            out bool clearHiddenAutoTombstones,
            out bool hasQuestRegistrationList,
            out int[] questIds,
            out string error)
        {
            opened = null;
            minimized = null;
            autoRegisterEnabled = null;
            clearHiddenAutoTombstones = false;
            hasQuestRegistrationList = false;
            questIds = Array.Empty<int>();
            error = "Quest-alarm registration-sync payload is missing.";

            if (payload == null || payload.Length == 0)
            {
                return false;
            }

            byte[] normalizedPayload = payload;
            if (TryUnwrapPacketOwnedPayloadForType(
                    payload,
                    LocalUtilityPacketInboxManager.QuestAlarmRegistrationSyncPacketType,
                    out byte[] unwrappedPayload))
            {
                normalizedPayload = unwrappedPayload;
            }

            if (TryDecodeQuestAlarmRegistrationSyncBinaryPayload(
                    normalizedPayload,
                    out opened,
                    out minimized,
                    out autoRegisterEnabled,
                    out clearHiddenAutoTombstones,
                    out hasQuestRegistrationList,
                    out questIds,
                    out error))
            {
                return true;
            }

            bool hasLengthPrefixedPayload = TryResolvePacketOwnedLengthPrefixedPayload(normalizedPayload, out byte[] lengthPrefixedPayload);
            if (hasLengthPrefixedPayload
                && TryDecodeQuestAlarmRegistrationSyncBinaryPayload(
                    lengthPrefixedPayload,
                    out opened,
                    out minimized,
                    out autoRegisterEnabled,
                    out clearHiddenAutoTombstones,
                    out hasQuestRegistrationList,
                    out questIds,
                    out error))
            {
                return true;
            }

            if (!TryDecodePacketOwnedStringPayload(normalizedPayload, out string decodedText)
                && (!hasLengthPrefixedPayload
                    || !TryDecodePacketOwnedStringPayload(lengthPrefixedPayload, out decodedText)))
            {
                error = "Quest-alarm registration-sync payload must decode to a binary sync envelope, MapleString, UTF-8 text, or a JSON text body.";
                return false;
            }

            if (TryDecodeQuestAlarmRegistrationSyncJsonPayload(
                    decodedText,
                    out opened,
                    out minimized,
                    out autoRegisterEnabled,
                    out clearHiddenAutoTombstones,
                    out hasQuestRegistrationList,
                    out questIds,
                    out error))
            {
                return true;
            }

            return TryDecodeQuestAlarmRegistrationSyncTextPayload(
                decodedText,
                out opened,
                out minimized,
                out autoRegisterEnabled,
                out clearHiddenAutoTombstones,
                out hasQuestRegistrationList,
                out questIds,
                out error);
        }

        private static bool TryDecodeQuestAlarmRegistrationSyncBinaryPayload(
            byte[] payload,
            out bool? opened,
            out bool? minimized,
            out bool? autoRegisterEnabled,
            out bool clearHiddenAutoTombstones,
            out bool hasQuestRegistrationList,
            out int[] questIds,
            out string error)
        {
            opened = null;
            minimized = null;
            autoRegisterEnabled = null;
            clearHiddenAutoTombstones = false;
            hasQuestRegistrationList = false;
            questIds = Array.Empty<int>();
            error = null;

            if (payload == null || payload.Length < 2)
            {
                error = "Quest-alarm registration-sync payload must contain flags and a quest count.";
                return false;
            }

            if (TryDecodeQuestAlarmRegistrationSyncCountPayload(
                    payload,
                    out opened,
                    out minimized,
                    out autoRegisterEnabled,
                    out clearHiddenAutoTombstones,
                    out questIds,
                    out error))
            {
                hasQuestRegistrationList = true;
                return true;
            }

            bool decoded = TryDecodeQuestAlarmRegistrationSyncFixedSlotPayload(
                payload,
                out opened,
                out minimized,
                out autoRegisterEnabled,
                out clearHiddenAutoTombstones,
                out questIds,
                out error);
            hasQuestRegistrationList = decoded;
            return decoded;
        }

        private static bool TryDecodeQuestAlarmRegistrationSyncCountPayload(
            byte[] payload,
            out bool? opened,
            out bool? minimized,
            out bool? autoRegisterEnabled,
            out bool clearHiddenAutoTombstones,
            out int[] questIds,
            out string error)
        {
            opened = null;
            minimized = null;
            autoRegisterEnabled = null;
            clearHiddenAutoTombstones = false;
            questIds = Array.Empty<int>();
            error = null;

            using var stream = new MemoryStream(payload, writable: false);
            using var reader = new BinaryReader(stream, Encoding.ASCII, leaveOpen: false);

            byte flags = reader.ReadByte();
            int count = reader.ReadByte();
            if (count > QuestAlarmRegistrationSyncMaxQuestCount)
            {
                error = "Quest-alarm registration-sync payload cannot register more than five quests.";
                return false;
            }

            long remainingBytes = stream.Length - stream.Position;
            int questIdByteWidth;
            if (remainingBytes == count * sizeof(ushort))
            {
                questIdByteWidth = sizeof(ushort);
            }
            else if (remainingBytes == count * sizeof(int))
            {
                questIdByteWidth = sizeof(int);
            }
            else
            {
                error = "Quest-alarm registration-sync payload quest-id list length does not match its count.";
                return false;
            }

            opened = (flags & 0x01) != 0;
            minimized = (flags & 0x02) != 0;
            autoRegisterEnabled = (flags & 0x04) != 0;
            clearHiddenAutoTombstones = (flags & 0x08) != 0;
            questIds = DecodeQuestAlarmRegistrationQuestIds(reader, count, questIdByteWidth);
            return true;
        }

        private static bool TryDecodeQuestAlarmRegistrationSyncFixedSlotPayload(
            byte[] payload,
            out bool? opened,
            out bool? minimized,
            out bool? autoRegisterEnabled,
            out bool clearHiddenAutoTombstones,
            out int[] questIds,
            out string error)
        {
            opened = null;
            minimized = null;
            autoRegisterEnabled = null;
            clearHiddenAutoTombstones = false;
            questIds = Array.Empty<int>();
            error = "Quest-alarm registration-sync payload quest-id list length does not match its count.";

            int expectedUShortLength = sizeof(byte) + (QuestAlarmRegistrationSyncMaxQuestCount * sizeof(ushort));
            int expectedInt32Length = sizeof(byte) + (QuestAlarmRegistrationSyncMaxQuestCount * sizeof(int));
            int questIdByteWidth;
            if (payload == null)
            {
                return false;
            }

            if (payload.Length == expectedUShortLength)
            {
                questIdByteWidth = sizeof(ushort);
            }
            else if (payload.Length == expectedInt32Length)
            {
                questIdByteWidth = sizeof(int);
            }
            else
            {
                return false;
            }

            using var stream = new MemoryStream(payload, writable: false);
            using var reader = new BinaryReader(stream, Encoding.ASCII, leaveOpen: false);

            byte flags = reader.ReadByte();
            opened = (flags & 0x01) != 0;
            minimized = (flags & 0x02) != 0;
            autoRegisterEnabled = (flags & 0x04) != 0;
            clearHiddenAutoTombstones = (flags & 0x08) != 0;
            questIds = DecodeQuestAlarmRegistrationQuestIds(reader, QuestAlarmRegistrationSyncMaxQuestCount, questIdByteWidth);
            error = null;
            return true;
        }

        private static int[] DecodeQuestAlarmRegistrationQuestIds(BinaryReader reader, int count, int questIdByteWidth)
        {
            List<int> decodedQuestIds = new(Math.Max(0, count));
            for (int i = 0; i < count; i++)
            {
                int questId = questIdByteWidth == sizeof(int)
                    ? reader.ReadInt32()
                    : reader.ReadUInt16();
                if (questId > 0 && !decodedQuestIds.Contains(questId))
                {
                    decodedQuestIds.Add(questId);
                }
            }

            return decodedQuestIds.ToArray();
        }

        private static bool TryDecodeQuestAlarmRegistrationSyncJsonPayload(
            string payloadText,
            out bool? opened,
            out bool? minimized,
            out bool? autoRegisterEnabled,
            out bool clearHiddenAutoTombstones,
            out bool hasQuestRegistrationList,
            out int[] questIds,
            out string error)
        {
            opened = null;
            minimized = null;
            autoRegisterEnabled = null;
            clearHiddenAutoTombstones = false;
            hasQuestRegistrationList = false;
            questIds = Array.Empty<int>();
            error = "Quest-alarm registration-sync JSON payload did not contain any usable quest registration rows.";
            if (string.IsNullOrWhiteSpace(payloadText))
            {
                return false;
            }

            string trimmed = payloadText.Trim();
            if (!trimmed.StartsWith("{", StringComparison.Ordinal)
                && !trimmed.StartsWith("[", StringComparison.Ordinal))
            {
                return false;
            }

            try
            {
                using JsonDocument document = JsonDocument.Parse(trimmed);
                JsonElement root = document.RootElement;
                JsonElement working = root;
                if (root.ValueKind == JsonValueKind.Object
                    && (TryGetJsonObjectProperty(root, out JsonElement nestedObject, "questAlarm", "cUIQuestAlarm", "payload", "data", "result", "body")
                        || TryGetJsonNestedObjectProperty(
                            root,
                            out nestedObject,
                            new[] { "questAlarm", "cUIQuestAlarm", "payload", "data", "result", "body" },
                            new[] { "questAlarm", "cUIQuestAlarm", "payload", "data", "result", "body" })))
                {
                    working = nestedObject;
                }

                if (working.ValueKind == JsonValueKind.Object)
                {
                    if (TryGetJsonBoolean(working, "opened", out bool parsedOpened)
                        || TryGetJsonBoolean(working, "open", out parsedOpened)
                        || TryGetJsonBoolean(working, "isOpened", out parsedOpened)
                        || TryGetJsonBoolean(working, "QuestAlarm_opened", out parsedOpened))
                    {
                        opened = parsedOpened;
                    }

                    if (TryGetJsonBoolean(working, "minimized", out bool parsedMinimized)
                        || TryGetJsonBoolean(working, "minimize", out parsedMinimized)
                        || TryGetJsonBoolean(working, "isMinimized", out parsedMinimized))
                    {
                        minimized = parsedMinimized;
                    }

                    if (TryGetJsonBoolean(working, "autoRegisterEnabled", out bool parsedAutoRegisterEnabled)
                        || TryGetJsonBoolean(working, "autoRegister", out parsedAutoRegisterEnabled)
                        || TryGetJsonBoolean(working, "auto", out parsedAutoRegisterEnabled)
                        || TryGetJsonBoolean(working, "QuestAlarm_autoregister", out parsedAutoRegisterEnabled))
                    {
                        autoRegisterEnabled = parsedAutoRegisterEnabled;
                    }

                    if (TryGetJsonBoolean(working, "clearHiddenAutoTombstones", out bool parsedClearHiddenAutoTombstones)
                        || TryGetJsonBoolean(working, "clearHidden", out parsedClearHiddenAutoTombstones)
                        || TryGetJsonBoolean(working, "clearDeleted", out parsedClearHiddenAutoTombstones))
                    {
                        clearHiddenAutoTombstones = parsedClearHiddenAutoTombstones;
                    }
                    else if (TryGetJsonBoolean(working, "replace", out bool parsedReplace))
                    {
                        clearHiddenAutoTombstones = parsedReplace;
                    }

                    if (TryGetJsonArrayProperty(
                            working,
                            out JsonElement questArray,
                            "questIds",
                            "registeredQuestIds",
                            "registered",
                            "entries",
                            "rows",
                            "quests")
                        || TryGetJsonNestedArrayProperty(
                            working,
                            out questArray,
                            new[] { "registration", "sync", "tracker", "state" },
                            new[] { "questIds", "registeredQuestIds", "registered", "entries", "rows", "quests" }))
                    {
                        hasQuestRegistrationList = true;
                        questIds = DecodeQuestAlarmRegistrationQuestIdsFromJsonArray(questArray);
                    }
                    else if (TryDecodeQuestAlarmRegistrationQuestIdsFromClientOptionJsonObject(working, out int[] clientOptionQuestIds))
                    {
                        hasQuestRegistrationList = true;
                        questIds = clientOptionQuestIds;
                    }
                }
                else if (working.ValueKind == JsonValueKind.Array)
                {
                    hasQuestRegistrationList = true;
                    questIds = DecodeQuestAlarmRegistrationQuestIdsFromJsonArray(working);
                }

                bool hasResetDirective = false;
                if (working.ValueKind == JsonValueKind.Object
                    && (TryGetJsonBoolean(working, "clear", out bool parsedClear)
                        || TryGetJsonBoolean(working, "reset", out parsedClear)))
                {
                    hasResetDirective = parsedClear;
                }

                if (hasResetDirective)
                {
                    opened = false;
                    minimized = true;
                    autoRegisterEnabled = false;
                    clearHiddenAutoTombstones = true;
                    hasQuestRegistrationList = true;
                    questIds = Array.Empty<int>();
                    error = null;
                    return true;
                }

                if (hasQuestRegistrationList)
                {
                    error = null;
                    return true;
                }

                if (working.ValueKind == JsonValueKind.Object
                    && (TryGetJsonBoolean(working, "opened", out _)
                        || TryGetJsonBoolean(working, "open", out _)
                        || TryGetJsonBoolean(working, "minimized", out _)
                        || TryGetJsonBoolean(working, "minimize", out _)
                        || TryGetJsonBoolean(working, "autoRegisterEnabled", out _)
                        || TryGetJsonBoolean(working, "autoRegister", out _)
                        || TryGetJsonBoolean(working, "auto", out _)
                        || TryGetJsonBoolean(working, "QuestAlarm_opened", out _)
                        || TryGetJsonBoolean(working, "QuestAlarm_autoregister", out _)))
                {
                    error = null;
                    return true;
                }

                return false;
            }
            catch (Exception ex)
            {
                error = $"Quest-alarm registration-sync JSON payload decode failed: {ex.Message}";
                return false;
            }
        }

        private static int[] DecodeQuestAlarmRegistrationQuestIdsFromJsonArray(JsonElement questArray)
        {
            List<int> questIds = new();
            if (questArray.ValueKind != JsonValueKind.Array)
            {
                return Array.Empty<int>();
            }

            foreach (JsonElement element in questArray.EnumerateArray())
            {
                if (questIds.Count >= QuestAlarmRegistrationSyncMaxQuestCount)
                {
                    break;
                }

                if (TryResolveQuestAlarmRegistrationQuestIdFromJsonElement(element, out int questId)
                    && questId > 0
                    && !questIds.Contains(questId))
                {
                    questIds.Add(questId);
                }
            }

            return questIds.ToArray();
        }

        private static bool TryResolveQuestAlarmRegistrationQuestIdFromJsonElement(JsonElement element, out int questId)
        {
            questId = 0;
            switch (element.ValueKind)
            {
                case JsonValueKind.Number:
                    return element.TryGetInt32(out questId) && questId > 0;
                case JsonValueKind.String:
                    return int.TryParse(element.GetString(), NumberStyles.Integer, CultureInfo.InvariantCulture, out questId) && questId > 0;
                case JsonValueKind.Object:
                    return TryGetJsonInt32Property(
                        element,
                        out questId,
                        "questId",
                        "id",
                        "q",
                        "quest");
                default:
                    return false;
            }
        }

        private static bool TryDecodeQuestAlarmRegistrationQuestIdsFromClientOptionJsonObject(
            JsonElement element,
            out int[] questIds)
        {
            questIds = Array.Empty<int>();
            if (element.ValueKind != JsonValueKind.Object)
            {
                return false;
            }

            SortedDictionary<int, int> slotQuestIds = new();
            foreach (JsonProperty property in element.EnumerateObject())
            {
                if (!TryResolveQuestAlarmRegistrationClientOptionSlotIndex(property.Name, out int slotIndex))
                {
                    continue;
                }

                if (slotIndex < 0 || slotIndex >= QuestAlarmRegistrationSyncMaxQuestCount)
                {
                    continue;
                }

                if (TryResolveQuestAlarmRegistrationQuestIdFromJsonElement(property.Value, out int questId) && questId > 0)
                {
                    slotQuestIds[slotIndex] = questId;
                }
            }

            if (slotQuestIds.Count == 0)
            {
                return false;
            }

            List<int> decodedQuestIds = new(QuestAlarmRegistrationSyncMaxQuestCount);
            foreach (int questId in slotQuestIds.Values)
            {
                AddQuestAlarmRegistrationSyncQuestId(decodedQuestIds, questId);
            }

            questIds = decodedQuestIds.ToArray();
            return true;
        }

        private static bool TryDecodeQuestAlarmRegistrationSyncTextPayload(
            string payloadText,
            out bool? opened,
            out bool? minimized,
            out bool? autoRegisterEnabled,
            out bool clearHiddenAutoTombstones,
            out bool hasQuestRegistrationList,
            out int[] questIds,
            out string error)
        {
            opened = null;
            minimized = null;
            autoRegisterEnabled = null;
            clearHiddenAutoTombstones = false;
            hasQuestRegistrationList = false;
            questIds = Array.Empty<int>();
            error = "Quest-alarm registration-sync payload did not contain any usable quest registration rows.";
            if (string.IsNullOrWhiteSpace(payloadText))
            {
                return false;
            }

            string normalizedText = payloadText.Trim();
            if (string.Equals(normalizedText, "clear", StringComparison.OrdinalIgnoreCase)
                || string.Equals(normalizedText, "reset", StringComparison.OrdinalIgnoreCase))
            {
                opened = false;
                minimized = true;
                autoRegisterEnabled = false;
                clearHiddenAutoTombstones = true;
                hasQuestRegistrationList = true;
                error = null;
                return true;
            }

            List<int> parsedQuestIds = new();
            bool sawDirective = false;
            bool sawQuestRegistrationListDirective = false;
            string[] segments = normalizedText.Split(
                new[] { "\r\n", "\n", ",", ";" },
                StringSplitOptions.RemoveEmptyEntries | StringSplitOptions.TrimEntries);
            for (int i = 0; i < segments.Length; i++)
            {
                string segment = segments[i];
                if (string.IsNullOrWhiteSpace(segment))
                {
                    continue;
                }

                if (TryParseQuestAlarmRegistrationSyncFlagDirective(segment, "open", out bool parsedOpen)
                    || TryParseQuestAlarmRegistrationSyncFlagDirective(segment, "opened", out parsedOpen)
                    || TryParseQuestAlarmRegistrationSyncFlagDirective(segment, "QuestAlarm_opened", out parsedOpen))
                {
                    opened = parsedOpen;
                    sawDirective = true;
                    continue;
                }

                if (TryParseQuestAlarmRegistrationSyncFlagDirective(segment, "min", out bool parsedMinimized)
                    || TryParseQuestAlarmRegistrationSyncFlagDirective(segment, "minimize", out parsedMinimized)
                    || TryParseQuestAlarmRegistrationSyncFlagDirective(segment, "minimized", out parsedMinimized))
                {
                    minimized = parsedMinimized;
                    sawDirective = true;
                    continue;
                }

                if (TryParseQuestAlarmRegistrationSyncFlagDirective(segment, "auto", out bool parsedAuto)
                    || TryParseQuestAlarmRegistrationSyncFlagDirective(segment, "autoregister", out parsedAuto)
                    || TryParseQuestAlarmRegistrationSyncFlagDirective(segment, "QuestAlarm_autoregister", out parsedAuto))
                {
                    autoRegisterEnabled = parsedAuto;
                    sawDirective = true;
                    continue;
                }

                if (TryParseQuestAlarmRegistrationSyncFlagDirective(segment, "clearhidden", out bool parsedClearHidden)
                    || TryParseQuestAlarmRegistrationSyncFlagDirective(segment, "clear", out parsedClearHidden)
                    || TryParseQuestAlarmRegistrationSyncFlagDirective(segment, "replace", out parsedClearHidden))
                {
                    clearHiddenAutoTombstones = parsedClearHidden;
                    sawDirective = true;
                    continue;
                }

                if (TryParseQuestAlarmRegistrationSyncListDirective(segment, parsedQuestIds))
                {
                    sawQuestRegistrationListDirective = true;
                    continue;
                }

                if (TryParseQuestAlarmRegistrationSyncClientOptionDirective(segment, parsedQuestIds, out bool isClientQuestSlotDirective))
                {
                    sawQuestRegistrationListDirective |= isClientQuestSlotDirective;
                    sawDirective |= !isClientQuestSlotDirective;
                    continue;
                }

                if (int.TryParse(segment, NumberStyles.Integer, CultureInfo.InvariantCulture, out int questId)
                    && questId > 0
                    && parsedQuestIds.Count < QuestAlarmRegistrationSyncMaxQuestCount)
                {
                    AddQuestAlarmRegistrationSyncQuestId(parsedQuestIds, questId);
                    continue;
                }

                string questToken = segment;
                int equalsIndex = segment.IndexOf('=');
                if (equalsIndex >= 0 && equalsIndex < segment.Length - 1)
                {
                    questToken = segment[(equalsIndex + 1)..].Trim();
                }

                if (int.TryParse(questToken, NumberStyles.Integer, CultureInfo.InvariantCulture, out questId)
                    && questId > 0
                    && parsedQuestIds.Count < QuestAlarmRegistrationSyncMaxQuestCount)
                {
                    AddQuestAlarmRegistrationSyncQuestId(parsedQuestIds, questId);
                }
            }

            questIds = parsedQuestIds.ToArray();
            hasQuestRegistrationList = sawQuestRegistrationListDirective || questIds.Length > 0;
            if (hasQuestRegistrationList || sawDirective)
            {
                error = null;
                return true;
            }

            return false;
        }

        private static bool TryParseQuestAlarmRegistrationSyncClientOptionDirective(
            string text,
            List<int> destination,
            out bool isQuestSlotDirective)
        {
            isQuestSlotDirective = false;
            if (string.IsNullOrWhiteSpace(text))
            {
                return false;
            }

            int separatorIndex = text.IndexOf('=');
            if (separatorIndex <= 0)
            {
                separatorIndex = text.IndexOf(':');
            }

            if (separatorIndex <= 0)
            {
                return false;
            }

            string key = text[..separatorIndex].Trim();
            if (string.Equals(key, "QuestAlarm_cnt", StringComparison.OrdinalIgnoreCase))
            {
                isQuestSlotDirective = true;
                return true;
            }

            if (!TryResolveQuestAlarmRegistrationClientOptionSlotIndex(key, out int slotIndex)
                || slotIndex < 0
                || slotIndex >= QuestAlarmRegistrationSyncMaxQuestCount)
            {
                return false;
            }

            isQuestSlotDirective = true;
            string value = text[(separatorIndex + 1)..].Trim();
            if (int.TryParse(value, NumberStyles.Integer, CultureInfo.InvariantCulture, out int questId) && questId > 0)
            {
                AddQuestAlarmRegistrationSyncQuestId(destination, questId);
            }

            return true;
        }

        private static bool TryResolveQuestAlarmRegistrationClientOptionSlotIndex(string key, out int slotIndex)
        {
            slotIndex = -1;
            const string prefix = "QuestAlarm_";
            return !string.IsNullOrWhiteSpace(key)
                && key.StartsWith(prefix, StringComparison.OrdinalIgnoreCase)
                && int.TryParse(key[prefix.Length..].Trim(), NumberStyles.Integer, CultureInfo.InvariantCulture, out slotIndex);
        }

        private static bool TryParseQuestAlarmRegistrationSyncListDirective(string text, List<int> destination)
        {
            if (string.IsNullOrWhiteSpace(text))
            {
                return false;
            }

            int separatorIndex = text.IndexOf('=');
            if (separatorIndex <= 0)
            {
                separatorIndex = text.IndexOf(':');
            }

            if (separatorIndex <= 0)
            {
                return false;
            }

            string candidateKey = text[..separatorIndex].Trim();
            if (!string.Equals(candidateKey, "questIds", StringComparison.OrdinalIgnoreCase)
                && !string.Equals(candidateKey, "registeredQuestIds", StringComparison.OrdinalIgnoreCase)
                && !string.Equals(candidateKey, "registered", StringComparison.OrdinalIgnoreCase)
                && !string.Equals(candidateKey, "entries", StringComparison.OrdinalIgnoreCase)
                && !string.Equals(candidateKey, "rows", StringComparison.OrdinalIgnoreCase)
                && !string.Equals(candidateKey, "quests", StringComparison.OrdinalIgnoreCase))
            {
                return false;
            }

            string value = text[(separatorIndex + 1)..].Trim();
            if (value.Length == 0)
            {
                return true;
            }

            string[] tokens = value.Split(
                QuestAlarmRegistrationSyncListTokenSeparators,
                StringSplitOptions.RemoveEmptyEntries | StringSplitOptions.TrimEntries);
            bool parsedAnyQuestId = false;
            for (int i = 0; i < tokens.Length && destination.Count < QuestAlarmRegistrationSyncMaxQuestCount; i++)
            {
                if (int.TryParse(tokens[i], NumberStyles.Integer, CultureInfo.InvariantCulture, out int questId)
                    && questId > 0)
                {
                    parsedAnyQuestId = true;
                    AddQuestAlarmRegistrationSyncQuestId(destination, questId);
                }
            }

            return parsedAnyQuestId;
        }

        private static void AddQuestAlarmRegistrationSyncQuestId(List<int> destination, int questId)
        {
            if (destination == null
                || questId <= 0
                || destination.Count >= QuestAlarmRegistrationSyncMaxQuestCount
                || destination.Contains(questId))
            {
                return;
            }

            destination.Add(questId);
        }

        private static bool TryParseQuestAlarmRegistrationSyncFlagDirective(string text, string key, out bool value)
        {
            value = false;
            if (string.IsNullOrWhiteSpace(text) || string.IsNullOrWhiteSpace(key))
            {
                return false;
            }

            string normalized = text.Trim();
            int separatorIndex = normalized.IndexOf('=');
            if (separatorIndex <= 0)
            {
                separatorIndex = normalized.IndexOf(':');
            }

            if (separatorIndex <= 0)
            {
                return false;
            }

            string candidateKey = normalized[..separatorIndex].Trim();
            if (!string.Equals(candidateKey, key, StringComparison.OrdinalIgnoreCase))
            {
                return false;
            }

            string candidateValue = normalized[(separatorIndex + 1)..].Trim();
            if (string.Equals(candidateValue, "1", StringComparison.OrdinalIgnoreCase)
                || string.Equals(candidateValue, "true", StringComparison.OrdinalIgnoreCase)
                || string.Equals(candidateValue, "yes", StringComparison.OrdinalIgnoreCase)
                || string.Equals(candidateValue, "on", StringComparison.OrdinalIgnoreCase))
            {
                value = true;
                return true;
            }

            if (string.Equals(candidateValue, "0", StringComparison.OrdinalIgnoreCase)
                || string.Equals(candidateValue, "false", StringComparison.OrdinalIgnoreCase)
                || string.Equals(candidateValue, "no", StringComparison.OrdinalIgnoreCase)
                || string.Equals(candidateValue, "off", StringComparison.OrdinalIgnoreCase))
            {
                value = false;
                return true;
            }

            return false;
        }

        private bool TryApplyPacketOwnedMakerResultPayload(byte[] payload, out string message)
        {
            message = null;
            if (!PacketOwnedItemMakerResultRuntime.TryDecode(payload, out PacketOwnedItemMakerResult packetResult, out string decodeError))
            {
                message = decodeError ?? "Maker-result payload could not be decoded.";
                return false;
            }

            StampPacketOwnedUtilityRequestState();
            EmitPacketOwnedMakerResultFeedback(packetResult);

            if (uiWindowManager?.GetWindow(MapSimulatorWindowNames.ItemMaker) is not ItemMakerUI itemMakerWindow)
            {
                _pendingPacketOwnedItemMakerResults.Add(packetResult);
                message = $"Stored packet-owned maker result for the next Item Maker launch. Pending results: {_pendingPacketOwnedItemMakerResults.Count}.";
                return true;
            }

            bool applied = itemMakerWindow.TryApplyPacketOwnedResult(packetResult, out message);
            if (applied)
            {
                _pendingPacketOwnedItemMakerRequest = null;
            }

            return applied;
        }

        private void EmitPacketOwnedMakerResultFeedback(PacketOwnedItemMakerResult packetResult)
        {
            IReadOnlyList<string> feedbackLines = PacketOwnedItemMakerResultRuntime.BuildFeedbackLines(packetResult);
            if (feedbackLines == null || feedbackLines.Count == 0)
            {
                return;
            }

            for (int i = 0; i < feedbackLines.Count; i++)
            {
                string line = feedbackLines[i];
                if (!string.IsNullOrWhiteSpace(line))
                {
                    _chat?.AddClientChatMessage(line, currTickCount, 7);
                }
            }
        }

        private bool TryApplyPacketOwnedSkillLearnItemResultPayload(byte[] payload, out string message)
        {
            message = null;
            if (!TryDecodePacketOwnedSkillLearnItemResult(payload, out PacketOwnedSkillLearnItemResult result, out string decodeError))
            {
                message = decodeError ?? "Skill-learn-item payload could not be decoded.";
                return false;
            }

            StampPacketOwnedUtilityRequestState();
            // Skill-learn result payloads expose the post-branch bExclRequestSent flag.
            // Mirror shared StartQuest follow-up clear only when that flag returns cleared.
            bool consumedQuestStartLatch =
                ShouldConsumePacketOwnedQuestResultStartQuestSharedExclusiveResetFromExternalFlag(result.OnExclusiveRequest)
                && TryConsumePacketOwnedQuestResultStartQuestLatchFromSharedExclusiveReset();

            int localCharacterId = _playerManager?.Player?.Build?.Id ?? 0;
            bool isLocalOwner = result.CharacterId > 0 && result.CharacterId == localCharacterId;
            string ownerName = isLocalOwner
                ? ResolvePacketOwnedLocalSkillLearnOwnerName()
                : ResolvePacketOwnedRemoteCharacterName(result.CharacterId);
            if (string.IsNullOrWhiteSpace(ownerName))
            {
                ownerName = result.CharacterId > 0
                    ? $"Character {result.CharacterId.ToString(CultureInfo.InvariantCulture)}"
                    : "Unknown character";
            }

            string itemCategoryLabel = result.IsMasteryBook ? "mastery book" : "skill book";
            string itemName = ResolvePacketOwnedSkillLearnItemName(result.ItemId, itemCategoryLabel);
            int? targetMasterLevel = null;

            if (result.Used)
            {
                if (isLocalOwner)
                {
                    TryConsumePacketOwnedSkillLearnItem(result.ItemId);

                    if (result.Succeeded
                        && result.IsMasteryBook
                        && TryResolvePacketOwnedSkillLearnMasterLevel(result.ItemId, result.SkillId, out int resolvedMasterLevel))
                    {
                        targetMasterLevel = resolvedMasterLevel;
                        ApplyQuestSkillMasterLevelReward(result.SkillId, resolvedMasterLevel);
                    }

                    uiWindowManager?.ProductionEnhancementAnimationDisplayer?.PlaySkillBookResult(result.Succeeded, currTickCount);
                }
                else if (!TryRegisterPacketOwnedRemoteSkillBookResultAvatarEffect(
                             result.CharacterId,
                             result.Succeeded,
                             currTickCount,
                             out string remoteEffectMessage)
                         && !string.IsNullOrWhiteSpace(remoteEffectMessage))
                {
                    ShowUtilityFeedbackMessage(remoteEffectMessage);
                }

                TryPlaySharedProductionEnhancementSound(
                    result.Succeeded ? PacketOwnedSkillLearnSuccessSoundStringPoolId : PacketOwnedSkillLearnFailureSoundStringPoolId,
                    result.Succeeded ? PacketOwnedSkillLearnSuccessSoundFallback : PacketOwnedSkillLearnFailureSoundFallback);
            }

            string chatLine = BuildPacketOwnedSkillLearnChatLine(
                ownerName,
                itemName,
                itemCategoryLabel,
                result,
                targetMasterLevel);
            _chat?.AddClientChatMessage(chatLine, currTickCount, 12);
            ShowUtilityFeedbackMessage(chatLine);

            string ownershipLabel = isLocalOwner ? "local" : "remote";
            string outcomeLabel = !result.Used
                ? "rejected"
                : result.Succeeded
                    ? "success"
                    : "failure";
            message = $"Applied packet-owned skill-learn-item {outcomeLabel} for {ownershipLabel} owner {ownerName} ({result.CharacterId}).";
            if (consumedQuestStartLatch)
            {
                message = $"{message} The skill-learn owner's cleared exclusive-request flag also consumed the packet-owned StartQuest follow-up latch.";
            }

            return true;
        }

        private bool TryApplyPacketOwnedMakerHiddenUnlockPayload(byte[] payload, out string message)
        {
            message = null;
            if (!PacketOwnedItemMakerHiddenRecipeUnlockRuntime.TryDecode(payload, out PacketOwnedItemMakerHiddenRecipeUnlock packetUnlock, out string decodeError))
            {
                message = decodeError ?? "Maker-hidden-unlock payload could not be decoded.";
                return false;
            }

            if (uiWindowManager?.GetWindow(MapSimulatorWindowNames.ItemMaker) is not ItemMakerUI itemMakerWindow)
            {
                int pendingCount = StorePendingPacketOwnedItemMakerHiddenUnlocks(packetUnlock);
                message = pendingCount > 0
                    ? $"Stored {pendingCount} packet-owned maker hidden unlock row(s) for the next Item Maker launch."
                    : "Maker-hidden-unlock packet arrived without any hidden unlock rows to store.";
                StampPacketOwnedUtilityRequestState();
                return true;
            }

            if (!itemMakerWindow.TryResolvePacketOwnedHiddenUnlockEntries(packetUnlock, out IReadOnlyCollection<ItemMakerRecipeProgressionEntry> unlockedEntries, out message))
            {
                return false;
            }

            if (unlockedEntries.Count > 0)
            {
                ApplyResolvedItemMakerHiddenUnlockEntries(itemMakerWindow, unlockedEntries, message);
            }
            else
            {
                itemMakerWindow.ApplyPacketOwnedResult(message, refreshSlotState: false);
            }

            StampPacketOwnedUtilityRequestState();
            return true;
        }

        private bool TryApplyPacketOwnedMakerSessionPayload(byte[] payload, out string message)
        {
            message = null;
            if (!PacketOwnedItemMakerSessionRuntime.TryDecode(payload, out PacketOwnedItemMakerSession packetSession, out string decodeError))
            {
                message = decodeError ?? "Maker-session payload could not be decoded.";
                return false;
            }

            _packetOwnedItemMakerSessionState = PacketOwnedItemMakerSessionStateRuntime.Apply(
                _packetOwnedItemMakerSessionState,
                packetSession);
            if (PacketOwnedItemMakerSessionStateRuntime.ShouldClearPendingRequest(
                    _packetOwnedItemMakerSessionState,
                    _pendingPacketOwnedItemMakerRequest))
            {
                _pendingPacketOwnedItemMakerRequest = null;
            }

            if (uiWindowManager?.GetWindow(MapSimulatorWindowNames.ItemMaker) is not ItemMakerUI itemMakerWindow)
            {
                message = DescribeStoredItemMakerSessionState(_packetOwnedItemMakerSessionState);
                StampPacketOwnedUtilityRequestState();
                return true;
            }

            if (!itemMakerWindow.TryApplyPacketOwnedSessionState(_packetOwnedItemMakerSessionState, out message))
            {
                return false;
            }

            StampPacketOwnedUtilityRequestState();
            return true;
        }

        private void ConfigureItemMakerWindow(ItemMakerUI itemMakerWindow)
        {
            if (itemMakerWindow == null)
            {
                return;
            }

            itemMakerWindow.PacketOwnedRequestStaged -= CapturePendingPacketOwnedItemMakerRequest;
            itemMakerWindow.PacketOwnedRequestStaged += CapturePendingPacketOwnedItemMakerRequest;

            itemMakerWindow.SetCraftingState(
                _playerManager?.Player?.Level ?? 1,
                _playerManager?.Player?.Build?.TraitCraft ?? 0,
                _playerManager?.Player?.Build?.Job ?? 0,
                GetActiveItemMakerProgression(),
                HasItemMakerRequiredEquip,
                MatchesItemMakerQuestRequirement);

            // Reapply even "empty" session updates so a clear/local-only packet received while the
            // window was hidden can still wipe stale authoritative owner state on the next launch.
            itemMakerWindow.TryApplyPacketOwnedSessionState(_packetOwnedItemMakerSessionState, out _);

            itemMakerWindow.RestorePendingPacketOwnedRequest(_pendingPacketOwnedItemMakerRequest);
            TryApplyStoredPacketOwnedItemMakerResults(itemMakerWindow, out _);
            TryApplyStoredPacketOwnedItemMakerHiddenUnlocks(itemMakerWindow, out _);
        }

        private void CapturePendingPacketOwnedItemMakerRequest(PacketOwnedItemMakerPendingRequest pendingRequest)
        {
            _pendingPacketOwnedItemMakerRequest = pendingRequest;
        }

        private static bool HasStoredItemMakerSessionState(PacketOwnedItemMakerSessionState sessionState)
        {
            return sessionState != null
                && (sessionState.ServerOwnsCraftExecution
                    || sessionState.HasAuthoritativeDisassemblyTargets
                    || sessionState.HasAuthoritativeHiddenRecipeList);
        }

        private static string DescribeStoredItemMakerSessionState(PacketOwnedItemMakerSessionState sessionState)
        {
            if (!HasStoredItemMakerSessionState(sessionState))
            {
                return "Stored a maker-session clear or local-only update for the next Item Maker launch.";
            }

            List<string> parts = new();
            parts.Add(sessionState.ServerOwnsCraftExecution
                ? "packet-owned craft execution enabled"
                : "local craft execution retained");

            if (sessionState.HasAuthoritativeDisassemblyTargets)
            {
                parts.Add($"authoritative disassembly targets {sessionState.DisassemblyTargets?.Count ?? 0}");
            }

            if (sessionState.HasAuthoritativeHiddenRecipeList)
            {
                parts.Add($"authoritative hidden list {sessionState.HiddenRecipeEntries?.Count ?? 0} row(s)");
            }

            return $"Stored maker session for the next Item Maker launch: {string.Join("; ", parts)}.";
        }

        private int StorePendingPacketOwnedItemMakerHiddenUnlocks(PacketOwnedItemMakerHiddenRecipeUnlock packetUnlock)
        {
            return PacketOwnedItemMakerHiddenRecipeUnlockRuntime.MergePendingEntries(
                _pendingPacketOwnedItemMakerHiddenUnlocks,
                packetUnlock);
        }

        private bool TryApplyStoredPacketOwnedItemMakerResults(ItemMakerUI itemMakerWindow, out string message)
        {
            message = null;
            if (itemMakerWindow == null || _pendingPacketOwnedItemMakerResults.Count == 0)
            {
                return false;
            }

            for (int i = 0; i < _pendingPacketOwnedItemMakerResults.Count; i++)
            {
                PacketOwnedItemMakerResult packetResult = _pendingPacketOwnedItemMakerResults[i];
                if (!itemMakerWindow.TryApplyPacketOwnedResult(packetResult, out message))
                {
                    if (i > 0)
                    {
                        _pendingPacketOwnedItemMakerResults.RemoveRange(0, i);
                    }

                    return false;
                }
            }

            _pendingPacketOwnedItemMakerResults.Clear();
            _pendingPacketOwnedItemMakerRequest = null;
            return true;
        }

        private bool TryApplyStoredPacketOwnedItemMakerHiddenUnlocks(ItemMakerUI itemMakerWindow, out string message)
        {
            message = null;
            if (itemMakerWindow == null || _pendingPacketOwnedItemMakerHiddenUnlocks.Count == 0)
            {
                return false;
            }

            PacketOwnedItemMakerHiddenRecipeUnlock pendingUnlock =
                PacketOwnedItemMakerHiddenRecipeUnlockRuntime.CreateReplayPayload(_pendingPacketOwnedItemMakerHiddenUnlocks);

            if (!itemMakerWindow.TryResolvePacketOwnedHiddenUnlockEntries(
                    pendingUnlock,
                    out IReadOnlyCollection<ItemMakerRecipeProgressionEntry> unlockedEntries,
                    out message))
            {
                return false;
            }

            _pendingPacketOwnedItemMakerHiddenUnlocks.Clear();
            if (unlockedEntries.Count > 0)
            {
                ApplyResolvedItemMakerHiddenUnlockEntries(itemMakerWindow, unlockedEntries, message);
            }
            else
            {
                itemMakerWindow.ApplyPacketOwnedResult(message, refreshSlotState: false);
            }

            return true;
        }

        private void ApplyResolvedItemMakerHiddenUnlockEntries(
            ItemMakerUI itemMakerWindow,
            IReadOnlyCollection<ItemMakerRecipeProgressionEntry> unlockedEntries,
            string message)
        {
            if (itemMakerWindow == null || unlockedEntries == null || unlockedEntries.Count == 0)
            {
                return;
            }

            CharacterBuild build = GetActiveItemMakerCharacterBuild();
            ItemMakerProgressionSnapshot updated = _itemMakerProgressionStore.RecordUnlockedHiddenRecipes(build, unlockedEntries);
            itemMakerWindow.UpdateProgression(updated, message);
        }

        private static bool TryDecodePacketOwnedSkillLearnItemResult(
            byte[] payload,
            out PacketOwnedSkillLearnItemResult result,
            out string error)
        {
            result = default;
            error = null;

            if (payload == null || payload.Length < 16)
            {
                error = "Skill-learn-item payload must include the exclusive-request flag, owner id, item metadata, and result bytes.";
                return false;
            }

            using var stream = new MemoryStream(payload, writable: false);
            using var reader = new BinaryReader(stream, Encoding.Default, leaveOpen: false);
            result = new PacketOwnedSkillLearnItemResult(
                OnExclusiveRequest: reader.ReadByte() != 0,
                CharacterId: reader.ReadInt32(),
                IsMasteryBook: reader.ReadByte() != 0,
                ItemId: reader.ReadInt32(),
                SkillId: reader.ReadInt32(),
                Used: reader.ReadByte() != 0,
                Succeeded: reader.ReadByte() != 0);
            return true;
        }

        private string ResolvePacketOwnedLocalSkillLearnOwnerName()
        {
            string playerName = _playerManager?.Player?.Name;
            if (!string.IsNullOrWhiteSpace(playerName))
            {
                return playerName;
            }

            string buildName = _playerManager?.Player?.Build?.Name;
            return string.IsNullOrWhiteSpace(buildName) ? "You" : buildName;
        }

        private string ResolvePacketOwnedSkillLearnItemName(int itemId, string fallbackCategoryLabel)
        {
            if (itemId > 0
                && InventoryItemMetadataResolver.TryResolveItemName(itemId, out string itemName)
                && !string.IsNullOrWhiteSpace(itemName))
            {
                return itemName;
            }

            return string.IsNullOrWhiteSpace(fallbackCategoryLabel)
                ? $"item #{itemId.ToString(CultureInfo.InvariantCulture)}"
                : fallbackCategoryLabel;
        }

        private void TryConsumePacketOwnedSkillLearnItem(int itemId)
        {
            if (itemId <= 0)
            {
                return;
            }

            InventoryType inventoryType = InventoryItemMetadataResolver.ResolveInventoryType(itemId);
            if (inventoryType == InventoryType.NONE)
            {
                return;
            }

            TryConsumeInventoryWindowItem(itemId, 1);
        }

        private static bool TryResolvePacketOwnedSkillLearnMasterLevel(int itemId, int skillId, out int masterLevel)
        {
            masterLevel = 0;
            if (!InventoryItemMetadataResolver.TryResolveSkillBookUseMetadata(itemId, out SkillBookUseMetadata metadata)
                || !metadata.IsValid)
            {
                return false;
            }

            if (skillId > 0 && metadata.SkillIds.Count > 0 && !metadata.SkillIds.Contains(skillId))
            {
                return false;
            }

            masterLevel = metadata.MasterLevel;
            return masterLevel > 0;
        }

        private string BuildPacketOwnedSkillLearnChatLine(
            string ownerName,
            string itemName,
            string itemCategoryLabel,
            PacketOwnedSkillLearnItemResult result,
            int? targetMasterLevel)
        {
            string stringPoolItemLabel = ResolvePacketOwnedSkillLearnItemLabel(result.IsMasteryBook, itemCategoryLabel);
            if (!result.Used)
            {
                return FormatPacketOwnedSkillLearnNotice(
                    PacketOwnedSkillLearnCannotUseStringPoolId,
                    "You cannot use {0}.",
                    stringPoolItemLabel);
            }

            if (result.Succeeded)
            {
                return MapleStoryStringPool.GetOrFallback(
                    result.IsMasteryBook
                        ? PacketOwnedSkillLearnMasterySuccessNoticeStringPoolId
                        : PacketOwnedSkillLearnSkillSuccessNoticeStringPoolId,
                    result.IsMasteryBook
                        ? "The Book of Mastery glows brightly, and the current skills have gone through an upgrade."
                        : "The Skill Book glows brightly, and new skills have now been added.");
            }

            return FormatPacketOwnedSkillLearnNotice(
                PacketOwnedSkillLearnFailureNoticeStringPoolId,
                "Despite using {0}, the effect was nowhere to be found.",
                stringPoolItemLabel);
        }

        private static string ResolvePacketOwnedSkillLearnItemLabel(bool isMasteryBook, string fallbackCategoryLabel)
        {
            int stringPoolId = isMasteryBook
                ? PacketOwnedSkillLearnMasteryBookLabelStringPoolId
                : PacketOwnedSkillLearnSkillBookLabelStringPoolId;
            return MapleStoryStringPool.GetOrFallback(
                stringPoolId,
                string.IsNullOrWhiteSpace(fallbackCategoryLabel)
                    ? isMasteryBook ? "Mastery Book" : "Skill Book"
                    : CultureInfo.InvariantCulture.TextInfo.ToTitleCase(fallbackCategoryLabel));
        }

        private static string FormatPacketOwnedSkillLearnNotice(int stringPoolId, string fallbackFormat, string itemLabel)
        {
            string format = MapleStoryStringPool.GetCompositeFormatOrFallback(
                stringPoolId,
                fallbackFormat,
                maxPlaceholderCount: 1,
                out _);
            return string.Format(CultureInfo.InvariantCulture, format, itemLabel);
        }

        private static bool TryReadPacketOwnedAsciiString(BinaryReader reader, out string value)
        {
            value = string.Empty;
            Stream stream = reader?.BaseStream;
            if (stream == null || stream.Length - stream.Position < sizeof(short))
            {
                return false;
            }

            short length = reader.ReadInt16();
            if (length < 0 || stream.Length - stream.Position < length)
            {
                return false;
            }

            value = Encoding.ASCII.GetString(reader.ReadBytes(length)).Trim();
            return true;
        }

        private static void AppendQuestIds(HashSet<int> questIds, QuestLogSnapshot snapshot)
        {
            if (questIds == null || snapshot?.Entries == null)
            {
                return;
            }

            foreach (QuestLogEntrySnapshot entry in snapshot.Entries)
            {
                if (entry != null && entry.QuestId > 0)
                {
                    questIds.Add(entry.QuestId);
                }
            }
        }

        private string BuildPacketOwnedChairCorrectionMessage(PlayerCharacter player, int seatIndex, string reason, int currentTick)
        {
            if (_packetOwnedLocalUtilityContext.TryEmitChairGetUpRequest(currentTick, player?.HP ?? 0, timeIntervalMs: 0, out PacketOwnedLocalUtilityOutboundRequest request))
            {
                string payloadHex = BitConverter.ToString(request.Payload.ToArray()).Replace("-", string.Empty);
                if (_localUtilityOfficialSessionBridge.TrySendOutboundPacket(request.Opcode, request.Payload, out string dispatchStatus))
                {
                    return $"Packet-owned sit result returned seat {seatIndex}, but {reason}. Forced a stand-up correction, emitted GetUpFromChairRequest(0) as opcode {request.Opcode} [{payloadHex}], and dispatched it through the live local-utility bridge. {dispatchStatus}";
                }

                if (_localUtilityPacketOutbox.TrySendOutboundPacket(request.Opcode, request.Payload, out string outboxStatus))
                {
                    return $"Packet-owned sit result returned seat {seatIndex}, but {reason}. Forced a stand-up correction, emitted GetUpFromChairRequest(0) as opcode {request.Opcode} [{payloadHex}], and dispatched it through the generic local-utility outbox transport after the live bridge path was unavailable. Bridge: {dispatchStatus} Outbox: {outboxStatus}";
                }

                string bridgeDeferredStatus = "Official-session bridge deferred delivery is disabled.";
                if (_localUtilityOfficialSessionBridgeEnabled
                    && _localUtilityOfficialSessionBridge.TryQueueOutboundPacket(request.Opcode, request.Payload, out bridgeDeferredStatus))
                {
                    return $"Packet-owned sit result returned seat {seatIndex}, but {reason}. Forced a stand-up correction, emitted GetUpFromChairRequest(0) as opcode {request.Opcode} [{payloadHex}], and queued it for deferred live official-session injection after the live bridge path was unavailable. Bridge: {dispatchStatus} Outbox: {outboxStatus} Deferred official bridge: {bridgeDeferredStatus}";
                }

                if (_localUtilityPacketOutbox.TryQueueOutboundPacket(request.Opcode, request.Payload, out string queuedStatus))
                {
                    return $"Packet-owned sit result returned seat {seatIndex}, but {reason}. Forced a stand-up correction, emitted GetUpFromChairRequest(0) as opcode {request.Opcode} [{payloadHex}], and queued it for deferred generic local-utility outbox delivery after the live bridge path was unavailable. Bridge: {dispatchStatus} Outbox: {outboxStatus} Deferred official bridge: {bridgeDeferredStatus} Deferred outbox: {queuedStatus}";
                }

                return $"Packet-owned sit result returned seat {seatIndex}, but {reason}. Forced a stand-up correction and emitted GetUpFromChairRequest(0) as opcode {request.Opcode} [{payloadHex}], but it remained simulator-owned because neither the live local-utility bridge nor the deferred official-session bridge queue nor the generic outbox transport or deferred outbox queue accepted the outbound packet. Bridge: {dispatchStatus} Outbox: {outboxStatus} Deferred official bridge: {bridgeDeferredStatus} Deferred outbox: {queuedStatus}";
            }

            return $"Packet-owned sit result returned seat {seatIndex}, but {reason}. Forced a stand-up correction, but the simulated CWvsContext gate suppressed GetUpFromChairRequest(0).";
        }

        private string ClearPacketOwnedChairPassengerLink(PlayerCharacter player)
        {
            if (player?.Build == null)
            {
                return null;
            }

            int passengerId = _localFollowRuntime.AttachedPassengerId;
            if (passengerId <= 0)
            {
                return null;
            }

            TryResolvePacketOwnedRemoteCharacterSnapshot(passengerId, out LocalFollowUserSnapshot passenger);
            string detachMessage = _localFollowRuntime.ClearAttachedPassenger(
                passenger.Exists
                    ? passenger
                    : LocalFollowUserSnapshot.Missing(passengerId, ResolvePacketOwnedRemoteCharacterName(passengerId)),
                transferField: false,
                transferPosition: null);
            _remoteUserPool?.TryApplyFollowCharacter(
                passengerId,
                driverId: 0,
                transferField: false,
                transferPosition: null,
                localCharacterId: player.Build.Id,
                localCharacterPosition: new Vector2(player.X, player.Y),
                out _);
            return detachMessage;
        }

        private static bool IsPacketOwnedChairSeatValidForPlayer(PlayerCharacter player, Vector2 seatPosition)
        {
            if (player == null)
            {
                return false;
            }

            return player.X >= seatPosition.X - 10f
                && player.X <= seatPosition.X + 10f
                && player.Y >= seatPosition.Y - 30f
                && player.Y <= seatPosition.Y + 30f;
        }

        private static bool TryResolvePacketOwnedChairSeatPosition(int mapId, int seatIndex, out Vector2 seatPosition)
        {
            seatPosition = Vector2.Zero;
            if (mapId <= 0 || seatIndex < 0)
            {
                return false;
            }

            WzImage mapImage = TryGetMapImageForMetadataLookup(mapId);
            if (mapImage == null)
            {
                return false;
            }

            bool shouldUnparse = !mapImage.Parsed;
            try
            {
                if (!mapImage.Parsed)
                {
                    mapImage.ParseImage();
                }

                if (mapImage["seat"] is not WzSubProperty seatParent
                    || seatParent[seatIndex.ToString(CultureInfo.InvariantCulture)] is not WzVectorProperty seatVector)
                {
                    return false;
                }

                seatPosition = new Vector2(seatVector.X.Value, seatVector.Y.Value);
                return true;
            }
            finally
            {
                if (shouldUnparse)
                {
                    mapImage.UnparseImage();
                }
            }
        }

