        private bool TryApplyPacketOwnedParcelDialogPayload(byte[] payload, out string message)
        {
            PacketOwnedSocialUtilityDialogDispatcher dispatcher = GetPacketOwnedSocialUtilityDialogDispatcher();
            bool parcelWindowWasVisible = uiWindowManager?.GetWindow(MapSimulatorWindowNames.MemoMailbox)?.IsVisible == true;
            bool applied = dispatcher.TryApplyParcelPacket(payload, out message);
            if (!applied)
            {
                return false;
            }

            if (dispatcher.ShouldShowParcelOwnerAfterLastPacket)
            {
                TryOpenFieldRestrictedWindow(
                    MapSimulatorWindowNames.MemoMailbox,
                    inheritDirectionModeOwner: true);
            }
            else if (dispatcher.ShouldHideParcelOwnerAfterLastPacket && parcelWindowWasVisible)
            {
                uiWindowManager?.HideWindow(MapSimulatorWindowNames.MemoMailbox);
            }

            IReadOnlyList<string> arrivalNotices = dispatcher.LastParcelArrivalNotices;
            if (arrivalNotices != null)
            {
                for (int i = 0; i < arrivalNotices.Count; i++)
                {
                    if (!string.IsNullOrWhiteSpace(arrivalNotices[i]))
                    {
                        ShowUtilityFeedbackMessage(arrivalNotices[i].Trim());
                    }
                }
            }

            if (dispatcher.LastParcelAlarmPrompt is ParcelAlarmPromptSnapshot alarmPrompt)
            {
                string alarmNotice = string.IsNullOrWhiteSpace(alarmPrompt.Body)
                    ? alarmPrompt.Title
                    : $"{alarmPrompt.Title}: {alarmPrompt.Body}";
                if (!string.IsNullOrWhiteSpace(alarmNotice))
                {
                    ShowUtilityFeedbackMessage(alarmNotice.Trim());
                }

                ShowPacketOwnedParcelAlarmPrompt(alarmPrompt);
            }

            return true;
        }

        private void ShowPacketOwnedParcelAlarmPrompt(ParcelAlarmPromptSnapshot alarmPrompt)
        {
            if (alarmPrompt == null
                || !alarmPrompt.RequiresFadeYesNoOwner
                || uiWindowManager?.GetWindow(MapSimulatorWindowNames.InGameConfirmDialog) is not InGameConfirmDialogWindow confirmDialogWindow)
            {
                return;
            }

            string title = string.IsNullOrWhiteSpace(alarmPrompt.Title)
                ? (alarmPrompt.IsQuickDelivery ? "Quick Delivery" : "Parcel Delivery")
                : alarmPrompt.Title.Trim();
            string body = string.IsNullOrWhiteSpace(alarmPrompt.Body)
                ? $"{title} notice has arrived."
                : alarmPrompt.Body.Trim();
            ConfigureInGameConfirmDialog(
                title,
                body,
                $"CParcelDlg packet {alarmPrompt.PacketSubtype.ToString(CultureInfo.InvariantCulture)} CUIFadeYesNo parcel alarm.",
                onConfirm: () =>
                {
                    TryOpenFieldRestrictedWindow(
                        MapSimulatorWindowNames.MemoMailbox,
                        inheritDirectionModeOwner: true,
                        beforeShow: () => _memoMailbox.SetActiveTab(alarmPrompt.IsQuickDelivery
                            ? ParcelDialogTab.QuickSend
                            : ParcelDialogTab.Receive));
                },
                onCancel: null,
                presentation: confirmDialogWindow.CreateParcelAlarmPresentation());
            ShowWindow(
                MapSimulatorWindowNames.InGameConfirmDialog,
                confirmDialogWindow,
                trackDirectionModeOwner: true);
        }

