        private bool TryDispatchMessengerOfficialSessionRequest(int opcode, byte[] payload, string source, out string message, bool queueOnly = false)
        {
            byte[] safePayload = payload ?? Array.Empty<byte>();
            string payloadHex = safePayload.Length > 0 ? Convert.ToHexString(safePayload) : "<empty>";
            if (queueOnly)
            {
                if (_messengerOfficialSessionBridge.TryQueueOutboundPacket(opcode, safePayload, out string queueOnlyStatus))
                {
                    message = $"{source} queued opcode {opcode} [{payloadHex}] for deferred Messenger session injection. {queueOnlyStatus}";
                    return true;
                }

                message = $"{source} could not queue opcode {opcode} [{payloadHex}] for deferred Messenger session injection. Bridge: {queueOnlyStatus}";
                return false;
            }

            string dispatchStatus = "live Messenger bridge unavailable";
            if (_messengerOfficialSessionBridge.TrySendOutboundPacket(opcode, safePayload, out dispatchStatus))
            {
                message = $"{source} dispatched opcode {opcode} [{payloadHex}] through the live Messenger session bridge. {dispatchStatus}";
                return true;
            }

            string queuedStatus = "Messenger deferred queue unavailable";
            if ((_messengerOfficialSessionBridgeEnabled || _messengerOfficialSessionBridge.IsRunning)
                && _messengerOfficialSessionBridge.TryQueueOutboundPacket(opcode, safePayload, out queuedStatus))
            {
                message = $"{source} queued opcode {opcode} [{payloadHex}] for deferred Messenger session injection after the live path was unavailable. Bridge: {dispatchStatus} Deferred bridge: {queuedStatus}";
                return true;
            }

            message = $"{source} remained simulator-local because the Messenger session bridge did not accept opcode {opcode} [{payloadHex}]. Bridge: {dispatchStatus} Deferred bridge: {queuedStatus}";
            return false;
        }

        private bool TryMirrorMessengerInviteClientRequest(string contactName, out string message, bool queueOnly = false)
        {
            if (!_messengerRuntime.TryBuildClientInviteRequestPayload(contactName, out byte[] payload, out string resolvedContactName, out message))
            {
                return false;
            }

            if (!TryDispatchMessengerOfficialSessionRequest(
                    MessengerPacketCodec.ClientMessengerRequestOpcode,
                    payload,
                    $"CUIMessenger::SendInviteMsg targeted {resolvedContactName}",
                    out string dispatchStatus,
                    queueOnly))
            {
                message = dispatchStatus;
                return false;
            }

            string runtimeStatus = _messengerRuntime.QueueSessionOwnedInviteRequest(resolvedContactName);
            message = $"{runtimeStatus} {dispatchStatus}";
            return true;
        }

        private bool TryMirrorMessengerProcessChatClientRequest(string chatText, out string message, bool queueOnly = false)
        {
            if (!_messengerRuntime.TryBuildClientProcessChatRequestPayload(chatText, out byte[] payload, out string normalizedMessage, out message))
            {
                return false;
            }

            if (!TryDispatchMessengerOfficialSessionRequest(
                    MessengerPacketCodec.ClientMessengerRequestOpcode,
                    payload,
                    "CUIMessenger::ProcessChat",
                    out string dispatchStatus,
                    queueOnly))
            {
                message = dispatchStatus;
                return false;
            }

            string localStatus = queueOnly
                ? $"Queued CUIMessenger::ProcessChat for '{normalizedMessage}' and left room state waiting for the session-owned chat result."
                : _messengerRuntime.SendMessage(normalizedMessage);
            message = $"{localStatus} {dispatchStatus}";
            return true;
        }

        private bool TryMirrorMessengerIncomingInviteAcceptClientRequest(string contactName, out string message, bool queueOnly = false)
        {
            if (!_messengerRuntime.TryBuildClientAcceptInviteRequestPayload(contactName, out byte[] payload, out string resolvedContactName, out int inviteSequence, out message))
            {
                return false;
            }

            if (!TryDispatchMessengerOfficialSessionRequest(
                    MessengerPacketCodec.ClientMessengerRequestOpcode,
                    payload,
                    $"CUIFadeYesNo::OnButtonClicked accepted Messenger invite from {resolvedContactName}",
                    out string dispatchStatus,
                    queueOnly))
            {
                message = dispatchStatus;
                return false;
            }

            string runtimeStatus = _messengerRuntime.QueueSessionOwnedIncomingInviteAccept(resolvedContactName);
            message = $"{runtimeStatus} {dispatchStatus}";
            return true;
        }

        private bool TryMirrorMessengerIncomingInviteRejectClientSeam(string contactName, out string message, bool queueOnly = false)
        {
            string runtimeStatus = _messengerRuntime.QueueSessionOwnedIncomingInviteReject(contactName);
            if (runtimeStatus.StartsWith("No Messenger invite is waiting", StringComparison.Ordinal))
            {
                message = runtimeStatus;
                return false;
            }

            string queueState = queueOnly
                ? "The client reject seam does not emit a Messenger request packet, so nothing was queued on the bridge."
                : "The client reject seam does not emit a Messenger request packet, so the bridge remains idle for this response.";
            message = $"{runtimeStatus} {queueState}";
            return true;
        }

        private bool TryMirrorMessengerLeaveClientRequest(out string message, bool queueOnly = false)
        {
            if (!_messengerRuntime.TryBuildClientLeaveRequestPayload(out byte[] payload, out message))
            {
                return false;
            }

            if (!TryDispatchMessengerOfficialSessionRequest(
                    MessengerPacketCodec.ClientMessengerRequestOpcode,
                    payload,
                    "CUIMessenger::OnDestroy",
                    out string dispatchStatus,
                    queueOnly))
            {
                message = dispatchStatus;
                return false;
            }

            string runtimeStatus = _messengerRuntime.QueueSessionOwnedLeaveRequest();
            message = $"{runtimeStatus} {dispatchStatus}";
            return true;
        }

        private string TryHandleMessengerLeaveActionThroughClientSeam()
        {
            return TryMirrorMessengerLeaveClientRequest(out string mirroredMessage)
                ? mirroredMessage
                : _messengerRuntime.LeaveMessenger();
        }

        private MessengerDeleteResult TryHandleMessengerCloseRequestThroughClientSeam(bool fromExitPrompt)
        {
            if (TryMirrorMessengerLeaveClientRequest(out string mirroredMessage))
            {
                if (fromExitPrompt)
                {
                    _messengerRuntime.CancelExitPrompt();
                }

                MessengerSnapshot snapshot = _messengerRuntime.BuildSnapshot(Environment.TickCount);
                return new MessengerDeleteResult(mirroredMessage, snapshot.ShouldCloseWindow);
            }

            return fromExitPrompt
                ? _messengerRuntime.ConfirmExitPrompt()
                : _messengerRuntime.TryDeleteMessenger();
        }

        private bool TryMirrorMessengerNativeClaimClientRequest(out string message, bool queueOnly = false)
        {
            if (!_messengerRuntime.TryBuildClientChatClaimRequestPayload(
                    out byte[] payload,
                    out string targetCharacterName,
                    out byte claimType,
                    out string context,
                    out int chatLineCount,
                    out message))
            {
                return false;
            }

            if (!TryDispatchMessengerOfficialSessionRequest(
                    118,
                    payload,
                    $"CWvsContext::SendClaimRequest targeted {targetCharacterName}",
                    out string dispatchStatus,
                    queueOnly))
            {
                message = dispatchStatus;
                return false;
            }

            string runtimeStatus = _messengerRuntime.QueueSessionOwnedChatClaimRequest(
                targetCharacterName,
                claimType,
                context,
                chatLineCount,
                queueOnly);
            message = $"{runtimeStatus} {dispatchStatus}";
            return true;
        }

