        {
            return TryMirrorMessengerNativeClaimClientRequest(out string mirroredMessage)
                ? mirroredMessage
                : _messengerRuntime.SubmitClaim();
        }

        private bool TryMirrorMessengerClaimClientRequest(string claimArguments, out string message, bool queueOnly = false)
        {
            message = null;
            string packedArguments = claimArguments?.Trim();
            if (string.IsNullOrWhiteSpace(packedArguments))
            {
                message = "Usage: /messenger session <send|queue> claim <target>|<type>|<context>[|<chatLog>]";
                return false;
            }

            string[] parts = packedArguments.Split('|');
            if (parts.Length < 3 || parts.Length > 4)
            {
                message = "Usage: /messenger session <send|queue> claim <target>|<type>|<context>[|<chatLog>]";
                return false;
            }

            string targetCharacterName = parts[0].Trim();
            string claimTypeText = parts[1].Trim();
            string context = parts[2].Trim();
            string chatLog = parts.Length >= 4 ? parts[3].Trim() : string.Empty;

            if (string.IsNullOrWhiteSpace(targetCharacterName))
            {
                message = "Messenger claim mirroring needs a target character name.";
                return false;
            }

            if (!byte.TryParse(claimTypeText, out byte claimType))
            {
                message = $"Messenger claim type '{claimTypeText}' is invalid. Use an exact byte value from the client claim dialog seam.";
                return false;
            }

            byte[] payload = MessengerPacketCodec.BuildClaimRequestPayload(targetCharacterName, claimType, context, chatLog);
            if (!TryDispatchMessengerOfficialSessionRequest(
                    118,
                    payload,
                    $"CWvsContext::SendClaimRequest targeted {targetCharacterName}",
                    out string dispatchStatus,
                    queueOnly))
            {
                message = dispatchStatus;
                return false;
            }

            int chatLineCount = CountMessengerClaimChatLogLines(chatLog);
            if (chatLineCount <= 0)
            {
                chatLineCount = _messengerRuntime.CountClaimableChatLines();
            }

            string runtimeStatus = _messengerRuntime.QueueSessionOwnedChatClaimRequest(
                targetCharacterName,
                claimType,
                context,
                chatLineCount,
                queueOnly);
            message = $"{runtimeStatus} {dispatchStatus}";
            return true;
        }

        private static int CountMessengerClaimChatLogLines(string chatLog)
        {
            if (string.IsNullOrWhiteSpace(chatLog))
            {
                return 0;
            }

            return chatLog
                .Split(new[] { "\r\n", "\n", "\r" }, StringSplitOptions.RemoveEmptyEntries)
                .Count(line => !string.IsNullOrWhiteSpace(line));
        }

        private bool TryMirrorMessengerBlockedAutoRejectClientRequest(string blockedArguments, out string message, bool queueOnly = false)
        {
            message = null;
            string packedArguments = blockedArguments?.Trim();
            if (string.IsNullOrWhiteSpace(packedArguments))
            {
                message = "Usage: /messenger session <send|queue> blocked <inviter> [localName] [blocked]";
                return false;
            }

            string[] parts = packedArguments.Split(new[] { ' ' }, StringSplitOptions.RemoveEmptyEntries);
            if (parts.Length < 1 || parts.Length > 3)
            {
                message = "Usage: /messenger session <send|queue> blocked <inviter> [localName] [blocked]";
                return false;
            }

            string inviterName = parts[0].Trim();
            if (string.IsNullOrWhiteSpace(inviterName))
            {
                message = "Messenger blocked-auto-reject mirroring needs a non-empty inviter name.";
                return false;
            }

            string localCharacterName = parts.Length >= 2
                ? parts[1].Trim()
                : _playerManager?.Player?.Name;
            if (string.IsNullOrWhiteSpace(localCharacterName))
            {
                localCharacterName = "Player";
            }

            bool blocked = true;
            if (parts.Length >= 3 && !TryParsePacketOwnedBooleanToken(parts[2], out blocked))
            {
                message = "Messenger blocked-auto-reject flag must be a boolean token (for example: on/off, true/false, 1/0).";
                return false;
            }

            byte[] requestPayload = MessengerPacketCodec.BuildBlockedAutoRejectPayload(inviterName, localCharacterName);
            if (requestPayload.Length > 0)
            {
                requestPayload[^1] = blocked ? (byte)1 : (byte)0;
            }

            if (!TryDispatchMessengerOfficialSessionRequest(
                    MessengerPacketCodec.ClientMessengerRequestOpcode,
                    requestPayload,
                    $"CUIMessenger::OnInvite blocked-auto-reject for {inviterName}",
                    out string dispatchStatus,
                    queueOnly))
            {
                message = dispatchStatus;
                return false;
            }

            if (queueOnly)
            {
                message = dispatchStatus;
                return true;
            }

            byte[] blockedPayload = MessengerPacketCodec.BuildBlockedPayload(inviterName, blocked);
            if (TryApplyPacketOwnedMessengerPacket(MessengerPacketType.Blocked, blockedPayload, out string runtimeStatus))
            {
                message = $"{runtimeStatus} {dispatchStatus}";
                return true;
            }

            message = $"{dispatchStatus} Messenger runtime blocked-state update was skipped: {runtimeStatus}";
            return true;
        }

        private bool TryMirrorMessengerChatEditInput(string text, out string message)
        {
            message = null;
            string normalizedText = text?.Trim();
            if (string.IsNullOrWhiteSpace(normalizedText))
            {
                return false;
            }

            if (!normalizedText.StartsWith("/", StringComparison.Ordinal))
            {
                return TryMirrorMessengerProcessChatClientRequest(normalizedText, out message);
            }

            string[] parts = normalizedText.Split(new[] { ' ' }, 2, StringSplitOptions.RemoveEmptyEntries);
            string command = parts.Length > 0 ? parts[0].TrimStart('/').ToLowerInvariant() : string.Empty;
            string argument = parts.Length > 1 ? parts[1].Trim() : string.Empty;
            switch (command)
            {
                case "m":
                case "msn":
                case "invite":
                    return !string.IsNullOrWhiteSpace(argument)
                        && TryMirrorMessengerInviteClientRequest(argument, out message);
                case "accept":
                case "yes":
                case "join":
                    return TryMirrorMessengerIncomingInviteAcceptClientRequest(argument, out message);
                case "reject":
                case "decline":
                case "no":
                    return TryMirrorMessengerIncomingInviteRejectClientSeam(argument, out message);
                case "claim":
                case "claimauto":
                case "claimnative":
                case "report":
                    return string.IsNullOrWhiteSpace(argument)
                        ? TryMirrorMessengerNativeClaimClientRequest(out message)
                        : TryMirrorMessengerClaimClientRequest(argument, out message);
                case "q":
                case "quit":
                case "leave":
                case "exit":
                case "close":
                    return TryMirrorMessengerLeaveClientRequest(out message);
                default:
                    return false;
            }
        }

