        private string DescribePacketOwnedLocalControlStatus(int currentTickCount)
        {
            string directionStatus = _lastPacketOwnedDirectionModeTick == int.MinValue
                ? $"Local control: packet direction mode inactive, scripted direction mode={_gameState.ScriptedDirectionModeActive.ToString().ToLowerInvariant()}, packet direction mode={_gameState.PacketDirectionModeActive.ToString().ToLowerInvariant()}."
                : _gameState.PacketDirectionModeReleaseAt != int.MinValue
                    ? $"Local control: packet direction request enabled={_lastPacketOwnedDirectionModeEnabled.ToString().ToLowerInvariant()}, releaseDelay={_lastPacketOwnedDirectionModeDelayMs}, dueIn={Math.Max(0, unchecked(_gameState.PacketDirectionModeReleaseAt - currentTickCount))} ms, scripted direction mode={_gameState.ScriptedDirectionModeActive.ToString().ToLowerInvariant()}, packet direction mode={_gameState.PacketDirectionModeActive.ToString().ToLowerInvariant()}."
                    : $"Local control: packet direction request enabled={_lastPacketOwnedDirectionModeEnabled.ToString().ToLowerInvariant()}, delay={_lastPacketOwnedDirectionModeDelayMs}, scripted direction mode={_gameState.ScriptedDirectionModeActive.ToString().ToLowerInvariant()}, packet direction mode={_gameState.PacketDirectionModeActive.ToString().ToLowerInvariant()}.";
            string standAloneStatus = _lastPacketOwnedStandAloneTick == int.MinValue
                ? $"Stand-alone flag={_gameState.StandAloneModeActive.ToString().ToLowerInvariant()}."
                : $"Stand-alone request enabled={_lastPacketOwnedStandAloneEnabled.ToString().ToLowerInvariant()}, flag={_gameState.StandAloneModeActive.ToString().ToLowerInvariant()}, age={Math.Max(0, unchecked(currentTickCount - _lastPacketOwnedStandAloneTick))} ms.";
            bool chairSecureSit = _playerManager?.Player?.PacketOwnedChairSitConfirmed == true;
            string chairStatus = _packetOwnedLocalUtilityContext.DescribeChairContext(currentTickCount, chairSecureSit);
            string radioCreateLayerContextStatus = DescribePacketOwnedRadioCreateLayerContextStatus();
            string teleportPortalNames = !string.IsNullOrWhiteSpace(_lastPacketOwnedTeleportSourcePortalName)
                || !string.IsNullOrWhiteSpace(_lastPacketOwnedTeleportTargetPortalName)
                    ? $"{_lastPacketOwnedTeleportSourcePortalName ?? "?"}->{_lastPacketOwnedTeleportTargetPortalName ?? "?"}"
                    : "none";
            string teleportEffectStatus = _lastPacketOwnedTeleportEffectTick == int.MinValue
                ? "idle"
                : $"{_lastPacketOwnedTeleportEffectPath ?? "unresolved"} age={Math.Max(0, unchecked(currentTickCount - _lastPacketOwnedTeleportEffectTick))} ms";
            string teleportMovePathPayloadStatus = (_lastPacketOwnedTeleportMovePathPayload?.Length ?? 0) == 0
                ? "none"
                : TruncatePacketOwnedUtilityText(Convert.ToHexString(_lastPacketOwnedTeleportMovePathPayload), 72);
            string teleportRegistrationStatus = _lastPacketOwnedTeleportRegistrationTick == int.MinValue
                ? "forced registration=idle"
                : $"forced registration age={Math.Max(0, unchecked(currentTickCount - _lastPacketOwnedTeleportRegistrationTick))} ms, movePathAttr={_lastPacketOwnedTeleportMovePathAttribute}, movePathPayload={teleportMovePathPayloadStatus}, setItemBackground={(_lastPacketOwnedTeleportSetItemBackgroundActive ? "1/1" : "0/0")}, effect={teleportEffectStatus}";
            string teleportOutboundSummary = string.IsNullOrWhiteSpace(_lastPacketOwnedTeleportOutboundSummary)
                ? string.Empty
                : $" ({TruncatePacketOwnedUtilityText(_lastPacketOwnedTeleportOutboundSummary, 180)})";
            string teleportOutboundStatus = _lastPacketOwnedTeleportOutboundOpcode < 0
                ? "outbound portal request=unresolved"
                : $"outbound portal request={_lastPacketOwnedTeleportOutboundOpcode}[{Convert.ToHexString(_lastPacketOwnedTeleportOutboundPayload ?? Array.Empty<byte>())}]{teleportOutboundSummary}";
            string teleportStatus = _lastPacketOwnedTeleportPortalRequestTick == int.MinValue
                ? $"Teleport request active={_packetOwnedTeleportRequestActive.ToString().ToLowerInvariant()}, last portal request=none, cooldown={IsPacketOwnedTeleportRegistrationCoolingDown(currentTickCount).ToString().ToLowerInvariant()}."
                : $"Teleport request active={_packetOwnedTeleportRequestActive.ToString().ToLowerInvariant()}, last portal request age={Math.Max(0, unchecked(currentTickCount - _lastPacketOwnedTeleportPortalRequestTick))} ms, handoff={teleportPortalNames}, portalIndex={_lastPacketOwnedTeleportPortalIndex}, cooldown={IsPacketOwnedTeleportRegistrationCoolingDown(currentTickCount).ToString().ToLowerInvariant()}, {teleportRegistrationStatus}, {teleportOutboundStatus}.";
            return $"{directionStatus} {standAloneStatus} {chairStatus} {radioCreateLayerContextStatus} {teleportStatus}";
        }

        private static string TruncatePacketOwnedUtilityText(string value, int maxLength = 80)
        {
            if (string.IsNullOrWhiteSpace(value))
            {
                return string.Empty;
            }

            string trimmed = value.Trim();
            return trimmed.Length <= maxLength
                ? trimmed
                : $"{trimmed[..Math.Max(0, maxLength - 3)]}...";
        }

        private string ApplyPacketOwnedOpenUi(int uiType, int defaultTab = -1)
        {
            StampPacketOwnedUtilityRequestState();
            _lastPacketOwnedOpenUiType = uiType;
            _lastPacketOwnedOpenUiOption = -1;

            return uiType switch
            {
                0 => ShowPacketOwnedWindow(MapSimulatorWindowNames.Inventory, "Inventory"),
                1 => ShowPacketOwnedWindow(MapSimulatorWindowNames.Equipment, "Equipment"),
                2 => ShowPacketOwnedWindow(MapSimulatorWindowNames.Ability, "Stat"),
                3 => ShowPacketOwnedWindow(MapSimulatorWindowNames.Skills, defaultTab >= 0 ? $"Skills (tab {defaultTab})" : "Skills"),
                5 => ShowPacketOwnedWindow(MapSimulatorWindowNames.KeyConfig, "Key Config"),
                6 => ShowPacketOwnedWindow(MapSimulatorWindowNames.Quest, defaultTab >= 0 ? $"Quest (tab {defaultTab})" : "Quest"),
                10 => ShowPacketOwnedWindow(MapSimulatorWindowNames.CharacterInfo, "Character Info"),
                21 => ApplyPacketOwnedPartySearchLaunch(defaultTab),
                22 => ShowPacketOwnedWindow(MapSimulatorWindowNames.ItemMaker, "Item Maker"),
                25 => ShowPacketOwnedWindow(MapSimulatorWindowNames.Ranking, "Ranking"),
                26 => ShowPacketOwnedWindow(MapSimulatorWindowNames.FamilyChart, "Family"),
                27 => ShowPacketOwnedWindow(MapSimulatorWindowNames.FamilyTree, "Family Tree"),
                39 => ShowPacketOwnedWindow(MapSimulatorWindowNames.GuildBbs, "Guild BBS"),
                41 => ShowPacketOwnedWindow(MapSimulatorWindowNames.SocialSearch, "Find Friend"),
                _ => ReportUnsupportedPacketOwnedOpenUi(uiType, defaultTab)
            };
        }

        private string ApplyPacketOwnedOpenUiWithOption(int uiType, int option)
        {
            StampPacketOwnedUtilityRequestState();
            _lastPacketOwnedOpenUiType = uiType;
            _lastPacketOwnedOpenUiOption = option;

            if (uiType == 21)
            {
                return ApplyPacketOwnedPartySearchLaunch(option);
            }

            if (uiType == 33)
            {
                string blockingOwner = GetVisibleUniqueModelessOwner(MapSimulatorWindowNames.RepairDurability);
                if (!string.IsNullOrWhiteSpace(blockingOwner))
                {
                    string blockedMessage = $"Packet-owned durability repair was suppressed because {blockingOwner} is already open.";
                    ShowUtilityFeedbackMessage(blockedMessage);
                    return blockedMessage;
                }

                if (!TryShowRepairDurabilityWindow(option, out RepairDurabilityWindow repairWindow, trackDirectionModeOwner: true))
                {
                    const string unavailable = "Repair durability owner is not available in this UI build.";
                    ShowUtilityFeedbackMessage(unavailable);
                    return unavailable;
                }

                string npcName = ResolveNpcDisplayName(option);
                string message = option > 0
                    ? $"Opened packet-owned durability repair through {npcName}."
                    : "Opened packet-owned durability repair.";
                repairWindow.SetStatusMessage(GetRepairDurabilityStatusMessage());
                ShowUtilityFeedbackMessage(message);
                return message;
            }

            if (uiType == 7)
            {
                return ApplyPacketOwnedSocialListToggle(option);
            }

            string baseMessage = ApplyPacketOwnedOpenUi(uiType);
            return string.IsNullOrWhiteSpace(baseMessage)
                ? $"Packet-owned UI open-with-option #{uiType} ({option}) did not resolve to a simulator owner."
                : $"{baseMessage} Option {option} was preserved on the packet-owned dispatch seam.";
        }

        private string ApplyPacketOwnedPartySearchLaunch(int option)
        {
            _socialListRuntime.OpenSearchWindow(SocialSearchTab.Party);
            WireSocialSearchWindowData();

            if (uiWindowManager?.GetWindow(MapSimulatorWindowNames.SocialSearch) is not UIWindowBase window)
            {
                const string unavailable = "Party search owner is not available in this UI build.";
                ShowUtilityFeedbackMessage(unavailable);
                return unavailable;
            }

            ShowWindow(MapSimulatorWindowNames.SocialSearch, window, trackDirectionModeOwner: true);
            string message = option >= 0
                ? $"Opened packet-owned party search and preserved request option {option} for the simulator search owner."
                : "Opened packet-owned party search.";
            ShowUtilityFeedbackMessage(message);
            return message;
        }

        private string ApplyPacketOwnedSocialListToggle(int option)
        {
            WireSocialListWindowData();

            if (uiWindowManager?.GetWindow(MapSimulatorWindowNames.SocialList) is not UIWindowBase socialListWindow)
            {
                const string unavailable = "Social List owner is not available in this UI build.";
                ShowUtilityFeedbackMessage(unavailable);
                return unavailable;
            }

            bool hasRequestedTab = TryResolvePacketOwnedSocialListTab(option, out SocialListTab requestedTab);
            SocialListTab targetTab = hasRequestedTab ? requestedTab : _socialListRuntime.CurrentTab;
            bool wasVisible = socialListWindow.IsVisible;
            if (wasVisible)
            {
                uiWindowManager.HideWindow(MapSimulatorWindowNames.SocialList);
            }

            _socialListRuntime.SelectTab(targetTab);
            ShowWindow(MapSimulatorWindowNames.SocialList, socialListWindow, trackDirectionModeOwner: true);

            string message = hasRequestedTab
                ? wasVisible
                    ? $"Refreshed packet-owned Social List through the recovered UI_Close(7)+UI_Toggle(7,{option}) seam on the {DescribePacketOwnedSocialListTab(targetTab)} tab."
                    : $"Opened packet-owned Social List on the {DescribePacketOwnedSocialListTab(targetTab)} tab."
                : wasVisible
                    ? $"Refreshed packet-owned Social List through the recovered UI_Close(7)+UI_Toggle(7,{option}) seam and preserved the unmapped tab option on the existing simulator tab."
                    : $"Opened packet-owned Social List and preserved unmapped tab option {option} on the existing simulator tab seam.";
            ShowUtilityFeedbackMessage(message);
            return message;
        }

        private static bool TryResolvePacketOwnedSocialListTab(int option, out SocialListTab tab)
        {
            tab = SocialListTab.Friend;
            if (!Enum.IsDefined(typeof(SocialListTab), option))
            {
                return false;
            }

            tab = (SocialListTab)option;
            return true;
        }

        private static string DescribePacketOwnedSocialListTab(SocialListTab tab)
        {
            return tab switch
            {
                SocialListTab.Friend => "Friend",
                SocialListTab.Party => "Party",
                SocialListTab.Guild => "Guild",
                SocialListTab.Alliance => "Alliance",
                SocialListTab.Blacklist => "Blacklist",
                _ => "Social"
            };
        }

        private static bool TryParsePacketOwnedBooleanToken(string token, out bool value)
        {
            value = false;
            if (string.IsNullOrWhiteSpace(token))
            {
                return false;
            }

            switch (token.Trim().ToLowerInvariant())
            {
                case "1":
                case "on":
                case "true":
                case "enable":
                case "enabled":
                    value = true;
                    return true;

                case "0":
                case "off":
                case "false":
                case "disable":
                case "disabled":
                    value = false;
                    return true;

                default:
                    return false;
            }
        }

        private string ReportUnsupportedPacketOwnedOpenUi(int uiType, int defaultTab)
        {
            string message = defaultTab >= 0
                ? $"Packet-owned UI open #{uiType} (tab {defaultTab}) does not map to a simulator owner yet."
                : $"Packet-owned UI open #{uiType} does not map to a simulator owner yet.";
            ShowUtilityFeedbackMessage(message);
            return message;
        }

        private string ShowPacketOwnedWindow(string windowName, string displayName)
        {
            string restrictionMessage = FieldInteractionRestrictionEvaluator.GetWindowOpenRestrictionMessage(
                _mapBoard?.MapInfo?.fieldLimit ?? 0,
                _mapBoard?.MapInfo,
                windowName);
            if (!string.IsNullOrWhiteSpace(restrictionMessage))
            {
                ShowUtilityFeedbackMessage(restrictionMessage);
                return restrictionMessage;
            }

            if (uiWindowManager?.GetWindow(windowName) is not UIWindowBase window)
            {
                string unavailable = $"{displayName} owner is not available in this UI build.";
                ShowUtilityFeedbackMessage(unavailable);
                return unavailable;
            }

            if (string.Equals(windowName, MapSimulatorWindowNames.Ranking, StringComparison.Ordinal)
                || string.Equals(windowName, MapSimulatorWindowNames.Event, StringComparison.Ordinal))
            {
                ShowRecordedUtilityWindow(windowName, $"packet-owned {displayName}");
                return $"Opened packet-owned {displayName}.";
            }

            ShowWindow(windowName, window, trackDirectionModeOwner: true);
            return $"Opened packet-owned {displayName}.";
        }

        private string ApplyPacketOwnedGoToCommoditySn(int commoditySerialNumber)
        {
            StampPacketOwnedUtilityRequestState();
            _lastPacketOwnedCommoditySerialNumber = Math.Max(0, commoditySerialNumber);
            _lastPacketOwnedCommodityRequestTick = Environment.TickCount;

            OpenCashServiceOwnerFamily(UI.CashServiceStageKind.CashShop, resetStageSession: false);
            bool focusedCommodity = TryFocusCashServiceCommodity(_lastPacketOwnedCommoditySerialNumber);

            string message = focusedCommodity
                ? $"Stored packet-owned commodity SN {_lastPacketOwnedCommoditySerialNumber}, requested shop migration, opened the staged Cash Shop owner family, and focused the matching Cash Shop row."
                : $"Stored packet-owned commodity SN {_lastPacketOwnedCommoditySerialNumber}, requested shop migration, and opened the staged Cash Shop owner family.";
            ShowUtilityFeedbackMessage(message);
            return message;
        }

        private bool TryApplyPacketOwnedRadioSchedulePayload(
            byte[] payload,
            int packetType,
            string source,
            bool requireExactClientPayload,
            out string message)
        {
            if (TryDecodePacketOwnedRadioSchedulePayload(
                    payload,
                    requireExactClientPayload,
                    out string trackDescriptor,
                    out int timeValue,
                    out message))
            {
                bool mutationFromOfficialSession = IsPacketOwnedRadioScheduleOfficialSessionSource(source);
                if (!ShouldAllowPacketOwnedRadioMutationSource(
                        _localUtilityOfficialSessionBridge.HasConnectedSession,
                        mutationFromOfficialSession))
                {
                    message =
                        $"Ignored packet-owned radio schedule from {ResolvePacketOwnedRadioScheduleSourceLabel(packetType, source)} because a live official-session bridge is attached and radio schedule mutations must come from official-session packet history.";
                    return false;
                }

                if (!ShouldApplyPacketOwnedRadioMutationWithOfficialHistory(
                        _packetOwnedRadioOfficialScheduleMutationObserved,
                        mutationFromOfficialSession))
                {
                    message =
                        $"Ignored packet-owned radio schedule from {ResolvePacketOwnedRadioScheduleSourceLabel(packetType, source)} because official-session radio schedule mutation history is already active for the current runtime owner.";
                    return false;
                }

                if (mutationFromOfficialSession)
                {
                    _packetOwnedRadioOfficialScheduleMutationObserved = true;
                }

                message = ApplyPacketOwnedRadioSchedule(
                    trackDescriptor,
                    timeValue,
                    packetType,
                    ResolvePacketOwnedRadioScheduleSourceLabel(packetType, source));
                return true;
            }

            return false;
        }

        private bool TryApplyPacketOwnedRadioCreateLayerContextPayload(
            byte[] payload,
            int packetType,
            string source,
            out string message)
        {
            if (!TryDecodePacketOwnedRadioCreateLayerContextPayload(payload, out bool hasOverride, out bool bLeft, out message))
            {
                return false;
            }

            string mutationSource = ResolvePacketOwnedRadioCreateLayerContextMutationSourceLabel(
                packetType,
                source,
                clearMutation: !hasOverride);
            bool mutationFromOfficialSession = IsPacketOwnedRadioScheduleOfficialSessionSource(source);
            if (!ShouldAllowPacketOwnedRadioMutationSource(
                    _localUtilityOfficialSessionBridge.HasConnectedSession,
                    mutationFromOfficialSession))
            {
                message =
                    $"Ignored packet-owned CWvsContext[{PacketOwnedRadioCreateLayerContextSlot}] radio bLeft mutation from {mutationSource} because a live official-session bridge is attached and context mutations must come from official-session packet history.";
                return false;
            }

            if (!ShouldApplyPacketOwnedRadioMutationWithOfficialHistory(
                    _packetOwnedRadioOfficialCreateLayerMutationObserved,
                    mutationFromOfficialSession))
            {
                message =
                    $"Ignored packet-owned CWvsContext[{PacketOwnedRadioCreateLayerContextSlot}] radio bLeft mutation from {mutationSource} because official-session context mutation history is already active for the current runtime owner.";
                return false;
            }

            if (mutationFromOfficialSession)
            {
                _packetOwnedRadioOfficialCreateLayerMutationObserved = true;
            }

            message = hasOverride
                ? SetPacketOwnedRadioCreateLayerContext(bLeft, mutationSource)
                : ClearPacketOwnedRadioCreateLayerContext(mutationSource);
            ShowUtilityFeedbackMessage($"{message} {DescribePacketOwnedRadioCreateLayerContextStatus()}");
            return true;
        }

        private bool TryApplyPacketOwnedRevivePremiumSafetyCharmContextPayload(
            byte[] payload,
            int packetType,
            string source,
            out string message)
        {
            if (!TryDecodePacketOwnedRevivePremiumSafetyCharmContextPayload(payload, out bool hasOverride, out bool armed, out message))
            {
                return false;
            }

            int runtimeCharacterId = Math.Max(0, _playerManager?.Player?.Build?.Id ?? 0);
            string mutationSource = $"packet-owned-revive-premium-safety-charm:{packetType}:{(string.IsNullOrWhiteSpace(source) ? "local-utility" : source)}";
            bool mutationFromOfficialSession = IsPacketOwnedRevivePremiumSafetyCharmContextOfficialSessionSource(source);
            if (!ShouldAllowPacketOwnedRevivePremiumSafetyCharmContextMutationSource(
                    _localUtilityOfficialSessionBridge.HasConnectedSession,
                    mutationFromOfficialSession))
            {
                message =
                    $"Ignored packet-owned CWvsContext[{ReviveOwnerPremiumSafetyCharmContextSlot}] revive premium safety charm mutation from {mutationSource} because a live official-session bridge is attached and context mutations must come from official-session packet history.";
                return false;
            }

            if (!ShouldApplyPacketOwnedRevivePremiumSafetyCharmContextMutationWithOfficialHistory(
                    _packetOwnedRevivePremiumSafetyCharmOfficialMutationObserved,
                    mutationFromOfficialSession))
            {
                message =
                    $"Ignored packet-owned CWvsContext[{ReviveOwnerPremiumSafetyCharmContextSlot}] revive premium safety charm mutation from {mutationSource} because official-session context mutation history is already active for the current runtime owner.";
                return false;
            }

            if (mutationFromOfficialSession)
            {
                _packetOwnedRevivePremiumSafetyCharmOfficialMutationObserved = true;
            }

            if (hasOverride)
            {
                _packetOwnedLocalUtilityContext.SetRevivePremiumSafetyCharmContextValue(armed, mutationSource, currTickCount, runtimeCharacterId);
                message = $"Applied revive premium safety charm context armed={(armed ? 1 : 0)}.";
            }
            else
            {
                _packetOwnedLocalUtilityContext.ClearRevivePremiumSafetyCharmContextValue(mutationSource, currTickCount, runtimeCharacterId);
                message = "Cleared revive premium safety charm context.";
            }

            ShowUtilityFeedbackMessage($"{message} {_packetOwnedLocalUtilityContext.DescribeRevivePremiumSafetyCharmContext(ReviveOwnerPremiumSafetyCharmContextSlot)}");
            return true;
        }

        internal static bool TryDecodePacketOwnedRevivePremiumSafetyCharmContextPayload(
            byte[] payload,
            out bool hasOverride,
            out bool armed,
            out string message)
        {
            hasOverride = false;
            armed = false;
            message = "Revive premium safety charm context payload is missing.";
            if (payload == null || payload.Length == 0)
            {
                return false;
            }

            if (payload.Length == sizeof(int))
            {
                // CUIRevive::OnCreate reads CWvsContext slot 2073 as a DWORD gate.
                int contextSlotValue = BitConverter.ToInt32(payload, 0);
                hasOverride = true;
                armed = contextSlotValue != 0;
                message = $"Decoded packet-authored CWvsContext[{ReviveOwnerPremiumSafetyCharmContextSlot}] DWORD armed={(armed ? 1 : 0)}.";
                return true;
            }

            if (payload.Length > 2)
            {
                message = "Revive premium safety charm context payload must be [0] to clear, [1,<armed>] to set, or a 4-byte CWvsContext[2073] DWORD value.";
                return false;
            }

            hasOverride = payload[0] != 0;
            armed = hasOverride && (payload.Length == 1 || payload[1] != 0);
            message = hasOverride
                ? $"Decoded revive premium safety charm context armed={(armed ? 1 : 0)}."
                : "Decoded revive premium safety charm context clear.";
            return true;
        }

        internal static bool TryDecodePacketOwnedRadioCreateLayerContextPayload(
            byte[] payload,
            out bool hasOverride,
            out bool bLeft,
            out string message)
        {
            hasOverride = false;
            bLeft = false;
            message = "Radio CreateLayer context payload is missing.";
            if (payload == null || payload.Length == 0)
            {
                return false;
            }

            if (payload.Length == sizeof(int))
            {
                // CUIRadio::CreateLayer consumes the packet-owned CWvsContext
                // slot as a DWORD bLeft value; zero is an authored right-side
                // value, not a simulator clear command.
                int contextSlotValue = BitConverter.ToInt32(payload, 0);
                hasOverride = true;
                bLeft = contextSlotValue != 0;
                message = $"Decoded packet-authored CWvsContext[3562] radio bLeft DWORD={(bLeft ? 1 : 0)}.";
                return true;
            }

            if (payload.Length > 2)
            {
                message = "Radio CreateLayer context payload must be [0] to clear, [1] to set left, [1,<bLeft>] to set right/left explicitly, or a 4-byte CWvsContext[3562] DWORD value.";
                return false;
            }

            hasOverride = payload[0] != 0;
            bLeft = hasOverride && (payload.Length == 1 || payload[1] != 0);
            message = hasOverride
                ? $"Decoded packet-authored CWvsContext[3562] radio bLeft={(bLeft ? 1 : 0)}."
                : "Decoded packet-authored CWvsContext[3562] radio bLeft clear.";
            return true;
        }

        internal static bool TryDecodePacketOwnedRadioSchedulePayload(
            byte[] payload,
            bool requireExactClientPayload,
            out string trackDescriptor,
            out int timeValue,
            out string message)
        {
            trackDescriptor = null;
            timeValue = 0;
            message = "Radio-schedule payload is missing.";
            if (payload == null || payload.Length == 0)
            {
                return false;
            }

            try
            {
                using MemoryStream stream = new(payload, writable: false);
                using BinaryReader reader = new(stream, Encoding.Default, leaveOpen: false);
                trackDescriptor = ReadPacketOwnedMapleString(reader);
                if (requireExactClientPayload && reader.BaseStream.Length - reader.BaseStream.Position < sizeof(int))
                {
                    message = "Radio-schedule client payload must match CUserLocal::OnRadioSchedule: DecodeStr followed by Decode4 timeValue.";
                    return false;
                }

                if (reader.BaseStream.Position <= reader.BaseStream.Length - sizeof(uint))
                {
                    uint decodedTimeValue = reader.ReadUInt32();
                    if (decodedTimeValue > int.MaxValue)
                    {
                        message = "Radio-schedule client payload timeValue exceeded the supported signed playback range.";
                        return false;
                    }

                    timeValue = (int)decodedTimeValue;
                }
                else
                {
                    timeValue = 0;
                }
                if (requireExactClientPayload && reader.BaseStream.Position != reader.BaseStream.Length)
                {
                    message = "Radio-schedule client payload contained trailing bytes after DecodeStr and Decode4 timeValue.";
                    return false;
                }

                message = "Decoded packet-owned radio schedule payload.";
                return true;
            }
            catch (Exception ex) when (ex is EndOfStreamException or IOException)
            {
                message = "Radio-schedule payload could not be decoded.";
                return false;
            }
        }

        private string ApplyPacketOwnedRadioSchedule(
            string trackDescriptor,
            int timeValue,
            int packetType,
            string packetSource)
        {
            StampPacketOwnedUtilityRequestState();
            SyncPacketOwnedRadioCreateLayerContextLifecycle();
            SyncPacketOwnedRadioScheduleContextLifecycle();
            string scheduleSource = string.IsNullOrWhiteSpace(packetSource)
                ? ResolvePacketOwnedRadioScheduleSourceLabel(packetType, null)
                : packetSource.Trim();
            _lastPacketOwnedRadioSchedulePacketType = packetType;
            _lastPacketOwnedRadioScheduleSource = scheduleSource;
            _lastPacketOwnedRadioScheduleFromOfficialSession = IsPacketOwnedRadioScheduleOfficialSessionSource(scheduleSource);

            string normalizedTrackDescriptor = trackDescriptor?.Trim();
            if (string.IsNullOrWhiteSpace(normalizedTrackDescriptor))
            {
                string emptyMessage = $"Packet-owned radio schedule from {scheduleSource} did not include a track descriptor.";
                _lastPacketOwnedRadioStatusMessage = emptyMessage;
                NotifyEventAlarmOwnerActivity("packet-owned radio schedule");
                ShowUtilityFeedbackMessage(emptyMessage);
                return emptyMessage;
            }

            if (IsPacketOwnedRadioPlaying())
            {
                string ignoreMessage = $"Ignored packet-owned radio schedule from {scheduleSource} for {normalizedTrackDescriptor} because a radio session is already active.";
                _lastPacketOwnedRadioStatusMessage = ignoreMessage;
                return ignoreMessage;
            }

            SetPacketOwnedRadioScheduleContext(normalizedTrackDescriptor, timeValue, scheduleSource);

            if (!TryResolvePacketOwnedRadioTrack(
                normalizedTrackDescriptor,
                out PacketOwnedRadioTrackResolution trackResolution))
            {
                RollBackPacketOwnedRadioScheduleContextAfterFailedStart(scheduleSource, "track-unresolved");
                string missingMessage = $"Packet-owned radio track '{normalizedTrackDescriptor}' from {scheduleSource} could not be resolved in the loaded Sound/*.img data.";
                _lastPacketOwnedRadioStatusMessage = missingMessage;
                NotifyEventAlarmOwnerActivity("packet-owned radio schedule");
                ShowUtilityFeedbackMessage(missingMessage);
                return missingMessage;
            }

            try
            {
                _packetOwnedRadioAudio?.Dispose();
                if (!TryResolvePacketOwnedRadioPlaybackOffset(
                        timeValue,
                        out int normalizedTimeValue,
                        out int startOffsetMs))
                {
                    RollBackPacketOwnedRadioScheduleContextAfterFailedStart(scheduleSource, "offset-invalid");
                    const string invalidOffsetMessage = "Packet-owned radio schedule did not contain a usable playback offset.";
                    _lastPacketOwnedRadioStatusMessage = invalidOffsetMessage;
                    NotifyEventAlarmOwnerActivity("packet-owned radio schedule");
                    ShowUtilityFeedbackMessage(invalidOffsetMessage);
                    return invalidOffsetMessage;
                }

                int clientTrackDurationMs = ResolvePacketOwnedRadioClientTrackDurationMs(trackResolution.AudioProperty);
                if (ShouldRejectPacketOwnedRadioOffsetFromClientLength(startOffsetMs, clientTrackDurationMs))
                {
                    RollBackPacketOwnedRadioScheduleContextAfterFailedStart(scheduleSource, "offset-past-client-length");
                    string rejectedByClientLengthMessage =
                        $"Ignored packet-owned radio schedule for {trackResolution.DisplayName} because authored timeValue {normalizedTimeValue}s resolves to {startOffsetMs} ms, past the client-recovered {clientTrackDurationMs} ms track length.";
                    _lastPacketOwnedRadioStatusMessage = rejectedByClientLengthMessage;
                    NotifyEventAlarmOwnerActivity("packet-owned radio schedule");
                    ShowUtilityFeedbackMessage(rejectedByClientLengthMessage);
                    return rejectedByClientLengthMessage;
                }

                bool rawBufferLoaded = TryLoadPacketOwnedRadioClientRawBuffer(
                    trackResolution.AudioProperty,
                    out int rawBufferLength,
                    out string rawBufferFailureReason);
                int startTick = Environment.TickCount;
                PacketOwnedRadioMmsPlayPlan mmsPlayPlan = ResolvePacketOwnedRadioMmsPlayPlan(
                    trackPropertyLoaded: true,
                    soundObjectLoaded: trackResolution.AudioProperty != null,
                    rawBufferLoaded: rawBufferLoaded,
                    msLength: clientTrackDurationMs,
                    requestedPositionMs: startOffsetMs,
                    currentTick: startTick,
                    rawBufferFailureReason: rawBufferFailureReason);
                _lastPacketOwnedRadioClientTrackPropertyLoaded = mmsPlayPlan.TrackPropertyLoaded;
                _lastPacketOwnedRadioClientSoundObjectLoaded = mmsPlayPlan.SoundObjectLoaded;
                _lastPacketOwnedRadioClientRawBufferLoaded = mmsPlayPlan.RawBufferLoaded;
                _lastPacketOwnedRadioClientRawBufferLength = rawBufferLength;
                _lastPacketOwnedRadioClientMmsPlaySucceeded = mmsPlayPlan.Started;
                _lastPacketOwnedRadioClientMmsPlayFailureReason = mmsPlayPlan.FailureReason;
                _lastPacketOwnedRadioClientHandleStatus = mmsPlayPlan.HandleStatus;
                _packetOwnedRadioClientHandle = null;
                if (!mmsPlayPlan.Started)
                {
                    RollBackPacketOwnedRadioScheduleContextAfterFailedStart(scheduleSource, "mms-play-failed");
                    string mmsPlayRejectedMessage =
                        $"Packet-owned radio track '{normalizedTrackDescriptor}' could not start through the client-shaped MMS_Play path: {mmsPlayPlan.FailureReason}";
                    _lastPacketOwnedRadioStatusMessage = mmsPlayRejectedMessage;
                    NotifyEventAlarmOwnerActivity("packet-owned radio schedule");
                    ShowUtilityFeedbackMessage(mmsPlayRejectedMessage);
                    return mmsPlayRejectedMessage;
                }

                _packetOwnedRadioClientHandle = PacketOwnedRadioClientPlaybackHandle.Create(
                    mmsPlayPlan,
                    rawBufferLength);
                _packetOwnedRadioAudio = new MonoGameBgmPlayer(trackResolution.AudioProperty, looped: false, startOffsetMs);
                ResolvePacketOwnedRadioRealizedPlaybackWindow(
                    _packetOwnedRadioAudio,
                    out int trackDurationMs,
                    out int realizedStartOffsetMs,
                    out int realizedRemainingDurationMs);
                bool hasClientTrackDuration = HasPacketOwnedRadioClientTrackDuration(clientTrackDurationMs);
                int authoritativeTrackDurationMs = ResolvePacketOwnedRadioAuthoritativeTrackDurationMs(
                    clientTrackDurationMs,
                    trackDurationMs);
                int authoritativeStartOffsetMs = ResolvePacketOwnedRadioAuthoritativeStartOffsetMs(
                    startOffsetMs,
                    realizedStartOffsetMs,
                    authoritativeTrackDurationMs,
                    hasClientTrackDuration);
                int authoritativeRemainingDurationMs = ResolvePacketOwnedRadioAuthoritativeRemainingDurationMs(
                    authoritativeTrackDurationMs,
                    authoritativeStartOffsetMs);
                if (!IsPacketOwnedRadioPlaybackOffsetUsable(authoritativeStartOffsetMs, authoritativeTrackDurationMs))
                {
                    RollBackPacketOwnedRadioScheduleContextAfterFailedStart(scheduleSource, "offset-unusable");
                    _packetOwnedRadioAudio.Dispose();
                    _packetOwnedRadioAudio = null;
                    _packetOwnedRadioClientHandle = null;
                    ResetPacketOwnedRadioCreateLayerSessionState();
                    string rejectedMessage = authoritativeTrackDurationMs > 0
                        ? $"Ignored packet-owned radio schedule for {trackResolution.DisplayName} because authored timeValue {normalizedTimeValue}s resolves to {authoritativeStartOffsetMs} ms, past the {authoritativeTrackDurationMs} ms track length."
                        : $"Ignored packet-owned radio schedule for {trackResolution.DisplayName} because the resolved track length is unavailable.";
                    _lastPacketOwnedRadioStatusMessage = rejectedMessage;
                    NotifyEventAlarmOwnerActivity("packet-owned radio schedule");
                    ShowUtilityFeedbackMessage(rejectedMessage);
                    return rejectedMessage;
                }

                _lastPacketOwnedRadioTrackDescriptor = normalizedTrackDescriptor;
                _lastPacketOwnedRadioResolvedTrackDescriptor = trackResolution.ResolvedTrackDescriptor;
                _lastPacketOwnedRadioResolvedDescriptor = trackResolution.ResolvedAudioDescriptor;
                _lastPacketOwnedRadioDisplayName = trackResolution.DisplayName;
                _lastPacketOwnedRadioTimeValue = normalizedTimeValue;
                _lastPacketOwnedRadioRequestedStartOffsetMs = startOffsetMs;
                _lastPacketOwnedRadioStartOffsetMs = authoritativeStartOffsetMs;
                _lastPacketOwnedRadioTrackDurationMs = authoritativeTrackDurationMs;
                _lastPacketOwnedRadioAvailableDurationMs = authoritativeRemainingDurationMs;
                _lastPacketOwnedRadioClientTrackDurationMs = mmsPlayPlan.MsLength;
                _lastPacketOwnedRadioClientPlaybackSeedMs = hasClientTrackDuration
                    ? mmsPlayPlan.MsPosition
                    : 0;
                _lastPacketOwnedRadioClientPlaybackPositionMs = _lastPacketOwnedRadioClientPlaybackSeedMs;
                _lastPacketOwnedRadioClientHandleStatus = mmsPlayPlan.HandleStatus;
                _lastPacketOwnedRadioMmsStopPlan = default;
                _lastPacketOwnedRadioStartTick = startTick;
                CapturePacketOwnedRadioCreateLayerSessionState();
                _lastPacketOwnedRadioExpectedStopTick = mmsPlayPlan.LastUpdateTick != int.MinValue
                    ? mmsPlayPlan.LastUpdateTick
                    : ResolvePacketOwnedRadioExpectedStopTick(startTick, _lastPacketOwnedRadioAvailableDurationMs);
                _lastPacketOwnedRadioLastPollTick = ResolvePacketOwnedRadioInitialUpdateTick(
                    startTick,
                    _lastPacketOwnedRadioAvailableDurationMs);
                _packetOwnedRadioMuted = false;
                _appliedPacketOwnedRadioVolume = 0f;
                _utilityAudioMixLastTick = startTick;
                _lastPacketOwnedRadioStatusMessage = FormatPacketOwnedRadioStartStatusMessage(
                    normalizedTimeValue,
                    scheduleSource,
                    trackResolution.DisplayName);
                NotifyEventAlarmOwnerActivity("packet-owned radio schedule");

                _packetOwnedRadioAudio.Play();
                ApplyUtilityAudioSettings();
                ShowPacketOwnedRadioWindow();
                _chat?.AddClientChatMessage(
                    FormatPacketOwnedRadioChatMessage(PacketOwnedRadioStartStringPoolId, trackResolution.DisplayName),
                    Environment.TickCount,
                    12);

                string message =
                    $"Started packet-owned radio playback from {scheduleSource} for {trackResolution.DisplayName} " +
                    $"via {FormatPacketOwnedRadioTemplateResolution(PacketOwnedRadioAudioTemplateStringPoolId, normalizedTrackDescriptor, trackResolution.ResolvedAudioDescriptor)} " +
                    $"(client ms_length={Math.Max(0, _lastPacketOwnedRadioClientTrackDurationMs)} ms, ms_position={Math.Max(0, _lastPacketOwnedRadioClientPlaybackSeedMs)} ms).";
                ShowUtilityFeedbackMessage(message);
                return message;
            }
            catch (Exception ex)
            {
                RollBackPacketOwnedRadioScheduleContextAfterFailedStart(scheduleSource, "exception");
                _packetOwnedRadioAudio?.Dispose();
                _packetOwnedRadioAudio = null;
                _packetOwnedRadioClientHandle = null;
                ResetPacketOwnedRadioCreateLayerSessionState();
                string failedMessage = $"Packet-owned radio track '{normalizedTrackDescriptor}' could not start: {ex.Message}";
                _lastPacketOwnedRadioStatusMessage = failedMessage;
                NotifyEventAlarmOwnerActivity("packet-owned radio schedule");
                ShowUtilityFeedbackMessage(failedMessage);
                return failedMessage;
            }
        }

        private void RollBackPacketOwnedRadioScheduleContextAfterFailedStart(string scheduleSource, string reason)
        {
            string normalizedSource = string.IsNullOrWhiteSpace(scheduleSource)
                ? "simulator-local"
                : scheduleSource.Trim();
            string normalizedReason = string.IsNullOrWhiteSpace(reason)
                ? "start-failed"
                : reason.Trim();
            ClearPacketOwnedRadioScheduleContext($"radio-start-failed:{normalizedReason} via {normalizedSource}");
        }

        internal static bool TryResolvePacketOwnedRadioPlaybackWindow(
            int timeValue,
            int trackDurationMs,
            out int normalizedTimeValue,
            out int startOffsetMs,
            out int remainingDurationMs)
        {
            if (!TryResolvePacketOwnedRadioPlaybackOffset(
                    timeValue,
                    out normalizedTimeValue,
                    out startOffsetMs))
            {
                remainingDurationMs = 0;
                return false;
            }

            remainingDurationMs = Math.Max(0, trackDurationMs - startOffsetMs);
            return IsPacketOwnedRadioPlaybackOffsetUsable(startOffsetMs, trackDurationMs);
        }

        internal static bool TryResolvePacketOwnedRadioPlaybackOffset(int timeValue, out int normalizedTimeValue, out int startOffsetMs)
        {
            normalizedTimeValue = Math.Max(0, timeValue);
            if (normalizedTimeValue > int.MaxValue / 1000)
            {
                startOffsetMs = int.MaxValue;
                return false;
            }

            startOffsetMs = normalizedTimeValue * 1000;
            return true;
        }

        internal static bool IsPacketOwnedRadioPlaybackOffsetUsable(int startOffsetMs, int trackDurationMs)
        {
            return startOffsetMs >= 0
                && trackDurationMs > 0
                && startOffsetMs <= trackDurationMs;
        }

        internal static void ResolvePacketOwnedRadioRealizedPlaybackWindow(
            MonoGameBgmPlayer audioPlayer,
            out int trackDurationMs,
            out int startOffsetMs,
            out int remainingDurationMs)
        {
            trackDurationMs = ResolvePacketOwnedRadioDurationMs(audioPlayer?.TotalDuration ?? TimeSpan.Zero);
            startOffsetMs = ResolvePacketOwnedRadioDurationMs(audioPlayer?.StartOffset ?? TimeSpan.Zero);
            remainingDurationMs = ResolvePacketOwnedRadioDurationMs(audioPlayer?.Duration ?? TimeSpan.Zero);
        }

        internal static int ResolvePacketOwnedRadioDurationMs(TimeSpan duration)
        {
            return (int)Math.Clamp(
                Math.Round(Math.Max(0d, duration.TotalMilliseconds)),
                0d,
                int.MaxValue);
        }

        internal static int ResolvePacketOwnedRadioExpectedStopTick(int startTick, int remainingDurationMs)
        {
            long expectedStopTick = (long)startTick + Math.Max(0, remainingDurationMs);
            return expectedStopTick > int.MaxValue
                ? int.MaxValue
                : expectedStopTick < int.MinValue
                    ? int.MinValue
                    : (int)expectedStopTick;
        }

        internal static int ResolvePacketOwnedRadioMmsLastUpdateTick(int currentTick, int positionMs, int lengthMs)
        {
            long mmsLastUpdateTick = (long)currentTick - Math.Max(0, positionMs) + Math.Max(0, lengthMs);
            return mmsLastUpdateTick > int.MaxValue
                ? int.MaxValue
                : mmsLastUpdateTick < int.MinValue
                    ? int.MinValue
                    : (int)mmsLastUpdateTick;
        }

        internal static int ResolvePacketOwnedRadioInitialUpdateTick(int startTick, int remainingDurationMs)
        {
            return ResolvePacketOwnedRadioExpectedStopTick(startTick, remainingDurationMs);
        }

        internal static int ResolvePacketOwnedRadioFirstCompletionPollTick(int lastUpdateTick)
        {
            long firstPollTick = (long)lastUpdateTick + PacketOwnedRadioUpdatePollIntervalMs + 1L;
            return firstPollTick > int.MaxValue
                ? int.MaxValue
                : firstPollTick < int.MinValue
                    ? int.MinValue
                    : (int)firstPollTick;
        }

        internal static bool ShouldPollPacketOwnedRadioCompletion(int currentTickCount, int lastUpdateTick)
        {
            return lastUpdateTick != int.MinValue
                && unchecked(currentTickCount - lastUpdateTick) > PacketOwnedRadioUpdatePollIntervalMs;
        }

        internal static int ResolvePacketOwnedRadioClientPlaybackPositionMs(
            int sessionStartOffsetMs,
            int sessionStartTick,
            int currentTickCount,
            int clientTrackDurationMs)
        {
            int normalizedTrackDurationMs = Math.Max(0, clientTrackDurationMs);
            int elapsedMs = sessionStartTick == int.MinValue
                ? 0
                : Math.Max(0, unchecked(currentTickCount - sessionStartTick));
            long playbackPositionMs = (long)Math.Max(0, sessionStartOffsetMs) + elapsedMs;
            if (normalizedTrackDurationMs <= 0)
            {
                return playbackPositionMs > int.MaxValue
                    ? int.MaxValue
                    : (int)playbackPositionMs;
            }

            return (int)Math.Clamp(playbackPositionMs, 0, normalizedTrackDurationMs);
        }

        internal static bool IsPacketOwnedRadioClientHandleStopped(int playbackPositionMs, int clientTrackDurationMs)
        {
            int normalizedTrackDurationMs = Math.Max(0, clientTrackDurationMs);
            return normalizedTrackDurationMs > 0
                && Math.Max(0, playbackPositionMs) >= normalizedTrackDurationMs;
        }

        internal static PacketOwnedRadioClientHandleStatus ResolvePacketOwnedRadioClientHandleStatusAfterPlay(
            int playbackPositionMs,
            int clientTrackDurationMs)
        {
            if (!HasPacketOwnedRadioClientTrackDuration(clientTrackDurationMs))
            {
                return PacketOwnedRadioClientHandleStatus.Loaded;
            }

            return IsPacketOwnedRadioClientHandleStopped(playbackPositionMs, clientTrackDurationMs)
                ? PacketOwnedRadioClientHandleStatus.Done
                : PacketOwnedRadioClientHandleStatus.Playing;
        }

        internal static PacketOwnedRadioClientHandleStatus ResolvePacketOwnedRadioClientHandleStatusAfterPoll(
            PacketOwnedRadioClientHandleStatus currentStatus,
            bool clientHandleStopped)
        {
            if (clientHandleStopped)
            {
                return PacketOwnedRadioClientHandleStatus.Done;
            }

            return currentStatus == PacketOwnedRadioClientHandleStatus.None
                || currentStatus == PacketOwnedRadioClientHandleStatus.Unloaded
                    ? PacketOwnedRadioClientHandleStatus.Loaded
                    : currentStatus;
        }

        internal static PacketOwnedRadioClientHandleStatus ResolvePacketOwnedRadioClientHandleStatusAfterStop(
            PacketOwnedRadioClientHandleStatus currentStatus)
        {
            return currentStatus == PacketOwnedRadioClientHandleStatus.None
                ? PacketOwnedRadioClientHandleStatus.None
                : PacketOwnedRadioClientHandleStatus.Unloaded;
        }

        internal static PacketOwnedRadioClientHandleStatus ResolvePacketOwnedRadioClientHandleStatusBeforeStop(
            PacketOwnedRadioClientHandleStatus currentStatus,
            int sessionStartOffsetMs,
            int sessionStartTick,
            int currentTickCount,
            int clientTrackDurationMs,
            out int playbackPositionMs)
        {
            playbackPositionMs = ResolvePacketOwnedRadioClientPlaybackPositionMs(
                sessionStartOffsetMs,
                sessionStartTick,
                currentTickCount,
                clientTrackDurationMs);
            if (currentStatus == PacketOwnedRadioClientHandleStatus.None
                || currentStatus == PacketOwnedRadioClientHandleStatus.Unloaded)
            {
                return currentStatus;
            }

            return ResolvePacketOwnedRadioClientHandleStatusAfterPoll(
                currentStatus,
                IsPacketOwnedRadioClientHandleStopped(playbackPositionMs, clientTrackDurationMs));
        }

        internal static PacketOwnedRadioMmsStopPlan ResolvePacketOwnedRadioMmsStopPlan(
            bool trackPropertyLoaded,
            bool soundObjectLoaded,
            bool rawBufferLoaded,
            PacketOwnedRadioClientHandleStatus currentStatus)
        {
            bool enteredStop = trackPropertyLoaded
                || soundObjectLoaded
                || rawBufferLoaded
                || currentStatus != PacketOwnedRadioClientHandleStatus.None;
            bool hasAilHandle = rawBufferLoaded
                && currentStatus != PacketOwnedRadioClientHandleStatus.None
                && currentStatus != PacketOwnedRadioClientHandleStatus.Unloaded;
            bool shouldHaltHandle = hasAilHandle
                && currentStatus == PacketOwnedRadioClientHandleStatus.Playing;
            bool shouldUnloadHandle = hasAilHandle;

            return new PacketOwnedRadioMmsStopPlan(
                EnteredStop: enteredStop,
                HaltedHandle: shouldHaltHandle,
                UnloadedHandle: shouldUnloadHandle,
                ClearedHandle: shouldUnloadHandle,
                ReleasedSoundObject: soundObjectLoaded,
                ReleasedTrackProperty: trackPropertyLoaded,
                HandleStatus: ResolvePacketOwnedRadioClientHandleStatusAfterStop(currentStatus));
        }

        internal static PacketOwnedRadioMmsPlayPlan ResolvePacketOwnedRadioMmsPlayPlan(
            bool trackPropertyLoaded,
            bool soundObjectLoaded,
            bool rawBufferLoaded,
            int msLength,
            int requestedPositionMs,
            int currentTick,
            string rawBufferFailureReason = null)
        {
            int normalizedLength = Math.Max(0, msLength);
            int normalizedPosition = Math.Max(0, requestedPositionMs);
            if (!trackPropertyLoaded)
            {
                return new PacketOwnedRadioMmsPlayPlan(
                    TrackPropertyLoaded: false,
                    SoundObjectLoaded: false,
                    RawBufferLoaded: false,
                    Started: false,
                    MsLength: normalizedLength,
                    MsPosition: normalizedPosition,
                    LastUpdateTick: int.MinValue,
                    HandleStatus: PacketOwnedRadioClientHandleStatus.None,
                    FailureReason: "CRadioManager::Play could not resolve the StringPool[0x1501] track property.");
            }

            if (!soundObjectLoaded)
            {
                return new PacketOwnedRadioMmsPlayPlan(
                    TrackPropertyLoaded: true,
                    SoundObjectLoaded: false,
                    RawBufferLoaded: false,
                    Started: false,
                    MsLength: normalizedLength,
                    MsPosition: normalizedPosition,
                    LastUpdateTick: int.MinValue,
                    HandleStatus: PacketOwnedRadioClientHandleStatus.Loaded,
                    FailureReason: "CRadioManager::MMS_Play could not query the StringPool[0x1502] IWzSound object.");
            }

            if (!rawBufferLoaded)
            {
                string failureReason = string.IsNullOrWhiteSpace(rawBufferFailureReason)
                    ? "CRadioManager::MMS_Play could not read a raw IWzSound buffer."
                    : rawBufferFailureReason.Trim();
                return new PacketOwnedRadioMmsPlayPlan(
                    TrackPropertyLoaded: true,
                    SoundObjectLoaded: true,
                    RawBufferLoaded: false,
                    Started: false,
                    MsLength: normalizedLength,
                    MsPosition: normalizedPosition,
                    LastUpdateTick: int.MinValue,
                    HandleStatus: PacketOwnedRadioClientHandleStatus.Loaded,
                    FailureReason: failureReason);
            }

            if (normalizedLength < normalizedPosition)
            {
                return new PacketOwnedRadioMmsPlayPlan(
                    TrackPropertyLoaded: true,
                    SoundObjectLoaded: true,
                    RawBufferLoaded: true,
                    Started: false,
                    MsLength: normalizedLength,
                    MsPosition: normalizedPosition,
                    LastUpdateTick: int.MinValue,
                    HandleStatus: PacketOwnedRadioClientHandleStatus.Unloaded,
                    FailureReason: $"CRadioManager::MMS_Play rejected ms_position {normalizedPosition} because AIL_quick_ms_length returned {normalizedLength}.");
            }

            int lastUpdateTick = HasPacketOwnedRadioClientTrackDuration(normalizedLength)
                ? ResolvePacketOwnedRadioMmsLastUpdateTick(currentTick, normalizedPosition, normalizedLength)
                : int.MinValue;
            PacketOwnedRadioClientHandleStatus handleStatus = ResolvePacketOwnedRadioClientHandleStatusAfterPlay(
                normalizedPosition,
                normalizedLength);
            return new PacketOwnedRadioMmsPlayPlan(
                TrackPropertyLoaded: true,
                SoundObjectLoaded: true,
                RawBufferLoaded: true,
                Started: true,
                MsLength: normalizedLength,
                MsPosition: normalizedPosition,
                LastUpdateTick: lastUpdateTick,
                HandleStatus: handleStatus,
                FailureReason: string.Empty);
        }

        private static bool TryLoadPacketOwnedRadioClientRawBuffer(WzBinaryProperty audioProperty, out int rawBufferLength, out string failureReason)
        {
            rawBufferLength = 0;
            failureReason = string.Empty;
            if (audioProperty == null)
            {
                failureReason = "CRadioManager::MMS_Play could not query the StringPool[0x1502] IWzSound object.";
                return false;
            }

            try
            {
                byte[] rawBuffer = audioProperty.GetBytes(false);
                if (rawBuffer == null || rawBuffer.Length == 0)
                {
                    failureReason = "CRadioManager::MMS_Play received an empty IWzSound raw buffer.";
                    return false;
                }

                rawBufferLength = rawBuffer.Length;
                return true;
            }
            catch (Exception ex)
            {
                failureReason = $"CRadioManager::MMS_Play raw IWzSound buffer load failed: {ex.Message}";
                return false;
            }
        }

        internal static bool ShouldCompletePacketOwnedRadioSchedule(
            int currentTickCount,
            int expectedStopTick,
            bool clientHandleStopped,
            bool useBackendStopSignal,
            bool backendStopped)
        {
            if (clientHandleStopped)
            {
                return true;
            }

            if (useBackendStopSignal && backendStopped)
            {
                return true;
            }

            return expectedStopTick != int.MinValue
                && unchecked(currentTickCount - expectedStopTick) > PacketOwnedRadioUpdatePollIntervalMs;
        }

        private void UpdatePacketOwnedRadioSchedule(int currentTickCount)
        {
            SyncPacketOwnedRadioOfficialSessionLifecycle();
            SyncPacketOwnedRadioCreateLayerContextLifecycle();
            SyncPacketOwnedRadioScheduleContextLifecycle();
            if (!IsPacketOwnedRadioPlaying())
            {
                return;
            }

            if (!ShouldPollPacketOwnedRadioCompletion(currentTickCount, _lastPacketOwnedRadioLastPollTick))
            {
                return;
            }

            bool clientHandleStopped;
            if (_packetOwnedRadioClientHandle != null)
            {
                clientHandleStopped = _packetOwnedRadioClientHandle.Update(
                    _lastPacketOwnedRadioStartOffsetMs,
                    _lastPacketOwnedRadioStartTick,
                    currentTickCount);
                _lastPacketOwnedRadioClientPlaybackPositionMs = _packetOwnedRadioClientHandle.MsPosition;
                _lastPacketOwnedRadioClientHandleStatus = _packetOwnedRadioClientHandle.Status;
            }
            else
            {
                _lastPacketOwnedRadioClientPlaybackPositionMs = ResolvePacketOwnedRadioClientPlaybackPositionMs(
                    _lastPacketOwnedRadioStartOffsetMs,
                    _lastPacketOwnedRadioStartTick,
                    currentTickCount,
                    _lastPacketOwnedRadioClientTrackDurationMs);
                clientHandleStopped = IsPacketOwnedRadioClientHandleStopped(
                    _lastPacketOwnedRadioClientPlaybackPositionMs,
                    _lastPacketOwnedRadioClientTrackDurationMs);
                _lastPacketOwnedRadioClientHandleStatus = ResolvePacketOwnedRadioClientHandleStatusAfterPoll(
                    _lastPacketOwnedRadioClientHandleStatus,
                    clientHandleStopped);
            }
            bool useBackendStopSignal = !HasPacketOwnedRadioClientTrackDuration(_lastPacketOwnedRadioClientTrackDurationMs);
            bool backendStopped = _packetOwnedRadioAudio?.State == Microsoft.Xna.Framework.Audio.SoundState.Stopped;
            if (ShouldCompletePacketOwnedRadioSchedule(
                    currentTickCount,
                    _lastPacketOwnedRadioExpectedStopTick,
                    clientHandleStopped,
                    useBackendStopSignal,
                    backendStopped))
            {
                StopPacketOwnedRadioSchedule(completed: true, emitChatNotice: true);
                return;
            }

            _lastPacketOwnedRadioLastPollTick = currentTickCount;
        }

        private void SyncPacketOwnedRadioOfficialSessionLifecycle()
        {
            bool officialSessionConnected = _localUtilityOfficialSessionBridge.HasConnectedSession;
            if (!ShouldResetPacketOwnedRadioOfficialMutationOwnershipOnSessionTransition(
                    _packetOwnedRadioLastObservedOfficialSessionConnected,
                    officialSessionConnected))
            {
                return;
            }

            _packetOwnedRadioLastObservedOfficialSessionConnected = officialSessionConnected;
            _packetOwnedRadioOfficialScheduleMutationObserved = false;
            _packetOwnedRadioOfficialCreateLayerMutationObserved = false;
            if (!officialSessionConnected)
            {
                ShowUtilityFeedbackMessage(
                    "Local utility official-session bridge disconnected; packet-owned radio mutation ownership is unlocked for the next runtime session.");
                return;
            }

            bool stoppedNonOfficialRuntime = false;
            if (ShouldResetPacketOwnedRadioRuntimeForOfficialSessionAttach(
                    officialSessionConnected,
                    IsPacketOwnedRadioPlaying(),
                    _lastPacketOwnedRadioScheduleFromOfficialSession))
            {
                string trackName = GetPacketOwnedRadioTrackName();
                StopPacketOwnedRadioSchedule(completed: false, emitChatNotice: false);
                _lastPacketOwnedRadioScheduleFromOfficialSession = false;
                _lastPacketOwnedRadioStatusMessage =
                    $"Reset packet-owned radio playback for {FormatPacketOwnedRadioQuotedValue(trackName)} after the official-session bridge attached and ownership moved to packet mutation history.";
                stoppedNonOfficialRuntime = true;
            }

            bool clearedScheduleContext = false;
            if (ShouldClearPacketOwnedRadioContextOnOfficialSessionAttach(
                    officialSessionConnected,
                    _packetOwnedLocalUtilityContext.HasRadioScheduleContextValue,
                    _packetOwnedLocalUtilityContext.RadioScheduleLastMutationSource))
            {
                ClearPacketOwnedRadioScheduleContext("official-session-attach-reset");
                clearedScheduleContext = true;
            }

            bool clearedCreateLayerContext = false;
            if (ShouldClearPacketOwnedRadioContextOnOfficialSessionAttach(
                    officialSessionConnected,
                    _packetOwnedLocalUtilityContext.HasRadioCreateLayerLeftContextValue,
                    _packetOwnedLocalUtilityContext.RadioCreateLayerLastMutationSource))
            {
                ClearPacketOwnedRadioCreateLayerContext("official-session-attach-reset");
                clearedCreateLayerContext = true;
            }

            if (stoppedNonOfficialRuntime || clearedScheduleContext || clearedCreateLayerContext)
            {
                ShowUtilityFeedbackMessage(
                    $"Local utility official-session bridge attached; reset simulator-owned radio state (runtime={stoppedNonOfficialRuntime}, scheduleCtx={clearedScheduleContext}, createLayerCtx={clearedCreateLayerContext}) so ownership follows official packet mutation history.");
                return;
            }

            ShowUtilityFeedbackMessage(
                "Local utility official-session bridge attached; packet-owned radio mutation ownership now follows official packet history.");
        }

        private void UpdatePacketOwnedTutorRuntime(int currentTickCount)
        {
            SyncPacketOwnedTutorLifecycle(currentTickCount);
            _packetOwnedTutorRuntime.Update(currentTickCount);
            SyncPacketOwnedTutorSummonState(currentTickCount);
        }

