        {
            if (string.IsNullOrWhiteSpace(message))
            {
                return;
            }

            ShowLoginUtilityDialog(
                "Notice",
                message,
                LoginUtilityDialogButtonLayout.Ok,
                LoginUtilityDialogAction.DismissOnly,
                frameVariant: LoginUtilityDialogFrameVariant.UtilDlgNotice,
