        private void ShowPacketOwnedSkillCooldownNotification(
            SkillData skill,
            int skillId,
            string skillName,
            int remainingMs,
            SkillCooldownNotificationTransition transition)
        {
            if (!ShouldShowOffBarSkillCooldownNotification(skillId)
                || transition == SkillCooldownNotificationTransition.None)
            {
                return;
            }

            string resolvedSkillName = string.IsNullOrWhiteSpace(skillName)
                ? $"Skill {skillId}"
                : skillName;
            string notification = transition == SkillCooldownNotificationTransition.Started
                ? $"{resolvedSkillName} is cooling down. {FormatCooldownNotificationSeconds(remainingMs)}."
                : $"{resolvedSkillName} is ready.";
            ShowSkillCooldownNotification(
                skill,
                notification,
                currTickCount,
                addChat: transition == SkillCooldownNotificationTransition.Ready,
                transition == SkillCooldownNotificationTransition.Started
                    ? SkillCooldownNoticeType.Started
                    : SkillCooldownNoticeType.Ready);
        }

        private void ApplyPacketOwnedBattleshipCooldownSideEffects(int remainingUnits)
        {
            int skillLevel = Math.Max(0, _playerManager.Skills?.GetSkillLevel(PacketOwnedBattleshipSkillId) ?? 0);
            int characterLevel = Math.Max(0, _playerManager?.Player?.Build?.Level ?? 0);
            if (remainingUnits > 0)
            {
                int maxDurability = ResolvePacketOwnedBattleshipMaxDurability(skillLevel, characterLevel);
                int boundedMaxDurability = Math.Max(0, maxDurability);
                int boundedCurrentDurability = boundedMaxDurability > 0
                    ? Math.Clamp(Math.Max(0, remainingUnits), 0, boundedMaxDurability)
                    : Math.Max(0, remainingUnits);
                _packetOwnedBattleshipDurabilityPresentation = new PacketOwnedBattleshipDurabilityPresentationState
                {
                    CurrentValue = boundedCurrentDurability,
                    MaxValue = Math.Max(boundedCurrentDurability, boundedMaxDurability)
                };
            }
            else
            {
                _packetOwnedBattleshipDurabilityPresentation = null;
            }

            SyncPacketOwnedBattleshipDurabilityPresentation(
                refreshRepairWindow: true,
                recordPassiveTemporaryStatUpdate: true);
        }

        private CharacterPart ResolveActivePacketOwnedBattleshipMountPart()
        {
            CharacterPart mountedStatePart = _playerManager?.Player?.ResolveMountedStateTamingMobPart();
            if (mountedStatePart?.Slot == EquipSlot.TamingMob
                && mountedStatePart.ItemId == PacketOwnedBattleshipMountItemId)
            {
                return mountedStatePart;
            }

            if (_playerManager?.Player?.Build?.Equipment == null
                || !_playerManager.Player.Build.Equipment.TryGetValue(EquipSlot.TamingMob, out CharacterPart mountPart)
                || mountPart?.Slot != EquipSlot.TamingMob
                || mountPart.ItemId != PacketOwnedBattleshipMountItemId)
            {
                return null;
            }

            return mountPart;
        }

        private void SyncPacketOwnedBattleshipDurabilityPresentation(
            bool refreshRepairWindow,
            bool recordPassiveTemporaryStatUpdate = false)
        {
            if (_playerManager?.Skills == null)
            {
                if (_packetOwnedBattleshipDurabilityOverride?.MountPart != null)
                {
                    RestorePacketOwnedBattleshipCooldownOverride();
                    refreshRepairWindow = true;
                }

                if (refreshRepairWindow)
                {
                    RefreshPacketOwnedBattleshipRepairWindow();
                }

                return;
            }

            bool hasPassiveTemporaryStatTrackingOwner =
                _playerManager.Skills.HasActiveClientOwnedVehicleTemporaryStatOwnerForParity(PacketOwnedBattleshipSkillId);
            bool isVehiclePresentationActive = IsPacketOwnedBattleshipVehiclePresentationActive();
            if (!TryResolvePacketOwnedBattleshipDurabilityPresentationState(out int currentValue, out int maxValue))
            {
                _playerManager.Skills.ClearAuthoritativeCooldownPresentation(PacketOwnedBattleshipSkillId);
                if (_packetOwnedBattleshipDurabilityOverride?.MountPart != null)
                {
                    RestorePacketOwnedBattleshipCooldownOverride();
                    refreshRepairWindow = true;
                }

                if (refreshRepairWindow)
                {
                    RefreshPacketOwnedBattleshipRepairWindow();
                }

                return;
            }

            bool hasPassiveTemporaryStatObject =
                TryGetPacketOwnedBattleshipPassiveTemporaryStatObjectState(out bool resolvedPassiveTemporaryStatObject)
                && resolvedPassiveTemporaryStatObject;
            bool allocatedPassiveTemporaryStatObject = false;
            if (ShouldAllocatePacketOwnedBattleshipPassiveTemporaryStatObject(
                    hasPassiveTemporaryStatTrackingOwner,
                    isVehiclePresentationActive,
                    hasPassiveTemporaryStatObject)
                && _playerManager.Skills.TryAllocatePassiveVehicleTemporaryStatObjectForParity(
                    PacketOwnedBattleshipSkillId,
                    currentValue,
                    maxValue,
                    currTickCount))
            {
                hasPassiveTemporaryStatObject = true;
                allocatedPassiveTemporaryStatObject = true;
            }

            if (!ShouldUpdatePacketOwnedBattleshipPassiveTemporaryStat(
                    hasPassiveTemporaryStatTrackingOwner,
                    hasPassiveTemporaryStatObject,
                    isVehiclePresentationActive))
            {
                _playerManager.Skills.ClearAuthoritativeCooldownPresentation(PacketOwnedBattleshipSkillId);
                if (_packetOwnedBattleshipDurabilityOverride?.MountPart != null)
                {
                    RestorePacketOwnedBattleshipCooldownOverride();
                    refreshRepairWindow = true;
                }

                if (refreshRepairWindow)
                {
                    RefreshPacketOwnedBattleshipRepairWindow();
                }

                return;
            }

            _playerManager.Skills.SetAuthoritativeVehicleDurabilityPresentation(
                PacketOwnedBattleshipSkillId,
                currentValue,
                maxValue,
                currTickCount,
                hasTemporaryObject: true,
                recordPassiveTemporaryStatUpdate: ShouldRecordPacketOwnedBattleshipPassiveTemporaryStatUpdate(
                    recordPassiveTemporaryStatUpdate,
                    allocatedPassiveTemporaryStatObject));

            CharacterPart mountPart = ResolveActivePacketOwnedBattleshipMountPart();
            if (mountPart == null)
            {
                ResetPacketOwnedBattleshipCooldownOverrideIfStale();
                if (refreshRepairWindow)
                {
                    RefreshPacketOwnedBattleshipRepairWindow();
                }

                return;
            }

            if (!ReferenceEquals(_packetOwnedBattleshipDurabilityOverride?.MountPart, mountPart))
            {
                RestorePacketOwnedBattleshipCooldownOverride();
                EnsurePacketOwnedBattleshipCooldownOverrideCaptured(mountPart);
            }

            if (!TryResolvePacketOwnedBattleshipDurabilityPresentation(
                    mountPart,
                    currentValue,
                    maxValue,
                    out int durability,
                    out int resolvedMaxDurability))
            {
                return;
            }

            bool changed = mountPart.Durability != durability || mountPart.MaxDurability != resolvedMaxDurability;
            mountPart.Durability = durability;
            mountPart.MaxDurability = resolvedMaxDurability;

            if (changed || refreshRepairWindow)
            {
                RefreshPacketOwnedBattleshipRepairWindow();
            }
        }

        private bool TryGetPacketOwnedBattleshipPassiveTemporaryStatObjectState(out bool hasPassiveTemporaryStatObject)
        {
            hasPassiveTemporaryStatObject = false;
            if (_playerManager?.Skills == null)
            {
                return false;
            }

            hasPassiveTemporaryStatObject =
                _playerManager.Skills.TryGetPassiveVehicleTemporaryStatStateForParity(
                    PacketOwnedBattleshipSkillId,
                    out SkillManager.PassiveVehicleTemporaryStatState passiveState)
                && passiveState?.HasTemporaryObject == true;
            return true;
        }

        private bool TryResolvePacketOwnedBattleshipDurabilityPresentationState(out int currentValue, out int maxValue)
        {
            currentValue = 0;
            maxValue = 0;
            if (_packetOwnedBattleshipDurabilityPresentation == null)
            {
                return false;
            }

            currentValue = Math.Max(0, _packetOwnedBattleshipDurabilityPresentation.CurrentValue);
            if (currentValue <= 0)
            {
                return false;
            }

            maxValue = Math.Max(currentValue, _packetOwnedBattleshipDurabilityPresentation.MaxValue);
            return true;
        }

        private bool IsPacketOwnedBattleshipVehiclePresentationActive()
        {
            PlayerCharacter player = _playerManager?.Player;
            if (player == null)
            {
                return false;
            }

            CharacterPart equippedMountPart = null;
            player.Build?.Equipment?.TryGetValue(EquipSlot.TamingMob, out equippedMountPart);
            CharacterPart activeMountedRenderOwner = player.ResolveMountedStateTamingMobPart();
            return ResolvePacketOwnedBattleshipMountedVehicleId(
                equippedMountPart,
                activeMountedRenderOwner,
                player.CurrentActionName) == PacketOwnedBattleshipMountItemId;
        }

        internal static int ResolvePacketOwnedBattleshipMountedVehicleId(
            CharacterPart equippedMountPart,
            CharacterPart activeMountedRenderOwner,
            string currentActionName)
        {
            return FollowCharacterEligibilityResolver.ResolveMountedVehicleId(
                equippedMountPart,
                currentActionName,
                mechanicMode: null,
                activeMountedRenderOwner: activeMountedRenderOwner);
        }

        internal static bool ShouldUpdatePacketOwnedBattleshipPassiveTemporaryStat(
            bool hasPassiveTemporaryStatTrackingOwner,
            bool hasPassiveTemporaryStatObject,
            bool isVehiclePresentationActive)
        {
            // Client evidence: CWvsContext::SetSkillCooltimeOver only calls
            // CTemporaryStatView::UpdatePassively for the Battleship sentinel
            // when SecondaryStat::IsRidingSkillVehicle is true, and that
            // routine only mutates an existing TEMPORARY_STAT node (no
            // object creation when the node is missing).
            return hasPassiveTemporaryStatTrackingOwner
                && isVehiclePresentationActive
                && hasPassiveTemporaryStatObject;
        }

        internal static bool ShouldAllocatePacketOwnedBattleshipPassiveTemporaryStatObject(
            bool hasPassiveTemporaryStatTrackingOwner,
            bool isVehiclePresentationActive,
            bool hasPassiveTemporaryStatObject)
        {
            // Client evidence: CWvsContext::SetSkillCooltimeOver does not allocate
            // TEMPORARY_STAT objects itself. The simulator therefore models
            // allocation through a separate owner-ready gate before applying the
            // UpdatePassively-style mutation path.
            return hasPassiveTemporaryStatTrackingOwner
                && isVehiclePresentationActive
                && !hasPassiveTemporaryStatObject;
        }

        internal static bool ShouldRecordPacketOwnedBattleshipPassiveTemporaryStatUpdate(
            bool recordPassiveTemporaryStatUpdate,
            bool allocatedPassiveTemporaryStatObject)
        {
            // Client evidence: SetSkillCooltimeOver itself remains the UpdatePassively entry seam.
            // When the simulator has to allocate a missing TEMPORARY_STAT owner surrogate first,
            // force one immediate update write so low-bucket metadata stays synchronized.
            return recordPassiveTemporaryStatUpdate || allocatedPassiveTemporaryStatObject;
        }

        internal static bool TryResolvePacketOwnedBattleshipDurabilityPresentation(
            CharacterPart mountPart,
            int currentValue,
            int maxValue,
            out int resolvedCurrentValue,
            out int resolvedMaxValue)
        {
            resolvedCurrentValue = 0;
            resolvedMaxValue = 0;

            if (mountPart?.Slot != EquipSlot.TamingMob || mountPart.ItemId != PacketOwnedBattleshipMountItemId)
            {
                return false;
            }

            resolvedMaxValue = Math.Max(
                0,
                Math.Max(
                    maxValue,
                    mountPart.MaxDurability ?? 0));
            resolvedCurrentValue = resolvedMaxValue > 0
                ? Math.Clamp(Math.Max(0, currentValue), 0, resolvedMaxValue)
                : Math.Max(0, currentValue);
            return true;
        }

        private void EnsurePacketOwnedBattleshipCooldownOverrideCaptured(CharacterPart mountPart)
        {
            if (mountPart?.Slot != EquipSlot.TamingMob)
            {
                return;
            }

            if (ReferenceEquals(_packetOwnedBattleshipDurabilityOverride?.MountPart, mountPart))
            {
                return;
            }

            _packetOwnedBattleshipDurabilityOverride = new PacketOwnedBattleshipDurabilityOverrideState
            {
                MountPart = mountPart,
                OriginalDurability = mountPart.Durability,
                OriginalMaxDurability = mountPart.MaxDurability
            };
        }

        private void RestorePacketOwnedBattleshipCooldownOverride()
        {
            if (_packetOwnedBattleshipDurabilityOverride?.MountPart == null)
            {
                _packetOwnedBattleshipDurabilityOverride = null;
                return;
            }

            _packetOwnedBattleshipDurabilityOverride.MountPart.Durability = _packetOwnedBattleshipDurabilityOverride.OriginalDurability;
            _packetOwnedBattleshipDurabilityOverride.MountPart.MaxDurability = _packetOwnedBattleshipDurabilityOverride.OriginalMaxDurability;
            _packetOwnedBattleshipDurabilityOverride = null;
        }

        private void ResetPacketOwnedBattleshipCooldownOverrideIfStale()
        {
            if (_packetOwnedBattleshipDurabilityOverride?.MountPart == null)
            {
                _packetOwnedBattleshipDurabilityOverride = null;
                return;
            }

            CharacterPart activeMountPart = ResolveActivePacketOwnedBattleshipMountPart();
            if (!ReferenceEquals(activeMountPart, _packetOwnedBattleshipDurabilityOverride.MountPart))
            {
                RestorePacketOwnedBattleshipCooldownOverride();
            }
        }

        private void RefreshPacketOwnedBattleshipRepairWindow()
        {
            if (uiWindowManager?.GetWindow(MapSimulatorWindowNames.RepairDurability) is RepairDurabilityWindow repairWindow)
            {
                RefreshRepairDurabilityWindow(repairWindow.NpcTemplateId, PacketOwnedBattleshipMountItemId);
            }
        }

        internal static int ResolvePacketOwnedBattleshipMaxDurability(int skillLevel, int characterLevel)
        {
            if (skillLevel <= 0 || characterLevel <= 0)
            {
                return 0;
            }

            // Client evidence: get_max_durability_of_vehicle(5221006, slv, charLevel)
            // returns 300 * level + 500 * (slv - 72) for the Battleship sentinel branch.
            return Math.Max(0, (300 * characterLevel) + (500 * (skillLevel - 72)));
        }

