        private void CapturePacketOwnedRadioCreateLayerSessionState()
        {
            SyncPacketOwnedRadioCreateLayerContextLifecycle();
            bool hasExplicitContextValue = _packetOwnedLocalUtilityContext.HasRadioCreateLayerLeftContextValue;
            bool explicitContextValue = _packetOwnedLocalUtilityContext.RadioCreateLayerLeftContextValue;
            bool minimapExpanded = miniMapUi?.IsExpandedOptionActive == true;
            _packetOwnedRadioSessionCreateLayerLeft = ResolvePacketOwnedRadioCreateLayerLeftState(
                hasExplicitContextValue,
                explicitContextValue,
                minimapExpanded);
            _packetOwnedRadioSessionCreateLayerMutationSequence = _packetOwnedLocalUtilityContext.RadioCreateLayerMutationSequence;
            string contextMutationSource = string.IsNullOrWhiteSpace(_packetOwnedLocalUtilityContext.RadioCreateLayerLastMutationSource)
                ? "unknown"
                : _packetOwnedLocalUtilityContext.RadioCreateLayerLastMutationSource.Trim();
            _packetOwnedRadioSessionCreateLayerSource = hasExplicitContextValue
                ? $"packet-owned CWvsContext[{PacketOwnedRadioCreateLayerContextSlot}]={(explicitContextValue ? 1 : 0)} from {contextMutationSource}"
                : $"minimap expanded fallback={(minimapExpanded ? 1 : 0)}";
        }

        private void EnsurePacketOwnedRadioCreateLayerSessionState()
        {
            if (ShouldCapturePacketOwnedRadioCreateLayerSessionState(
                    IsPacketOwnedRadioPlaying(),
                    _packetOwnedRadioSessionCreateLayerMutationSequence))
            {
                CapturePacketOwnedRadioCreateLayerSessionState();
            }
        }

        private void ResetPacketOwnedRadioCreateLayerSessionState()
        {
            _packetOwnedRadioSessionCreateLayerLeft = false;
            _packetOwnedRadioSessionCreateLayerMutationSequence = -1;
            _packetOwnedRadioSessionCreateLayerSource = "uninitialized";
        }

        private void SyncPacketOwnedTutorLifecycle(int currentTickCount)
        {
            int runtimeCharacterId = ResolvePacketOwnedTutorRuntimeCharacterId();
            if (runtimeCharacterId <= 0)
            {
                return;
            }

            ObservePacketOwnedTutorLevelGate(runtimeCharacterId, currentTickCount);
            if (_packetOwnedTutorRuntime.RequiresCharacterRebind(runtimeCharacterId))
            {
                RemovePacketOwnedTutorSummonForRuntimeOwner();
                _packetOwnedTutorRuntime.ResetActiveTutorForRuntimeCharacter(runtimeCharacterId, currentTickCount);
                return;
            }

            _packetOwnedTutorRuntime.BindRuntimeCharacter(runtimeCharacterId);
            if (!_packetOwnedTutorRuntime.IsActive)
            {
                _packetOwnedTutorRuntime.TryRestoreVisibleActorFromSharedVariant(runtimeCharacterId, currentTickCount);
            }
        }

        private void ObservePacketOwnedTutorLevelGate(int runtimeCharacterId, int currentTickCount)
        {
            int currentLevel = Math.Max(0, _playerManager?.Player?.Build?.Level ?? 0);
            if (_packetOwnedTutorObservedCharacterId != runtimeCharacterId)
            {
                _packetOwnedTutorObservedCharacterId = runtimeCharacterId;
                _packetOwnedTutorObservedLevel = currentLevel;
                return;
            }

            int previousObservedLevel = _packetOwnedTutorObservedLevel;
            ApplyPacketOwnedTutorAdjacentLevelUpEffects(previousObservedLevel, currentLevel);
            if (!ShouldRemovePacketOwnedTutorForLevelTransition(_packetOwnedTutorObservedLevel, currentLevel))
            {
                _packetOwnedTutorObservedLevel = currentLevel;
                return;
            }

            int tutorSkillId = ResolvePacketOwnedTutorSkillIdForCharacter(runtimeCharacterId);
            bool removedVisibleTutor = _packetOwnedTutorRuntime.IsActive
                && _packetOwnedTutorRuntime.BoundCharacterId == runtimeCharacterId
                && _packetOwnedTutorRuntime.ActiveSkillId == tutorSkillId;
            bool removedSharedTutor = false;

            if (removedVisibleTutor)
            {
                RemovePacketOwnedTutorSummonForRuntimeOwner();
                _packetOwnedTutorRuntime.ApplyRemovalRequest(
                    tutorSkillId,
                    currentTickCount,
                    "packet-owned tutor auto-removed after level 11 stat change.");
            }
            else if (_packetOwnedTutorRuntime.TryGetSharedTutorVariantForCharacter(tutorSkillId, runtimeCharacterId, out TutorVariantSnapshot sharedVariant)
                && sharedVariant.IsActive)
            {
                _packetOwnedTutorRuntime.ApplySharedRemovalRequestForCharacter(tutorSkillId, currentTickCount, runtimeCharacterId);
                removedSharedTutor = true;
            }

            if (removedVisibleTutor || removedSharedTutor)
            {
                SyncPacketOwnedTutorSummonState(currentTickCount);
            }

            _packetOwnedTutorObservedLevel = currentLevel;
        }

