        private bool TryApplyPacketOwnedChatPayload(byte[] payload, bool requireExactClientPayload, out string message)
        {
            if (!TryDecodePacketOwnedChatPayload(
                    payload,
                    requireExactClientPayload,
                    out ushort chatLogType,
                    out string chatText,
                    out bool hasChatLogType,
                    out bool hasChannelId,
                    out int channelId,
                    out message))
            {
                return false;
            }

            message = hasChannelId
                ? ApplyPacketOwnedChatMessage(chatText, chatLogType, channelId: channelId)
                : hasChatLogType
                    ? ApplyPacketOwnedChatMessage(chatText, chatLogType)
                    : ApplyPacketOwnedChatMessage(chatText);
            return true;
        }

        internal static bool TryDecodePacketOwnedChatPayload(
            byte[] payload,
            bool requireExactClientPayload,
            out ushort chatLogType,
            out string chatText,
            out bool hasChannelId,
            out int channelId,
            out string message)
        {
            return TryDecodePacketOwnedChatPayload(
                payload,
                requireExactClientPayload,
                out chatLogType,
                out chatText,
                out _,
                out hasChannelId,
                out channelId,
                out message);
        }

        internal static bool TryDecodePacketOwnedChatPayload(
            byte[] payload,
            bool requireExactClientPayload,
            out ushort chatLogType,
            out string chatText,
            out bool hasChatLogType,
            out bool hasChannelId,
            out int channelId,
            out string message)
        {
            chatLogType = 0;
            chatText = null;
            hasChatLogType = false;
            hasChannelId = false;
            channelId = -1;
            message = "Chat payload is missing.";
            if (payload == null || payload.Length == 0)
            {
                return false;
            }

            if (TryDecodePacketOwnedTypedChatPayload(payload, out chatLogType, out chatText))
            {
                hasChatLogType = true;
                message = "Decoded packet-owned chat payload.";
                return true;
            }

            if (requireExactClientPayload)
            {
                message = "Chat client payload must match CUserLocal::OnChatMsg: Decode2 chatLogType followed by one DecodeStr body.";
                return false;
            }

            if (TryDecodePacketOwnedChannelChatPayload(payload, out chatLogType, out channelId, out chatText))
            {
                hasChatLogType = true;
                hasChannelId = true;
                message = "Decoded packet-owned channel chat payload.";
                return true;
            }

            if (IsPacketOwnedTypedChatPayloadWithOutOfRangeLogType(payload)
                || IsPacketOwnedChannelChatPayloadWithOutOfRangeLogType(payload))
            {
                message = "Chat payload contained an out-of-range ChatLogAdd lType.";
                return false;
            }

            if (!TryDecodePacketOwnedStringPayload(payload, out chatText))
            {
                return false;
            }

            message = "Decoded packet-owned chat payload.";
            return true;
        }

        private static bool TryDecodePacketOwnedTypedChatPayload(
            byte[] payload,
            out ushort chatLogType,
            out string chatText)
        {
            chatLogType = 0;
            chatText = null;
            if (payload == null || payload.Length < sizeof(ushort))
            {
                return false;
            }

            try
            {
                using MemoryStream stream = new(payload, writable: false);
                using BinaryReader reader = new(stream);
                chatLogType = reader.ReadUInt16();
                string decodedText = ReadPacketOwnedMapleString(reader);
                if (reader.BaseStream.Position != reader.BaseStream.Length || string.IsNullOrWhiteSpace(decodedText))
                {
                    return false;
                }

                if (!IsRecoveredClientChatLogType(chatLogType))
                {
                    return false;
                }

                chatText = decodedText.Trim();
                return true;
            }
            catch
            {
                return false;
            }
        }

        private static bool TryDecodePacketOwnedChannelChatPayload(
            byte[] payload,
            out ushort chatLogType,
            out int channelId,
            out string chatText)
        {
            chatLogType = 0;
            channelId = -1;
            chatText = null;
            if (payload == null || payload.Length < sizeof(ushort) + sizeof(int))
            {
                return false;
            }

            try
            {
                using MemoryStream stream = new(payload, writable: false);
                using BinaryReader reader = new(stream);
                chatLogType = reader.ReadUInt16();
                channelId = reader.ReadInt32();
                string decodedText = ReadPacketOwnedMapleString(reader);
                if (reader.BaseStream.Position != reader.BaseStream.Length || string.IsNullOrWhiteSpace(decodedText))
                {
                    return false;
                }

                if (!IsRecoveredClientChatLogType(chatLogType))
                {
                    return false;
                }

                chatText = decodedText.Trim();
                return true;
            }
            catch
            {
                return false;
            }
        }

        private static bool IsPacketOwnedTypedChatPayloadWithOutOfRangeLogType(byte[] payload)
        {
            if (!TryReadPacketOwnedTypedChatPayloadEnvelope(payload, out ushort chatLogType, out _))
            {
                return false;
            }

            return !IsRecoveredClientChatLogType(chatLogType);
        }

        private static bool IsPacketOwnedChannelChatPayloadWithOutOfRangeLogType(byte[] payload)
        {
            if (!TryReadPacketOwnedChannelChatPayloadEnvelope(payload, out ushort chatLogType, out _, out _))
            {
                return false;
            }

            return !IsRecoveredClientChatLogType(chatLogType);
        }

