        private bool TryApplyPacketOwnedMechanicEquipPayload(byte[] payload, out string message)
        {
            message = null;
            if (!MechanicEquipmentPacketParity.TryDecodePayload(payload, out MechanicEquipPacketPayload decodedPayload, out string errorMessage))
            {
                message = errorMessage;
                return false;
            }

            if (decodedPayload.Mode == MechanicEquipPacketPayloadMode.AuthorityRequest)
            {
                return TryResolvePacketOwnedMechanicAuthorityRequest(decodedPayload, out message);
            }

            if (decodedPayload.Mode == MechanicEquipPacketPayloadMode.AuthorityResult)
            {
                return TryQueuePacketOwnedMechanicAuthorityResult(decodedPayload, out message);
            }

            if (TryQueueMechanicAuthorityResultFromStatePayload(decodedPayload, out message))
            {
                StampPacketOwnedUtilityRequestState();
                return true;
            }

            string tamingMobRestrictionMessage = FieldInteractionRestrictionEvaluator.GetTamingMobRestrictionMessage(_mapBoard?.MapInfo?.fieldLimit ?? 0);
            if (!string.IsNullOrWhiteSpace(tamingMobRestrictionMessage))
            {
                message = tamingMobRestrictionMessage;
                return false;
            }

            CharacterBuild build = _playerManager?.Player?.Build;
            MechanicEquipmentController controller = _playerManager?.CompanionEquipment?.Mechanic;
            if (build == null || controller == null)
            {
                message = "Mechanic equipment runtime is unavailable.";
                return false;
            }

            bool applied = decodedPayload.Mode switch
            {
                MechanicEquipPacketPayloadMode.Snapshot => controller.TryApplyExternalSnapshot(
                    build,
                    decodedPayload.SnapshotItems,
                    out errorMessage),
                MechanicEquipPacketPayloadMode.SlotMutation when decodedPayload.Slot.HasValue => controller.TryApplyExternalSlotMutation(
                    build,
                    decodedPayload.Slot.Value,
                    decodedPayload.ItemId,
                    out errorMessage),
                MechanicEquipPacketPayloadMode.ClearAll => controller.TryApplyExternalSnapshot(
                    build,
                    null,
                    out errorMessage),
                MechanicEquipPacketPayloadMode.ResetDefaults => ApplyPacketOwnedMechanicEquipDefaults(controller, build, out errorMessage),
                _ => false
            };
            if (!applied)
            {
                message = string.IsNullOrWhiteSpace(errorMessage)
                    ? "Packet-authored mechanic equipment payload could not be applied."
                    : errorMessage;
                return false;
            }

            StampPacketOwnedUtilityRequestState();
            message = decodedPayload.Mode switch
            {
                MechanicEquipPacketPayloadMode.Snapshot => "Applied packet-authored mechanic equipment snapshot.",
                MechanicEquipPacketPayloadMode.SlotMutation => decodedPayload.ItemId > 0
                    ? $"Applied packet-authored mechanic slot update for {decodedPayload.Slot} with item {decodedPayload.ItemId}."
                    : $"Applied packet-authored mechanic slot clear for {decodedPayload.Slot}.",
                MechanicEquipPacketPayloadMode.ClearAll => "Cleared packet-authored mechanic equipment state.",
                MechanicEquipPacketPayloadMode.ResetDefaults => "Reset mechanic equipment to the client default machine-part set.",
                _ => "Applied packet-authored mechanic equipment state."
            };
            return true;
        }

        private bool TryApplyPacketOwnedInventoryOperationAuthorityPayload(byte[] payload, out string message)
        {
            bool consumedCollisionScriptReset = TryConsumeCollisionScriptExclusiveResetFromInventoryOperationPayload(payload);
            bool consumedQuestStartRequestReset =
                TryConsumePacketOwnedQuestResultStartQuestExclusiveResetFromInventoryOperationPayload(payload);
            string collisionScriptResetMessage = consumedCollisionScriptReset
                ? "Inventory-operation payload consumed the client bExclRequestSent reset marker and cleared collision-script/transfer exclusive-request state."
                : null;
            string questStartRequestResetMessage = consumedQuestStartRequestReset
                ? "The same reset marker also cleared the packet-owned StartQuest follow-up exclusive-request latch while sent ownership was still active."
                : null;
            if (TryApplyPendingLocalItemDropInventoryOperationPayload(payload, out message))
            {
                StampPacketOwnedUtilityRequestState();
                if (!string.IsNullOrWhiteSpace(collisionScriptResetMessage))
                {
                    message = $"{message} {collisionScriptResetMessage}";
                }

                if (!string.IsNullOrWhiteSpace(questStartRequestResetMessage))
                {
                    message = $"{message} {questStartRequestResetMessage}";
                }

                return true;
            }

            if (TryQueueCharacterAuthorityResultFromInventoryOperationPayload(payload, out message))
            {
                StampPacketOwnedUtilityRequestState();
                if (!string.IsNullOrWhiteSpace(collisionScriptResetMessage))
                {
                    message = $"{message} {collisionScriptResetMessage}";
                }

                if (!string.IsNullOrWhiteSpace(questStartRequestResetMessage))
                {
                    message = $"{message} {questStartRequestResetMessage}";
                }

                return true;
            }

            string characterRejectReason = message;
            if (TryQueueMechanicAuthorityResultFromInventoryOperationPayload(payload, out message))
            {
                StampPacketOwnedUtilityRequestState();
                if (!string.IsNullOrWhiteSpace(collisionScriptResetMessage))
                {
                    message = $"{message} {collisionScriptResetMessage}";
                }

                if (!string.IsNullOrWhiteSpace(questStartRequestResetMessage))
                {
                    message = $"{message} {questStartRequestResetMessage}";
                }

                return true;
            }

            string mechanicRejectReason = message;
            if (TryApplyPassiveMechanicInventoryOperationMutationsFromInventoryOperationPayload(payload, out message))
            {
                StampPacketOwnedUtilityRequestState();
                if (!string.IsNullOrWhiteSpace(collisionScriptResetMessage))
                {
                    message = $"{message} {collisionScriptResetMessage}";
                }

                if (!string.IsNullOrWhiteSpace(questStartRequestResetMessage))
                {
                    message = $"{message} {questStartRequestResetMessage}";
                }

                return true;
            }

            if (TryApplyPacketOwnedMonsterBookInventoryOperationPickupPayload(payload, out string monsterBookPickupMessage))
            {
                StampPacketOwnedUtilityRequestState();
                message = string.IsNullOrWhiteSpace(message)
                    ? monsterBookPickupMessage
                    : $"{message} {monsterBookPickupMessage}";
                if (!string.IsNullOrWhiteSpace(collisionScriptResetMessage))
                {
                    message = $"{message} {collisionScriptResetMessage}";
                }

                if (!string.IsNullOrWhiteSpace(questStartRequestResetMessage))
                {
                    message = $"{message} {questStartRequestResetMessage}";
                }

                return true;
            }

            if (!string.IsNullOrWhiteSpace(characterRejectReason)
                && !string.IsNullOrWhiteSpace(message))
            {
                message = $"{characterRejectReason} {message}";
            }
            else if (!string.IsNullOrWhiteSpace(characterRejectReason))
            {
                message = characterRejectReason;
            }

            if (!string.IsNullOrWhiteSpace(mechanicRejectReason))
            {
                message = string.IsNullOrWhiteSpace(message)
                    ? mechanicRejectReason
                    : $"{message} {mechanicRejectReason}";
            }

            if (!consumedCollisionScriptReset && !consumedQuestStartRequestReset)
            {
                return false;
            }

            string resetMessage = string.Join(
                " ",
                new[] { collisionScriptResetMessage, questStartRequestResetMessage }
                    .Where(static text => !string.IsNullOrWhiteSpace(text)));
            message = string.IsNullOrWhiteSpace(message)
                ? resetMessage
                : $"{message} {resetMessage}";
            return true;
        }

        private bool TryApplyPacketOwnedMonsterBookInventoryOperationPickupPayload(byte[] payload, out string message)
        {
            message = null;
            if (payload == null || payload.Length == 0)
            {
                return false;
            }

            if (!MonsterBookInventoryOperationParity.TryCollectConsumeOnPickupCardPickups(
                    payload,
                    _monsterBookManager.IsConsumeOnPickupCardItem,
                    out IReadOnlyList<MonsterBookInventoryCardPickup> pickups,
                    out _)
                || pickups.Count <= 0)
            {
                return false;
            }

            CharacterBuild activeBuild = _playerManager?.Player?.Build ?? _loginCharacterRoster.SelectedEntry?.Build;
            int activeCharacterId = activeBuild?.Id ?? 0;
            string activeCharacterName = activeBuild?.Name;
            int appliedCardUpdates = 0;
            int fullCardUpdates = 0;
            int observedPickupRows = 0;
            HashSet<int> registeredCardGetItemIds = new();
            MonsterBookSnapshot latestSnapshot = null;
            for (int i = 0; i < pickups.Count; i++)
            {
                MonsterBookInventoryCardPickup pickup = pickups[i];
                if (pickup.ItemId <= 0 || pickup.Quantity <= 0)
                {
                    continue;
                }

                observedPickupRows++;
                MonsterBookManager.CardPickupResult pickupResult = _monsterBookManager.RecordCardPickupWithResult(
                    activeBuild,
                    activeCharacterId,
                    activeCharacterName,
                    pickup.ItemId,
                    pickup.Quantity,
                    persistToDisk: false);

                if (pickupResult.Changed)
                {
                    appliedCardUpdates++;
                    latestSnapshot = pickupResult.Snapshot;
                    if (activeCharacterId > 0 && _playerManager?.Player?.Build?.Id == activeCharacterId)
                    {
                        if (ShouldRegisterAnimationDisplayerPacketOwnedMonsterBookCardGetForChangedPickup(
                                registeredCardGetItemIds,
                                pickup.ItemId))
                        {
                            TryRegisterAnimationDisplayerMonsterBookCardPickup(
                                activeCharacterId,
                                () => _playerManager?.Player?.Position ?? Vector2.Zero,
                                pickup.ItemId,
                                out _);
                        }
                    }
                }
                else if (pickupResult.Outcome == MonsterBookManager.CardPickupOutcome.AlreadyFull)
                {
                    fullCardUpdates++;
                }
            }

            if (appliedCardUpdates > 0 && latestSnapshot != null)
            {
                QueuePacketOwnedMonsterBookOwnershipSaveApply(
                    activeBuild,
                    activeCharacterId,
                    activeCharacterName,
                    latestSnapshot,
                    "Inventory-operation consume-on-pickup Monster Card intake",
                    showFeedback: false);
            }

            if (observedPickupRows <= 0)
            {
                return false;
            }

            if (appliedCardUpdates > 0)
            {
                message = $"Inventory-operation intake applied {appliedCardUpdates.ToString(CultureInfo.InvariantCulture)} consume-on-pickup Monster Card update(s).";
                return true;
            }

            message = fullCardUpdates > 0
                ? $"Inventory-operation consume-on-pickup Monster Card intake was already at the 5-card completion mark for {fullCardUpdates.ToString(CultureInfo.InvariantCulture)} row(s)."
                : "Inventory-operation consume-on-pickup Monster Card intake did not change ownership.";
            return true;
        }

        private bool TryApplyPassiveMechanicInventoryOperationMutationsFromInventoryOperationPayload(
            byte[] payload,
            out string message)
        {
            message = null;
            if (payload == null || payload.Length == 0)
            {
                message = "Inventory-operation payload is empty.";
                return false;
            }

            CharacterBuild build = _playerManager?.Player?.Build;
            MechanicEquipmentController controller = _playerManager?.CompanionEquipment?.Mechanic;
            if (build == null || controller == null)
            {
                return false;
            }

            InventoryUI inventoryWindow = uiWindowManager?.InventoryWindow as InventoryUI;
            IReadOnlyList<InventorySlotData> equipInventory =
                inventoryWindow != null
                    ? CaptureInventorySnapshot(inventoryWindow, InventoryType.EQUIP)
                    : Array.Empty<InventorySlotData>();
            if (!MechanicEquipmentPacketParity.TryDecodePassiveClientInventoryOperationMutations(
                    payload,
                    equipInventory,
                    out IReadOnlyList<MechanicEquipmentPacketParity.MechanicInventoryOperationMutation> mutations,
                    out string rejectReason))
            {
                message = rejectReason;
                return false;
            }

            controller.EnsureDefaults(build);
            int appliedMutationCount = 0;
            int unchangedMutationCount = 0;
            for (int i = 0; i < mutations.Count; i++)
            {
                MechanicEquipmentPacketParity.MechanicInventoryOperationMutation mutation = mutations[i];
                int equippedItemId = 0;
                if (controller.TryGetItem(mutation.Slot, out CompanionEquipItem equippedItem)
                    && equippedItem?.ItemId > 0)
                {
                    equippedItemId = equippedItem.ItemId;
                }

                if (equippedItemId == mutation.ItemId)
                {
                    unchangedMutationCount++;
                    continue;
                }

                if (!controller.TryApplyExternalSlotMutation(
                        build,
                        mutation.Slot,
                        mutation.ItemId,
                        out rejectReason))
                {
                    message = rejectReason;
                    return false;
                }

                appliedMutationCount++;
            }

            if (appliedMutationCount <= 0)
            {
                if (mutations.Count <= 0)
                {
                    return false;
                }

                message = "Recovered mechanic inventory-operation mutation payload did not change the current machine-part state.";
                return true;
            }

            message =
                $"Applied {appliedMutationCount.ToString(CultureInfo.InvariantCulture)} passive mechanic inventory-operation mutation(s).";
            if (unchangedMutationCount > 0)
            {
                message =
                    $"{message} {unchangedMutationCount.ToString(CultureInfo.InvariantCulture)} decoded mutation(s) already matched the current machine-part state.";
            }

            return true;
        }

        private bool TryConsumeCollisionScriptExclusiveResetFromInventoryOperationPayload(byte[] payload)
        {
            if (!ShouldConsumeCollisionScriptExclusiveResetFromInventoryOperationPayload(payload))
            {
                return false;
            }

            // CWvsContext::SetExclRequestSent writes the current update tick for both set and clear.
            int resetTick = currTickCount;
            ApplyCollisionScriptExclusiveRequestClear(
                preserveCooldown: false,
                ref _collisionScriptExclusiveRequestSent,
                ref _collisionScriptExclusiveRequestSentTick,
                ref _collisionScriptExclusiveRequestPortalIndex,
                ref _collisionScriptExclusiveRequestDelayMs,
                stampResetTick: true,
                resetTick: resetTick);
            ApplyTransferFieldExclusiveRequestClear(
                preserveCooldown: false,
                ref _transferFieldExclusiveRequestSent,
                ref _transferFieldExclusiveRequestSentTick,
                stampResetTick: true,
                resetTick: resetTick);
            return true;
        }

        internal static bool ShouldConsumeCollisionScriptExclusiveResetFromInventoryOperationPayload(byte[] payload)
        {
            return TryDecodeInventoryOperationExclusiveResetMarker(
                       payload,
                       out bool resetMarker,
                       out _)
                   && resetMarker;
        }

        internal static bool TryDecodeInventoryOperationExclusiveResetMarker(
            byte[] payload,
            out bool resetMarker,
            out byte operationCount)
        {
            resetMarker = false;
            operationCount = 0;
            if (payload == null || payload.Length < 2)
            {
                return false;
            }

            byte rawResetMarker = payload[0];
            if (rawResetMarker > 1)
            {
                return false;
            }

            resetMarker = rawResetMarker == 1;
            operationCount = payload[1];
            const int operationHeaderSize = sizeof(byte) + sizeof(byte) + sizeof(short);
            int bodyLength = payload.Length - 2;
            if (bodyLength < 0)
            {
                resetMarker = false;
                operationCount = 0;
                return false;
            }

            int minimumRequiredBodyLength = operationCount * operationHeaderSize;
            if (bodyLength < minimumRequiredBodyLength)
            {
                resetMarker = false;
                operationCount = 0;
                return false;
            }

            return true;
        }

        private bool TryResolvePacketOwnedTutorDisplayState(
            out TutorVariantSnapshot displayVariant,
            out PacketOwnedTutorDisplayOwner displayOwner)
        {
            displayOwner = default;
            if (!TryResolvePacketOwnedTutorDisplayVariant(out displayVariant))
            {
                return false;
            }

            return TryResolvePacketOwnedTutorDisplayOwner(displayVariant, out displayOwner);
        }

        private bool TryResolvePacketOwnedTutorDisplayVariant(out TutorVariantSnapshot displayVariant)
        {
            if (_packetOwnedTutorRuntime.IsActive && _packetOwnedTutorRuntime.ActiveSkillId > 0)
            {
                displayVariant = new TutorVariantSnapshot(
                    _packetOwnedTutorRuntime.ActiveSkillId,
                    _packetOwnedTutorRuntime.ActiveSummonObjectId,
                    _packetOwnedTutorRuntime.ResolveActorHeight(),
                    _packetOwnedTutorRuntime.BoundCharacterId,
                    true,
                    _packetOwnedTutorRuntime.LastHireTick,
                    int.MinValue,
                    _packetOwnedTutorRuntime.LastRegistryMutationTick);
                return true;
            }

            return _packetOwnedTutorRuntime.TryGetSharedActiveVariant(out displayVariant);
        }

        private bool TryResolvePacketOwnedTutorDisplayOwner(
            TutorVariantSnapshot displayVariant,
            out PacketOwnedTutorDisplayOwner owner)
        {
            owner = default;
            int ownerCharacterId = Math.Max(0, displayVariant.BoundCharacterId);
            if (ownerCharacterId <= 0)
            {
                return false;
            }

            PlayerCharacter localPlayer = _playerManager?.Player;
            if (localPlayer?.Build?.Id == ownerCharacterId)
            {
                owner = new PacketOwnedTutorDisplayOwner(
                    ownerCharacterId,
                    localPlayer.Position,
                    localPlayer.FacingRight,
                    Math.Max(1, localPlayer.Level),
                    IsLocalOwner: true);
                return true;
            }

            if (_remoteUserPool != null && _remoteUserPool.TryGetActor(ownerCharacterId, out RemoteUserActor actor))
            {
                owner = new PacketOwnedTutorDisplayOwner(
                    ownerCharacterId,
                    actor.Position,
                    actor.FacingRight,
                    Math.Max(1, actor.Build?.Level ?? 1),
                    IsLocalOwner: false);
                return true;
            }

            return false;
        }

        private int ResolvePacketOwnedTutorDisplaySkillLevel(
            TutorVariantSnapshot displayVariant,
            PacketOwnedTutorDisplayOwner owner)
        {
            if (owner.IsLocalOwner)
            {
                return Math.Max(1, _playerManager?.Skills?.GetSkillLevel(displayVariant.SkillId) ?? 0);
            }

            return 1;
        }

        private static bool ApplyPacketOwnedMechanicEquipDefaults(
            MechanicEquipmentController controller,
            CharacterBuild build,
            out string errorMessage)
        {
            errorMessage = null;
            if (controller == null)
            {
                errorMessage = "Mechanic equipment runtime is unavailable.";
                return false;
            }

            if (!CompanionEquipmentController.HasMechanicOwnerState(build))
            {
                errorMessage = "Mechanic equipment is only available to Mechanic job paths.";
                return false;
            }

            controller.ResetToDefaults(build);
            return true;
        }

        private bool TryApplyPacketOwnedQuestGuidePayload(byte[] payload, out string message)
        {
            message = null;
            if (!TryDecodePacketOwnedQuestGuidePayload(
                    payload,
                    out byte mode,
                    out int questId,
                    out (int PrimaryId, int[] ChildIds)[] records,
                    out string error))
            {
                message = error ?? "Quest-guide payload could not be decoded.";
                return false;
            }

            if (mode == 2)
            {
                message = ResetPacketQuestGuideLaunch();
                return true;
            }

            bool looksLikeLegacyMobGuide = records.Length > 0
                && records.All(record => record.ChildIds.All(childId => childId <= 0 || childId >= 100000000));
            if (looksLikeLegacyMobGuide)
            {
                Dictionary<int, IReadOnlyList<int>> targetsByMobId = new();
                for (int i = 0; i < records.Length; i++)
                {
                    int mobId = records[i].PrimaryId;
                    List<int> mapIds = records[i].ChildIds
                        .Where(mapId => mapId > 0)
                        .Distinct()
                        .ToList();
                    if (mobId > 0 && mapIds.Count > 0)
                    {
                        targetsByMobId[mobId] = mapIds;
                    }
                }

                message = ApplyPacketQuestGuideLaunch(questId, targetsByMobId);
                return true;
            }

            QuestDemandItemQueryState runtimeFallbackQuery = null;
            _questRuntime.TryBuildQuestDemandItemQuery(questId, out runtimeFallbackQuery);
            QuestDemandItemQueryState queryState = BuildPacketOwnedQuestDemandItemQueryState(
                questId,
                records.Select(record => (record.PrimaryId, (IReadOnlyList<int>)record.ChildIds)).ToArray(),
                _mapBoard?.MapInfo?.id ?? 0,
                runtimeFallbackQuery,
                ResolveQuestMobMapIds);
            message = ApplyQuestDemandItemQueryLaunch(queryState);
            return true;
        }

        private bool TryApplyPacketOwnedDeliveryPayload(byte[] payload, out string message)
        {
            message = null;
            if (!TryDecodePacketOwnedDeliveryQuestPayload(
                    payload,
                    out int questId,
                    out int itemId,
                    out int[] disallowedQuestIds,
                    out QuestDetailDeliveryType packetOwnedDeliveryType,
                    out string error))
            {
                message = error ?? "Delivery payload could not be decoded.";
                return false;
            }

            message = ApplyDeliveryQuestLaunch(questId, itemId, disallowedQuestIds, packetOwnedDeliveryType);
            return true;
        }

        internal static bool TryDecodePacketOwnedQuestGuidePayloadForTests(
            byte[] payload,
            out byte mode,
            out int questId,
            out (int PrimaryId, int[] ChildIds)[] records,
            out string error)
        {
            return TryDecodePacketOwnedQuestGuidePayload(payload, out mode, out questId, out records, out error);
        }

        private static bool TryDecodePacketOwnedQuestGuidePayload(
            byte[] payload,
            out byte mode,
            out int questId,
            out (int PrimaryId, int[] ChildIds)[] records,
            out string error)
        {
            mode = 0;
            questId = 0;
            records = Array.Empty<(int PrimaryId, int[] ChildIds)>();
            error = null;

            if (payload == null || payload.Length < sizeof(byte))
            {
                error = "Quest-guide payload is missing.";
                return false;
            }

            try
            {
                using MemoryStream stream = new(payload, writable: false);
                using BinaryReader reader = new(stream);
                mode = reader.ReadByte();
                if (mode == 2)
                {
                    if (reader.BaseStream.Position != reader.BaseStream.Length)
                    {
                        error = $"Quest-guide reset payload has {reader.BaseStream.Length - reader.BaseStream.Position} trailing byte(s).";
                        return false;
                    }

                    return true;
                }

                if (mode != 1)
                {
                    error = $"Quest-guide payload mode {mode} is not modeled by the simulator.";
                    return false;
                }

                questId = reader.ReadUInt16();
                int targetCount = reader.ReadInt32();
                if (targetCount < 0)
                {
                    error = "Quest-guide payload declared a negative target count.";
                    return false;
                }

                var decodedRecords = new (int PrimaryId, int[] ChildIds)[targetCount];
                for (int i = 0; i < targetCount; i++)
                {
                    int primaryId = reader.ReadInt32();
                    int childCount = reader.ReadUInt16();
                    int[] childIds = new int[childCount];
                    for (int childIndex = 0; childIndex < childCount; childIndex++)
                    {
                        childIds[childIndex] = reader.ReadInt32();
                    }

                    decodedRecords[i] = (primaryId, childIds);
                }

                if (reader.BaseStream.Position != reader.BaseStream.Length)
                {
                    error = $"Quest-guide payload has {reader.BaseStream.Length - reader.BaseStream.Position} trailing byte(s) after the decoded target records.";
                    return false;
                }

                records = decodedRecords;
                return true;
            }
            catch (Exception ex) when (ex is EndOfStreamException or IOException)
            {
                error = $"Quest-guide payload could not be decoded: {ex.Message}";
                return false;
            }
        }

        private static List<int> DecodePacketOwnedDisallowedDeliveryQuestIds(BinaryReader reader)
        {
            List<int> questIds = new();
            int remaining = (int)(reader.BaseStream.Length - reader.BaseStream.Position);
            if (remaining <= 0)
            {
                return questIds;
            }

            long listStart = reader.BaseStream.Position;
            if (remaining >= 2)
            {
                ushort count = reader.ReadUInt16();
                int afterCount = (int)(reader.BaseStream.Length - reader.BaseStream.Position);
                if (count == 0)
                {
                    return questIds;
                }

                if (afterCount == count * sizeof(short))
                {
                    for (int i = 0; i < count; i++)
                    {
                        int questId = reader.ReadUInt16();
                        if (questId > 0)
                        {
                            questIds.Add(questId);
                        }
                    }

                    return questIds;
                }

                if (afterCount == count * sizeof(int))
                {
                    for (int i = 0; i < count; i++)
                    {
                        int questId = reader.ReadInt32();
                        if (questId > 0)
                        {
                            questIds.Add(questId);
                        }
                    }

                    return questIds;
                }

                reader.BaseStream.Position = listStart;
            }

            remaining = (int)(reader.BaseStream.Length - reader.BaseStream.Position);
            if (TryDecodeRawDeliveryQuestIdsWithOptionalType(reader, sizeof(int), out questIds)
                || TryDecodeRawDeliveryQuestIdsWithOptionalType(reader, sizeof(short), out questIds))
            {
                return questIds;
            }

            if (remaining % sizeof(int) == 0)
            {
                while (reader.BaseStream.Position < reader.BaseStream.Length)
                {
                    int questId = reader.ReadInt32();
                    if (questId > 0)
                    {
                        questIds.Add(questId);
                    }
                }
            }
            else if (remaining % sizeof(short) == 0)
            {
                while (reader.BaseStream.Position < reader.BaseStream.Length)
                {
                    int questId = reader.ReadUInt16();
                    if (questId > 0)
                    {
                        questIds.Add(questId);
                    }
                }
            }

            return questIds;
        }

        private static bool TryDecodeRawDeliveryQuestIdsWithOptionalType(
            BinaryReader reader,
            int entryWidth,
            out List<int> questIds)
        {
            questIds = new List<int>();
            if (reader == null || entryWidth <= 0)
            {
                return false;
            }

            long listStart = reader.BaseStream.Position;
            int remaining = (int)(reader.BaseStream.Length - listStart);
            foreach (int trailingTypeWidth in new[] { sizeof(byte), sizeof(short), sizeof(int) })
            {
                if (remaining <= trailingTypeWidth)
                {
                    continue;
                }

                int listBytes = remaining - trailingTypeWidth;
                if (listBytes <= 0 || listBytes % entryWidth != 0)
                {
                    continue;
                }

                long trailingTypePosition = listStart + listBytes;
                if (!IsDeliveryTypeDiscriminatorAt(reader, trailingTypePosition, trailingTypeWidth))
                {
                    continue;
                }

                reader.BaseStream.Position = listStart;
                int entryCount = listBytes / entryWidth;
                for (int i = 0; i < entryCount; i++)
                {
                    int questId = entryWidth == sizeof(int)
                        ? reader.ReadInt32()
                        : reader.ReadUInt16();
                    if (questId > 0)
                    {
                        questIds.Add(questId);
                    }
                }

                return true;
            }

            reader.BaseStream.Position = listStart;
            return false;
        }

        private static bool IsDeliveryTypeDiscriminatorAt(BinaryReader reader, long position, int width)
        {
            if (reader == null || position < 0)
            {
                return false;
            }

            long restorePosition = reader.BaseStream.Position;
            try
            {
                if (position > reader.BaseStream.Length - width)
                {
                    return false;
                }

                reader.BaseStream.Position = position;
                int rawType = width switch
                {
                    sizeof(byte) => reader.ReadByte(),
                    sizeof(short) => reader.ReadUInt16(),
                    sizeof(int) => reader.ReadInt32(),
                    _ => int.MinValue
                };

                return rawType is >= 0 and <= 2;
            }
            finally
            {
                reader.BaseStream.Position = restorePosition;
            }
        }

        private static bool TryDecodePacketOwnedDeliveryType(BinaryReader reader, out QuestDetailDeliveryType deliveryType, out string error)
        {
            deliveryType = QuestDetailDeliveryType.None;
            error = null;
            if (reader == null)
            {
                return true;
            }

            int remaining = (int)(reader.BaseStream.Length - reader.BaseStream.Position);
            if (remaining <= 0)
            {
                return true;
            }

            int rawType = remaining switch
            {
                4 => reader.ReadInt32(),
                2 => reader.ReadUInt16(),
                1 => reader.ReadByte(),
                _ => int.MinValue
            };
            if (rawType == int.MinValue)
            {
                error = $"Delivery-quest payload left {remaining} byte(s) for the optional delivery-type discriminator; expected 0, 1, 2, or 4 bytes.";
                return false;
            }

            if (rawType is < 0 or > 2)
            {
                error = $"Delivery-quest payload used unsupported delivery-type discriminator value {rawType}; expected 0, 1, or 2.";
                return false;
            }

            deliveryType = QuestDetailDeliveryTypeCodec.FromClientRawValue(rawType);
            return true;
        }

        internal static QuestDemandItemQueryState BuildPacketOwnedQuestDemandItemQueryState(
            int questId,
            IReadOnlyList<(int PrimaryId, IReadOnlyList<int> ChildIds)> records,
            int currentMapId,
            QuestDemandItemQueryState runtimeFallbackQuery,
            Func<int, IReadOnlyList<int>> resolveMobMapIds)
        {
            List<int> visibleItemIds = new();
            Dictionary<int, IReadOnlyList<int>> visibleItemMapIds = new();
            Dictionary<int, QuestDemandItemMapResultSet> visibleItemMapResults = new();
            int hiddenItemCount = 0;
            bool hasPacketOwnedMapResults = false;
            int preferredItemId = 0;

            if (records != null)
            {
                for (int i = 0; i < records.Count; i++)
                {
                    int itemId = records[i].PrimaryId;
                    if (itemId <= 0)
                    {
                        hiddenItemCount++;
                        continue;
                    }

                    HashSet<int> mapIds = new();
                    IReadOnlyList<int> childIds = records[i].ChildIds ?? Array.Empty<int>();
                    bool itemHasPacketOwnedMapResults = false;
                    for (int childIndex = 0; childIndex < childIds.Count; childIndex++)
                    {
                        int mobId = childIds[childIndex];
                        if (mobId <= 0)
                        {
                            continue;
                        }

                        IReadOnlyList<int> packetResolvedMapIds = resolveMobMapIds?.Invoke(mobId) ?? Array.Empty<int>();
                        for (int mapIndex = 0; mapIndex < packetResolvedMapIds.Count; mapIndex++)
                        {
                            if (packetResolvedMapIds[mapIndex] > 0)
                            {
                                mapIds.Add(packetResolvedMapIds[mapIndex]);
                                itemHasPacketOwnedMapResults = true;
                                hasPacketOwnedMapResults = true;
                            }
                        }
                    }

                    if (!visibleItemIds.Contains(itemId))
                    {
                        visibleItemIds.Add(itemId);
                        if (preferredItemId <= 0)
                        {
                            preferredItemId = itemId;
                        }
                    }

                    QuestDemandItemMapResultSet runtimeFallbackMapResult = ResolveRuntimeFallbackDemandItemMapResult(runtimeFallbackQuery, itemId);
                    IReadOnlyList<int> runtimeFallbackMapIds = runtimeFallbackMapResult?.MapIds ?? Array.Empty<int>();
                    bool itemHasRuntimeFallbackMapResults = false;
                    for (int mapIndex = 0; mapIndex < runtimeFallbackMapIds.Count; mapIndex++)
                    {
                        if (runtimeFallbackMapIds[mapIndex] > 0)
                        {
                            mapIds.Add(runtimeFallbackMapIds[mapIndex]);
                            itemHasRuntimeFallbackMapResults = true;
                        }
                    }

                    QuestDemandItemMapResultSource mapSource = itemHasPacketOwnedMapResults
                        ? QuestDemandItemMapResultSource.PacketOwnedMob
                        : itemHasRuntimeFallbackMapResults
                            ? runtimeFallbackMapResult.Source
                            : QuestDemandItemMapResultSource.None;

                    if (mapIds.Count == 0 && currentMapId > 0)
                    {
                        mapIds.Add(currentMapId);
                        mapSource = QuestDemandItemMapResultSource.CurrentFieldFallback;
                    }

                    if (mapIds.Count > 0)
                    {
                        int[] normalizedMapIds = mapIds.OrderBy(mapId => mapId).ToArray();
                        visibleItemMapIds[itemId] = normalizedMapIds;
                        visibleItemMapResults[itemId] = new QuestDemandItemMapResultSet
                        {
                            MapIds = normalizedMapIds,
                            Source = mapSource
                        };
                    }
                }
            }

            string fallbackNpcName = runtimeFallbackQuery?.FallbackNpcName ?? string.Empty;
            if (visibleItemIds.Count == 0 && runtimeFallbackQuery?.VisibleItemIds != null)
            {
                for (int i = 0; i < runtimeFallbackQuery.VisibleItemIds.Count; i++)
                {
                    int itemId = runtimeFallbackQuery.VisibleItemIds[i];
                    if (itemId <= 0 || visibleItemIds.Contains(itemId))
                    {
                        continue;
                    }

                    visibleItemIds.Add(itemId);
                    if (preferredItemId <= 0)
                    {
                        preferredItemId = itemId;
                    }
                    QuestDemandItemMapResultSet runtimeFallbackMapResult = ResolveRuntimeFallbackDemandItemMapResult(runtimeFallbackQuery, itemId);
                    IReadOnlyList<int> runtimeFallbackMapIds = runtimeFallbackMapResult?.MapIds ?? Array.Empty<int>();
                    if (runtimeFallbackMapIds.Count > 0)
                    {
                        int[] normalizedMapIds = runtimeFallbackMapIds
                            .Where(mapId => mapId > 0)
                            .Distinct()
                            .OrderBy(mapId => mapId)
                            .ToArray();
                        visibleItemMapIds[itemId] = normalizedMapIds;
                        visibleItemMapResults[itemId] = new QuestDemandItemMapResultSet
                        {
                            MapIds = normalizedMapIds,
                            Source = runtimeFallbackMapResult.Source
                        };
                    }
                }
            }

            if (hiddenItemCount == 0 && runtimeFallbackQuery?.HiddenItemCount > 0)
            {
                hiddenItemCount = runtimeFallbackQuery.HiddenItemCount;
            }

            if (runtimeFallbackQuery?.PreferredItemId is int runtimePreferredItemId &&
                runtimePreferredItemId > 0 &&
                visibleItemIds.Contains(runtimePreferredItemId))
            {
                preferredItemId = runtimePreferredItemId;
            }

            return new QuestDemandItemQueryState
            {
                QuestId = questId,
                RequestItemIds = records != null && records.Count > 0
                    ? records.Select(record => Math.Max(0, record.PrimaryId)).ToArray()
                    : runtimeFallbackQuery?.RequestItemIds ?? Array.Empty<int>(),
                VisibleItemIds = visibleItemIds,
                VisibleItemMapIds = visibleItemMapIds,
                VisibleItemMapResults = visibleItemMapResults,
                PreferredItemId = preferredItemId,
                HiddenItemCount = hiddenItemCount,
                FallbackNpcName = fallbackNpcName,
                HasPacketOwnedMapResults = hasPacketOwnedMapResults
            };
        }

        private static bool TryParseQuestDeliveryTypeToken(string token, out QuestDetailDeliveryType deliveryType)
        {
            return QuestDetailDeliveryTypeCodec.TryParseToken(token, out deliveryType);
        }

        private bool TryApplyPacketOwnedStringPayload(byte[] payload, Func<string, string> applier, string emptyMessage, out string message)
        {
            message = emptyMessage;
            if (payload == null || payload.Length == 0)
            {
                return false;
            }

            if (!TryDecodePacketOwnedStringPayload(payload, out string decodedText))
            {
                return false;
            }

            message = applier(decodedText);
            return true;
        }

        private static bool TryDecodePacketOwnedStringPayload(byte[] payload, out string text)
        {
            text = null;
            if (payload == null || payload.Length == 0)
            {
                return false;
            }

            try
            {
                using MemoryStream stream = new(payload, writable: false);
                using BinaryReader reader = new(stream);
                string mapleString = ReadPacketOwnedMapleString(reader);
                if (reader.BaseStream.Position == reader.BaseStream.Length && !string.IsNullOrWhiteSpace(mapleString))
                {
                    text = mapleString.Trim();
                    return true;
                }
            }
            catch
            {
            }

            string utf8 = Encoding.UTF8.GetString(payload).TrimEnd('\0', '\r', '\n', ' ');
            if (!string.IsNullOrWhiteSpace(utf8))
            {
                text = utf8;
                return true;
            }

            return false;
        }

        private static bool TryDecodeExactPacketOwnedMapleString(byte[] payload, out string text)
        {
            text = null;
            if (payload == null || payload.Length == 0)
            {
                return false;
            }

            try
            {
                using MemoryStream stream = new(payload, writable: false);
                using BinaryReader reader = new(stream);
                string mapleString = ReadPacketOwnedMapleString(reader);
                if (reader.BaseStream.Position != reader.BaseStream.Length || string.IsNullOrWhiteSpace(mapleString))
                {
                    return false;
                }

                text = mapleString.Trim();
                return true;
            }
            catch
            {
                return false;
            }
        }

        private bool TryApplyPacketOwnedEventAlarmTextPayload(byte[] payload, out string message)
        {
            if (!TryDecodePacketOwnedEventAlarmTextPayload(
                    payload,
                    out bool clearRequested,
                    out EventAlarmLineSnapshot[] lines,
                    out string summary,
                    out string decodeMessage))
            {
                message = decodeMessage ?? "Event-alarm text payload could not be decoded.";
                return false;
            }

            StampPacketOwnedUtilityRequestState();
            _packetOwnedEventAlarmLines.Clear();
            if (!clearRequested)
            {
                _packetOwnedEventAlarmLines.AddRange(lines ?? Array.Empty<EventAlarmLineSnapshot>());
            }

            _lastPacketOwnedEventAlarmTick = Environment.TickCount;
            _lastPacketOwnedEventAlarmSummary = string.IsNullOrWhiteSpace(summary)
                ? clearRequested
                    ? "Packet-authored event-alarm CT lines cleared."
                    : $"Packet-authored event-alarm feed now carries {_packetOwnedEventAlarmLines.Count.ToString(CultureInfo.InvariantCulture)} CT line(s)."
                : summary;
            NotifyEventAlarmOwnerActivity("packet-owned event alarm");
            message = _lastPacketOwnedEventAlarmSummary;
            return true;
        }

        private bool TryApplyPacketOwnedEventCalendarEntriesPayload(byte[] payload, out string message)
        {
            if (!TryDecodePacketOwnedEventCalendarEntriesPayload(
                    payload,
                    out bool clearRequested,
                    out bool replaceExistingEntries,
                    out EventEntrySnapshot[] entries,
                    out bool hasAlarmLines,
                    out bool replaceAlarmLines,
                    out EventAlarmLineSnapshot[] alarmLines,
                    out string summary,
                    out string decodeMessage))
            {
                message = decodeMessage ?? "Event-calendar payload could not be decoded.";
                return false;
            }

            StampPacketOwnedUtilityRequestState();
            if (clearRequested || replaceExistingEntries)
            {
                _packetOwnedEventCalendarEntries.Clear();
            }

            int now = Environment.TickCount;
            int sortOrder = _packetOwnedEventCalendarEntries.Count;
            foreach (EventEntrySnapshot entry in entries ?? Array.Empty<EventEntrySnapshot>())
            {
                _packetOwnedEventCalendarEntries.Add(CloneEventEntryForOwnerSnapshot(entry, sortOrder++, now));
            }

            if (clearRequested || (hasAlarmLines && replaceAlarmLines))
            {
                _packetOwnedEventAlarmLines.Clear();
            }

            if (hasAlarmLines && !clearRequested)
            {
                _packetOwnedEventAlarmLines.AddRange(alarmLines ?? Array.Empty<EventAlarmLineSnapshot>());
                _lastPacketOwnedEventAlarmTick = now;
                _lastPacketOwnedEventAlarmSummary = string.IsNullOrWhiteSpace(summary)
                    ? $"Packet-authored attendance/calendar payload now carries {_packetOwnedEventAlarmLines.Count.ToString(CultureInfo.InvariantCulture)} CT line(s)."
                    : summary;
            }

            _lastPacketOwnedEventCalendarTick = now;
            _lastPacketOwnedEventCalendarSummary = string.IsNullOrWhiteSpace(summary)
                ? clearRequested
                    ? "Packet-authored event-calendar entries cleared."
                    : $"Packet-authored event-calendar feed now carries {_packetOwnedEventCalendarEntries.Count.ToString(CultureInfo.InvariantCulture)} owner row(s)."
                : summary;
            NotifyEventAlarmOwnerActivity("packet-owned event calendar");
            message = _lastPacketOwnedEventCalendarSummary;
            return true;
        }

        private bool TryApplyPacketOwnedRankingPagePayload(byte[] payload, out string message)
        {
            if (!TryDecodePacketOwnedRankingPagePayload(
                    payload,
                    out bool clearRequested,
                    out RankingEntrySnapshot[] entries,
                    out bool hasOwnerState,
                    out PacketOwnedRankingOwnerStateSnapshot ownerState,
                    out string summary,
                    out string decodeMessage))
            {
                message = decodeMessage ?? "Ranking-page payload could not be decoded.";
                return false;
            }

            StampPacketOwnedUtilityRequestState();
            if (ShouldReplacePacketOwnedRankingEntries(clearRequested, entries?.Length ?? 0))
            {
                _packetOwnedRankingEntries.Clear();
            }

            if (!clearRequested && entries is { Length: > 0 })
            {
                _packetOwnedRankingEntries.AddRange(entries);
            }

            if (clearRequested)
            {
                _packetOwnedRankingOwnerState = new PacketOwnedRankingOwnerStateSnapshot();
            }
            else if (hasOwnerState)
            {
                _packetOwnedRankingOwnerState = NormalizePacketOwnedRankingOwnerState(
                    ownerState,
                    _lastRankingOpenTick,
                    Environment.TickCount);
            }

            _lastPacketOwnedRankingTick = Environment.TickCount;
            _lastPacketOwnedRankingSummary = string.IsNullOrWhiteSpace(summary)
                ? clearRequested
                    ? "Packet-authored CUIRanking page rows cleared."
                    : $"Packet-authored CUIRanking page now carries {_packetOwnedRankingEntries.Count.ToString(CultureInfo.InvariantCulture)} row(s)."
                : summary;
            TryShowRecordedProgressionUtilityWindow(
                MapSimulatorWindowNames.Ranking,
                "packet-owned ranking page",
                allowVisibleReset: false);
            message = _lastPacketOwnedRankingSummary;
            return true;
        }

        internal static bool ShouldReplacePacketOwnedRankingEntries(bool clearRequested, int decodedEntryCount)
        {
            return clearRequested || decodedEntryCount > 0;
        }

        private static PacketOwnedRankingOwnerStateSnapshot NormalizePacketOwnedRankingOwnerState(
            PacketOwnedRankingOwnerStateSnapshot ownerState,
            int rankingOpenTick,
            int nowTick)
        {
            PacketOwnedRankingOwnerStateSnapshot normalized = ownerState ?? new PacketOwnedRankingOwnerStateSnapshot();
            if (normalized.IsLoading != true || normalized.LoadingStartTick != int.MinValue)
            {
                return normalized;
            }

            int resolvedLoadingStartTick = rankingOpenTick != int.MinValue
                ? rankingOpenTick
                : nowTick;
            return new PacketOwnedRankingOwnerStateSnapshot
            {
                Subtitle = normalized.Subtitle,
                StatusText = normalized.StatusText,
                NavigationCaption = normalized.NavigationCaption,
                NavigationSeedText = normalized.NavigationSeedText,
                NavigateUrl = normalized.NavigateUrl,
                NavigationHostText = normalized.NavigationHostText,
                NavigationRequestText = normalized.NavigationRequestText,
                NavigationStateText = normalized.NavigationStateText,
                ServerHost = normalized.ServerHost,
                TemplateId = normalized.TemplateId,
                WorldId = normalized.WorldId,
                CharacterId = normalized.CharacterId,
                IsLoading = normalized.IsLoading,
                LoadingStartTick = resolvedLoadingStartTick
            };
        }

        private static bool TryDecodePacketOwnedEventAlarmTextPayload(
            byte[] payload,
            out bool clearRequested,
            out EventAlarmLineSnapshot[] lines,
            out string summary,
            out string message)
        {
            clearRequested = false;
            lines = Array.Empty<EventAlarmLineSnapshot>();
            summary = string.Empty;
            message = "Event-alarm text payload is missing.";
            if (payload == null || payload.Length == 0)
            {
                return false;
            }

            if (!TryDecodePacketOwnedStringPayload(payload, out string decodedText))
            {
                message = "Event-alarm text payload must decode to MapleString, UTF-8 text, or a JSON text body.";
                return false;
            }

            if (TryDecodePacketOwnedEventAlarmTextJsonPayload(decodedText, out clearRequested, out lines, out summary, out message))
            {
                return clearRequested || lines.Length > 0;
            }

            string normalizedText = decodedText.Trim();
            if (string.Equals(normalizedText, "clear", StringComparison.OrdinalIgnoreCase)
                || string.Equals(normalizedText, "reset", StringComparison.OrdinalIgnoreCase))
            {
                clearRequested = true;
                summary = "Cleared packet-authored event-alarm CT lines.";
                message = summary;
                return true;
            }

            string[] textLines = normalizedText.Split(
                new[] { "\r\n", "\n" },
                StringSplitOptions.RemoveEmptyEntries | StringSplitOptions.TrimEntries);
            if (textLines.Length == 0)
            {
                message = "Event-alarm text payload did not contain any usable line text.";
                return false;
            }

            lines = textLines
                .Select((line, index) => CreateEventAlarmLine(line, index))
                .ToArray();
            summary = $"Applied packet-authored event-alarm text with {lines.Length.ToString(CultureInfo.InvariantCulture)} CT line(s).";
            message = summary;
            return true;
        }

        internal static bool TryDecodePacketOwnedEventAlarmTextPayloadForTests(
            byte[] payload,
            out bool clearRequested,
            out EventAlarmLineSnapshot[] lines,
            out string summary,
            out string message)
        {
            return TryDecodePacketOwnedEventAlarmTextPayload(payload, out clearRequested, out lines, out summary, out message);
        }

        private static bool TryDecodePacketOwnedEventAlarmTextJsonPayload(
            string payloadText,
            out bool clearRequested,
            out EventAlarmLineSnapshot[] lines,
            out string summary,
            out string message)
        {
            clearRequested = false;
            lines = Array.Empty<EventAlarmLineSnapshot>();
            summary = string.Empty;
            message = "Event-alarm JSON payload did not contain any usable CT line data.";
            if (string.IsNullOrWhiteSpace(payloadText))
            {
                return false;
            }

            string trimmed = payloadText.Trim();
            if (!trimmed.StartsWith("{", StringComparison.Ordinal)
                && !trimmed.StartsWith("[", StringComparison.Ordinal))
            {
                return false;
            }

            try
            {
                using JsonDocument document = JsonDocument.Parse(trimmed);
                JsonElement root = document.RootElement;
                List<EventAlarmLineSnapshot> parsedLines = new();
                if (root.ValueKind == JsonValueKind.Object)
                {
                    if (TryGetJsonBoolean(root, "clear", out bool parsedClear))
                    {
                        clearRequested = parsedClear;
                    }

                    if (TryGetJsonString(root, "summary", out string parsedSummary))
                    {
                        summary = parsedSummary;
                    }

                    if (TryGetJsonArrayProperty(root, out JsonElement lineArray, "lines", "alarmLines", "ctLines", "texts", "messages", "m_aCT", "ct")
                        || TryGetJsonNestedArrayProperty(
                            root,
                            out lineArray,
                            new[] { "alarm", "eventAlarm", "cUIEventAlarm", "payload", "data", "result", "body" },
                            new[] { "lines", "alarmLines", "ctLines", "messages", "m_aCT", "ct" }))
                    {
                        AppendPacketOwnedEventAlarmJsonLines(lineArray, parsedLines);
                    }
                    else if (TryGetJsonStringProperty(root, out string inlineText, "text", "message", "alarmText", "ctText", "m_aCT", "ct"))
                    {
                        AppendPacketOwnedEventAlarmStringLines(inlineText, parsedLines);
                    }
                }
                else if (root.ValueKind == JsonValueKind.Array)
                {
                    AppendPacketOwnedEventAlarmJsonLines(root, parsedLines);
                }

                lines = parsedLines.ToArray();
                if (string.IsNullOrWhiteSpace(summary))
                {
                    summary = clearRequested
                        ? "Cleared packet-authored event-alarm CT lines."
                        : lines.Length > 0
                            ? $"Applied packet-authored event-alarm JSON payload with {lines.Length.ToString(CultureInfo.InvariantCulture)} CT line(s)."
                            : string.Empty;
                }

                message = summary;
                return clearRequested || lines.Length > 0;
            }
            catch (JsonException ex)
            {
                message = $"Event-alarm JSON payload could not be parsed: {ex.Message}";
                return false;
            }
        }

        private static void AppendPacketOwnedEventAlarmJsonLines(JsonElement element, ICollection<EventAlarmLineSnapshot> destination)
        {
            if (destination == null || element.ValueKind != JsonValueKind.Array)
            {
                return;
            }

            int index = destination.Count;
            foreach (JsonElement item in element.EnumerateArray())
            {
                if (item.ValueKind == JsonValueKind.String)
                {
                    string text = item.GetString()?.Trim();
                    if (!string.IsNullOrWhiteSpace(text))
                    {
                        destination.Add(CreateEventAlarmLine(text, index++));
                    }

                    continue;
                }

                if (item.ValueKind != JsonValueKind.Object
                    || !TryGetJsonStringProperty(item, out string lineText, "text", "message", "line", "caption", "label", "ct", "m_aCT")
                    || string.IsNullOrWhiteSpace(lineText))
                {
                    continue;
                }

                destination.Add(new EventAlarmLineSnapshot
                {
                    Text = lineText.Trim(),
                    Left = TryGetJsonInt32(item, "left", out int left) ? left : 0,
                    Top = TryGetJsonInt32(item, "top", out int top) ? top : index * 13,
                    FontIndex = TryGetPacketOwnedEventAlarmLineFontIndex(item, out int fontIndex) ? fontIndex : null,
                    IsHighlighted = TryGetJsonBoolean(item, "highlight", out bool highlight) && highlight,
                    TextColorArgb = TryGetPacketOwnedEventAlarmLineColor(item, out int colorArgb) ? colorArgb : null
                });
                index++;
            }
        }

        private static bool TryGetPacketOwnedEventAlarmLineFontIndex(JsonElement element, out int fontIndex)
        {
            return TryGetJsonInt32Property(
                       element,
                       out fontIndex,
                       "fontIndex",
                       "font",
                       "fontId",
                       "fontType")
                   && fontIndex >= 0;
        }

        private static bool TryGetPacketOwnedEventAlarmLineColor(JsonElement element, out int colorArgb)
        {
            if (TryGetJsonInt32Property(
                    element,
                    out colorArgb,
                    "textColorArgb",
                    "fontColorArgb",
                    "colorArgb",
                    "argb",
                    "fontColor",
                    "color"))
            {
                return true;
            }

            if (TryGetJsonStringProperty(
                    element,
                    out string colorText,
                    "textColorArgb",
                    "fontColorArgb",
                    "colorArgb",
                    "argb",
                    "fontColor",
                    "color"))
            {
                return TryParsePacketOwnedEventAlarmLineColor(colorText, out colorArgb);
            }

            colorArgb = 0;
            return false;
        }

        private static bool TryParsePacketOwnedEventAlarmLineColor(string colorText, out int colorArgb)
        {
            colorArgb = 0;
            if (string.IsNullOrWhiteSpace(colorText))
            {
                return false;
            }

            string normalized = colorText.Trim();
            if (normalized.StartsWith("#", StringComparison.Ordinal))
            {
                normalized = normalized[1..];
            }
            else if (normalized.StartsWith("0x", StringComparison.OrdinalIgnoreCase))
            {
                normalized = normalized[2..];
            }

            if (normalized.Length == 6
                && uint.TryParse(normalized, NumberStyles.HexNumber, CultureInfo.InvariantCulture, out uint rgb))
            {
                colorArgb = unchecked((int)(0xFF000000u | rgb));
                return true;
            }

            if (normalized.Length == 8
                && uint.TryParse(normalized, NumberStyles.HexNumber, CultureInfo.InvariantCulture, out uint argb))
            {
                colorArgb = unchecked((int)argb);
                return true;
            }

            return int.TryParse(colorText, NumberStyles.Integer, CultureInfo.InvariantCulture, out colorArgb);
        }

        private static void AppendPacketOwnedEventAlarmStringLines(string text, ICollection<EventAlarmLineSnapshot> destination)
        {
            if (destination == null || string.IsNullOrWhiteSpace(text))
            {
                return;
            }

            int index = destination.Count;
            string[] segments = text.Split(
                new[] { "\r\n", "\n" },
                StringSplitOptions.RemoveEmptyEntries | StringSplitOptions.TrimEntries);
            for (int i = 0; i < segments.Length; i++)
            {
                if (!string.IsNullOrWhiteSpace(segments[i]))
                {
                    destination.Add(CreateEventAlarmLine(segments[i], index++));
                }
            }
        }

        private static bool TryDecodePacketOwnedEventCalendarEntriesPayload(
            byte[] payload,
            out bool clearRequested,
            out bool replaceExistingEntries,
            out EventEntrySnapshot[] entries,
            out bool hasAlarmLines,
            out bool replaceAlarmLines,
            out EventAlarmLineSnapshot[] alarmLines,
            out string summary,
            out string message)
        {
            clearRequested = false;
            replaceExistingEntries = true;
            entries = Array.Empty<EventEntrySnapshot>();
            hasAlarmLines = false;
            replaceAlarmLines = true;
            alarmLines = Array.Empty<EventAlarmLineSnapshot>();
            summary = string.Empty;
            message = "Event-calendar payload is missing.";
            if (payload == null || payload.Length == 0)
            {
                return false;
            }

            byte[] normalizedPayload = payload;
            if (TryUnwrapPacketOwnedPayloadForType(
                    payload,
                    LocalUtilityPacketInboxManager.EventCalendarEntriesPacketType,
                    out byte[] unwrappedPayload))
            {
                normalizedPayload = unwrappedPayload;
            }

            if (TryDecodePacketOwnedEventCalendarBinaryPayload(
                    normalizedPayload,
                    out clearRequested,
                    out replaceExistingEntries,
                    out entries,
                    out hasAlarmLines,
                    out replaceAlarmLines,
                    out alarmLines,
                    out summary,
                    out message))
            {
                return clearRequested || entries.Length > 0 || (hasAlarmLines && alarmLines.Length > 0);
            }

            bool hasLengthPrefixedPayload = TryResolvePacketOwnedLengthPrefixedPayload(normalizedPayload, out byte[] lengthPrefixedPayload);
            if (hasLengthPrefixedPayload
                && TryDecodePacketOwnedEventCalendarBinaryPayload(
                    lengthPrefixedPayload,
                    out clearRequested,
                    out replaceExistingEntries,
                    out entries,
                    out hasAlarmLines,
                    out replaceAlarmLines,
                    out alarmLines,
                    out summary,
                    out message))
            {
                return clearRequested || entries.Length > 0 || (hasAlarmLines && alarmLines.Length > 0);
            }

            if (!TryDecodePacketOwnedStringPayload(normalizedPayload, out string decodedText)
                && (!hasLengthPrefixedPayload
                    || !TryDecodePacketOwnedStringPayload(lengthPrefixedPayload, out decodedText)))
            {
                message = "Event-calendar payload must decode to a binary owner-row envelope, MapleString, UTF-8 text, or a JSON text body.";
                return false;
            }

            if (TryDecodePacketOwnedEventCalendarJsonPayload(
                    decodedText,
                    out clearRequested,
                    out replaceExistingEntries,
                    out entries,
                    out hasAlarmLines,
                    out replaceAlarmLines,
                    out alarmLines,
                    out summary,
                    out message))
            {
                return clearRequested || entries.Length > 0 || (hasAlarmLines && alarmLines.Length > 0);
            }

            string normalizedText = decodedText.Trim();
            if (string.Equals(normalizedText, "clear", StringComparison.OrdinalIgnoreCase)
                || string.Equals(normalizedText, "reset", StringComparison.OrdinalIgnoreCase))
            {
                clearRequested = true;
                summary = "Cleared packet-authored event-calendar entries.";
                message = summary;
                return true;
            }

            if (TryDecodePacketOwnedEventCalendarHtmlPayload(
                    normalizedText,
                    out entries,
                    out alarmLines,
                    out summary,
                    out message))
            {
                hasAlarmLines = alarmLines.Length > 0;
                return entries.Length > 0 || hasAlarmLines;
            }

            List<EventEntrySnapshot> parsedEntries = new();
            string[] entryLines = normalizedText.Split(
                new[] { "\r\n", "\n" },
                StringSplitOptions.RemoveEmptyEntries | StringSplitOptions.TrimEntries);
            for (int i = 0; i < entryLines.Length; i++)
            {
                if (TryParsePacketOwnedEventCalendarTextEntry(entryLines[i], i, out EventEntrySnapshot parsedEntry))
                {
                    parsedEntries.Add(parsedEntry);
                }
            }

            if (parsedEntries.Count == 0)
            {
                message = "Event-calendar payload did not contain any usable event rows.";
                return false;
            }

            entries = parsedEntries.ToArray();
            alarmLines = BuildFallbackPacketOwnedEventCalendarAlarmLines(entries);
            hasAlarmLines = alarmLines.Length > 0;
            summary = $"Applied packet-authored event-calendar payload with {entries.Length.ToString(CultureInfo.InvariantCulture)} owner row(s).";
            message = summary;
            return true;
        }

        private static bool TryDecodePacketOwnedEventCalendarHtmlPayload(
            string payloadText,
            out EventEntrySnapshot[] entries,
            out EventAlarmLineSnapshot[] alarmLines,
            out string summary,
            out string message)
        {
            entries = Array.Empty<EventEntrySnapshot>();
            alarmLines = Array.Empty<EventAlarmLineSnapshot>();
            summary = string.Empty;
            message = "Event-calendar HTML payload did not contain a usable CUIEventAlarm owner table.";
            if (string.IsNullOrWhiteSpace(payloadText)
                || payloadText.IndexOf('<') < 0
                || (payloadText.IndexOf("<tr", StringComparison.OrdinalIgnoreCase) < 0
                    && payloadText.IndexOf("<li", StringComparison.OrdinalIgnoreCase) < 0
                    && payloadText.IndexOf("<div", StringComparison.OrdinalIgnoreCase) < 0))
            {
                return false;
            }

            List<EventEntrySnapshot> parsedEntries = new();
            List<string> headerCells = new();
            MatchCollection rowMatches = Regex.Matches(
                payloadText,
                @"<tr\b[^>]*>(.*?)</tr>",
                RegexOptions.IgnoreCase | RegexOptions.Singleline | RegexOptions.CultureInvariant);
            foreach (Match rowMatch in rowMatches)
            {
                string rowHtml = rowMatch.Groups[1].Value;
                MatchCollection cellMatches = Regex.Matches(
                    rowHtml,
                    @"<t[dh]\b[^>]*>(.*?)</t[dh]>",
                    RegexOptions.IgnoreCase | RegexOptions.Singleline | RegexOptions.CultureInvariant);
                if (cellMatches.Count == 0)
                {
                    continue;
                }

                List<string> cells = cellMatches
                    .Cast<Match>()
                    .Select(match => NormalizePacketOwnedRankingHtmlCell(match.Groups[1].Value))
                    .Where(cell => !string.IsNullOrWhiteSpace(cell))
                    .ToList();
                if (cells.Count == 0)
                {
                    continue;
                }

                if (Regex.IsMatch(rowHtml, @"<th\b", RegexOptions.IgnoreCase | RegexOptions.CultureInvariant))
                {
                    headerCells = cells;
                    continue;
                }

                if (TryCreatePacketOwnedEventCalendarEntryFromHtmlCells(cells, headerCells, parsedEntries.Count, out EventEntrySnapshot entry))
                {
                    parsedEntries.Add(entry);
                }
            }

            if (parsedEntries.Count == 0)
            {
                AppendPacketOwnedEventCalendarHtmlListEntries(payloadText, parsedEntries);
            }

            if (parsedEntries.Count == 0)
            {
                return false;
            }

            entries = parsedEntries.ToArray();
            alarmLines = BuildFallbackPacketOwnedEventCalendarAlarmLines(entries);
            summary = $"Applied packet-authored CUIEventAlarm HTML page with {entries.Length.ToString(CultureInfo.InvariantCulture)} owner row(s).";
            message = summary;
            return true;
        }

        private static void AppendPacketOwnedEventCalendarHtmlListEntries(string payloadText, ICollection<EventEntrySnapshot> destination)
        {
            if (string.IsNullOrWhiteSpace(payloadText) || destination == null)
            {
                return;
            }

            MatchCollection rowMatches = Regex.Matches(
                payloadText,
                @"<(?:li|div)\b(?<attrs>[^>]*)>(?<body>.*?)</(?:li|div)>",
                RegexOptions.IgnoreCase | RegexOptions.Singleline | RegexOptions.CultureInvariant);
            foreach (Match rowMatch in rowMatches)
            {
                string attrs = rowMatch.Groups["attrs"].Value;
                string body = rowMatch.Groups["body"].Value;
                string dateText = TryExtractPacketOwnedHtmlAttribute(attrs, "data-date")
                    ?? TryExtractPacketOwnedHtmlAttribute(attrs, "data-day")
                    ?? ExtractPacketOwnedHtmlClassText(body, "date")
                    ?? ExtractPacketOwnedHtmlClassText(body, "day");
                string title = TryExtractPacketOwnedHtmlAttribute(attrs, "data-title")
                    ?? TryExtractPacketOwnedHtmlAttribute(attrs, "data-event")
                    ?? ExtractPacketOwnedHtmlClassText(body, "title")
                    ?? ExtractPacketOwnedHtmlClassText(body, "event")
                    ?? NormalizePacketOwnedRankingHtmlCell(body);
                string detail = TryExtractPacketOwnedHtmlAttribute(attrs, "data-detail")
                    ?? ExtractPacketOwnedHtmlClassText(body, "detail")
                    ?? ExtractPacketOwnedHtmlClassText(body, "desc");
                string statusText = TryExtractPacketOwnedHtmlAttribute(attrs, "data-status")
                    ?? ExtractPacketOwnedHtmlClassText(body, "status");
                string alarmText = TryExtractPacketOwnedHtmlAttribute(attrs, "data-alarm")
                    ?? ExtractPacketOwnedHtmlClassText(body, "alarm");

                if (string.IsNullOrWhiteSpace(dateText)
                    || string.IsNullOrWhiteSpace(title)
                    || !TryParsePacketOwnedEventDate(dateText, out DateTime scheduledAt))
                {
                    continue;
                }

                EventEntryStatus status = TryParsePacketOwnedEventEntryStatus(statusText, out EventEntryStatus parsedStatus)
                    ? parsedStatus
                    : EventEntryStatus.Upcoming;
                destination.Add(CreatePacketOwnedEventCalendarEntry(
                    scheduledAt,
                    title.Trim(),
                    detail?.Trim() ?? string.Empty,
                    status,
                    string.IsNullOrWhiteSpace(statusText) ? GetDefaultPacketOwnedEventStatusText(status) : statusText.Trim(),
                    int.MinValue,
                    ResolvePacketOwnedEventEntrySortPriority(status),
                    destination.Count,
                    alarmText: alarmText?.Trim() ?? string.Empty));
            }
        }

        private static bool TryCreatePacketOwnedEventCalendarEntryFromHtmlCells(
            IReadOnlyList<string> cells,
            IReadOnlyList<string> headerCells,
            int sortOrder,
            out EventEntrySnapshot entry)
        {
            entry = new EventEntrySnapshot();
            if (cells == null || cells.Count == 0)
            {
                return false;
            }

            string dateText = GetPacketOwnedHtmlCell(cells, headerCells, "date", "day", "start", "event date") ?? cells[0];
            if (!TryParsePacketOwnedEventDate(dateText, out DateTime scheduledAt))
            {
                return false;
            }

            string title = GetPacketOwnedHtmlCell(cells, headerCells, "title", "event", "name", "subject")
                ?? (cells.Count > 1 ? cells[1] : string.Empty);
            if (string.IsNullOrWhiteSpace(title))
            {
                return false;
            }

            string detail = GetPacketOwnedHtmlCell(cells, headerCells, "detail", "desc", "description", "reward") ?? string.Empty;
            string statusText = GetPacketOwnedHtmlCell(cells, headerCells, "status", "state", "progress") ?? string.Empty;
            string alarmText = GetPacketOwnedHtmlCell(cells, headerCells, "alarm", "ct", "message", "notice") ?? string.Empty;
            EventEntryStatus status = TryParsePacketOwnedEventEntryStatus(statusText, out EventEntryStatus parsedStatus)
                ? parsedStatus
                : EventEntryStatus.Upcoming;

            entry = CreatePacketOwnedEventCalendarEntry(
                scheduledAt,
                title.Trim(),
                detail.Trim(),
                status,
                string.IsNullOrWhiteSpace(statusText) ? GetDefaultPacketOwnedEventStatusText(status) : statusText.Trim(),
                int.MinValue,
                ResolvePacketOwnedEventEntrySortPriority(status),
                sortOrder,
                alarmText: alarmText.Trim());
            return true;
        }

        private static string GetPacketOwnedHtmlCell(IReadOnlyList<string> cells, IReadOnlyList<string> headerCells, params string[] names)
        {
            if (cells == null || headerCells == null || names == null || headerCells.Count == 0)
            {
                return null;
            }

            for (int i = 0; i < headerCells.Count && i < cells.Count; i++)
            {
                string header = headerCells[i]?.Trim();
                if (string.IsNullOrWhiteSpace(header))
                {
                    continue;
                }

                for (int j = 0; j < names.Length; j++)
                {
                    if (header.IndexOf(names[j], StringComparison.OrdinalIgnoreCase) >= 0)
                    {
                        return cells[i];
                    }
                }
            }

            return null;
        }

        private static string TryExtractPacketOwnedHtmlAttribute(string attrs, string name)
        {
            if (string.IsNullOrWhiteSpace(attrs) || string.IsNullOrWhiteSpace(name))
            {
                return null;
            }

            Match match = Regex.Match(
                attrs,
                $@"\b{Regex.Escape(name)}\s*=\s*(?:""(?<value>[^""]*)""|'(?<value>[^']*)'|(?<value>[^\s>]+))",
                RegexOptions.IgnoreCase | RegexOptions.CultureInvariant);
            return match.Success
                ? WebUtility.HtmlDecode(match.Groups["value"].Value).Trim()
                : null;
        }

        private static string ExtractPacketOwnedHtmlClassText(string html, string className)
        {
            if (string.IsNullOrWhiteSpace(html) || string.IsNullOrWhiteSpace(className))
            {
                return null;
            }

            Match match = Regex.Match(
                html,
                $@"<[^>]*\bclass\s*=\s*(?:""[^""]*\b{Regex.Escape(className)}\b[^""]*""|'[^']*\b{Regex.Escape(className)}\b[^']*')[^>]*>(?<body>.*?)</[^>]+>",
                RegexOptions.IgnoreCase | RegexOptions.Singleline | RegexOptions.CultureInvariant);
            return match.Success
                ? NormalizePacketOwnedRankingHtmlCell(match.Groups["body"].Value)
                : null;
        }

