        private static bool TryDecodePacketOwnedRankingPageHtmlPayload(
            string payloadText,
            out RankingEntrySnapshot[] entries,
            out string summary,
            out string message)
        {
            entries = Array.Empty<RankingEntrySnapshot>();
            summary = string.Empty;
            message = "Ranking-page HTML payload did not contain a usable CWebWnd ranking table.";
            if (string.IsNullOrWhiteSpace(payloadText)
                || (payloadText.IndexOf("<tr", StringComparison.OrdinalIgnoreCase) < 0
                    && payloadText.IndexOf("<li", StringComparison.OrdinalIgnoreCase) < 0
                    && payloadText.IndexOf("<div", StringComparison.OrdinalIgnoreCase) < 0))
            {
                return false;
            }

            List<RankingEntrySnapshot> parsedEntries = new();
            List<string> headerCells = new();
            if (payloadText.IndexOf("<tr", StringComparison.OrdinalIgnoreCase) >= 0)
            {
                MatchCollection rowMatches = Regex.Matches(
                    payloadText,
                    @"<tr\b[^>]*>(.*?)</tr>",
                    RegexOptions.IgnoreCase | RegexOptions.Singleline | RegexOptions.CultureInvariant);
                foreach (Match rowMatch in rowMatches)
                {
                    string rowHtml = rowMatch.Groups[1].Value;
                    MatchCollection cellMatches = Regex.Matches(
                        rowHtml,
                        @"<t[dh]\b[^>]*>(.*?)</t[dh]>",
                        RegexOptions.IgnoreCase | RegexOptions.Singleline | RegexOptions.CultureInvariant);
                    if (cellMatches.Count == 0)
                    {
                        continue;
                    }

                    List<string> cells = cellMatches
                        .Cast<Match>()
                        .Select(match => NormalizePacketOwnedRankingHtmlCell(match.Groups[1].Value))
                        .Where(cell => !string.IsNullOrWhiteSpace(cell))
                        .ToList();
                    if (cells.Count == 0)
                    {
                        continue;
                    }

                    bool isHeaderRow = Regex.IsMatch(rowHtml, @"<th\b", RegexOptions.IgnoreCase | RegexOptions.CultureInvariant);
                    if (isHeaderRow)
                    {
                        headerCells = cells;
                        continue;
                    }

                    if (TryCreatePacketOwnedRankingEntryFromHtmlCells(cells, headerCells, out RankingEntrySnapshot entry))
                    {
                        parsedEntries.Add(entry);
                    }
                }
            }

            if (parsedEntries.Count == 0)
            {
                AppendPacketOwnedRankingHtmlListEntries(payloadText, parsedEntries);
            }

            if (parsedEntries.Count == 0)
            {
                AppendPacketOwnedRankingEmbeddedJsonEntries(payloadText, parsedEntries);
            }

            if (parsedEntries.Count == 0)
            {
                return false;
            }

            entries = parsedEntries.ToArray();
            summary = $"Applied packet-authored CWebWnd ranking HTML page with {entries.Length.ToString(CultureInfo.InvariantCulture)} row(s).";
            message = summary;
            return true;
        }

        private static void AppendPacketOwnedRankingEmbeddedJsonEntries(string payloadText, ICollection<RankingEntrySnapshot> destination)
        {
            if (string.IsNullOrWhiteSpace(payloadText) || destination == null)
            {
                return;
            }

            MatchCollection scriptMatches = Regex.Matches(
                payloadText,
                @"<script\b[^>]*>(?<body>.*?)</script>",
                RegexOptions.IgnoreCase | RegexOptions.Singleline | RegexOptions.CultureInvariant);
            foreach (Match scriptMatch in scriptMatches)
            {
                AppendPacketOwnedRankingEmbeddedJsonEntriesFromScript(scriptMatch.Groups["body"].Value, destination);
                if (destination.Count > 0)
                {
                    return;
                }
            }

            AppendPacketOwnedRankingEmbeddedJsonEntriesFromScript(payloadText, destination);
        }

        private static void AppendPacketOwnedRankingEmbeddedJsonEntriesFromScript(string scriptText, ICollection<RankingEntrySnapshot> destination)
        {
            if (string.IsNullOrWhiteSpace(scriptText) || destination == null)
            {
                return;
            }

            MatchCollection jsonMatches = Regex.Matches(
                scriptText,
                @"(?:(?:rankings?|rankingList|rankingRows|standings|rows|entries)\s*[:=]\s*)(?<json>\[[\s\S]*?\])",
                RegexOptions.IgnoreCase | RegexOptions.CultureInvariant);
            foreach (Match jsonMatch in jsonMatches)
            {
                string json = jsonMatch.Groups["json"].Value;
                if (TryAppendPacketOwnedRankingEmbeddedJsonArray(json, destination)
                    && destination.Count > 0)
                {
                    return;
                }
            }
        }

        private static bool TryAppendPacketOwnedRankingEmbeddedJsonArray(string json, ICollection<RankingEntrySnapshot> destination)
        {
            if (string.IsNullOrWhiteSpace(json) || destination == null)
            {
                return false;
            }

            try
            {
                using JsonDocument document = JsonDocument.Parse(json);
                if (document.RootElement.ValueKind != JsonValueKind.Array)
                {
                    return false;
                }

                int beforeCount = destination.Count;
                AppendPacketOwnedRankingJsonEntries(document.RootElement, destination);
                return destination.Count > beforeCount;
            }
            catch (JsonException)
            {
                return false;
            }
        }

        private static void AppendPacketOwnedRankingHtmlListEntries(string payloadText, ICollection<RankingEntrySnapshot> destination)
        {
            if (string.IsNullOrWhiteSpace(payloadText) || destination == null)
            {
                return;
            }

            MatchCollection rowMatches = Regex.Matches(
                payloadText,
                @"<(?<tag>li|div)\b(?<attrs>[^>]*)>(?<body>.*?)</\k<tag>>",
                RegexOptions.IgnoreCase | RegexOptions.Singleline | RegexOptions.CultureInvariant);
            foreach (Match rowMatch in rowMatches)
            {
                string attrs = rowMatch.Groups["attrs"].Value;
                string rowHtml = rowMatch.Groups["body"].Value;
                if (!IsPacketOwnedRankingHtmlRow(attrs, rowHtml))
                {
                    continue;
                }

                if (TryCreatePacketOwnedRankingEntryFromHtmlListRow(attrs, rowHtml, out RankingEntrySnapshot entry))
                {
                    destination.Add(entry);
                }
            }
        }

        private static bool IsPacketOwnedRankingHtmlRow(string attrs, string rowHtml)
        {
            string rowMarker = ((attrs ?? string.Empty) + " " + (rowHtml ?? string.Empty)).ToLowerInvariant();
            return rowMarker.Contains("rank")
                || rowMarker.Contains("character")
                || rowMarker.Contains("char")
                || rowMarker.Contains("world")
                || rowMarker.Contains("job");
        }

        private static bool TryCreatePacketOwnedRankingEntryFromHtmlListRow(
            string attrs,
            string rowHtml,
            out RankingEntrySnapshot entry)
        {
            entry = null;
            string rank = ResolvePacketOwnedRankingHtmlField(attrs, rowHtml, "rank", "ranking", "position", "place", "data-rank", "data-position");
            string label = ResolvePacketOwnedRankingHtmlField(attrs, rowHtml, "character", "charactername", "charname", "name", "player", "ranker", "data-character", "data-name");
            string job = ResolvePacketOwnedRankingHtmlField(attrs, rowHtml, "job", "jobname", "class", "data-job");
            string world = ResolvePacketOwnedRankingHtmlField(attrs, rowHtml, "world", "worldname", "server", "data-world");
            if (string.IsNullOrWhiteSpace(label))
            {
                List<string> cells = Regex.Matches(
                        rowHtml,
                        @"<(?:span|a|em|strong|p)\b[^>]*>(.*?)</(?:span|a|em|strong|p)>",
                        RegexOptions.IgnoreCase | RegexOptions.Singleline | RegexOptions.CultureInvariant)
                    .Cast<Match>()
                    .Select(match => NormalizePacketOwnedRankingHtmlCell(match.Groups[1].Value))
                    .Where(cell => !string.IsNullOrWhiteSpace(cell))
                    .ToList();
                if (cells.Count >= 2)
                {
                    rank = string.IsNullOrWhiteSpace(rank) ? cells[0] : rank;
                    label = cells[1];
                    job = string.IsNullOrWhiteSpace(job) && cells.Count >= 3 ? cells[2] : job;
                    world = string.IsNullOrWhiteSpace(world) && cells.Count >= 4 ? cells[3] : world;
                }
            }

            if (string.IsNullOrWhiteSpace(label))
            {
                return false;
            }

            List<string> detailParts = new();
            AddPacketOwnedRankingHtmlDetailPart(detailParts, job);
            AddPacketOwnedRankingHtmlDetailPart(detailParts, world);
            entry = CreatePacketOwnedRankingEntry(label, rank, string.Join(" / ", detailParts));
            return true;
        }

        private static string ResolvePacketOwnedRankingHtmlField(string attrs, string rowHtml, params string[] aliases)
        {
            foreach (string alias in aliases ?? Array.Empty<string>())
            {
                if (TryExtractPacketOwnedRankingHtmlAttribute(attrs, alias, out string attributeValue)
                    || TryExtractPacketOwnedRankingHtmlClassText(rowHtml, alias, out attributeValue))
                {
                    return attributeValue;
                }
            }

            return string.Empty;
        }

        private static bool TryExtractPacketOwnedRankingHtmlAttribute(string attrs, string alias, out string value)
        {
            value = string.Empty;
            if (string.IsNullOrWhiteSpace(attrs) || string.IsNullOrWhiteSpace(alias))
            {
                return false;
            }

            string normalizedAlias = Regex.Escape(alias);
            Match match = Regex.Match(
                attrs,
                $@"(?:^|\s){normalizedAlias}\s*=\s*(?:""(?<value>[^""]*)""|'(?<value>[^']*)'|(?<value>[^\s>]+))",
                RegexOptions.IgnoreCase | RegexOptions.CultureInvariant);
            if (!match.Success)
            {
                return false;
            }

            value = WebUtility.HtmlDecode(match.Groups["value"].Value)?.Trim() ?? string.Empty;
            return !string.IsNullOrWhiteSpace(value);
        }

        private static bool TryExtractPacketOwnedRankingHtmlClassText(string rowHtml, string alias, out string value)
        {
            value = string.Empty;
            if (string.IsNullOrWhiteSpace(rowHtml) || string.IsNullOrWhiteSpace(alias))
            {
                return false;
            }

            string normalizedAlias = Regex.Escape(alias);
            Match match = Regex.Match(
                rowHtml,
                $@"<(?<tag>[a-z0-9]+)\b[^>]*(?:class|id)\s*=\s*(?:""[^""]*\b{normalizedAlias}\b[^""]*""|'[^']*\b{normalizedAlias}\b[^']*'|[^\s>]*\b{normalizedAlias}\b[^\s>]*)[^>]*>(?<value>.*?)</\k<tag>>",
                RegexOptions.IgnoreCase | RegexOptions.Singleline | RegexOptions.CultureInvariant);
            if (!match.Success)
            {
                return false;
            }

            value = NormalizePacketOwnedRankingHtmlCell(match.Groups["value"].Value);
            return !string.IsNullOrWhiteSpace(value);
        }

        private static string NormalizePacketOwnedRankingHtmlCell(string html)
        {
            if (string.IsNullOrWhiteSpace(html))
            {
                return string.Empty;
            }

            string withoutTags = Regex.Replace(
                html,
                @"<[^>]+>",
                " ",
                RegexOptions.Singleline | RegexOptions.CultureInvariant);
            string decoded = WebUtility.HtmlDecode(withoutTags) ?? string.Empty;
            return Regex.Replace(decoded, @"\s+", " ", RegexOptions.CultureInvariant).Trim();
        }

        private static bool TryCreatePacketOwnedRankingEntryFromHtmlCells(
            IReadOnlyList<string> cells,
            IReadOnlyList<string> headerCells,
            out RankingEntrySnapshot entry)
        {
            entry = null;
            if (cells == null || cells.Count == 0)
            {
                return false;
            }

            int rankIndex = ResolvePacketOwnedRankingHtmlColumnIndex(headerCells, "rank", "ranking", "position", "place");
            int nameIndex = ResolvePacketOwnedRankingHtmlColumnIndex(headerCells, "character", "charactername", "charname", "name", "player", "ranker");
            int jobIndex = ResolvePacketOwnedRankingHtmlColumnIndex(headerCells, "job", "jobname", "class");
            int worldIndex = ResolvePacketOwnedRankingHtmlColumnIndex(headerCells, "world", "worldname", "server");
            if (rankIndex < 0 && cells.Count >= 2)
            {
                rankIndex = 0;
            }

            if (nameIndex < 0 && cells.Count >= 2)
            {
                nameIndex = rankIndex == 0 ? 1 : 0;
            }

            if (jobIndex < 0 && cells.Count >= 3)
            {
                jobIndex = cells.Count > 3 && nameIndex == 1 ? 2 : -1;
            }

            if (worldIndex < 0 && cells.Count >= 4)
            {
                worldIndex = cells.Count > 3 && nameIndex == 1 ? 3 : -1;
            }

            string label = GetPacketOwnedRankingHtmlCell(cells, nameIndex);
            if (string.IsNullOrWhiteSpace(label))
            {
                return false;
            }

            string value = GetPacketOwnedRankingHtmlCell(cells, rankIndex);
            List<string> detailParts = new();
            AddPacketOwnedRankingHtmlDetailPart(detailParts, GetPacketOwnedRankingHtmlCell(cells, jobIndex));
            AddPacketOwnedRankingHtmlDetailPart(detailParts, GetPacketOwnedRankingHtmlCell(cells, worldIndex));
            for (int i = 0; i < cells.Count; i++)
            {
                if (i == rankIndex || i == nameIndex || i == jobIndex || i == worldIndex)
                {
                    continue;
                }

                AddPacketOwnedRankingHtmlDetailPart(detailParts, cells[i]);
            }

            entry = CreatePacketOwnedRankingEntry(label, value, string.Join(" / ", detailParts));
            return true;
        }

        private static int ResolvePacketOwnedRankingHtmlColumnIndex(IReadOnlyList<string> headerCells, params string[] aliases)
        {
            if (headerCells == null || aliases == null)
            {
                return -1;
            }

            for (int i = 0; i < headerCells.Count; i++)
            {
                string normalizedHeader = Regex.Replace(
                    headerCells[i] ?? string.Empty,
                    @"[^a-z0-9]",
                    string.Empty,
                    RegexOptions.IgnoreCase | RegexOptions.CultureInvariant);
                for (int aliasIndex = 0; aliasIndex < aliases.Length; aliasIndex++)
                {
                    if (string.Equals(normalizedHeader, aliases[aliasIndex], StringComparison.OrdinalIgnoreCase))
                    {
                        return i;
                    }
                }
            }

            return -1;
        }

        private static string GetPacketOwnedRankingHtmlCell(IReadOnlyList<string> cells, int index)
        {
            return cells != null && index >= 0 && index < cells.Count
                ? cells[index]?.Trim() ?? string.Empty
                : string.Empty;
        }

        private static void AddPacketOwnedRankingHtmlDetailPart(ICollection<string> detailParts, string value)
        {
            if (detailParts != null && !string.IsNullOrWhiteSpace(value))
            {
                detailParts.Add(value.Trim());
            }
        }

        internal static bool TryDecodePacketOwnedRankingPagePayloadForTests(
            byte[] payload,
            out bool clearRequested,
            out RankingEntrySnapshot[] entries,
            out bool hasOwnerState,
            out PacketOwnedRankingOwnerStateSnapshot ownerState,
            out string summary,
            out string message)
        {
            return TryDecodePacketOwnedRankingPagePayload(
                payload,
                out clearRequested,
                out entries,
                out hasOwnerState,
                out ownerState,
                out summary,
                out message);
        }

        private static bool TryDecodePacketOwnedRankingPageBinaryPayload(
            byte[] payload,
            out bool clearRequested,
            out RankingEntrySnapshot[] entries,
            out bool hasOwnerState,
            out PacketOwnedRankingOwnerStateSnapshot ownerState,
            out string summary,
            out string message)
        {
            clearRequested = false;
            entries = Array.Empty<RankingEntrySnapshot>();
            hasOwnerState = false;
            ownerState = new PacketOwnedRankingOwnerStateSnapshot();
            summary = string.Empty;
            message = "Ranking-page binary payload did not match the owner-row envelope or compact row payload.";
            if (payload == null || payload.Length < 8)
            {
                return false;
            }

            try
            {
                using MemoryStream stream = new(payload, writable: false);
                using BinaryReader reader = new(stream);
                if (reader.ReadByte() != (byte)'R'
                    || reader.ReadByte() != (byte)'N'
                    || reader.ReadByte() != (byte)'K'
                    || reader.ReadByte() != 1)
                {
                    return TryDecodePacketOwnedRankingPageCompactBinaryPayload(
                        payload,
                        out clearRequested,
                        out entries,
                        out hasOwnerState,
                        out ownerState,
                        out summary,
                        out message);
                }

                byte flags = reader.ReadByte();
                clearRequested = (flags & 0x1) != 0;
                bool includesOwnerState = (flags & 0x2) != 0;
                int rowCount = reader.ReadUInt16();
                if (rowCount < 0 || rowCount > 100)
                {
                    return false;
                }

                List<RankingEntrySnapshot> parsedEntries = new(rowCount);
                for (int i = 0; i < rowCount; i++)
                {
                    string label = ReadPacketOwnedMapleString(reader)?.Trim();
                    string value = ReadPacketOwnedMapleString(reader)?.Trim();
                    string detail = ReadPacketOwnedMapleString(reader)?.Trim();
                    if (!string.IsNullOrWhiteSpace(label))
                    {
                        parsedEntries.Add(CreatePacketOwnedRankingEntry(label, value, detail));
                    }
                }

                if (includesOwnerState)
                {
                    string serverHost = ReadPacketOwnedMapleString(reader)?.Trim();
                    int templateId = reader.ReadInt32();
                    int worldId = reader.ReadInt32();
                    int characterId = reader.ReadInt32();
                    bool isLoading = reader.ReadByte() != 0;
                    string navigateUrl = string.Empty;
                    string navigationCaption = string.Empty;
                    string navigationHostText = string.Empty;
                    string navigationRequestText = string.Empty;
                    if (!string.IsNullOrWhiteSpace(serverHost))
                    {
                        navigateUrl = ProgressionUtilityParityRules.ResolveRankingLandingUrl(
                            serverHost,
                            templateId,
                            worldId,
                            characterId,
                            out _);
                        navigationCaption = ProgressionUtilityParityRules.FormatRankingLandingTemplateSeed(templateId, out _);
                        navigationHostText = $"get_server_string_0 => {serverHost}";
                        navigationRequestText = ProgressionUtilityParityRules.FormatRankingRequestParameters(worldId, characterId);
                    }

                    ownerState = new PacketOwnedRankingOwnerStateSnapshot
                    {
                        NavigationCaption = navigationCaption,
                        NavigationSeedText = string.IsNullOrWhiteSpace(navigateUrl) ? string.Empty : $"NavigateUrl => {navigateUrl}",
                        NavigateUrl = navigateUrl,
                        NavigationHostText = navigationHostText,
                        NavigationRequestText = navigationRequestText,
                        NavigationStateText = isLoading
                            ? "Packet-authored binary CWebWnd loading state remains active before NavigateUrl completes."
                            : string.IsNullOrWhiteSpace(navigateUrl)
                                ? string.Empty
                                : "Packet-authored binary CWebWnd owner resolved the ranking landing request.",
                        ServerHost = serverHost,
                        TemplateId = templateId,
                        WorldId = worldId,
                        CharacterId = characterId,
                        IsLoading = isLoading
                    };
                    hasOwnerState = ownerState.HasAnyState;
                }

                if (reader.BaseStream.Position != reader.BaseStream.Length)
                {
                    return false;
                }

                entries = parsedEntries.ToArray();
                summary = clearRequested
                    ? "Cleared packet-authored binary CUIRanking page rows."
                    : $"Applied packet-authored binary CUIRanking page with {entries.Length.ToString(CultureInfo.InvariantCulture)} row(s).";
                message = summary;
                return clearRequested || entries.Length > 0 || hasOwnerState;
            }
            catch
            {
                return TryDecodePacketOwnedRankingPageCompactBinaryPayload(
                    payload,
                    out clearRequested,
                    out entries,
                    out hasOwnerState,
                    out ownerState,
                    out summary,
                    out message);
            }
        }

        private static bool TryDecodePacketOwnedRankingPageCompactBinaryPayload(
            byte[] payload,
            out bool clearRequested,
            out RankingEntrySnapshot[] entries,
            out bool hasOwnerState,
            out PacketOwnedRankingOwnerStateSnapshot ownerState,
            out string summary,
            out string message)
        {
            clearRequested = false;
            entries = Array.Empty<RankingEntrySnapshot>();
            hasOwnerState = false;
            ownerState = new PacketOwnedRankingOwnerStateSnapshot();
            summary = string.Empty;
            message = "Ranking-page binary payload did not match the compact row payload.";
            if (payload == null || payload.Length < sizeof(ushort))
            {
                return false;
            }

            if (!TryDecodePacketOwnedRankingPageCompactBinaryVariant(
                    payload,
                    flagsBeforeRows: false,
                    rowCountByteWidth: sizeof(ushort),
                    out clearRequested,
                    out entries,
                    out hasOwnerState,
                    out ownerState))
            {
                if (!TryDecodePacketOwnedRankingPageCompactBinaryVariant(
                        payload,
                        flagsBeforeRows: true,
                        rowCountByteWidth: sizeof(ushort),
                        out clearRequested,
                        out entries,
                        out hasOwnerState,
                        out ownerState)
                    && !TryDecodePacketOwnedRankingPageCompactBinaryVariant(
                        payload,
                        flagsBeforeRows: true,
                        rowCountByteWidth: sizeof(byte),
                        out clearRequested,
                        out entries,
                        out hasOwnerState,
                        out ownerState)
                    && !TryDecodePacketOwnedRankingPageCompactBinaryVariant(
                        payload,
                        flagsBeforeRows: false,
                        rowCountByteWidth: sizeof(byte),
                        out clearRequested,
                        out entries,
                        out hasOwnerState,
                        out ownerState)
                    && !TryDecodePacketOwnedRankingPageCompactBinaryVariant(
                        payload,
                        flagsBeforeRows: true,
                        rowCountByteWidth: sizeof(int),
                        out clearRequested,
                        out entries,
                        out hasOwnerState,
                        out ownerState)
                    && !TryDecodePacketOwnedRankingPageCompactBinaryVariant(
                        payload,
                        flagsBeforeRows: false,
                        rowCountByteWidth: sizeof(int),
                        rowByteCountByteWidth: 0,
                        out clearRequested,
                        out entries,
                        out hasOwnerState,
                        out ownerState)
                    && !TryDecodePacketOwnedRankingPageCompactBinaryVariant(
                        payload,
                        flagsBeforeRows: true,
                        rowCountByteWidth: sizeof(byte),
                        rowByteCountByteWidth: sizeof(byte),
                        out clearRequested,
                        out entries,
                        out hasOwnerState,
                        out ownerState)
                    && !TryDecodePacketOwnedRankingPageCompactBinaryVariant(
                        payload,
                        flagsBeforeRows: false,
                        rowCountByteWidth: sizeof(byte),
                        rowByteCountByteWidth: sizeof(byte),
                        out clearRequested,
                        out entries,
                        out hasOwnerState,
                        out ownerState)
                    && !TryDecodePacketOwnedRankingPageCompactBinaryVariant(
                        payload,
                        flagsBeforeRows: true,
                        rowCountByteWidth: sizeof(ushort),
                        rowByteCountByteWidth: sizeof(byte),
                        out clearRequested,
                        out entries,
                        out hasOwnerState,
                        out ownerState)
                    && !TryDecodePacketOwnedRankingPageCompactBinaryVariant(
                        payload,
                        flagsBeforeRows: false,
                        rowCountByteWidth: sizeof(ushort),
                        rowByteCountByteWidth: sizeof(byte),
                        out clearRequested,
                        out entries,
                        out hasOwnerState,
                        out ownerState)
                    && !TryDecodePacketOwnedRankingPageCompactBinaryWiderRowLengthVariants(
                        payload,
                        out clearRequested,
                        out entries,
                        out hasOwnerState,
                        out ownerState))
                {
                    entries = Array.Empty<RankingEntrySnapshot>();
                    hasOwnerState = false;
                    ownerState = new PacketOwnedRankingOwnerStateSnapshot();
                    summary = string.Empty;
                    message = "Ranking-page binary payload did not match the compact row payload.";
                    return false;
                }
            }

            summary = clearRequested
                ? "Cleared packet-authored compact binary CUIRanking page rows."
                : $"Applied packet-authored compact binary CUIRanking page with {entries.Length.ToString(CultureInfo.InvariantCulture)} row(s).";
            message = summary;
            return clearRequested || entries.Length > 0 || hasOwnerState;
        }

        private static bool TryDecodePacketOwnedRankingPageCompactBinaryWiderRowLengthVariants(
            byte[] payload,
            out bool clearRequested,
            out RankingEntrySnapshot[] entries,
            out bool hasOwnerState,
            out PacketOwnedRankingOwnerStateSnapshot ownerState)
        {
            clearRequested = false;
            entries = Array.Empty<RankingEntrySnapshot>();
            hasOwnerState = false;
            ownerState = new PacketOwnedRankingOwnerStateSnapshot();
            if (payload == null || payload.Length < sizeof(ushort))
            {
                return false;
            }

            int[] rowCountWidths = { sizeof(byte), sizeof(ushort), sizeof(int) };
            int[] rowByteCountWidths = { sizeof(byte), sizeof(ushort), sizeof(int) };
            foreach (bool flagsBeforeRows in new[] { true, false })
            {
                foreach (int rowCountWidth in rowCountWidths)
                {
                    foreach (int rowByteCountWidth in rowByteCountWidths)
                    {
                        if (TryDecodePacketOwnedRankingPageCompactBinaryVariant(
                                payload,
                                flagsBeforeRows,
                                rowCountWidth,
                                rowByteCountWidth,
                                out clearRequested,
                                out entries,
                                out hasOwnerState,
                                out ownerState))
                        {
                            return true;
                        }
                    }
                }
            }

            return false;
        }

        private static bool TryDecodePacketOwnedRankingPageCompactBinaryVariant(
            byte[] payload,
            bool flagsBeforeRows,
            int rowCountByteWidth,
            out bool clearRequested,
            out RankingEntrySnapshot[] entries,
            out bool hasOwnerState,
            out PacketOwnedRankingOwnerStateSnapshot ownerState)
        {
            return TryDecodePacketOwnedRankingPageCompactBinaryVariant(
                payload,
                flagsBeforeRows,
                rowCountByteWidth,
                rowByteCountByteWidth: 0,
                out clearRequested,
                out entries,
                out hasOwnerState,
                out ownerState);
        }

        private static bool TryDecodePacketOwnedRankingPageCompactBinaryVariant(
            byte[] payload,
            bool flagsBeforeRows,
            int rowCountByteWidth,
            int rowByteCountByteWidth,
            out bool clearRequested,
            out RankingEntrySnapshot[] entries,
            out bool hasOwnerState,
            out PacketOwnedRankingOwnerStateSnapshot ownerState)
        {
            clearRequested = false;
            entries = Array.Empty<RankingEntrySnapshot>();
            hasOwnerState = false;
            ownerState = new PacketOwnedRankingOwnerStateSnapshot();
            if (payload == null || payload.Length < sizeof(ushort))
            {
                return false;
            }

            try
            {
                using MemoryStream stream = new(payload, writable: false);
                using BinaryReader reader = new(stream);

                byte flags = 0;
                bool includesOwnerState = false;
                if (flagsBeforeRows)
                {
                    flags = reader.ReadByte();
                    if ((flags & 0xFC) != 0)
                    {
                        return false;
                    }

                    clearRequested = (flags & 0x1) != 0;
                    includesOwnerState = (flags & 0x2) != 0;
                }

                if (!TryReadPacketOwnedCompactRowCount(reader, rowCountByteWidth, out int rowCount)
                    || rowCount < 0
                    || rowCount > 100)
                {
                    return false;
                }

                List<RankingEntrySnapshot> parsedEntries = new(rowCount);
                for (int i = 0; i < rowCount; i++)
                {
                    if (rowByteCountByteWidth > 0)
                    {
                        if (!TryReadPacketOwnedCompactRowCount(reader, rowByteCountByteWidth, out int rowByteCount)
                            || rowByteCount <= 0
                            || reader.BaseStream.Length - reader.BaseStream.Position < rowByteCount)
                        {
                            return false;
                        }

                        byte[] rowPayload = reader.ReadBytes(rowByteCount);
                        if (!TryDecodePacketOwnedRankingCompactRow(rowPayload, out RankingEntrySnapshot rowEntry))
                        {
                            return false;
                        }

                        if (!string.IsNullOrWhiteSpace(rowEntry.Label))
                        {
                            parsedEntries.Add(rowEntry);
                        }
                    }
                    else
                    {
                        string label = ReadPacketOwnedMapleString(reader)?.Trim();
                        string value = ReadPacketOwnedMapleString(reader)?.Trim();
                        string detail = ReadPacketOwnedMapleString(reader)?.Trim();
                        if (!string.IsNullOrWhiteSpace(label))
                        {
                            parsedEntries.Add(CreatePacketOwnedRankingEntry(label, value, detail));
                        }
                    }
                }

                if (!flagsBeforeRows && reader.BaseStream.Position < reader.BaseStream.Length)
                {
                    flags = reader.ReadByte();
                    clearRequested = (flags & 0x1) != 0;
                    includesOwnerState = (flags & 0x2) != 0;
                    if ((flags & 0xFC) != 0)
                    {
                        return false;
                    }
                }

                if (includesOwnerState
                    && !TryDecodePacketOwnedRankingOwnerStateBinary(
                        reader,
                        "Packet-authored compact binary CWebWnd loading state remains active before NavigateUrl completes.",
                        "Packet-authored compact binary CWebWnd owner resolved the ranking landing request.",
                        out ownerState))
                {
                    return false;
                }

                if (reader.BaseStream.Position != reader.BaseStream.Length)
                {
                    return false;
                }

                entries = parsedEntries.ToArray();
                hasOwnerState = ownerState.HasAnyState;
                return clearRequested || entries.Length > 0 || hasOwnerState;
            }
            catch
            {
                return false;
            }
        }

        private static bool TryDecodePacketOwnedRankingCompactRow(byte[] rowPayload, out RankingEntrySnapshot rowEntry)
        {
            rowEntry = default;
            if (rowPayload == null || rowPayload.Length == 0)
            {
                return false;
            }

            if (TryDecodePacketOwnedRankingCompactRowWithLeadingRank(rowPayload, out rowEntry))
            {
                return true;
            }

            if (TryDecodePacketOwnedRankingCompactRowWithByteStrings(rowPayload, out rowEntry))
            {
                return true;
            }

            try
            {
                using MemoryStream rowStream = new(rowPayload, writable: false);
                using BinaryReader rowReader = new(rowStream);
                if (!TryReadPacketOwnedOptionalMapleString(rowReader, out string label)
                    || string.IsNullOrWhiteSpace(label))
                {
                    return false;
                }

                if (!TryReadPacketOwnedOptionalMapleString(rowReader, out string value)
                    || !TryReadPacketOwnedOptionalMapleString(rowReader, out string detail)
                    || rowReader.BaseStream.Position != rowReader.BaseStream.Length)
                {
                    return false;
                }

                rowEntry = CreatePacketOwnedRankingEntry(label.Trim(), value?.Trim() ?? string.Empty, detail?.Trim() ?? string.Empty);
                return true;
            }
            catch
            {
                rowEntry = default;
                return false;
            }
        }

        private static bool TryDecodePacketOwnedRankingCompactRowWithByteStrings(byte[] rowPayload, out RankingEntrySnapshot rowEntry)
        {
            rowEntry = default;
            if (rowPayload == null || rowPayload.Length == 0)
            {
                return false;
            }

            try
            {
                using MemoryStream rowStream = new(rowPayload, writable: false);
                using BinaryReader rowReader = new(rowStream);
                if (!TryReadPacketOwnedCompactString(rowReader, sizeof(byte), out string label)
                    || string.IsNullOrWhiteSpace(label)
                    || !TryReadPacketOwnedCompactString(rowReader, sizeof(byte), out string value)
                    || !TryReadPacketOwnedCompactString(rowReader, sizeof(byte), out string detail)
                    || rowReader.BaseStream.Position != rowReader.BaseStream.Length)
                {
                    return false;
                }

                rowEntry = CreatePacketOwnedRankingEntry(label.Trim(), value?.Trim() ?? string.Empty, detail?.Trim() ?? string.Empty);
                return true;
            }
            catch
            {
                rowEntry = default;
                return false;
            }
        }

        private static bool TryDecodePacketOwnedRankingCompactRowWithLeadingRank(byte[] rowPayload, out RankingEntrySnapshot rowEntry)
        {
            rowEntry = default;
            int[] rankWidths = { sizeof(int), sizeof(ushort), sizeof(byte) };
            for (int i = 0; i < rankWidths.Length; i++)
            {
                if (TryDecodePacketOwnedRankingCompactRowWithLeadingRank(rowPayload, rankWidths[i], out rowEntry))
                {
                    return true;
                }
            }

            return false;
        }

        private bool TryApplyPacketOwnedEngagementRequestPayload(byte[] payload, string source, out string message)
        {
            if (!EngagementProposalRuntime.TryDecodePayloadSubtype(payload, out byte subtype, out message))
            {
                return false;
            }

            if (subtype == EngagementProposalRuntime.RequestPayloadValue)
            {
                string proposerName = ResolvePacketOwnedEngagementSourceName(source, _lastPacketOwnedMateName);
                string partnerName = ResolvePacketOwnedEngagementLocalName();
                if (!_engagementProposalController.TryOpenIncomingProposalFromRequestPayload(
                        proposerName,
                        partnerName,
                        EngagementProposalRuntime.DefaultSealItemId,
                        payload,
                        ResolvePacketOwnedEngagementSourceMessage(source),
                        uiWindowManager,
                        _playerManager?.Player?.Build,
                        _fontChat,
                        ShowUtilityFeedbackMessage,
                        () => ShowDirectionModeOwnedWindow(MapSimulatorWindowNames.EngagementProposal),
                        out message))
                {
                    return false;
                }

                message = $"Applied client-shaped engagement request packet {EngagementProposalRuntime.AcceptPacketType} [00] from {proposerName}. {message}";
                return true;
            }

            if (subtype == EngagementProposalRuntime.WithdrawPayloadValue)
            {
                return _engagementProposalController.TryApplyWithdrawPayload(payload, uiWindowManager, out message);
            }

            if (subtype == EngagementProposalRuntime.DecisionPayloadValue)
            {
                return _engagementProposalController.TryApplyDecisionPayload(payload, uiWindowManager, out message);
            }

            message = $"Engagement request packet {EngagementProposalRuntime.AcceptPacketType} subtype {subtype:00} is not owned by CEngageDlg.";
            return false;
        }

        internal static string ResolvePacketOwnedEngagementSourceName(string source)
        {
            return ResolvePacketOwnedEngagementSourceName(source, string.Empty);
        }

        internal static string ResolvePacketOwnedEngagementSourceName(string source, string packetOwnedMateName)
        {
            string normalized = source?.Trim();
            string mateName = packetOwnedMateName?.Trim();
            if (string.IsNullOrWhiteSpace(normalized))
            {
                return string.IsNullOrWhiteSpace(mateName) ? "Requester" : mateName;
            }

            Match match = Regex.Match(normalized, @"(?:^|[;,\s])(?:from|proposer|requester|name)[:=](?<name>[^;,\s]+)", RegexOptions.IgnoreCase);
            if (match.Success && !string.IsNullOrWhiteSpace(match.Groups["name"].Value))
            {
                return match.Groups["name"].Value.Trim();
            }

            if (normalized.StartsWith("official-session:", StringComparison.OrdinalIgnoreCase))
            {
                return string.IsNullOrWhiteSpace(mateName) ? "Requester" : mateName;
            }

            return normalized.Length <= 12 && normalized.All(ch => char.IsLetterOrDigit(ch) || ch == '_')
                ? normalized
                : string.IsNullOrWhiteSpace(mateName) ? "Requester" : mateName;
        }

        private string ResolvePacketOwnedEngagementLocalName()
        {
            string localName = _playerManager?.Player?.Build?.Name;
            return string.IsNullOrWhiteSpace(localName)
                ? "Player"
                : localName.Trim();
        }

        private static string ResolvePacketOwnedEngagementSourceMessage(string source)
        {
            string normalized = source?.Trim();
            if (string.IsNullOrWhiteSpace(normalized))
            {
                return string.Empty;
            }

            Match match = Regex.Match(normalized, @"(?:^|[;,\s])(?:message|note)[:=](?<message>[^;]+)", RegexOptions.IgnoreCase);
            return match.Success
                ? match.Groups["message"].Value.Trim()
                : string.Empty;
        }

        private static bool TryDecodePacketOwnedRankingCompactRowWithLeadingRank(byte[] rowPayload, int rankByteWidth, out RankingEntrySnapshot rowEntry)
        {
            rowEntry = default;
            if (rowPayload == null || rowPayload.Length <= rankByteWidth)
            {
                return false;
            }

            try
            {
                using MemoryStream rowStream = new(rowPayload, writable: false);
                using BinaryReader rowReader = new(rowStream);
                if (!TryReadPacketOwnedCompactRowCount(rowReader, rankByteWidth, out int rank)
                    || rank <= 0
                    || rank > 1000000
                    || !TryReadPacketOwnedOptionalMapleString(rowReader, out string label)
                    || string.IsNullOrWhiteSpace(label)
                    || !TryReadPacketOwnedOptionalMapleString(rowReader, out string detail))
                {
                    return false;
                }

                string value = rank.ToString(CultureInfo.InvariantCulture);
                if (rowReader.BaseStream.Position < rowReader.BaseStream.Length)
                {
                    if (!TryReadPacketOwnedOptionalMapleString(rowReader, out string explicitValue))
                    {
                        return false;
                    }

                    explicitValue = explicitValue?.Trim();
                    if (!string.IsNullOrWhiteSpace(explicitValue))
                    {
                        value = explicitValue;
                    }
                }

                if (rowReader.BaseStream.Position != rowReader.BaseStream.Length)
                {
                    return false;
                }

                rowEntry = CreatePacketOwnedRankingEntry(label.Trim(), value, detail?.Trim() ?? string.Empty);
                return true;
            }
            catch
            {
                rowEntry = default;
                return false;
            }
        }

        private static bool TryDecodePacketOwnedRankingOwnerStateBinary(
            BinaryReader reader,
            string loadingStateText,
            string resolvedStateText,
            out PacketOwnedRankingOwnerStateSnapshot ownerState)
        {
            ownerState = new PacketOwnedRankingOwnerStateSnapshot();
            if (reader == null)
            {
                return false;
            }

            try
            {
                string serverHost = ReadPacketOwnedMapleString(reader)?.Trim();
                int templateId = reader.ReadInt32();
                int worldId = reader.ReadInt32();
                int characterId = reader.ReadInt32();
                bool isLoading = reader.ReadByte() != 0;
                string navigateUrl = string.Empty;
                string navigationCaption = string.Empty;
                string navigationHostText = string.Empty;
                string navigationRequestText = string.Empty;
                if (!string.IsNullOrWhiteSpace(serverHost))
                {
                    navigateUrl = ProgressionUtilityParityRules.ResolveRankingLandingUrl(
                        serverHost,
                        templateId,
                        worldId,
                        characterId,
                        out _);
                    navigationCaption = ProgressionUtilityParityRules.FormatRankingLandingTemplateSeed(templateId, out _);
                    navigationHostText = $"get_server_string_0 => {serverHost}";
                    navigationRequestText = ProgressionUtilityParityRules.FormatRankingRequestParameters(worldId, characterId);
                }

                ownerState = new PacketOwnedRankingOwnerStateSnapshot
                {
                    NavigationCaption = navigationCaption,
                    NavigationSeedText = string.IsNullOrWhiteSpace(navigateUrl) ? string.Empty : $"NavigateUrl => {navigateUrl}",
                    NavigateUrl = navigateUrl,
                    NavigationHostText = navigationHostText,
                    NavigationRequestText = navigationRequestText,
                    NavigationStateText = isLoading
                        ? loadingStateText
                        : string.IsNullOrWhiteSpace(navigateUrl)
                            ? string.Empty
                            : resolvedStateText,
                    ServerHost = serverHost,
                    TemplateId = templateId,
                    WorldId = worldId,
                    CharacterId = characterId,
                    IsLoading = isLoading
                };
                return true;
            }
            catch
            {
                ownerState = new PacketOwnedRankingOwnerStateSnapshot();
                return false;
            }
        }

        private static bool TryUnwrapPacketOwnedPayloadForType(byte[] payload, int packetType, out byte[] unwrappedPayload)
        {
            unwrappedPayload = payload ?? Array.Empty<byte>();
            if (payload == null || payload.Length <= 0)
            {
                return false;
            }

            if (LocalUtilityPacketInboxManager.TryDecodeOpcodeFramedPacket(
                    payload,
                    out int decodedPacketType,
                    out byte[] decodedPayload,
                    out _)
                && decodedPacketType == packetType)
            {
                unwrappedPayload = decodedPayload ?? Array.Empty<byte>();
                return true;
            }

            if (payload.Length >= sizeof(int)
                && BitConverter.ToInt32(payload, 0) == packetType)
            {
                unwrappedPayload = payload.Length == sizeof(int)
                    ? Array.Empty<byte>()
                    : payload[sizeof(int)..];
                return true;
            }

            return false;
        }

        private static bool TryResolvePacketOwnedLengthPrefixedPayload(byte[] payload, out byte[] resolvedPayload)
        {
            resolvedPayload = payload ?? Array.Empty<byte>();
            if (payload == null || payload.Length <= sizeof(int))
            {
                return false;
            }

            int littleEndianLength = BitConverter.ToInt32(payload, 0);
            int bigEndianLength =
                (payload[0] << 24)
                | (payload[1] << 16)
                | (payload[2] << 8)
                | payload[3];

            if (TryMatchPacketOwnedLengthPrefixedBodyLength(payload, littleEndianLength, out resolvedPayload)
                || TryMatchPacketOwnedLengthPrefixedBodyLength(payload, bigEndianLength, out resolvedPayload))
            {
                return true;
            }

            resolvedPayload = payload;
            return false;
        }

        private static bool TryMatchPacketOwnedLengthPrefixedBodyLength(byte[] payload, int declaredLength, out byte[] resolvedPayload)
        {
            resolvedPayload = payload;
            if (declaredLength <= 0)
            {
                return false;
            }

            if (declaredLength == payload.Length - sizeof(int)
                || declaredLength == payload.Length)
            {
                resolvedPayload = payload[sizeof(int)..];
                return true;
            }

            return false;
        }

        private static bool TryReadPacketOwnedCompactRowCount(BinaryReader reader, int rowCountByteWidth, out int rowCount)
        {
            rowCount = 0;
            if (reader == null)
            {
                return false;
            }

            switch (rowCountByteWidth)
            {
                case sizeof(byte):
                    if (reader.BaseStream.Length - reader.BaseStream.Position < sizeof(byte))
                    {
                        return false;
                    }

                    rowCount = reader.ReadByte();
                    return true;

                case sizeof(ushort):
                    if (reader.BaseStream.Length - reader.BaseStream.Position < sizeof(ushort))
                    {
                        return false;
                    }

                    rowCount = reader.ReadUInt16();
                    return true;

                case sizeof(int):
                    if (reader.BaseStream.Length - reader.BaseStream.Position < sizeof(int))
                    {
                        return false;
                    }

                    rowCount = reader.ReadInt32();
                    return true;

                default:
                    return false;
            }
        }

        private static bool TryReadPacketOwnedOptionalMapleString(BinaryReader reader, out string value)
        {
            value = string.Empty;
            if (reader == null)
            {
                return false;
            }

            long remaining = reader.BaseStream.Length - reader.BaseStream.Position;
            if (remaining <= 0)
            {
                return true;
            }

            if (remaining < sizeof(ushort))
            {
                return false;
            }

            long startPosition = reader.BaseStream.Position;
            try
            {
                value = ReadPacketOwnedMapleString(reader);
                return true;
            }
            catch
            {
                if (reader.BaseStream.CanSeek)
                {
                    reader.BaseStream.Position = startPosition;
                }

                value = string.Empty;
                return false;
            }
        }

        private static bool TryDecodePacketOwnedRankingPageJsonPayload(
            string payloadText,
            out bool clearRequested,
            out RankingEntrySnapshot[] entries,
            out bool hasOwnerState,
            out PacketOwnedRankingOwnerStateSnapshot ownerState,
            out string summary,
            out string message)
        {
            clearRequested = false;
            entries = Array.Empty<RankingEntrySnapshot>();
            hasOwnerState = false;
            ownerState = new PacketOwnedRankingOwnerStateSnapshot();
            summary = string.Empty;
            message = "Ranking-page JSON payload did not contain any usable owner rows.";
            if (string.IsNullOrWhiteSpace(payloadText))
            {
                return false;
            }

            string trimmed = payloadText.Trim();
            if (!trimmed.StartsWith("{", StringComparison.Ordinal)
                && !trimmed.StartsWith("[", StringComparison.Ordinal))
            {
                return false;
            }

            try
            {
                using JsonDocument document = JsonDocument.Parse(trimmed);
                JsonElement root = document.RootElement;
                List<RankingEntrySnapshot> parsedEntries = new();
                if (root.ValueKind == JsonValueKind.Object)
                {
                    if (TryGetJsonBoolean(root, "clear", out bool parsedClear))
                    {
                        clearRequested = parsedClear;
                    }

                    if (TryGetJsonString(root, "summary", out string parsedSummary))
                    {
                        summary = parsedSummary;
                    }

                    JsonElement ownerStateElement = root;
                    if (TryGetJsonObjectProperty(root, out JsonElement nestedOwnerState, "ownerState", "web", "webOwner", "cwebwnd", "cWebWnd"))
                    {
                        ownerStateElement = nestedOwnerState;
                    }

                    hasOwnerState = TryParsePacketOwnedRankingOwnerState(ownerStateElement, out ownerState);
                    if (TryGetJsonArrayProperty(
                        root,
                        out JsonElement entryArray,
                        "entries",
                        "rows",
                        "standings",
                        "rankingEntries",
                        "rankingRows",
                        "cards",
                        "items",
                        "results",
                        "records",
                        "rankings",
                        "rankingList")
                        || TryGetJsonNestedArrayProperty(
                            root,
                            out entryArray,
                            new[] { "ownerState", "web", "webOwner", "cwebwnd", "cWebWnd", "page", "payload", "data", "result", "body", "ranking", "rankings" },
                            new[] { "entries", "rows", "standings", "rankingEntries", "rankingRows", "cards", "items", "results", "records", "rankingList" }))
                    {
                        AppendPacketOwnedRankingJsonEntries(entryArray, parsedEntries);
                    }

                    if (parsedEntries.Count == 0
                        && TryResolvePacketOwnedRankingHtmlText(root, out string embeddedHtml)
                        && TryDecodePacketOwnedRankingPageHtmlPayload(embeddedHtml, out RankingEntrySnapshot[] htmlEntries, out string htmlSummary, out _))
                    {
                        parsedEntries.AddRange(htmlEntries);
                        if (string.IsNullOrWhiteSpace(summary))
                        {
                            summary = htmlSummary;
                        }
                    }
                }
                else if (root.ValueKind == JsonValueKind.Array)
                {
                    AppendPacketOwnedRankingJsonEntries(root, parsedEntries);
                }

                entries = parsedEntries.ToArray();
                if (string.IsNullOrWhiteSpace(summary))
                {
                    summary = clearRequested
                        ? "Cleared packet-authored CUIRanking page rows."
                        : entries.Length > 0
                            ? $"Applied packet-authored CUIRanking JSON page with {entries.Length.ToString(CultureInfo.InvariantCulture)} row(s)."
                            : string.Empty;
                }

                message = summary;
                return clearRequested || entries.Length > 0 || hasOwnerState;
            }
            catch (JsonException ex)
            {
                message = $"Ranking-page JSON payload could not be parsed: {ex.Message}";
                return false;
            }
        }

        private static void AppendPacketOwnedRankingJsonEntries(JsonElement element, ICollection<RankingEntrySnapshot> destination)
        {
            if (destination == null || element.ValueKind != JsonValueKind.Array)
            {
                return;
            }

            foreach (JsonElement item in element.EnumerateArray())
            {
                if (item.ValueKind == JsonValueKind.String)
                {
                    string text = item.GetString()?.Trim();
                    if (!string.IsNullOrWhiteSpace(text)
                        && TryParsePacketOwnedRankingTextEntry(text, out RankingEntrySnapshot textEntry))
                    {
                        destination.Add(textEntry);
                    }

                    continue;
                }

                if (item.ValueKind != JsonValueKind.Object)
                {
                    continue;
                }

                JsonElement rankingItem = item;
                if (TryGetJsonObjectProperty(
                        rankingItem,
                        out JsonElement nestedRankingEntry,
                        "entry",
                        "row",
                        "standing",
                        "card",
                        "item",
                        "record",
                        "character",
                        "player",
                        "avatar",
                        "ranker"))
                {
                    rankingItem = nestedRankingEntry;
                }

                string label = ResolvePacketOwnedRankingEntryText(
                    rankingItem,
                    item,
                    "label",
                    "title",
                    "name",
                    "category",
                    "characterName",
                    "charName",
                    "userName",
                    "avatarName",
                    "rowLabel");
                string value = ResolvePacketOwnedRankingEntryText(
                    item,
                    rankingItem,
                    "value",
                    "rank",
                    "position",
                    "place",
                    "ranking",
                    "rankNo",
                    "orderNo",
                    "score",
                    "level",
                    "worldRank");
                string detail = ResolvePacketOwnedRankingEntryText(
                    item,
                    rankingItem,
                    "detail",
                    "description",
                    "desc",
                    "job",
                    "jobName",
                    "world",
                    "worldName",
                    "guild",
                    "guildName",
                    "message",
                    "extra");
                if (string.IsNullOrWhiteSpace(label))
                {
                    continue;
                }

                destination.Add(CreatePacketOwnedRankingEntry(label, value, detail));
            }
        }

        private static bool TryParsePacketOwnedRankingTextEntry(string line, out RankingEntrySnapshot entry)
        {
            entry = null;
            if (string.IsNullOrWhiteSpace(line))
            {
                return false;
            }

            string[] tokens = line.Split('|', 3);
            string label = tokens[0].Trim();
            if (string.IsNullOrWhiteSpace(label))
            {
                return false;
            }

            string value = tokens.Length > 1 ? tokens[1].Trim() : string.Empty;
            string detail = tokens.Length > 2 ? tokens[2].Trim() : string.Empty;
            entry = CreatePacketOwnedRankingEntry(label, value, detail);
            return true;
        }

        private static RankingEntrySnapshot CreatePacketOwnedRankingEntry(string label, string value, string detail)
        {
            return new RankingEntrySnapshot
            {
                Label = label?.Trim() ?? string.Empty,
                Value = value?.Trim() ?? string.Empty,
                Detail = detail?.Trim() ?? string.Empty
            };
        }

        private static bool TryDecodePacketOwnedEventCalendarBinaryPayload(
            byte[] payload,
            out bool clearRequested,
            out bool replaceExistingEntries,
            out EventEntrySnapshot[] entries,
            out bool hasAlarmLines,
            out bool replaceAlarmLines,
            out EventAlarmLineSnapshot[] alarmLines,
            out string summary,
            out string message)
        {
            clearRequested = false;
            replaceExistingEntries = true;
            entries = Array.Empty<EventEntrySnapshot>();
            hasAlarmLines = false;
            replaceAlarmLines = true;
            alarmLines = Array.Empty<EventAlarmLineSnapshot>();
            summary = string.Empty;
            message = "Event-calendar binary payload did not match the owner-row envelope or compact row payload.";
            if (payload == null || payload.Length < 8)
            {
                return false;
            }

            try
            {
                using MemoryStream stream = new(payload, writable: false);
                using BinaryReader reader = new(stream);
                if (reader.ReadByte() != (byte)'E'
                    || reader.ReadByte() != (byte)'V'
                    || reader.ReadByte() != (byte)'C')
                {
                    return TryDecodePacketOwnedEventCalendarCompactBinaryPayload(
                        payload,
                        out clearRequested,
                        out replaceExistingEntries,
                        out entries,
                        out hasAlarmLines,
                        out replaceAlarmLines,
                        out alarmLines,
                        out summary,
                        out message);
                }

                byte version = reader.ReadByte();
                if (version is not 1 and not 2)
                {
                    return false;
                }

                byte flags = reader.ReadByte();
                clearRequested = (flags & 0x1) != 0;
                replaceExistingEntries = (flags & 0x2) != 0;
                bool includesAlarmLines = (flags & 0x4) != 0;
                replaceAlarmLines = (flags & 0x8) != 0;
                int rowCount = reader.ReadUInt16();
                if (rowCount < 0 || rowCount > 100)
                {
                    return false;
                }

                List<EventEntrySnapshot> parsedEntries = new(rowCount);
                for (int i = 0; i < rowCount; i++)
                {
                    int year = reader.ReadUInt16();
                    int month = reader.ReadByte();
                    int day = reader.ReadByte();
                    EventEntryStatus status = DecodePacketOwnedEventCalendarBinaryStatus(reader.ReadByte());
                    string title = ReadPacketOwnedMapleString(reader)?.Trim();
                    string detail = ReadPacketOwnedMapleString(reader)?.Trim();
                    string statusText = ReadPacketOwnedMapleString(reader)?.Trim();
                    string alarmText = version >= 2
                        ? ReadPacketOwnedMapleString(reader)?.Trim()
                        : string.Empty;
                    if (!TryCreatePacketOwnedEventCalendarBinaryDate(year, month, day, out DateTime scheduledAt)
                        || string.IsNullOrWhiteSpace(title))
                    {
                        continue;
                    }

                    parsedEntries.Add(CreatePacketOwnedEventCalendarEntry(
                        scheduledAt,
                        title,
                        detail,
                        status,
                        string.IsNullOrWhiteSpace(statusText) ? GetDefaultPacketOwnedEventStatusText(status) : statusText,
                        int.MinValue,
                        ResolvePacketOwnedEventEntrySortPriority(status),
                        parsedEntries.Count,
                        alarmText: alarmText));
                }

                if (includesAlarmLines)
                {
                    int lineCount = reader.ReadUInt16();
                    if (lineCount < 0 || lineCount > EventAlarmOwnerMaxVisibleLines)
                    {
                        return false;
                    }

                    List<EventAlarmLineSnapshot> parsedLines = new(lineCount);
                    for (int i = 0; i < lineCount; i++)
                    {
                        string text = ReadPacketOwnedMapleString(reader)?.Trim();
                        int left = reader.ReadInt16();
                        int top = reader.ReadInt16();
                        byte lineFlags = reader.ReadByte();
                        int colorArgb = reader.ReadInt32();
                        if (string.IsNullOrWhiteSpace(text))
                        {
                            continue;
                        }

                        parsedLines.Add(new EventAlarmLineSnapshot
                        {
                            Text = text,
                            Left = left,
                            Top = top,
                            FontIndex = ResolvePacketOwnedEventAlarmLineFontIndex(lineFlags),
                            IsHighlighted = (lineFlags & 0x1) != 0,
                            TextColorArgb = colorArgb == 0 ? null : colorArgb
                        });
                    }

                    alarmLines = parsedLines.ToArray();
                    hasAlarmLines = alarmLines.Length > 0;
                }

                if (reader.BaseStream.Position != reader.BaseStream.Length)
                {
                    return false;
                }

                entries = parsedEntries.ToArray();
                if (!clearRequested && !hasAlarmLines && entries.Length > 0)
                {
                    alarmLines = BuildFallbackPacketOwnedEventCalendarAlarmLines(entries);
                    hasAlarmLines = alarmLines.Length > 0;
                }

                summary = clearRequested
                    ? "Cleared packet-authored binary event-calendar entries."
                    : $"Applied packet-authored binary event-calendar payload with {entries.Length.ToString(CultureInfo.InvariantCulture)} owner row(s).";
                message = summary;
                return clearRequested || entries.Length > 0 || (hasAlarmLines && alarmLines.Length > 0);
            }
            catch
            {
                return TryDecodePacketOwnedEventCalendarCompactBinaryPayload(
                    payload,
                    out clearRequested,
                    out replaceExistingEntries,
                    out entries,
                    out hasAlarmLines,
                    out replaceAlarmLines,
                    out alarmLines,
                    out summary,
                    out message);
            }
        }

