        private static bool TryDecodePacketOwnedEventCalendarCompactRow(
            byte[] rowPayload,
            bool usePackedDate,
            out EventEntrySnapshot entry)
        {
            entry = default;
            if (rowPayload == null || rowPayload.Length == 0)
            {
                return false;
            }

            try
            {
                using MemoryStream rowStream = new(rowPayload, writable: false);
                using BinaryReader rowReader = new(rowStream);
                if (!TryDecodePacketOwnedEventCalendarCompactRow(rowReader, usePackedDate, out entry)
                    || rowReader.BaseStream.Position != rowReader.BaseStream.Length)
                {
                    if (!TryDecodePacketOwnedEventCalendarCompactRowWithTrailingStatus(rowPayload, usePackedDate, out entry)
                        && !TryDecodePacketOwnedEventCalendarCompactRowWithByteStrings(rowPayload, usePackedDate, statusBeforeText: true, out entry)
                        && !TryDecodePacketOwnedEventCalendarCompactRowWithByteStrings(rowPayload, usePackedDate, statusBeforeText: false, out entry))
                    {
                        return false;
                    }
                }

                return true;
            }
            catch
            {
                return TryDecodePacketOwnedEventCalendarCompactRowWithTrailingStatus(rowPayload, usePackedDate, out entry)
                       || TryDecodePacketOwnedEventCalendarCompactRowWithByteStrings(rowPayload, usePackedDate, statusBeforeText: true, out entry)
                       || TryDecodePacketOwnedEventCalendarCompactRowWithByteStrings(rowPayload, usePackedDate, statusBeforeText: false, out entry);
            }
        }

        private static bool TryDecodePacketOwnedEventCalendarCompactRowWithByteStrings(
            byte[] rowPayload,
            bool usePackedDate,
            bool statusBeforeText,
            out EventEntrySnapshot entry)
        {
            entry = default;
            if (rowPayload == null || rowPayload.Length == 0)
            {
                return false;
            }

            try
            {
                using MemoryStream rowStream = new(rowPayload, writable: false);
                using BinaryReader rowReader = new(rowStream);

                int year;
                int month;
                int day;
                if (usePackedDate)
                {
                    int yyyymmdd = rowReader.ReadInt32();
                    year = yyyymmdd / 10000;
                    month = Math.Abs((yyyymmdd / 100) % 100);
                    day = Math.Abs(yyyymmdd % 100);
                }
                else
                {
                    year = rowReader.ReadUInt16();
                    month = rowReader.ReadByte();
                    day = rowReader.ReadByte();
                }

                EventEntryStatus status = EventEntryStatus.Upcoming;
                if (statusBeforeText)
                {
                    status = DecodePacketOwnedEventCalendarBinaryStatus(rowReader.ReadByte());
                }

                if (!TryReadPacketOwnedCompactString(rowReader, sizeof(byte), out string title)
                    || string.IsNullOrWhiteSpace(title)
                    || !TryReadPacketOwnedCompactString(rowReader, sizeof(byte), out string detail))
                {
                    return false;
                }

                if (!statusBeforeText)
                {
                    status = DecodePacketOwnedEventCalendarBinaryStatus(rowReader.ReadByte());
                }

                if (!TryReadPacketOwnedCompactString(rowReader, sizeof(byte), out string statusText)
                    || !TryReadPacketOwnedCompactString(rowReader, sizeof(byte), out string alarmText)
                    || rowReader.BaseStream.Position != rowReader.BaseStream.Length)
                {
                    return false;
                }

                title = title.Trim();
                detail = detail?.Trim() ?? string.Empty;
                statusText = statusText?.Trim() ?? string.Empty;
                alarmText = alarmText?.Trim() ?? string.Empty;
                if (!TryCreatePacketOwnedEventCalendarBinaryDate(year, month, day, out DateTime scheduledAt))
                {
                    return false;
                }

                entry = CreatePacketOwnedEventCalendarEntry(
                    scheduledAt,
                    title,
                    detail,
                    status,
                    string.IsNullOrWhiteSpace(statusText) ? GetDefaultPacketOwnedEventStatusText(status) : statusText,
                    int.MinValue,
                    ResolvePacketOwnedEventEntrySortPriority(status),
                    sortOrder: 0,
                    alarmText: alarmText);
                return true;
            }
            catch
            {
                entry = default;
                return false;
            }
        }

        private static bool TryDecodePacketOwnedRankingPageFormPayload(
            string payloadText,
            out RankingEntrySnapshot[] entries,
            out bool hasOwnerState,
            out PacketOwnedRankingOwnerStateSnapshot ownerState,
            out string summary,
            out string message)
        {
            entries = Array.Empty<RankingEntrySnapshot>();
            hasOwnerState = false;
            ownerState = new PacketOwnedRankingOwnerStateSnapshot();
            summary = string.Empty;
            message = "Ranking-page form payload did not contain CWebWnd ranking HTML.";
            if (string.IsNullOrWhiteSpace(payloadText)
                || payloadText.IndexOf('=') < 0
                || payloadText.IndexOf('&') < 0)
            {
                return false;
            }

            Dictionary<string, string> fields = ParsePacketOwnedFormFields(payloadText);
            if (fields.Count == 0)
            {
                return false;
            }

            if (TryGetPacketOwnedFormField(fields, out string htmlText, "html", "page", "body", "document", "response", "responseText", "payload")
                && TryDecodePacketOwnedRankingPageHtmlPayload(htmlText, out entries, out summary, out message))
            {
                ownerState = BuildPacketOwnedRankingOwnerStateFromForm(fields);
                hasOwnerState = ownerState.HasAnyState;
                return true;
            }

            if (TryGetPacketOwnedFormField(fields, out string navigateUrl, "navigateUrl", "url")
                && ProgressionUtilityParityRules.TryParseRankingLandingRequest(navigateUrl, out string serverHost, out int worldId, out int characterId))
            {
                ownerState = new PacketOwnedRankingOwnerStateSnapshot
                {
                    NavigateUrl = navigateUrl,
                    ServerHost = serverHost,
                    WorldId = worldId,
                    CharacterId = characterId
                };
                hasOwnerState = true;
                summary = "Applied packet-authored CWebWnd ranking form owner state.";
                message = summary;
                return true;
            }

            ownerState = BuildPacketOwnedRankingOwnerStateFromForm(fields);
            if (ownerState.HasAnyState)
            {
                hasOwnerState = true;
                summary = "Applied packet-authored CWebWnd ranking form request state.";
                message = summary;
                return true;
            }

            return false;
        }

        private static Dictionary<string, string> ParsePacketOwnedFormFields(string payloadText)
        {
            Dictionary<string, string> fields = new(StringComparer.OrdinalIgnoreCase);
            string[] pairs = payloadText.Split('&', StringSplitOptions.RemoveEmptyEntries | StringSplitOptions.TrimEntries);
            for (int i = 0; i < pairs.Length; i++)
            {
                string pair = pairs[i];
                int separator = pair.IndexOf('=');
                if (separator <= 0)
                {
                    continue;
                }

                string key = Uri.UnescapeDataString(pair[..separator].Replace('+', ' ')).Trim();
                string value = Uri.UnescapeDataString(pair[(separator + 1)..].Replace('+', ' ')).Trim();
                if (!string.IsNullOrWhiteSpace(key))
                {
                    fields[key] = value;
                }
            }

            return fields;
        }

        private static bool TryGetPacketOwnedFormField(
            IReadOnlyDictionary<string, string> fields,
            out string value,
            params string[] names)
        {
            value = string.Empty;
            if (fields == null)
            {
                return false;
            }

            foreach (string name in names ?? Array.Empty<string>())
            {
                if (!string.IsNullOrWhiteSpace(name)
                    && fields.TryGetValue(name, out string fieldValue)
                    && !string.IsNullOrWhiteSpace(fieldValue))
                {
                    value = fieldValue.Trim();
                    return true;
                }
            }

            return false;
        }

        private static PacketOwnedRankingOwnerStateSnapshot BuildPacketOwnedRankingOwnerStateFromForm(
            IReadOnlyDictionary<string, string> fields)
        {
            string serverHost = TryGetPacketOwnedFormField(fields, out string host, "serverHost", "host", "get_server_string_0")
                ? host
                : string.Empty;
            string navigateUrl = TryGetPacketOwnedFormField(fields, out string url, "navigateUrl", "url")
                ? url
                : string.Empty;
            int? worldId = TryGetPacketOwnedFormInt(fields, out int parsedWorldId, "worldId", "worldid")
                ? parsedWorldId
                : null;
            int? characterId = TryGetPacketOwnedFormInt(fields, out int parsedCharacterId, "characterId", "characterid")
                ? parsedCharacterId
                : null;
            int templateId = TryGetPacketOwnedFormInt(fields, out int parsedTemplateId, "templateId", "stringPoolId")
                ? parsedTemplateId
                : 0;

            return new PacketOwnedRankingOwnerStateSnapshot
            {
                NavigateUrl = navigateUrl,
                ServerHost = serverHost,
                WorldId = worldId,
                CharacterId = characterId,
                TemplateId = templateId
            };
        }

        private static bool TryGetPacketOwnedFormInt(
            IReadOnlyDictionary<string, string> fields,
            out int value,
            params string[] names)
        {
            value = 0;
            return TryGetPacketOwnedFormField(fields, out string text, names)
                && int.TryParse(text, NumberStyles.Integer, CultureInfo.InvariantCulture, out value);
        }

        private static bool TryResolvePacketOwnedRankingHtmlText(JsonElement root, out string htmlText)
        {
            htmlText = string.Empty;
            if (root.ValueKind != JsonValueKind.Object)
            {
                return false;
            }

            if (TryGetJsonStringProperty(root, out htmlText, "html", "pageHtml", "documentHtml", "bodyHtml", "responseHtml", "responseText"))
            {
                return !string.IsNullOrWhiteSpace(htmlText);
            }

            if (TryGetJsonNestedStringProperty(
                    root,
                    out htmlText,
                    new[] { "ownerState", "web", "webOwner", "cwebwnd", "cWebWnd", "page", "payload", "data", "result", "body", "response" },
                    new[] { "html", "pageHtml", "documentHtml", "bodyHtml", "responseHtml", "responseText" }))
            {
                return !string.IsNullOrWhiteSpace(htmlText);
            }

            return false;
        }

        private static bool TryDecodePacketOwnedEventCalendarCompactRowWithTrailingStatus(
            byte[] rowPayload,
            bool usePackedDate,
            out EventEntrySnapshot entry)
        {
            entry = default;
            if (rowPayload == null || rowPayload.Length == 0)
            {
                return false;
            }

            try
            {
                using MemoryStream rowStream = new(rowPayload, writable: false);
                using BinaryReader rowReader = new(rowStream);

                int year;
                int month;
                int day;
                if (usePackedDate)
                {
                    int yyyymmdd = rowReader.ReadInt32();
                    year = yyyymmdd / 10000;
                    month = Math.Abs((yyyymmdd / 100) % 100);
                    day = Math.Abs(yyyymmdd % 100);
                }
                else
                {
                    year = rowReader.ReadUInt16();
                    month = rowReader.ReadByte();
                    day = rowReader.ReadByte();
                }

                if (!TryReadPacketOwnedOptionalMapleString(rowReader, out string title)
                    || string.IsNullOrWhiteSpace(title)
                    || !TryReadPacketOwnedOptionalMapleString(rowReader, out string detail)
                    || rowReader.BaseStream.Length - rowReader.BaseStream.Position < sizeof(byte))
                {
                    return false;
                }

                EventEntryStatus status = DecodePacketOwnedEventCalendarBinaryStatus(rowReader.ReadByte());
                string statusText = string.Empty;
                string alarmText = string.Empty;
                if (!TryReadPacketOwnedOptionalMapleString(rowReader, out statusText)
                    || !TryReadPacketOwnedOptionalMapleString(rowReader, out alarmText)
                    || rowReader.BaseStream.Position != rowReader.BaseStream.Length)
                {
                    return false;
                }

                title = title.Trim();
                detail = detail?.Trim() ?? string.Empty;
                statusText = statusText?.Trim() ?? string.Empty;
                alarmText = alarmText?.Trim() ?? string.Empty;
                if (!TryCreatePacketOwnedEventCalendarBinaryDate(year, month, day, out DateTime scheduledAt))
                {
                    return false;
                }

                entry = CreatePacketOwnedEventCalendarEntry(
                    scheduledAt,
                    title,
                    detail,
                    status,
                    string.IsNullOrWhiteSpace(statusText) ? GetDefaultPacketOwnedEventStatusText(status) : statusText,
                    int.MinValue,
                    ResolvePacketOwnedEventEntrySortPriority(status),
                    sortOrder: 0,
                    alarmText: alarmText);
                return true;
            }
            catch
            {
                entry = default;
                return false;
            }
        }

        private static bool TryDecodePacketOwnedEventCalendarCompactRow(
            BinaryReader reader,
            bool usePackedDate,
            out EventEntrySnapshot entry)
        {
            entry = default;
            if (reader == null)
            {
                return false;
            }

            int year;
            int month;
            int day;
            if (usePackedDate)
            {
                int yyyymmdd = reader.ReadInt32();
                year = yyyymmdd / 10000;
                month = Math.Abs((yyyymmdd / 100) % 100);
                day = Math.Abs(yyyymmdd % 100);
            }
            else
            {
                year = reader.ReadUInt16();
                month = reader.ReadByte();
                day = reader.ReadByte();
            }

            EventEntryStatus status = DecodePacketOwnedEventCalendarBinaryStatus(reader.ReadByte());
            if (!TryReadPacketOwnedOptionalMapleString(reader, out string title)
                || !TryReadPacketOwnedOptionalMapleString(reader, out string detail)
                || !TryReadPacketOwnedOptionalMapleString(reader, out string statusText)
                || !TryReadPacketOwnedOptionalMapleString(reader, out string alarmText))
            {
                return false;
            }

            title = title?.Trim();
            detail = detail?.Trim() ?? string.Empty;
            statusText = statusText?.Trim() ?? string.Empty;
            alarmText = alarmText?.Trim() ?? string.Empty;
            if (!TryCreatePacketOwnedEventCalendarBinaryDate(year, month, day, out DateTime scheduledAt)
                || string.IsNullOrWhiteSpace(title))
            {
                return false;
            }

            entry = CreatePacketOwnedEventCalendarEntry(
                scheduledAt,
                title,
                detail,
                status,
                string.IsNullOrWhiteSpace(statusText) ? GetDefaultPacketOwnedEventStatusText(status) : statusText,
                int.MinValue,
                ResolvePacketOwnedEventEntrySortPriority(status),
                sortOrder: 0,
                alarmText: alarmText);
            return true;
        }

        private static bool TryCreatePacketOwnedEventCalendarBinaryDate(int year, int month, int day, out DateTime date)
        {
            try
            {
                date = new DateTime(year, month, day);
                return true;
            }
            catch
            {
                date = default;
                return false;
            }
        }

        private static EventEntryStatus DecodePacketOwnedEventCalendarBinaryStatus(byte status)
        {
            return status switch
            {
                1 => EventEntryStatus.Start,
                2 => EventEntryStatus.InProgress,
                3 => EventEntryStatus.Clear,
                _ => EventEntryStatus.Upcoming
            };
        }

        private static bool TryDecodePacketOwnedEventCalendarJsonPayload(
            string payloadText,
            out bool clearRequested,
            out bool replaceExistingEntries,
            out EventEntrySnapshot[] entries,
            out bool hasAlarmLines,
            out bool replaceAlarmLines,
            out EventAlarmLineSnapshot[] alarmLines,
            out string summary,
            out string message)
        {
            clearRequested = false;
            replaceExistingEntries = true;
            entries = Array.Empty<EventEntrySnapshot>();
            hasAlarmLines = false;
            replaceAlarmLines = true;
            alarmLines = Array.Empty<EventAlarmLineSnapshot>();
            summary = string.Empty;
            message = "Event-calendar JSON payload did not contain any usable owner rows.";
            if (string.IsNullOrWhiteSpace(payloadText))
            {
                return false;
            }

            string trimmed = payloadText.Trim();
            if (!trimmed.StartsWith("{", StringComparison.Ordinal)
                && !trimmed.StartsWith("[", StringComparison.Ordinal))
            {
                return false;
            }

            try
            {
                using JsonDocument document = JsonDocument.Parse(trimmed);
                JsonElement root = document.RootElement;
                List<EventEntrySnapshot> parsedEntries = new();
                if (root.ValueKind == JsonValueKind.Object)
                {
                    if (TryGetJsonBoolean(root, "clear", out bool parsedClear))
                    {
                        clearRequested = parsedClear;
                    }

                    if (TryGetJsonBoolean(root, "replace", out bool parsedReplace))
                    {
                        replaceExistingEntries = parsedReplace;
                    }

                    if (TryGetJsonString(root, "summary", out string parsedSummary))
                    {
                        summary = parsedSummary;
                    }

                    if (TryGetJsonBoolean(root, "replaceAlarmLines", out bool parsedReplaceAlarmLines)
                        || TryGetJsonBoolean(root, "replaceLines", out parsedReplaceAlarmLines))
                    {
                        replaceAlarmLines = parsedReplaceAlarmLines;
                    }

                    if (TryGetJsonArrayProperty(
                            root,
                            out JsonElement entryArray,
                            "entries",
                            "rows",
                            "calendarEntries",
                            "eventEntries",
                            "eventRows",
                            "attendanceEntries",
                            "attendanceRows",
                            "events",
                            "schedules")
                        || TryGetJsonNestedArrayProperty(
                            root,
                            out entryArray,
                            new[] { "calendar", "attendance", "attendanceCalendar", "eventCalendar", "payload", "data", "result", "body", "days", "month" },
                            new[] { "entries", "rows", "events", "attendanceEntries", "calendarEntries", "eventRows", "schedules", "items", "days" }))
                    {
                        AppendPacketOwnedEventCalendarJsonEntries(entryArray, parsedEntries);
                    }

                    if (TryGetJsonArrayProperty(root, out JsonElement lineArray, "alarmLines", "ctLines", "lines", "alarmTextLines", "eventAlarmLines", "m_aCT", "ct")
                        || TryGetJsonNestedArrayProperty(
                            root,
                            out lineArray,
                            new[] { "calendar", "attendance", "attendanceCalendar", "eventCalendar", "payload", "data", "result", "body", "alarm", "eventAlarm" },
                            new[] { "alarmLines", "ctLines", "lines", "messages", "m_aCT", "ct" }))
                    {
                        List<EventAlarmLineSnapshot> parsedLines = new();
                        AppendPacketOwnedEventAlarmJsonLines(lineArray, parsedLines);
                        if (parsedLines.Count > 0)
                        {
                            alarmLines = parsedLines.ToArray();
                            hasAlarmLines = true;
                        }
                    }
                    else if (TryGetJsonStringProperty(root, out string inlineAlarmText, "alarmText", "ctText", "message", "m_aCT", "ct"))
                    {
                        List<EventAlarmLineSnapshot> parsedLines = new();
                        AppendPacketOwnedEventAlarmStringLines(inlineAlarmText, parsedLines);
                        if (parsedLines.Count > 0)
                        {
                            alarmLines = parsedLines.ToArray();
                            hasAlarmLines = true;
                        }
                    }
                }
                else if (root.ValueKind == JsonValueKind.Array)
                {
                    AppendPacketOwnedEventCalendarJsonEntries(root, parsedEntries);
                }

                entries = parsedEntries.ToArray();
                if (!clearRequested && !hasAlarmLines && entries.Length > 0)
                {
                    alarmLines = BuildFallbackPacketOwnedEventCalendarAlarmLines(entries);
                    hasAlarmLines = alarmLines.Length > 0;
                }

                if (string.IsNullOrWhiteSpace(summary))
                {
                    summary = clearRequested
                        ? "Cleared packet-authored event-calendar entries."
                        : entries.Length > 0
                            ? $"Applied packet-authored event-calendar JSON payload with {entries.Length.ToString(CultureInfo.InvariantCulture)} owner row(s)."
                            : string.Empty;
                }

                message = summary;
                return clearRequested || entries.Length > 0 || (hasAlarmLines && alarmLines.Length > 0);
            }
            catch (JsonException ex)
            {
                message = $"Event-calendar JSON payload could not be parsed: {ex.Message}";
                return false;
            }
        }

        private static EventAlarmLineSnapshot[] BuildFallbackPacketOwnedEventCalendarAlarmLines(IReadOnlyList<EventEntrySnapshot> entries)
        {
            if (entries == null || entries.Count == 0)
            {
                return Array.Empty<EventAlarmLineSnapshot>();
            }

            DateTime anchorDate = ResolvePacketOwnedEventCalendarAlarmAnchorDate(entries);
            List<EventEntrySnapshot> selectedEntries = entries
                .Where(entry => entry != null && entry.IncludeInCalendar && entry.ScheduledAt.Date == anchorDate)
                .OrderBy(ResolvePacketOwnedEventCalendarAlarmEntryRank)
                .ThenByDescending(entry => entry.SourceTick)
                .ThenBy(entry => entry.SortOrder)
                .Take(EventAlarmOwnerMaxVisibleLines)
                .ToList();
            if (selectedEntries.Count == 0)
            {
                return Array.Empty<EventAlarmLineSnapshot>();
            }

            List<EventAlarmLineSnapshot> lines = new(selectedEntries.Count);
            for (int i = 0; i < selectedEntries.Count; i++)
            {
                EventEntrySnapshot entry = selectedEntries[i];
                lines.Add(new EventAlarmLineSnapshot
                {
                    Text = FormatPacketOwnedEventCalendarAlarmLine(entry, anchorDate),
                    Left = 0,
                    Top = i * 13,
                    IsHighlighted = entry.Status is EventEntryStatus.Start or EventEntryStatus.InProgress
                });
            }

            return lines.ToArray();
        }

        private static int? ResolvePacketOwnedEventAlarmLineFontIndex(byte lineFlags)
        {
            int fontIndex = lineFlags >> 1;
            return fontIndex > 0 ? fontIndex : null;
        }

        internal static EventAlarmLineSnapshot[] BuildFallbackPacketOwnedEventCalendarAlarmLinesForTests(IReadOnlyList<EventEntrySnapshot> entries)
        {
            return BuildFallbackPacketOwnedEventCalendarAlarmLines(entries);
        }

        private static DateTime ResolvePacketOwnedEventCalendarAlarmAnchorDate(IReadOnlyList<EventEntrySnapshot> entries)
        {
            DateTime today = DateTime.Today;
            DateTime selectedDate = default;
            long bestDistance = long.MaxValue;
            int bestRank = int.MaxValue;
            int bestSortOrder = int.MaxValue;
            for (int i = 0; i < entries.Count; i++)
            {
                EventEntrySnapshot entry = entries[i];
                if (entry == null || !entry.IncludeInCalendar)
                {
                    continue;
                }

                DateTime date = entry.ScheduledAt.Date;
                if (date.Year <= 1)
                {
                    continue;
                }

                long distance = Math.Abs((date - today).Ticks);
                int rank = ResolvePacketOwnedEventCalendarAlarmEntryRank(entry);
                if (distance < bestDistance
                    || (distance == bestDistance && rank < bestRank)
                    || (distance == bestDistance && rank == bestRank && entry.SortOrder < bestSortOrder)
                    || (distance == bestDistance && rank == bestRank && entry.SortOrder == bestSortOrder && (selectedDate == default || date < selectedDate)))
                {
                    selectedDate = date;
                    bestDistance = distance;
                    bestRank = rank;
                    bestSortOrder = entry.SortOrder;
                }
            }

            return selectedDate.Year > 1 ? selectedDate : today;
        }

        private static int ResolvePacketOwnedEventCalendarAlarmEntryRank(EventEntrySnapshot entry)
        {
            if (entry == null)
            {
                return int.MaxValue;
            }

            return entry.Status switch
            {
                EventEntryStatus.InProgress => 0,
                EventEntryStatus.Start => 1,
                EventEntryStatus.Clear => 2,
                EventEntryStatus.Upcoming => 3,
                _ => 4
            };
        }

        private static string FormatPacketOwnedEventCalendarAlarmLine(EventEntrySnapshot entry, DateTime anchorDate)
        {
            if (entry == null)
            {
                return string.Empty;
            }

            string title = string.IsNullOrWhiteSpace(entry.Title) ? "Event" : entry.Title.Trim();
            if (!string.IsNullOrWhiteSpace(entry.AlarmText))
            {
                // Client evidence: CUIEventAlarm::Draw emits each CT_INFO.sText verbatim inside the m_aCT clip rect.
                return entry.AlarmText.Trim();
            }

            string datePrefix = entry.ScheduledAt.Date == anchorDate
                ? string.Empty
                : entry.ScheduledAt.ToString("MMM d", CultureInfo.InvariantCulture) + " ";
            string statusPrefix = entry.Status switch
            {
                EventEntryStatus.InProgress => "Running: ",
                EventEntryStatus.Start => "Start: ",
                EventEntryStatus.Clear => "Clear: ",
                _ => "Will: "
            };
            return $"{datePrefix}{statusPrefix}{title}";
        }

        private static void AppendPacketOwnedEventCalendarJsonEntries(
            JsonElement element,
            ICollection<EventEntrySnapshot> destination,
            JsonElement? inheritedFallbackElement = null)
        {
            if (destination == null || element.ValueKind != JsonValueKind.Array)
            {
                return;
            }

            int index = destination.Count;
            foreach (JsonElement item in element.EnumerateArray())
            {
                if (item.ValueKind == JsonValueKind.String)
                {
                    string stringTitle = item.GetString()?.Trim();
                    if (!string.IsNullOrWhiteSpace(stringTitle))
                    {
                        DateTime scheduledAt = inheritedFallbackElement.HasValue
                                                && TryResolvePacketOwnedEventDate(inheritedFallbackElement.Value, inheritedFallbackElement.Value, out DateTime inheritedDate)
                            ? inheritedDate
                            : DateTime.Today;
                        destination.Add(CreatePacketOwnedEventCalendarEntry(scheduledAt, stringTitle, string.Empty, EventEntryStatus.Upcoming, "Will", int.MinValue, int.MinValue, index++));
                    }

                    continue;
                }

                if (item.ValueKind != JsonValueKind.Object)
                {
                    continue;
                }

                if (TryGetJsonArrayProperty(
                        item,
                        out JsonElement nestedEntries,
                        "entries",
                        "rows",
                        "events",
                        "attendanceEntries",
                        "attendanceRows",
                        "calendarEntries",
                        "eventRows",
                        "schedules",
                        "days")
                    || TryGetJsonNestedArrayProperty(
                        item,
                        out nestedEntries,
                        new[] { "entry", "row", "event", "schedule", "attendance", "calendar", "day" },
                        new[] { "entries", "rows", "events", "attendanceEntries", "calendarEntries", "schedules", "days" }))
                {
                    AppendPacketOwnedEventCalendarJsonEntries(nestedEntries, destination, item);
                    index = destination.Count;
                    continue;
                }

                JsonElement eventItem = item;
                if (TryGetJsonObjectProperty(
                        eventItem,
                        out JsonElement nestedEventItem,
                        "entry",
                        "row",
                        "event",
                        "schedule",
                        "attendance",
                        "calendarEntry",
                        "attendanceEntry"))
                {
                    eventItem = nestedEventItem;
                }

                JsonElement fallbackElement = inheritedFallbackElement ?? item;
                string title = ResolvePacketOwnedJsonText(
                    eventItem,
                    fallbackElement,
                    "title",
                    "name",
                    "label",
                    "subject",
                    "eventName");
                if (string.IsNullOrWhiteSpace(title))
                {
                    continue;
                }

                DateTime itemScheduledAt = TryResolvePacketOwnedEventDate(eventItem, fallbackElement, out DateTime parsedScheduledAt)
                    ? parsedScheduledAt
                    : DateTime.Today;
                string detail = ResolvePacketOwnedJsonText(
                    eventItem,
                    fallbackElement,
                    "detail",
                    "description",
                    "desc",
                    "body",
                    "message");

                EventEntryStatus status = ResolvePacketOwnedJsonText(
                        eventItem,
                        fallbackElement,
                        "status",
                        "state",
                        "progress",
                        "attendanceState")
                    is string parsedStatusToken
                    && TryParsePacketOwnedEventEntryStatus(parsedStatusToken, out EventEntryStatus parsedStatus)
                    ? parsedStatus
                    : EventEntryStatus.Upcoming;
                string statusText = ResolvePacketOwnedJsonText(
                    eventItem,
                    fallbackElement,
                    "statusText",
                    "statusLabel",
                    "stateLabel",
                    "progressLabel");
                string alarmText = ResolvePacketOwnedJsonText(
                    eventItem,
                    fallbackElement,
                    "alarmText",
                    "ctText",
                    "m_aCT",
                    "ct",
                    "alarmLine",
                    "eventAlarmText");
                int sourceTick = TryGetJsonInt32Property(eventItem, out int parsedSourceTick, "sourceTick", "tick")
                    || TryGetJsonInt32Property(fallbackElement, out parsedSourceTick, "sourceTick", "tick")
                    ? parsedSourceTick
                    : int.MinValue;
                int sortPriority = TryGetJsonInt32Property(eventItem, out int parsedSortPriority, "sortPriority", "priority")
                    || TryGetJsonInt32Property(fallbackElement, out parsedSortPriority, "sortPriority", "priority")
                    ? parsedSortPriority
                    : ResolvePacketOwnedEventEntrySortPriority(status);
                int sortOrder = TryGetJsonInt32Property(eventItem, out int parsedSortOrder, "sortOrder", "index", "order")
                    || TryGetJsonInt32Property(fallbackElement, out parsedSortOrder, "sortOrder", "index", "order")
                    ? parsedSortOrder
                    : index;
                bool parsedIncludeInCalendar = false;
                bool includeInCalendar = !(TryGetJsonBoolean(eventItem, "includeInCalendar", out parsedIncludeInCalendar)
                                           || TryGetJsonBoolean(eventItem, "showInCalendar", out parsedIncludeInCalendar)
                                           || TryGetJsonBoolean(eventItem, "showOnCalendar", out parsedIncludeInCalendar)
                                           || TryGetJsonBoolean(eventItem, "calendarVisible", out parsedIncludeInCalendar)
                                           || TryGetJsonBoolean(fallbackElement, "includeInCalendar", out parsedIncludeInCalendar)
                                           || TryGetJsonBoolean(fallbackElement, "showInCalendar", out parsedIncludeInCalendar)
                                           || TryGetJsonBoolean(fallbackElement, "showOnCalendar", out parsedIncludeInCalendar)
                                           || TryGetJsonBoolean(fallbackElement, "calendarVisible", out parsedIncludeInCalendar))
                    || parsedIncludeInCalendar;
                EventEntryRowLayoutSnapshot rowLayout = ResolvePacketOwnedEventRowLayoutSnapshot(eventItem, fallbackElement);
                destination.Add(CreatePacketOwnedEventCalendarEntry(itemScheduledAt, title.Trim(), detail, status, statusText, sourceTick, sortPriority, sortOrder, alarmText, includeInCalendar, rowLayout));
                index++;
            }
        }

        private static EventEntryRowLayoutSnapshot ResolvePacketOwnedEventRowLayoutSnapshot(
            JsonElement primaryElement,
            JsonElement fallbackElement)
        {
            EventEntryRowLayoutSnapshot primaryLayout = ResolvePacketOwnedEventRowLayoutSnapshot(primaryElement);
            EventEntryRowLayoutSnapshot fallbackLayout = ResolvePacketOwnedEventRowLayoutSnapshot(fallbackElement);
            if (primaryLayout?.HasAnyValue == true)
            {
                if (fallbackLayout?.HasAnyValue != true)
                {
                    return primaryLayout;
                }

                return new EventEntryRowLayoutSnapshot
                {
                    TitleLeft = primaryLayout.TitleLeft ?? fallbackLayout.TitleLeft,
                    TitleTop = primaryLayout.TitleTop ?? fallbackLayout.TitleTop,
                    TitleWidth = primaryLayout.TitleWidth ?? fallbackLayout.TitleWidth,
                    DetailLeft = primaryLayout.DetailLeft ?? fallbackLayout.DetailLeft,
                    DetailTop = primaryLayout.DetailTop ?? fallbackLayout.DetailTop,
                    DetailWidth = primaryLayout.DetailWidth ?? fallbackLayout.DetailWidth,
                    StatusLeft = primaryLayout.StatusLeft ?? fallbackLayout.StatusLeft,
                    StatusTop = primaryLayout.StatusTop ?? fallbackLayout.StatusTop,
                    StatusWidth = primaryLayout.StatusWidth ?? fallbackLayout.StatusWidth
                };
            }

            return fallbackLayout ?? new EventEntryRowLayoutSnapshot();
        }

        private static EventEntryRowLayoutSnapshot ResolvePacketOwnedEventRowLayoutSnapshot(JsonElement element)
        {
            if (element.ValueKind != JsonValueKind.Object)
            {
                return new EventEntryRowLayoutSnapshot();
            }

            JsonElement layoutElement = element;
            if (TryGetJsonObjectProperty(
                    element,
                    out JsonElement nestedLayoutElement,
                    "rowLayout",
                    "layout",
                    "textLayout",
                    "rowText",
                    "bodyLayout"))
            {
                layoutElement = nestedLayoutElement;
            }

            return new EventEntryRowLayoutSnapshot
            {
                TitleLeft = ResolveOptionalPacketOwnedEventRowLayoutInt(layoutElement, element, "titleLeft", "titleX"),
                TitleTop = ResolveOptionalPacketOwnedEventRowLayoutInt(layoutElement, element, "titleTop", "titleY"),
                TitleWidth = ResolveOptionalPacketOwnedEventRowLayoutInt(layoutElement, element, "titleWidth", "titleW"),
                DetailLeft = ResolveOptionalPacketOwnedEventRowLayoutInt(layoutElement, element, "detailLeft", "detailX"),
                DetailTop = ResolveOptionalPacketOwnedEventRowLayoutInt(layoutElement, element, "detailTop", "detailY"),
                DetailWidth = ResolveOptionalPacketOwnedEventRowLayoutInt(layoutElement, element, "detailWidth", "detailW"),
                StatusLeft = ResolveOptionalPacketOwnedEventRowLayoutInt(layoutElement, element, "statusLeft", "statusX"),
                StatusTop = ResolveOptionalPacketOwnedEventRowLayoutInt(layoutElement, element, "statusTop", "statusY"),
                StatusWidth = ResolveOptionalPacketOwnedEventRowLayoutInt(layoutElement, element, "statusWidth", "statusW")
            };
        }

        private static int? ResolveOptionalPacketOwnedEventRowLayoutInt(
            JsonElement primaryElement,
            JsonElement fallbackElement,
            params string[] propertyNames)
        {
            if (TryGetJsonInt32Property(primaryElement, out int value, propertyNames)
                || TryGetJsonInt32Property(fallbackElement, out value, propertyNames))
            {
                return value;
            }

            return null;
        }

        private static string ResolvePacketOwnedRankingEntryText(
            JsonElement primaryElement,
            JsonElement fallbackElement,
            params string[] propertyNames)
        {
            return ResolvePacketOwnedJsonText(primaryElement, fallbackElement, propertyNames);
        }

        private static string ResolvePacketOwnedJsonText(
            JsonElement primaryElement,
            JsonElement fallbackElement,
            params string[] propertyNames)
        {
            foreach (string propertyName in propertyNames ?? Array.Empty<string>())
            {
                if (TryGetJsonText(primaryElement, propertyName, out string value)
                    || TryGetJsonText(fallbackElement, propertyName, out value))
                {
                    return value;
                }
            }

            return string.Empty;
        }

        private static bool TryResolvePacketOwnedEventDate(
            JsonElement primaryElement,
            JsonElement fallbackElement,
            out DateTime scheduledAt)
        {
            return TryGetJsonDateProperty(
                       primaryElement,
                       out scheduledAt,
                       "scheduledAt",
                       "date",
                       "day",
                       "startDate",
                       "start",
                       "eventDate")
                   || TryGetJsonDateProperty(
                       fallbackElement,
                       out scheduledAt,
                       "scheduledAt",
                       "date",
                       "day",
                       "startDate",
                       "start",
                       "eventDate")
                   || TryBuildPacketOwnedEventDateFromFields(primaryElement, out scheduledAt)
                   || TryBuildPacketOwnedEventDateFromFields(fallbackElement, out scheduledAt);
        }

        private static bool TryParsePacketOwnedEventCalendarTextEntry(string line, int sortOrder, out EventEntrySnapshot entry)
        {
            entry = new EventEntrySnapshot();
            if (string.IsNullOrWhiteSpace(line))
            {
                return false;
            }

            string[] tokens = line.Split('|');
            if (tokens.Length == 0)
            {
                return false;
            }

            int tokenIndex = 0;
            DateTime scheduledAt = DateTime.Today;
            if (TryParsePacketOwnedEventDate(tokens[0], out DateTime parsedDate))
            {
                scheduledAt = parsedDate;
                tokenIndex = 1;
            }

            if (tokenIndex >= tokens.Length)
            {
                return false;
            }

            string title = tokens[tokenIndex++].Trim();
            if (string.IsNullOrWhiteSpace(title))
            {
                return false;
            }

            string detail = tokenIndex < tokens.Length ? tokens[tokenIndex++].Trim() : string.Empty;
            EventEntryStatus status = tokenIndex < tokens.Length
                && TryParsePacketOwnedEventEntryStatus(tokens[tokenIndex], out EventEntryStatus parsedStatus)
                ? parsedStatus
                : EventEntryStatus.Upcoming;
            if (tokenIndex < tokens.Length && TryParsePacketOwnedEventEntryStatus(tokens[tokenIndex], out _))
            {
                tokenIndex++;
            }

            string alarmText = tokenIndex < tokens.Length ? tokens[tokenIndex].Trim() : string.Empty;
            tokenIndex++;
            bool includeInCalendar = true;
            EventEntryRowLayoutSnapshot rowLayout = ParsePacketOwnedEventRowLayoutFromTextTokens(tokens, tokenIndex, out bool? includeInCalendarOverride);
            if (includeInCalendarOverride.HasValue)
            {
                includeInCalendar = includeInCalendarOverride.Value;
            }

            entry = CreatePacketOwnedEventCalendarEntry(
                scheduledAt,
                title,
                detail,
                status,
                GetDefaultPacketOwnedEventStatusText(status),
                int.MinValue,
                ResolvePacketOwnedEventEntrySortPriority(status),
                sortOrder,
                alarmText: alarmText,
                includeInCalendar: includeInCalendar,
                rowLayout: rowLayout);
            return true;
        }

        private static EventEntryRowLayoutSnapshot ParsePacketOwnedEventRowLayoutFromTextTokens(
            string[] tokens,
            int startIndex,
            out bool? includeInCalendar)
        {
            includeInCalendar = null;
            if (tokens == null || tokens.Length == 0 || startIndex >= tokens.Length)
            {
                return new EventEntryRowLayoutSnapshot();
            }

            int? titleLeft = null;
            int? titleTop = null;
            int? titleWidth = null;
            int? detailLeft = null;
            int? detailTop = null;
            int? detailWidth = null;
            int? statusLeft = null;
            int? statusTop = null;
            int? statusWidth = null;

            for (int i = Math.Max(0, startIndex); i < tokens.Length; i++)
            {
                string rawToken = tokens[i]?.Trim();
                if (string.IsNullOrWhiteSpace(rawToken))
                {
                    continue;
                }

                string[] segments = rawToken.Split(new[] { ';', ',' }, StringSplitOptions.RemoveEmptyEntries | StringSplitOptions.TrimEntries);
                for (int segmentIndex = 0; segmentIndex < segments.Length; segmentIndex++)
                {
                    string segment = segments[segmentIndex];
                    int separatorIndex = segment.IndexOf('=');
                    if (separatorIndex < 0)
                    {
                        separatorIndex = segment.IndexOf(':');
                    }

                    if (separatorIndex <= 0 || separatorIndex >= segment.Length - 1)
                    {
                        continue;
                    }

                    string key = segment[..separatorIndex].Trim();
                    string value = segment[(separatorIndex + 1)..].Trim();
                    if (string.IsNullOrWhiteSpace(key))
                    {
                        continue;
                    }

                    if (string.Equals(key, "includeInCalendar", StringComparison.OrdinalIgnoreCase)
                        || string.Equals(key, "showInCalendar", StringComparison.OrdinalIgnoreCase)
                        || string.Equals(key, "calendarVisible", StringComparison.OrdinalIgnoreCase))
                    {
                        if (TryParsePacketOwnedLooseBoolean(value, out bool parsedIncludeInCalendar))
                        {
                            includeInCalendar = parsedIncludeInCalendar;
                        }

                        continue;
                    }

                    if (!int.TryParse(value, NumberStyles.Integer, CultureInfo.InvariantCulture, out int parsedValue))
                    {
                        continue;
                    }

                    switch (key.Trim().ToLowerInvariant())
                    {
                        case "titleleft":
                        case "titlex":
                            titleLeft = parsedValue;
                            break;
                        case "titletop":
                        case "titley":
                            titleTop = parsedValue;
                            break;
                        case "titlewidth":
                        case "titlew":
                            titleWidth = parsedValue;
                            break;
                        case "detailleft":
                        case "detailx":
                            detailLeft = parsedValue;
                            break;
                        case "detailtop":
                        case "detaily":
                            detailTop = parsedValue;
                            break;
                        case "detailwidth":
                        case "detailw":
                            detailWidth = parsedValue;
                            break;
                        case "statusleft":
                        case "statusx":
                            statusLeft = parsedValue;
                            break;
                        case "statustop":
                        case "statusy":
                            statusTop = parsedValue;
                            break;
                        case "statuswidth":
                        case "statusw":
                            statusWidth = parsedValue;
                            break;
                    }
                }
            }

            return new EventEntryRowLayoutSnapshot
            {
                TitleLeft = titleLeft,
                TitleTop = titleTop,
                TitleWidth = titleWidth,
                DetailLeft = detailLeft,
                DetailTop = detailTop,
                DetailWidth = detailWidth,
                StatusLeft = statusLeft,
                StatusTop = statusTop,
                StatusWidth = statusWidth
            };
        }

        private static bool TryParsePacketOwnedLooseBoolean(string value, out bool parsedValue)
        {
            if (bool.TryParse(value, out parsedValue))
            {
                return true;
            }

            if (int.TryParse(value, NumberStyles.Integer, CultureInfo.InvariantCulture, out int intValue))
            {
                parsedValue = intValue != 0;
                return true;
            }

            parsedValue = false;
            return false;
        }

        private static EventEntrySnapshot CreatePacketOwnedEventCalendarEntry(
            DateTime scheduledAt,
            string title,
            string detail,
            EventEntryStatus status,
            string statusText,
            int sourceTick,
            int sortPriority,
            int sortOrder,
            string alarmText = "",
            bool includeInCalendar = true,
            EventEntryRowLayoutSnapshot rowLayout = null)
        {
            return new EventEntrySnapshot
            {
                Title = title ?? string.Empty,
                Detail = detail ?? string.Empty,
                StatusText = string.IsNullOrWhiteSpace(statusText) ? GetDefaultPacketOwnedEventStatusText(status) : statusText.Trim(),
                AlarmText = alarmText?.Trim() ?? string.Empty,
                Status = status,
                ScheduledAt = scheduledAt.Date,
                SourceTick = sourceTick,
                IncludeInCalendar = includeInCalendar,
                RowLayout = rowLayout ?? new EventEntryRowLayoutSnapshot(),
                SortPriority = sortPriority,
                SortOrder = Math.Max(0, sortOrder)
            };
        }

        private static bool TryParsePacketOwnedRankingOwnerState(JsonElement element, out PacketOwnedRankingOwnerStateSnapshot ownerState)
        {
            ownerState = new PacketOwnedRankingOwnerStateSnapshot();
            if (element.ValueKind != JsonValueKind.Object)
            {
                return false;
            }

            string subtitle = TryGetJsonString(element, "subtitle", out string parsedSubtitle)
                ? parsedSubtitle
                : string.Empty;
            string statusText = TryGetJsonString(element, "statusText", out string parsedStatusText)
                ? parsedStatusText
                : string.Empty;
            string navigationCaption = TryGetJsonString(element, "navigationCaption", out string parsedNavigationCaption)
                ? parsedNavigationCaption
                : TryGetJsonString(element, "caption", out string parsedCaption)
                    ? parsedCaption
                    : string.Empty;
            string navigationSeedText = TryGetJsonString(element, "navigationSeedText", out string parsedNavigationSeedText)
                ? parsedNavigationSeedText
                : TryGetJsonString(element, "seed", out string parsedSeed)
                    ? parsedSeed
                    : string.Empty;
            string navigateUrl = TryGetJsonString(element, "navigateUrl", out string parsedNavigateUrl)
                ? parsedNavigateUrl
                : TryGetJsonString(element, "url", out string parsedUrl)
                    ? parsedUrl
                    : string.Empty;
            string navigationHostText = TryGetJsonString(element, "navigationHostText", out string parsedNavigationHostText)
                ? parsedNavigationHostText
                : TryGetJsonString(element, "host", out string parsedHost)
                    ? parsedHost
                    : string.Empty;
            string navigationRequestText = TryGetJsonString(element, "navigationRequestText", out string parsedNavigationRequestText)
                ? parsedNavigationRequestText
                : TryGetJsonString(element, "request", out string parsedRequest)
                    ? parsedRequest
                    : string.Empty;
            string navigationStateText = TryGetJsonString(element, "navigationStateText", out string parsedNavigationStateText)
                ? parsedNavigationStateText
                : TryGetJsonString(element, "state", out string parsedState)
                    ? parsedState
                    : string.Empty;
            bool? isLoading = TryGetJsonBoolean(element, "isLoading", out bool parsedIsLoading)
                ? parsedIsLoading
                : TryGetJsonBoolean(element, "loading", out parsedIsLoading)
                    ? parsedIsLoading
                    : null;
            int loadingStartTick = TryGetJsonInt32(element, "loadingStartTick", out int parsedLoadingStartTick)
                ? parsedLoadingStartTick
                : int.MinValue;
            bool hasRequestObject = TryGetJsonObjectProperty(element, out JsonElement requestElement, "request");
            bool hasLandingObject = TryGetJsonObjectProperty(element, out JsonElement landingElement, "landing");
            bool hasNavigateObject = TryGetJsonObjectProperty(element, out JsonElement navigateElement, "navigate");
            bool hasRequestBodyObject = TryGetJsonObjectProperty(
                element,
                out JsonElement requestBodyElement,
                "requestBody",
                "requestPayload",
                "requestData",
                "body");
            if (!hasRequestBodyObject && hasRequestObject)
            {
                hasRequestBodyObject = TryGetJsonObjectProperty(
                    requestElement,
                    out requestBodyElement,
                    "body",
                    "requestBody",
                    "requestPayload",
                    "requestData",
                    "payload");
            }

            string serverHost = ResolvePacketOwnedRankingOwnerString(
                element,
                hasRequestObject ? requestElement : default,
                hasLandingObject ? landingElement : default,
                hasRequestBodyObject ? requestBodyElement : default,
                hasNavigateObject ? navigateElement : default,
                "serverHost",
                "hostSeed",
                "rankingHost",
                "hostName",
                "host");
            serverHost = ResolvePacketOwnedRankingHostSeed(serverHost);
            if (string.IsNullOrWhiteSpace(serverHost) && !string.IsNullOrWhiteSpace(navigationHostText))
            {
                serverHost = ResolvePacketOwnedRankingHostSeed(navigationHostText);
            }
            int templateId = ResolvePacketOwnedRankingOwnerInt32(
                defaultValue: 0xAA2,
                element,
                hasRequestObject ? requestElement : default,
                hasLandingObject ? landingElement : default,
                hasRequestBodyObject ? requestBodyElement : default,
                hasNavigateObject ? navigateElement : default,
                "templateId",
                "urlTemplateId",
                "stringPoolId");
            int? requestWorldId = ResolveOptionalPacketOwnedRankingOwnerInt32(
                element,
                hasRequestObject ? requestElement : default,
                hasLandingObject ? landingElement : default,
                hasRequestBodyObject ? requestBodyElement : default,
                hasNavigateObject ? navigateElement : default,
                "worldId",
                "worldid");
            int? requestCharacterId = ResolveOptionalPacketOwnedRankingOwnerInt32(
                element,
                hasRequestObject ? requestElement : default,
                hasLandingObject ? landingElement : default,
                hasRequestBodyObject ? requestBodyElement : default,
                hasNavigateObject ? navigateElement : default,
                "characterId",
                "characterid");
            if ((!requestWorldId.HasValue || !requestCharacterId.HasValue)
                && TryResolvePacketOwnedRankingRequestPartsFromRequestText(
                    navigationRequestText,
                    out int? requestTextWorldId,
                    out int? requestTextCharacterId))
            {
                requestWorldId ??= requestTextWorldId;
                requestCharacterId ??= requestTextCharacterId;
            }

            if (TryResolvePacketOwnedRankingNavigateUrlParts(
                    navigateUrl,
                    out string navigateHostSeed,
                    out int? navigateWorldId,
                    out int? navigateCharacterId))
            {
                if (string.IsNullOrWhiteSpace(serverHost))
                {
                    serverHost = navigateHostSeed;
                }

                requestWorldId ??= navigateWorldId;
                requestCharacterId ??= navigateCharacterId;
            }
            else if (TryResolvePacketOwnedRankingNavigateUrlParts(
                         navigationSeedText,
                         out string seedHost,
                         out int? seedWorldId,
                         out int? seedCharacterId))
            {
                if (string.IsNullOrWhiteSpace(serverHost))
                {
                    serverHost = seedHost;
                }

                requestWorldId ??= seedWorldId;
                requestCharacterId ??= seedCharacterId;
            }

            if (string.IsNullOrWhiteSpace(navigateUrl)
                && !string.IsNullOrWhiteSpace(serverHost)
                && requestWorldId.HasValue
                && requestCharacterId.HasValue)
            {
                navigateUrl = ProgressionUtilityParityRules.ResolveRankingLandingUrl(
                    serverHost,
                    templateId,
                    requestWorldId.Value,
                    requestCharacterId.Value,
                    out _);
            }

            if (string.IsNullOrWhiteSpace(navigationCaption)
                && !string.IsNullOrWhiteSpace(serverHost))
            {
                navigationCaption = ProgressionUtilityParityRules.FormatRankingLandingTemplateSeed(templateId, out _);
            }

            if (string.IsNullOrWhiteSpace(navigationHostText)
                && !string.IsNullOrWhiteSpace(serverHost))
            {
                navigationHostText = $"get_server_string_0 => {serverHost.Trim()}";
            }

            if (string.IsNullOrWhiteSpace(navigationRequestText)
                && requestWorldId.HasValue
                && requestCharacterId.HasValue)
            {
                navigationRequestText = ProgressionUtilityParityRules.FormatRankingRequestParameters(
                    requestWorldId.Value,
                    requestCharacterId.Value);
            }

            if (string.IsNullOrWhiteSpace(navigationStateText))
            {
                if (isLoading == true)
                {
                    navigationStateText = "Packet-authored CWebWnd loading state remains active before NavigateUrl completes.";
                }
                else if (!string.IsNullOrWhiteSpace(navigateUrl))
                {
                    navigationStateText = "Packet-authored CWebWnd owner resolved the ranking landing request.";
                }
            }

            ownerState = new PacketOwnedRankingOwnerStateSnapshot
            {
                Subtitle = subtitle,
                StatusText = statusText,
                NavigationCaption = navigationCaption,
                NavigationSeedText = navigationSeedText,
                NavigateUrl = navigateUrl,
                NavigationHostText = navigationHostText,
                NavigationRequestText = navigationRequestText,
                NavigationStateText = navigationStateText,
                ServerHost = serverHost,
                TemplateId = templateId,
                WorldId = requestWorldId,
                CharacterId = requestCharacterId,
                IsLoading = isLoading,
                LoadingStartTick = loadingStartTick
            };
            return ownerState.HasAnyState;
        }

        private static bool TryResolvePacketOwnedRankingNavigateUrlParts(
            string navigateUrl,
            out string serverHost,
            out int? worldId,
            out int? characterId)
        {
            serverHost = string.Empty;
            worldId = null;
            characterId = null;
            if (string.IsNullOrWhiteSpace(navigateUrl))
            {
                return false;
            }

            string normalizedNavigateUrl = navigateUrl.Trim();
            int markerIndex = normalizedNavigateUrl.IndexOf("=>", StringComparison.Ordinal);
            if (markerIndex >= 0 && markerIndex + 2 < normalizedNavigateUrl.Length)
            {
                normalizedNavigateUrl = normalizedNavigateUrl[(markerIndex + 2)..].Trim();
            }

            if (!Uri.TryCreate(normalizedNavigateUrl, UriKind.Absolute, out Uri uri)
                && !normalizedNavigateUrl.Contains("://", StringComparison.Ordinal)
                && Uri.TryCreate("http://" + normalizedNavigateUrl, UriKind.Absolute, out Uri syntheticUri))
            {
                uri = syntheticUri;
            }

            if (uri != null)
            {
                serverHost = ResolvePacketOwnedRankingHostSeed(uri.Host);
                string query = uri.Query;
                if (!string.IsNullOrWhiteSpace(query))
                {
                    if (query.StartsWith("?", StringComparison.Ordinal))
                    {
                        query = query[1..];
                    }

                    string[] parameters = query.Split('&', StringSplitOptions.RemoveEmptyEntries | StringSplitOptions.TrimEntries);
                    for (int i = 0; i < parameters.Length; i++)
                    {
                        string[] pair = parameters[i].Split('=', 2);
                        if (pair.Length == 0)
                        {
                            continue;
                        }

                        string name = WebUtility.UrlDecode(pair[0]) ?? string.Empty;
                        string value = pair.Length > 1 ? WebUtility.UrlDecode(pair[1]) ?? string.Empty : string.Empty;
                        if (string.Equals(name, "worldid", StringComparison.OrdinalIgnoreCase)
                            && int.TryParse(value, NumberStyles.Integer, CultureInfo.InvariantCulture, out int parsedWorldId))
                        {
                            worldId = parsedWorldId;
                        }
                        else if (string.Equals(name, "characterid", StringComparison.OrdinalIgnoreCase)
                                 && int.TryParse(value, NumberStyles.Integer, CultureInfo.InvariantCulture, out int parsedCharacterId))
                        {
                            characterId = parsedCharacterId;
                        }
                        else if (string.Equals(name, "url", StringComparison.OrdinalIgnoreCase)
                                 && TryResolvePacketOwnedRankingRequestPartsFromRelativeUrl(
                                     value,
                                     out int? embeddedWorldId,
                                     out int? embeddedCharacterId))
                        {
                            worldId ??= embeddedWorldId;
                            characterId ??= embeddedCharacterId;
                        }
                    }
                }
            }
            else if (TryResolvePacketOwnedRankingRequestPartsFromRelativeUrl(
                         normalizedNavigateUrl,
                         out int? relativeWorldId,
                         out int? relativeCharacterId))
            {
                worldId = relativeWorldId;
                characterId = relativeCharacterId;
            }
            else
            {
                TryResolvePacketOwnedRankingRequestPartsFromRequestText(
                    normalizedNavigateUrl,
                    out worldId,
                    out characterId);
            }

            return !string.IsNullOrWhiteSpace(serverHost) || worldId.HasValue || characterId.HasValue;
        }

        private static bool TryResolvePacketOwnedRankingRequestPartsFromRequestText(
            string requestText,
            out int? worldId,
            out int? characterId)
        {
            worldId = null;
            characterId = null;
            if (string.IsNullOrWhiteSpace(requestText))
            {
                return false;
            }

            string normalized = requestText.Trim();
            int markerIndex = normalized.IndexOf("=>", StringComparison.Ordinal);
            if (markerIndex >= 0 && markerIndex + 2 < normalized.Length)
            {
                normalized = normalized[(markerIndex + 2)..].Trim();
            }

            if (TryResolvePacketOwnedRankingRequestPartsFromRelativeUrl(normalized, out int? relativeWorldId, out int? relativeCharacterId))
            {
                worldId = relativeWorldId;
                characterId = relativeCharacterId;
            }

            if (!worldId.HasValue && TryExtractPacketOwnedRankingNamedInt(normalized, "worldid", out int parsedWorldId))
            {
                worldId = parsedWorldId;
            }

            if (!characterId.HasValue && TryExtractPacketOwnedRankingNamedInt(normalized, "characterid", out int parsedCharacterId))
            {
                characterId = parsedCharacterId;
            }

            return worldId.HasValue || characterId.HasValue;
        }

        private static bool TryExtractPacketOwnedRankingNamedInt(
            string text,
            string key,
            out int value)
        {
            value = 0;
            if (string.IsNullOrWhiteSpace(text) || string.IsNullOrWhiteSpace(key))
            {
                return false;
            }

            int keyIndex = text.IndexOf(key, StringComparison.OrdinalIgnoreCase);
            if (keyIndex < 0)
            {
                return false;
            }

            int cursor = keyIndex + key.Length;
            while (cursor < text.Length && (char.IsWhiteSpace(text[cursor]) || text[cursor] == '=' || text[cursor] == ':' || text[cursor] == ','))
            {
                cursor++;
            }

            if (cursor >= text.Length)
            {
                return false;
            }

            int sign = 1;
            if (text[cursor] == '+')
            {
                cursor++;
            }
            else if (text[cursor] == '-')
            {
                sign = -1;
                cursor++;
            }

            int start = cursor;
            while (cursor < text.Length && char.IsDigit(text[cursor]))
            {
                cursor++;
            }

            if (cursor <= start)
            {
                return false;
            }

            if (!int.TryParse(text[start..cursor], NumberStyles.Integer, CultureInfo.InvariantCulture, out int parsed))
            {
                return false;
            }

            value = parsed * sign;
            return true;
        }

        private static string ResolvePacketOwnedRankingHostSeed(string host)
        {
            if (string.IsNullOrWhiteSpace(host))
            {
                return string.Empty;
            }

            string normalizedHost = host.Trim();
            int markerIndex = normalizedHost.IndexOf("=>", StringComparison.Ordinal);
            if (markerIndex >= 0 && markerIndex + 2 < normalizedHost.Length)
            {
                normalizedHost = normalizedHost[(markerIndex + 2)..].Trim();
            }

            normalizedHost = ProgressionUtilityParityRules.NormalizeRankingServerHostSeed(normalizedHost);
            return normalizedHost.Trim();
        }

        private static bool TryResolvePacketOwnedRankingRequestPartsFromRelativeUrl(
            string relativeUrl,
            out int? worldId,
            out int? characterId)
        {
            worldId = null;
            characterId = null;
            if (string.IsNullOrWhiteSpace(relativeUrl))
            {
                return false;
            }

            string query = relativeUrl.Trim();
            int queryIndex = query.IndexOf('?', StringComparison.Ordinal);
            if (queryIndex >= 0 && queryIndex + 1 < query.Length)
            {
                query = query[(queryIndex + 1)..];
            }

            string[] parameters = query.Split('&', StringSplitOptions.RemoveEmptyEntries | StringSplitOptions.TrimEntries);
            for (int i = 0; i < parameters.Length; i++)
            {
                string[] pair = parameters[i].Split('=', 2);
                if (pair.Length == 0)
                {
                    continue;
                }

                string name = WebUtility.UrlDecode(pair[0]) ?? string.Empty;
                string value = pair.Length > 1 ? WebUtility.UrlDecode(pair[1]) ?? string.Empty : string.Empty;
                if (string.Equals(name, "worldid", StringComparison.OrdinalIgnoreCase)
                    && int.TryParse(value, NumberStyles.Integer, CultureInfo.InvariantCulture, out int parsedWorldId))
                {
                    worldId = parsedWorldId;
                }
                else if (string.Equals(name, "characterid", StringComparison.OrdinalIgnoreCase)
                         && int.TryParse(value, NumberStyles.Integer, CultureInfo.InvariantCulture, out int parsedCharacterId))
                {
                    characterId = parsedCharacterId;
                }
            }

            return worldId.HasValue || characterId.HasValue;
        }

        private static string ResolvePacketOwnedRankingOwnerString(
            JsonElement primaryElement,
            JsonElement requestElement,
            JsonElement landingElement,
            JsonElement requestBodyElement,
            JsonElement navigateElement,
            params string[] propertyNames)
        {
            foreach (string propertyName in propertyNames ?? Array.Empty<string>())
            {
                if (TryGetJsonString(primaryElement, propertyName, out string value)
                    || TryGetJsonString(requestElement, propertyName, out value)
                    || TryGetJsonString(landingElement, propertyName, out value)
                    || TryGetJsonString(requestBodyElement, propertyName, out value)
                    || TryGetJsonString(navigateElement, propertyName, out value))
                {
                    return value;
                }
            }

            return string.Empty;
        }

        private static bool TryGetJsonStringProperty(JsonElement element, out string value, params string[] propertyNames)
        {
            value = string.Empty;
            foreach (string propertyName in propertyNames ?? Array.Empty<string>())
            {
                if (TryGetJsonString(element, propertyName, out value))
                {
                    return true;
                }
            }

            return false;
        }

        private static bool TryGetJsonInt32Property(JsonElement element, out int value, params string[] propertyNames)
        {
            value = 0;
            foreach (string propertyName in propertyNames ?? Array.Empty<string>())
            {
                if (TryGetJsonInt32(element, propertyName, out value))
                {
                    return true;
                }
            }

            return false;
        }

        private static bool TryGetJsonArrayProperty(JsonElement element, out JsonElement value, params string[] propertyNames)
        {
            value = default;
            if (element.ValueKind != JsonValueKind.Object)
            {
                return false;
            }

            foreach (string propertyName in propertyNames ?? Array.Empty<string>())
            {
                if (TryGetJsonProperty(element, propertyName, out JsonElement propertyValue)
                    && propertyValue.ValueKind == JsonValueKind.Array)
                {
                    value = propertyValue;
                    return true;
                }
            }

            return false;
        }

        private static bool TryGetJsonObjectProperty(JsonElement element, out JsonElement value, params string[] propertyNames)
        {
            value = default;
            if (element.ValueKind != JsonValueKind.Object)
            {
                return false;
            }

            foreach (string propertyName in propertyNames ?? Array.Empty<string>())
            {
                if (TryGetJsonProperty(element, propertyName, out JsonElement propertyValue)
                    && propertyValue.ValueKind == JsonValueKind.Object)
                {
                    value = propertyValue;
                    return true;
                }
            }

            return false;
        }

        private static bool TryGetJsonNestedArrayProperty(
            JsonElement element,
            out JsonElement value,
            string[] objectPropertyNames,
            string[] arrayPropertyNames)
        {
            value = default;
            if (element.ValueKind != JsonValueKind.Object
                || objectPropertyNames == null
                || arrayPropertyNames == null)
            {
                return false;
            }

            for (int i = 0; i < objectPropertyNames.Length; i++)
            {
                if (!TryGetJsonObjectProperty(element, out JsonElement nestedObject, objectPropertyNames[i]))
                {
                    continue;
                }

                if (TryGetJsonArrayProperty(nestedObject, out value, arrayPropertyNames))
                {
                    return true;
                }
            }

            return false;
        }

        private static bool TryGetJsonNestedStringProperty(
            JsonElement element,
            out string value,
            string[] objectPropertyNames,
            string[] stringPropertyNames)
        {
            value = string.Empty;
            if (element.ValueKind != JsonValueKind.Object
                || objectPropertyNames == null
                || stringPropertyNames == null)
            {
                return false;
            }

            for (int i = 0; i < objectPropertyNames.Length; i++)
            {
                if (!TryGetJsonObjectProperty(element, out JsonElement nestedObject, objectPropertyNames[i]))
                {
                    continue;
                }

                if (TryGetJsonStringProperty(nestedObject, out value, stringPropertyNames))
                {
                    return true;
                }
            }

            return false;
        }

        private static int ResolvePacketOwnedRankingOwnerInt32(
            int defaultValue,
            JsonElement primaryElement,
            JsonElement requestElement,
            JsonElement landingElement,
            JsonElement requestBodyElement,
            JsonElement navigateElement,
            params string[] propertyNames)
        {
            return ResolveOptionalPacketOwnedRankingOwnerInt32(
                primaryElement,
                requestElement,
                landingElement,
                requestBodyElement,
                navigateElement,
                propertyNames) ?? defaultValue;
        }

        private static int? ResolveOptionalPacketOwnedRankingOwnerInt32(
            JsonElement primaryElement,
            JsonElement requestElement,
            JsonElement landingElement,
            JsonElement requestBodyElement,
            JsonElement navigateElement,
            params string[] propertyNames)
        {
            foreach (string propertyName in propertyNames ?? Array.Empty<string>())
            {
                if (TryGetJsonInt32(primaryElement, propertyName, out int value)
                    || TryGetJsonInt32(requestElement, propertyName, out value)
                    || TryGetJsonInt32(landingElement, propertyName, out value)
                    || TryGetJsonInt32(requestBodyElement, propertyName, out value)
                    || TryGetJsonInt32(navigateElement, propertyName, out value))
                {
                    return value;
                }
            }

            return null;
        }

        internal static int ResolvePacketOwnedEventEntrySortPriority(EventEntryStatus status)
        {
            return status switch
            {
                EventEntryStatus.Start or EventEntryStatus.InProgress => EventEntrySortPriorityPrimary,
                EventEntryStatus.Clear => EventEntrySortPrioritySecondary,
                EventEntryStatus.Upcoming => EventEntrySortPriorityFallback,
                _ => EventEntrySortPriorityRuntime
            };
        }

        private static string GetDefaultPacketOwnedEventStatusText(EventEntryStatus status)
        {
            return status switch
            {
                EventEntryStatus.Start => "Start",
                EventEntryStatus.InProgress => "Running",
                EventEntryStatus.Clear => "Clear",
                EventEntryStatus.Upcoming => "Will",
                _ => string.Empty
            };
        }

        private static bool TryParsePacketOwnedEventEntryStatus(string token, out EventEntryStatus status)
        {
            status = EventEntryStatus.Upcoming;
            if (string.IsNullOrWhiteSpace(token))
            {
                return false;
            }

            switch (token.Trim().ToLowerInvariant())
            {
                case "start":
                    status = EventEntryStatus.Start;
                    return true;
                case "running":
                case "inprogress":
                case "ing":
                    status = EventEntryStatus.InProgress;
                    return true;
                case "clear":
                case "complete":
                case "completed":
                    status = EventEntryStatus.Clear;
                    return true;
                case "will":
                case "upcoming":
                case "none":
                    status = EventEntryStatus.Upcoming;
                    return true;
                default:
                    return false;
            }
        }

        private static bool TryParsePacketOwnedEventDate(string token, out DateTime date)
        {
            if (DateTime.TryParse(
                    token?.Trim(),
                    CultureInfo.InvariantCulture,
                    DateTimeStyles.AllowWhiteSpaces | DateTimeStyles.AssumeLocal,
                    out date))
            {
                date = date.Date;
                return true;
            }

            date = default;
            return false;
        }

        private static bool TryGetJsonString(JsonElement element, string propertyName, out string value)
        {
            value = string.Empty;
            if (!TryGetJsonProperty(element, propertyName, out JsonElement property)
                || property.ValueKind != JsonValueKind.String)
            {
                return false;
            }

            value = property.GetString() ?? string.Empty;
            return true;
        }

        private static bool TryGetJsonText(JsonElement element, string propertyName, out string value)
        {
            value = string.Empty;
            if (!TryGetJsonProperty(element, propertyName, out JsonElement property))
            {
                return false;
            }

            switch (property.ValueKind)
            {
                case JsonValueKind.String:
                    value = property.GetString() ?? string.Empty;
                    return true;
                case JsonValueKind.Number:
                    value = property.ToString();
                    return true;
                case JsonValueKind.True:
                case JsonValueKind.False:
                    value = property.GetBoolean().ToString(CultureInfo.InvariantCulture);
                    return true;
                default:
                    return false;
            }
        }

        private static bool TryGetJsonBoolean(JsonElement element, string propertyName, out bool value)
        {
            value = false;
            if (!TryGetJsonProperty(element, propertyName, out JsonElement property))
            {
                return false;
            }

            if (property.ValueKind == JsonValueKind.True || property.ValueKind == JsonValueKind.False)
            {
                value = property.GetBoolean();
                return true;
            }

            return false;
        }

        private static bool TryGetJsonInt32(JsonElement element, string propertyName, out int value)
        {
            value = 0;
            if (!TryGetJsonProperty(element, propertyName, out JsonElement property))
            {
                return false;
            }

            if (property.ValueKind == JsonValueKind.Number && property.TryGetInt32(out value))
            {
                return true;
            }

            if (property.ValueKind != JsonValueKind.String)
            {
                return false;
            }

            string rawValue = property.GetString();
            if (string.IsNullOrWhiteSpace(rawValue))
            {
                return false;
            }

            string normalized = rawValue.Trim();
            if (int.TryParse(normalized, NumberStyles.Integer, CultureInfo.InvariantCulture, out value))
            {
                return true;
            }

            bool negative = false;
            if (normalized.StartsWith("-", StringComparison.Ordinal))
            {
                negative = true;
                normalized = normalized[1..];
            }
            else if (normalized.StartsWith("+", StringComparison.Ordinal))
            {
                normalized = normalized[1..];
            }

            if (!normalized.StartsWith("0x", StringComparison.OrdinalIgnoreCase))
            {
                return false;
            }

            string hexDigits = normalized[2..];
            if (!int.TryParse(hexDigits, NumberStyles.AllowHexSpecifier, CultureInfo.InvariantCulture, out int hexValue))
            {
                return false;
            }

            value = negative ? -hexValue : hexValue;
            return true;
        }

        private static bool TryGetJsonDateProperty(JsonElement element, out DateTime value, params string[] propertyNames)
        {
            value = default;
            foreach (string propertyName in propertyNames ?? Array.Empty<string>())
            {
                if (TryGetJsonDate(element, propertyName, out value))
                {
                    return true;
                }
            }

            return false;
        }

        private static bool TryGetJsonDate(JsonElement element, string propertyName, out DateTime value)
        {
            value = default;
            if (!TryGetJsonProperty(element, propertyName, out JsonElement property))
            {
                return false;
            }

            if (property.ValueKind == JsonValueKind.String
                && TryParsePacketOwnedEventDate(property.GetString(), out value))
            {
                return true;
            }

            if (property.ValueKind == JsonValueKind.Number)
            {
                if (property.TryGetInt64(out long unixValue)
                    && TryConvertPacketOwnedUnixDate(unixValue, out value))
                {
                    return true;
                }

                return false;
            }

            if (property.ValueKind == JsonValueKind.Object)
            {
                return TryBuildPacketOwnedEventDateFromFields(property, out value);
            }

            return false;
        }

        private static bool TryGetJsonProperty(JsonElement element, string propertyName, out JsonElement property)
        {
            property = default;
            if (element.ValueKind != JsonValueKind.Object
                || string.IsNullOrWhiteSpace(propertyName))
            {
                return false;
            }

            if (element.TryGetProperty(propertyName, out property))
            {
                return true;
            }

            foreach (JsonProperty candidate in element.EnumerateObject())
            {
                if (string.Equals(candidate.Name, propertyName, StringComparison.OrdinalIgnoreCase))
                {
                    property = candidate.Value;
                    return true;
                }
            }

            return false;
        }

        private static bool TryBuildPacketOwnedEventDateFromFields(JsonElement element, out DateTime value)
        {
            value = default;
            if (element.ValueKind != JsonValueKind.Object)
            {
                return false;
            }

            if (TryGetJsonInt32Property(element, out int timestamp, "timestamp", "time", "timeValue", "epoch", "epochMs", "unixTime")
                && TryConvertPacketOwnedUnixDate(timestamp, out value))
            {
                return true;
            }

            if (TryGetJsonInt32Property(element, out int year, "year", "yyyy")
                && TryGetJsonInt32Property(element, out int month, "month", "mm")
                && TryGetJsonInt32Property(element, out int day, "day", "date", "dd")
                && TryCreatePacketOwnedEventDate(year, month, day, out value))
            {
                return true;
            }

            return false;
        }

        private static bool TryConvertPacketOwnedUnixDate(long unixValue, out DateTime value)
        {
            value = default;
            try
            {
                DateTimeOffset offset = Math.Abs(unixValue) >= 100000000000L
                    ? DateTimeOffset.FromUnixTimeMilliseconds(unixValue)
                    : DateTimeOffset.FromUnixTimeSeconds(unixValue);
                value = offset.LocalDateTime.Date;
                return true;
            }
            catch (ArgumentOutOfRangeException)
            {
                return false;
            }
        }

        private static bool TryCreatePacketOwnedEventDate(int year, int month, int day, out DateTime value)
        {
            value = default;
            if (year < DateTime.MinValue.Year
                || year > DateTime.MaxValue.Year
                || month < 1
                || month > 12)
            {
                return false;
            }

            int daysInMonth = DateTime.DaysInMonth(year, month);
            if (day < 1 || day > daysInMonth)
            {
                return false;
            }

            value = new DateTime(year, month, day);
            return true;
        }

        private ChatCommandHandler.CommandResult HandlePacketOwnedUtilityCommand(string[] args)
        {
            int currentTickCount = Environment.TickCount;
            if (args.Length == 0)
            {
                return ChatCommandHandler.CommandResult.Info($"{DescribeLocalUtilityPacketInboxStatus()} {DescribeLocalUtilityPacketOutboxStatus()} {DescribePacketOwnedUtilityDispatchStatus(currentTickCount)} {_localUtilityPacketInbox.LastStatus} {_localUtilityPacketOutbox.LastStatus} {DescribeLocalUtilityOfficialSessionBridgeStatus()}");
            }

            switch (args[0].ToLowerInvariant())
            {
                case "status":
                    return ChatCommandHandler.CommandResult.Info($"{DescribeLocalUtilityPacketInboxStatus()} {DescribeLocalUtilityPacketOutboxStatus()} {DescribePacketOwnedUtilityDispatchStatus(currentTickCount)} {_localUtilityPacketInbox.LastStatus} {_localUtilityPacketOutbox.LastStatus} {DescribeLocalUtilityOfficialSessionBridgeStatus()}");

                case "inbox":
                    return HandlePacketOwnedUtilityInboxCommand(args);

                case "outbox":
                    return HandlePacketOwnedUtilityOutboxCommand(args);

                case "directionmode":
                    if (args.Length < 2 || !TryParsePacketOwnedBooleanToken(args[1], out bool directionModeEnabled))
                    {
                        return ChatCommandHandler.CommandResult.Error("Usage: /localutility directionmode <on|off|1|0> [delayMs]");
                    }

                    int directionModeDelay = 0;
                    if (args.Length >= 3 && !int.TryParse(args[2], NumberStyles.Integer, CultureInfo.InvariantCulture, out directionModeDelay))
                    {
                        return ChatCommandHandler.CommandResult.Error("Usage: /localutility directionmode <on|off|1|0> [delayMs]");
                    }

                    return ChatCommandHandler.CommandResult.Ok(ApplyPacketOwnedDirectionMode(directionModeEnabled, directionModeDelay));

                case "standalone":
                case "standalonemode":
                    if (args.Length < 2 || !TryParsePacketOwnedBooleanToken(args[1], out bool standAloneEnabled))
                    {
                        return ChatCommandHandler.CommandResult.Error("Usage: /localutility standalone <on|off|1|0>");
                    }

                    return ChatCommandHandler.CommandResult.Ok(ApplyPacketOwnedStandAloneMode(standAloneEnabled));

                case "openui":
                    if (args.Length < 2 || !int.TryParse(args[1], NumberStyles.Integer, CultureInfo.InvariantCulture, out int uiType))
                    {
                        return ChatCommandHandler.CommandResult.Error("Usage: /localutility openui <uiType> [defaultTab]");
                    }

                    int defaultTab = -1;
                    if (args.Length >= 3 && !int.TryParse(args[2], NumberStyles.Integer, CultureInfo.InvariantCulture, out defaultTab))
                    {
                        return ChatCommandHandler.CommandResult.Error("Usage: /localutility openui <uiType> [defaultTab]");
                    }

                    return ChatCommandHandler.CommandResult.Ok(ApplyPacketOwnedOpenUi(uiType, defaultTab));

                case "openuiwithoption":
                    if (args.Length < 3
                        || !int.TryParse(args[1], NumberStyles.Integer, CultureInfo.InvariantCulture, out int optionUiType)
                        || !int.TryParse(args[2], NumberStyles.Integer, CultureInfo.InvariantCulture, out int optionValue))
                    {
                        return ChatCommandHandler.CommandResult.Error("Usage: /localutility openuiwithoption <uiType> <option>");
                    }

                    return ChatCommandHandler.CommandResult.Ok(ApplyPacketOwnedOpenUiWithOption(optionUiType, optionValue));

                case "commodity":
                    if (args.Length < 2 || !int.TryParse(args[1], NumberStyles.Integer, CultureInfo.InvariantCulture, out int commoditySn))
                    {
                        return ChatCommandHandler.CommandResult.Error("Usage: /localutility commodity <serialNumber>");
                    }

                    return ChatCommandHandler.CommandResult.Ok(ApplyPacketOwnedGoToCommoditySn(commoditySn));

                case "notice":
                    if (args.Length < 2)
                    {
                        return ChatCommandHandler.CommandResult.Error("Usage: /localutility notice <text>");
                    }

                    return ChatCommandHandler.CommandResult.Ok(ApplyPacketOwnedNoticeMessage(string.Join(" ", args.Skip(1))));

                case "chat":
                    if (args.Length < 2)
                    {
                        return ChatCommandHandler.CommandResult.Error("Usage: /localutility chat [channel|type19|couple|whisper:name|whisperout:name] <text>");
                    }

                    if (args.Length >= 3)
                    {
                        return ChatCommandHandler.CommandResult.Ok(ApplyPacketOwnedChatMessage(string.Join(" ", args.Skip(2)), args[1]));
                    }

                    return ChatCommandHandler.CommandResult.Ok(ApplyPacketOwnedChatMessage(args[1]));

                case "buffzone":
                    return ChatCommandHandler.CommandResult.Ok(ApplyPacketOwnedBuffzoneEffect(args.Length >= 2 ? string.Join(" ", args.Skip(1)) : null));

                case "eventsound":
                    if (args.Length < 2)
                    {
                        return ChatCommandHandler.CommandResult.Error("Usage: /localutility eventsound <image/path or path>");
                    }

                    return ChatCommandHandler.CommandResult.Ok(ApplyPacketOwnedEventSound(string.Join(" ", args.Skip(1)), minigame: false));

                case "minigamesound":
                    if (args.Length < 2)
                    {
                        return ChatCommandHandler.CommandResult.Error("Usage: /localutility minigamesound <image/path or path>");
                    }

                    return ChatCommandHandler.CommandResult.Ok(ApplyPacketOwnedEventSound(string.Join(" ", args.Skip(1)), minigame: true));

                case "questguide":
                    if (args.Length >= 2 && string.Equals(args[1], "clear", StringComparison.OrdinalIgnoreCase))
                    {
                        return ChatCommandHandler.CommandResult.Ok(ResetPacketQuestGuideLaunch());
                    }

                    if (args.Length < 3 || !int.TryParse(args[1], NumberStyles.Integer, CultureInfo.InvariantCulture, out int questId))
                    {
                        return ChatCommandHandler.CommandResult.Error("Usage: /localutility questguide <questId> <mobId:mapId[,mapId...]>... | /localutility questguide clear");
                    }

                    Dictionary<int, IReadOnlyList<int>> targetsByMobId = new();
                    for (int i = 2; i < args.Length; i++)
                    {
                        string[] parts = args[i].Split(':');
                        if (parts.Length != 2
                            || !int.TryParse(parts[0], NumberStyles.Integer, CultureInfo.InvariantCulture, out int mobId))
                        {
                            return ChatCommandHandler.CommandResult.Error("Usage: /localutility questguide <questId> <mobId:mapId[,mapId...]>... | /localutility questguide clear");
                        }

                        List<int> mapIds = parts[1]
                            .Split(new[] { ',' }, StringSplitOptions.RemoveEmptyEntries)
                            .Select(value => int.TryParse(value, NumberStyles.Integer, CultureInfo.InvariantCulture, out int parsedMapId) ? parsedMapId : 0)
                            .Where(mapId => mapId > 0)
                            .Distinct()
                            .ToList();
                        if (mapIds.Count == 0)
                        {
                            return ChatCommandHandler.CommandResult.Error("Usage: /localutility questguide <questId> <mobId:mapId[,mapId...]>... | /localutility questguide clear");
                        }

                        targetsByMobId[mobId] = mapIds;
                    }

                    return ChatCommandHandler.CommandResult.Ok(ApplyPacketQuestGuideLaunch(questId, targetsByMobId));

                case "delivery":
                    if (args.Length < 3
                        || !int.TryParse(args[1], NumberStyles.Integer, CultureInfo.InvariantCulture, out int deliveryQuestId)
                        || !int.TryParse(args[2], NumberStyles.Integer, CultureInfo.InvariantCulture, out int deliveryItemId))
                    {
                        return ChatCommandHandler.CommandResult.Error("Usage: /localutility delivery <questId> <itemId> [blockedQuestIdsCsv] [accept|complete|none]");
                    }

                    List<int> blockedQuestIds = new();
                    QuestDetailDeliveryType packetOwnedDeliveryType = QuestDetailDeliveryType.None;
                    if (args.Length >= 4)
                    {
                        if (TryParseQuestDeliveryTypeToken(args[3], out packetOwnedDeliveryType))
                        {
                        }
                        else
                        {
                            blockedQuestIds.AddRange(
                                args[3].Split(new[] { ',' }, StringSplitOptions.RemoveEmptyEntries)
                                    .Select(value => int.TryParse(value, NumberStyles.Integer, CultureInfo.InvariantCulture, out int blockedQuestId) ? blockedQuestId : 0)
                                    .Where(blockedQuestId => blockedQuestId > 0));
                        }
                    }

                    if (args.Length >= 5)
                    {
                        if (!TryParseQuestDeliveryTypeToken(args[4], out packetOwnedDeliveryType))
                        {
                            return ChatCommandHandler.CommandResult.Error("Usage: /localutility delivery <questId> <itemId> [blockedQuestIdsCsv] [accept|complete|none]");
                        }
                    }

                    return ChatCommandHandler.CommandResult.Ok(ApplyDeliveryQuestLaunch(deliveryQuestId, deliveryItemId, blockedQuestIds, packetOwnedDeliveryType));

                case "classcompetition":
                    return ChatCommandHandler.CommandResult.Ok(ApplyClassCompetitionPageLaunch());

                case "skillguide":
                    return ChatCommandHandler.CommandResult.Ok(ApplyPacketOwnedSkillGuideLaunch());

                case "radioctx":
                case "radiocontext":
                    if (args.Length < 2)
                    {
                        return ChatCommandHandler.CommandResult.Info($"Usage: /localutility radioctx <status|left|right|on|off|1|0|reset>. {DescribePacketOwnedRadioCreateLayerContextStatus()}");
                    }

                    switch (args[1].ToLowerInvariant())
                    {
                        case "status":
                            return ChatCommandHandler.CommandResult.Info(DescribePacketOwnedRadioCreateLayerContextStatus());

                        case "left":
                        case "on":
                        case "1":
                            return ChatCommandHandler.CommandResult.Ok($"{SetPacketOwnedRadioCreateLayerContext(true)} {DescribePacketOwnedRadioCreateLayerContextStatus()}");

                        case "right":
                        case "off":
                        case "0":
                            return ChatCommandHandler.CommandResult.Ok($"{SetPacketOwnedRadioCreateLayerContext(false)} {DescribePacketOwnedRadioCreateLayerContextStatus()}");

                        case "reset":
                        case "clear":
                            return ChatCommandHandler.CommandResult.Ok($"{ClearPacketOwnedRadioCreateLayerContext()} {DescribePacketOwnedRadioCreateLayerContextStatus()}");

                        default:
                            return ChatCommandHandler.CommandResult.Error("Usage: /localutility radioctx <status|left|right|on|off|1|0|reset>");
                    }

                case "antimacro":
                    return HandlePacketOwnedAntiMacroCommand(args.Skip(1).ToArray());

                case "apsp":
                    if (args.Length >= 2)
                    {
                        switch (args[1].ToLowerInvariant())
                        {
                            case "status":
                                return ChatCommandHandler.CommandResult.Info(DescribePacketOwnedApspContextStatus());

                            case "seed":
                                int? apspSeedCharacterId = null;
                                int parsedApspSeedCharacterId = 0;
                                if (args.Length >= 3
                                    && !int.TryParse(args[2], NumberStyles.Integer, CultureInfo.InvariantCulture, out parsedApspSeedCharacterId))
                                {
                                    return ChatCommandHandler.CommandResult.Error("Usage: /localutility apsp [status|seed [characterId]|receive <token>|send <token>|context <receiveToken> [sendToken]|<contextToken> <11|12|13>|text]");
                                }

                                if (args.Length >= 3)
                                {
                                    apspSeedCharacterId = parsedApspSeedCharacterId;
                                }

                                return ChatCommandHandler.CommandResult.Ok(
                                    SeedPacketOwnedApspContextTokens(apspSeedCharacterId));

                            case "receive":
                                if (args.Length < 3
                                    || !int.TryParse(args[2], NumberStyles.Integer, CultureInfo.InvariantCulture, out int apspReceiveToken)
                                    || apspReceiveToken <= 0)
                                {
                                    return ChatCommandHandler.CommandResult.Error("Usage: /localutility apsp [status|seed [characterId]|receive <token>|send <token>|context <receiveToken> [sendToken]|<contextToken> <11|12|13>|text]");
                                }

                                return ChatCommandHandler.CommandResult.Ok(OverridePacketOwnedApspReceiveContextToken(apspReceiveToken));

                            case "send":
                                if (args.Length < 3
                                    || !int.TryParse(args[2], NumberStyles.Integer, CultureInfo.InvariantCulture, out int apspSendToken)
                                    || apspSendToken <= 0)
                                {
                                    return ChatCommandHandler.CommandResult.Error("Usage: /localutility apsp [status|seed [characterId]|receive <token>|send <token>|context <receiveToken> [sendToken]|<contextToken> <11|12|13>|text]");
                                }

                                return ChatCommandHandler.CommandResult.Ok(OverridePacketOwnedApspSendContextToken(apspSendToken));

                            case "context":
                                if (args.Length < 3
                                    || !int.TryParse(args[2], NumberStyles.Integer, CultureInfo.InvariantCulture, out int apspReceiveContextToken)
                                    || apspReceiveContextToken <= 0)
                                {
                                    return ChatCommandHandler.CommandResult.Error("Usage: /localutility apsp [status|seed [characterId]|receive <token>|send <token>|context <receiveToken> [sendToken]|<contextToken> <11|12|13>|text]");
                                }

                                int? apspSendContextToken = null;
                                int parsedApspSendContextToken = 0;
                                if (args.Length >= 4
                                    && (!int.TryParse(args[3], NumberStyles.Integer, CultureInfo.InvariantCulture, out parsedApspSendContextToken)
                                        || parsedApspSendContextToken <= 0))
                                {
                                    return ChatCommandHandler.CommandResult.Error("Usage: /localutility apsp [status|seed [characterId]|receive <token>|send <token>|context <receiveToken> [sendToken]|<contextToken> <11|12|13>|text]");
                                }

                                if (args.Length >= 4)
                                {
                                    apspSendContextToken = parsedApspSendContextToken;
                                }

                                return ChatCommandHandler.CommandResult.Ok(
                                    OverridePacketOwnedApspContextTokens(
                                        apspReceiveContextToken,
                                        apspSendContextToken));
                        }
                    }

                    if (args.Length >= 3
                        && int.TryParse(args[1], NumberStyles.Integer, CultureInfo.InvariantCulture, out int apspContextToken)
                        && int.TryParse(args[2], NumberStyles.Integer, CultureInfo.InvariantCulture, out int apspEventType))
                    {
                        return TryApplyPacketOwnedAskApspEvent(apspContextToken, apspEventType, out string structuredApspMessage)
                            ? ChatCommandHandler.CommandResult.Ok(structuredApspMessage)
                            : ChatCommandHandler.CommandResult.Error(structuredApspMessage);
                    }

                    return ChatCommandHandler.CommandResult.Ok(ApplyPacketOwnedAskApspEvent(args.Length >= 2 ? string.Join(" ", args.Skip(1)) : null));

                case "follow":
                    return HandlePacketOwnedFollowCommand(args.Skip(1).ToArray());

                case "followfail":
                    if (args.Length >= 2
                        && int.TryParse(args[1], NumberStyles.Integer, CultureInfo.InvariantCulture, out int followReasonCode))
                    {
                        int followDriverId = 0;
                        if (args.Length >= 3
                            && !int.TryParse(args[2], NumberStyles.Integer, CultureInfo.InvariantCulture, out followDriverId))
                        {
                            return ChatCommandHandler.CommandResult.Error("Usage: /localutility followfail [reasonCode [driverId]|text]");
                        }

                        FollowCharacterFailureInfo info = FollowCharacterFailureCodec.Resolve(
                            followReasonCode,
                            followDriverId,
                            ResolvePacketOwnedRemoteCharacterName);
                        return ChatCommandHandler.CommandResult.Ok(ApplyPacketOwnedFollowCharacterFailed(info));
                    }

                    return ChatCommandHandler.CommandResult.Ok(ApplyPacketOwnedFollowCharacterFailed(args.Length >= 2 ? string.Join(" ", args.Skip(1)) : null));

                case "packet":
                case "packetraw":
                    return HandlePacketOwnedUtilityPacketCommand(args, rawHex: string.Equals(args[0], "packetraw", StringComparison.OrdinalIgnoreCase));
